import React, { useState, useEffect, useRef } from 'react';
import { Search, SlidersHorizontal, Upload, LayoutGrid, BarChart2, Moon, Sun, Globe, User, LogOut, Settings, Shield, History, X, Trash2, Clock, Command, Download, Loader2, Maximize, Minimize, ArrowRight } from 'lucide-react';
import { ColumnConfig, ViewMode, User as UserType } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import { useTheme } from '../contexts/ThemeContext';

interface TopBarProps {
  user: UserType | null;
  onLogout: () => void;
  onOpenProfile: () => void;
  onOpenAdmin: () => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  isSearching?: boolean;
  columns: ColumnConfig[];
  onToggleColumn: (key: string) => void;
  onToggleAllColumns: (visible: boolean) => void;
  onOpenImport: () => void;
  onExport: () => void;
  isExporting: boolean;
  viewMode: ViewMode;
  onViewModeChange: (mode: ViewMode) => void;
}

export const TopBar: React.FC<TopBarProps> = ({
  user, onLogout, onOpenProfile, onOpenAdmin, searchQuery, onSearchChange, isSearching, columns, onToggleColumn, onToggleAllColumns, onOpenImport, onExport, isExporting, viewMode, onViewModeChange
}) => {
  const [isColumnMenuOpen, setIsColumnMenuOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const { t, language, toggleLanguage, tProp } = useLanguage();
  const { theme, toggleTheme } = useTheme();
  const inputRef = useRef<HTMLInputElement>(null);

  const colMenuRef = useRef<HTMLDivElement>(null);
  const userMenuRef = useRef<HTMLDivElement>(null);

  // Search History State
  const [searchHistory, setSearchHistory] = useState<string[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [historyIndex, setHistoryIndex] = useState(-1);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
            e.preventDefault();
            inputRef.current?.focus();
        }
    };

    const handleClickOutside = (e: MouseEvent) => {
        if (colMenuRef.current && !colMenuRef.current.contains(e.target as Node)) {
            setIsColumnMenuOpen(false);
        }
        if (userMenuRef.current && !userMenuRef.current.contains(e.target as Node)) {
            setIsUserMenuOpen(false);
        }
    };

    const handleFullscreenChange = () => {
        setIsFullscreen(!!document.fullscreenElement);
    };

    window.addEventListener('keydown', handleKeyDown);
    document.addEventListener('mousedown', handleClickOutside);
    document.addEventListener('fullscreenchange', handleFullscreenChange);

    // Load history
    const savedHistory = localStorage.getItem('resindb_search_history');
    if (savedHistory) {
        try {
            setSearchHistory(JSON.parse(savedHistory));
        } catch (e) {
            console.error('Failed to load search history');
        }
    }

    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        document.removeEventListener('mousedown', handleClickOutside);
        document.removeEventListener('fullscreenchange', handleFullscreenChange);
    };
  }, []);

  const saveToHistory = (query: string) => {
      if (!query.trim()) return;
      const clean = query.trim();
      setSearchHistory(prev => {
          const filtered = prev.filter(item => item !== clean);
          const updated = [clean, ...filtered].slice(0, 5);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const removeFromHistory = (e: React.MouseEvent, itemToRemove: string) => {
      e.stopPropagation();
      setSearchHistory(prev => {
          const updated = prev.filter(item => item !== itemToRemove);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
      // Keep input focused
      inputRef.current?.focus();
  };

  const clearHistory = () => {
      setSearchHistory([]);
      localStorage.removeItem('resindb_search_history');
      inputRef.current?.focus();
  };

  const handleInputKeyDown = (e: React.KeyboardEvent) => {
      if (showHistory && searchHistory.length > 0) {
          if (e.key === 'ArrowDown') {
              e.preventDefault();
              setHistoryIndex(prev => (prev + 1) % searchHistory.length);
              return;
          }
          if (e.key === 'ArrowUp') {
              e.preventDefault();
              setHistoryIndex(prev => (prev - 1 + searchHistory.length) % searchHistory.length);
              return;
          }
      }

      if (e.key === 'Enter') {
          e.preventDefault();
          if (historyIndex >= 0 && showHistory && searchHistory[historyIndex]) {
              const selected = searchHistory[historyIndex];
              onSearchChange(selected);
              saveToHistory(selected);
              setShowHistory(false);
              setHistoryIndex(-1);
              inputRef.current?.blur();
          } else {
              saveToHistory(searchQuery);
              setShowHistory(false);
              setHistoryIndex(-1);
              inputRef.current?.blur();
          }
      }

      if (e.key === 'Escape') {
          setShowHistory(false);
          inputRef.current?.blur();
      }
  };

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
        document.documentElement.requestFullscreen().catch((e) => {
            console.error(`Error attempting to enable fullscreen: ${e.message}`);
        });
    } else {
        if (document.exitFullscreen) {
            document.exitFullscreen();
        }
    }
  };

  const nonSystemCols = columns.filter(c => !c.isSystem);
  const visibleCount = nonSystemCols.filter(c => c.visible).length;
  const isAllSelected = nonSystemCols.length > 0 && visibleCount === nonSystemCols.length;
  const isIndeterminate = visibleCount > 0 && !isAllSelected;

  const handleSelectAll = () => {
    onToggleAllColumns(!isAllSelected);
  };

  return (
    <div className="w-full flex items-center justify-between gap-6 px-2 py-2 pointer-events-none">
      {/* Search Pill - Clean & Minimal */}
      <div className="flex-1 max-w-2xl relative z-[60] pointer-events-auto">
        <div className="relative group transition-all duration-300 focus-within:scale-[1.01]">
            <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                {isSearching ? (
                    <Loader2 className="text-primary-500 animate-spin" size={20} />
                ) : (
                    <Search className="text-slate-400 group-focus-within:text-primary-500 transition-colors" size={20} />
                )}
            </div>
            <input
                ref={inputRef}
                type="text"
                value={historyIndex >= 0 && showHistory ? searchHistory[historyIndex] : searchQuery}
                onChange={(e) => {
                    onSearchChange(e.target.value);
                    setHistoryIndex(-1);
                }}
                onFocus={() => {
                    setShowHistory(true);
                    setHistoryIndex(-1);
                }}
                onBlur={() => setTimeout(() => setShowHistory(false), 200)}
                onKeyDown={handleInputKeyDown}
                placeholder={t('searchPlaceholder')}
                className="block w-full pl-14 pr-12 py-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur-2xl border border-slate-200/50 dark:border-slate-800/50 rounded-[2rem] text-sm font-medium shadow-glass dark:shadow-none outline-none focus:ring-4 focus:ring-primary-500/10 focus:border-primary-500/20 transition-all text-slate-700 dark:text-slate-200 placeholder:text-slate-400"
            />
            <div className="absolute inset-y-0 right-5 flex items-center">
                {searchQuery ? (
                    <button 
                        onClick={() => { onSearchChange(''); inputRef.current?.focus(); }}
                        className="p-1 rounded-full text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700 hover:text-slate-600 dark:hover:text-slate-200 transition-colors animate-in fade-in zoom-in duration-200"
                    >
                        <X size={14} />
                    </button>
                ) : (
                    <span className="flex items-center gap-1 px-2.5 py-1 bg-slate-100/50 dark:bg-slate-800/50 rounded-lg border border-slate-200/50 dark:border-slate-700/50 text-[10px] font-bold text-slate-400 shadow-sm pointer-events-none">
                        <Command size={10} /> K
                    </span>
                )}
            </div>

            {/* Search History Dropdown */}
            {showHistory && searchHistory.length > 0 && (
                <div className="absolute top-full left-4 right-4 mt-2 bg-white/95 dark:bg-slate-900/95 backdrop-blur-xl border border-slate-200/50 dark:border-slate-800/50 rounded-2xl shadow-xl overflow-hidden z-50 animate-in fade-in slide-in-from-top-2 duration-200 ring-1 ring-black/5">
                    <div className="flex items-center justify-between px-4 py-2.5 border-b border-slate-100 dark:border-slate-800/50 bg-slate-50/50 dark:bg-slate-950/30">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1.5">
                            <Clock size={10} /> {t('recentSearches')}
                        </span>
                        <button 
                            onMouseDown={(e) => { e.preventDefault(); clearHistory(); }}
                            className="text-[10px] text-rose-500 hover:text-rose-600 font-bold uppercase tracking-wider flex items-center gap-1 hover:bg-rose-50 dark:hover:bg-rose-900/20 px-2 py-0.5 rounded transition-colors"
                        >
                            <Trash2 size={10} /> {t('clearHistory')}
                        </button>
                    </div>
                    <div className="py-1">
                        {searchHistory.map((query, index) => (
                            <div
                                key={index}
                                onMouseDown={(e) => { 
                                    e.preventDefault(); // Prevent blur
                                    onSearchChange(query); 
                                    saveToHistory(query); 
                                    setShowHistory(false); 
                                    inputRef.current?.blur();
                                }}
                                className={`w-full flex items-center justify-between px-4 py-2.5 cursor-pointer transition-colors group text-left ${
                                    index === historyIndex 
                                    ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-200' 
                                    : 'hover:bg-slate-100 dark:hover:bg-slate-800/50 text-slate-600 dark:text-slate-300'
                                }`}
                            >
                                <div className="flex items-center gap-3 overflow-hidden">
                                    <History size={14} className={`shrink-0 transition-colors ${index === historyIndex ? 'text-primary-500' : 'text-slate-400 group-hover:text-primary-500'}`} />
                                    <span className="text-sm font-medium truncate">{query}</span>
                                </div>
                                <div className="flex items-center gap-2">
                                    {index === historyIndex && <ArrowRight size={12} className="text-primary-400 animate-in slide-in-from-left-2 fade-in" />}
                                    <button 
                                        onMouseDown={(e) => removeFromHistory(e, query)}
                                        className="p-1 text-slate-300 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded opacity-0 group-hover:opacity-100 transition-all"
                                    >
                                        <X size={12} />
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
      </div>

      {/* Right Actions Island - Floating Glass */}
      <div className="flex items-center gap-2 p-2 bg-white/80 dark:bg-slate-900/80 backdrop-blur-2xl border border-slate-200/50 dark:border-slate-800/50 rounded-[2rem] shadow-glass dark:shadow-none pointer-events-auto z-[60]">

        {/* View Toggle */}
        <div className="flex items-center bg-slate-100 dark:bg-slate-800 rounded-[1.5rem] p-1 border border-slate-200 dark:border-slate-700">
            <button onClick={() => onViewModeChange('grid')} className={`p-2.5 rounded-[1.2rem] transition-all active:scale-95 ${viewMode === 'grid' ? 'bg-white dark:bg-slate-700 text-primary-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}>
                <LayoutGrid size={18} />
            </button>
            <button onClick={() => onViewModeChange('chart')} className={`p-2.5 rounded-[1.2rem] transition-all active:scale-95 ${viewMode === 'chart' ? 'bg-white dark:bg-slate-700 text-primary-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}>
                <BarChart2 size={18} />
            </button>
        </div>

        <div className="h-6 w-px bg-slate-200 dark:bg-slate-700 mx-2"></div>

        <button onClick={onOpenImport} className="w-10 h-10 flex items-center justify-center text-slate-500 hover:text-primary-600 hover:bg-primary-50 dark:hover:bg-primary-900/20 rounded-full transition-all active:scale-95" title={t('importData')}>
            <Upload size={20} />
        </button>

        <button 
            onClick={onExport} 
            disabled={isExporting}
            className="w-10 h-10 flex items-center justify-center text-slate-500 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-full transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed" 
            title="Download Report (CSV)"
        >
            {isExporting ? <Loader2 size={20} className="animate-spin text-blue-500" /> : <Download size={20} />}
        </button>

        <div className="relative" ref={colMenuRef}>
            <button onClick={() => setIsColumnMenuOpen(!isColumnMenuOpen)} className={`w-10 h-10 flex items-center justify-center rounded-full transition-all active:scale-95 ${isColumnMenuOpen ? 'bg-primary-50 text-primary-600' : 'text-slate-500 hover:text-primary-600 hover:bg-primary-50 dark:hover:bg-primary-900/20'}`}>
                <SlidersHorizontal size={20} />
            </button>
            {isColumnMenuOpen && (
                <div className="absolute top-full right-0 mt-4 w-72 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-[2rem] shadow-2xl p-4 animate-in fade-in zoom-in-95 origin-top-right z-[100]">
                    <h4 className="text-xs font-black uppercase text-slate-400 mb-3 tracking-widest px-2">{t('visibleAttributes')}</h4>

                    <label className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 cursor-pointer transition-colors group mb-2 border-b border-slate-100 dark:border-slate-800 pb-2">
                        <div className={`w-5 h-5 rounded-md border flex items-center justify-center transition-colors ${isAllSelected || isIndeterminate ? 'bg-primary-600 border-primary-600' : 'border-slate-300 dark:border-slate-600 group-hover:border-primary-400'}`}>
                            {isAllSelected && <div className="w-2 h-2 bg-white rounded-full"></div>}
                            {isIndeterminate && <div className="w-2.5 h-0.5 bg-white rounded-full"></div>}
                        </div>
                        <input 
                            type="checkbox" 
                            checked={isAllSelected} 
                            ref={(el) => { if(el) el.indeterminate = isIndeterminate; }}
                            onChange={handleSelectAll} 
                            className="hidden" 
                        />
                        <span className="text-xs font-bold text-slate-800 dark:text-white transition-colors">{t('selectAll')}</span>
                    </label>

                    <div className="max-h-64 overflow-y-auto custom-scrollbar space-y-1 pr-1">
                        {columns.map(col => (
                            <label key={col.key} className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 cursor-pointer transition-colors group">
                                <div className={`w-5 h-5 rounded-md border flex items-center justify-center transition-colors ${col.visible ? 'bg-primary-600 border-primary-600' : 'border-slate-300 dark:border-slate-600 group-hover:border-primary-400'}`}>
                                    {col.visible && <div className="w-2 h-2 bg-white rounded-full"></div>}
                                </div>
                                <input type="checkbox" checked={col.visible} onChange={() => !col.isSystem && onToggleColumn(col.key)} disabled={col.isSystem} className="hidden" />
                                <span className={`text-xs font-bold transition-colors ${col.visible ? 'text-slate-800 dark:text-white' : 'text-slate-500'}`}>{tProp(col.label)}</span>
                            </label>
                        ))}
                    </div>
                </div>
            )}
        </div>

        <button onClick={toggleTheme} className="w-10 h-10 flex items-center justify-center text-slate-500 hover:text-amber-500 hover:bg-amber-50 dark:hover:bg-amber-900/20 rounded-full transition-all active:scale-95">
            {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
        </button>

        <button onClick={toggleFullScreen} className="w-10 h-10 flex items-center justify-center text-slate-500 hover:text-indigo-500 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded-full transition-all active:scale-95" title={isFullscreen ? "Exit Full Screen" : "Full Screen"}>
            {isFullscreen ? <Minimize size={20} /> : <Maximize size={20} />}
        </button>

        <div className="h-6 w-px bg-slate-200 dark:bg-slate-700 mx-2"></div>

        {/* Profile Pill */}
        <div className="relative" ref={userMenuRef}>
            <button onClick={() => setIsUserMenuOpen(!isUserMenuOpen)} className="flex items-center gap-2 pl-1 pr-4 py-1.5 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-full transition-all border border-slate-200 dark:border-slate-700 active:scale-95">
                <img src={user?.avatar} alt="" className="w-8 h-8 rounded-full border border-white dark:border-slate-600 shadow-sm" />
                <span className="text-xs font-bold text-slate-700 dark:text-slate-200 max-w-[80px] truncate">{user?.name.split(' ')[0]}</span>
            </button>
            {isUserMenuOpen && (
                <div className="absolute top-full right-0 mt-4 w-60 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-[2rem] shadow-2xl p-2 animate-in fade-in zoom-in-95 origin-top-right z-[100] flex flex-col gap-1">
                    <button onClick={() => { setIsUserMenuOpen(false); onOpenProfile(); }} className="flex items-center gap-3 px-4 py-3 rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-800 text-sm font-bold text-slate-700 dark:text-slate-200 transition-colors"><User size={18} /> {t('profile')}</button>
                    <button onClick={() => { setIsUserMenuOpen(false); onOpenAdmin(); }} className="flex items-center gap-3 px-4 py-3 rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-800 text-sm font-bold text-slate-700 dark:text-slate-200 transition-colors"><Shield size={18} /> {t('adminPanel')}</button>
                    <button onClick={() => { setIsUserMenuOpen(false); toggleLanguage(); }} className="flex items-center gap-3 px-4 py-3 rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-800 text-sm font-bold text-slate-700 dark:text-slate-200 transition-colors"><Globe size={18} /> {language === 'zh' ? 'English' : '中文'}</button>
                    <div className="h-px bg-slate-100 dark:bg-slate-800 my-1"></div>
                    <button onClick={onLogout} className="flex items-center gap-3 px-4 py-3 rounded-2xl hover:bg-blue-50 dark:hover:bg-blue-900/20 text-sm font-bold text-blue-600 transition-colors"><LogOut size={18} /> {t('logout')}</button>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect, ReactNode } from 'react';
import { CATEGORY_TREE, MOCK_PRODUCTS } from './constants';
import { Product, ColumnConfig, ViewMode, Category, User, PropertyValue } from './types';
import { TreeSidebar } from './components/TreeSidebar';
import { DataGrid } from './components/DataGrid';
import { DataVisualizer } from './components/DataVisualizer';
import { TopBar } from './components/TopBar';
import { ImportModal } from './components/ImportModal';
import { AIAssistant } from './components/AIAssistant';
import { AuthScreen } from './components/AuthScreen';
import { ProfileModal } from './components/ProfileModal';
import { AdminModal } from './components/AdminModal';
import { LayoutDashboard, Database, Activity, Home, ChevronRight, Package, Factory, BarChart3, FlaskConical, TrendingUp, AlertCircle, RefreshCw, ShieldCheck, Microscope, Info, Zap, Sparkles, PieChart, Bot, MessageSquare, Beaker, Layout } from 'lucide-react';
import { LanguageProvider, useLanguage } from './contexts/LanguageContext';
import { ThemeProvider } from './contexts/ThemeContext';

// --- Error Boundary Component ---
interface ErrorBoundaryProps {
  children?: ReactNode;
  fallback?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error?: Error;
}

class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(error: Error) {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    console.error("ErrorBoundary caught an error:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return this.props.fallback || (
        <div className="flex flex-col items-center justify-center h-full min-h-[400px] p-8 text-center bg-white dark:bg-slate-900 border border-rose-200 dark:border-rose-900/30 rounded-xl shadow-sm animate-in fade-in duration-300">
          <div className="w-16 h-16 bg-rose-100 dark:bg-rose-900/20 text-rose-600 dark:text-rose-400 rounded-full flex items-center justify-center mb-4">
            <AlertCircle size={32} />
          </div>
          <h2 className="text-lg font-bold text-slate-900 dark:text-white mb-2">Something went wrong</h2>
          <p className="text-sm text-slate-500 dark:text-slate-400 mb-6 max-w-sm mx-auto">
            An unexpected error occurred while rendering this component.
          </p>
          <button 
            onClick={() => this.setState({ hasError: false })}
            className="flex items-center gap-2 px-4 py-2 bg-rose-600 hover:bg-rose-700 text-white text-sm font-semibold rounded-lg transition-all shadow-lg shadow-rose-500/20 active:scale-95"
          >
            <RefreshCw size={14} />
            Try to reload
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}

const getDynamicColumns = (products: Product[]): ColumnConfig[] => {
  const propertyKeys = new Set<string>();
  products.forEach(p => {
    Object.keys(p.properties).forEach(k => propertyKeys.add(k));
  });

  const defaultVisible = ['密度', '熔体质量流动速率', '应用', '类型', '典型应用', '硬度', '悬臂梁缺口冲击', '拉伸强度'];

  const dynamicCols: ColumnConfig[] = Array.from(propertyKeys).map(key => ({
    key,
    label: key,
    visible: defaultVisible.includes(key),
    isSystem: false
  })).sort((a, b) => {
      const aIsLikelyImportant = defaultVisible.includes(a.key);
      const bIsLikelyImportant = defaultVisible.includes(b.key);
      if (aIsLikelyImportant && !bIsLikelyImportant) return -1;
      if (!aIsLikelyImportant && bIsLikelyImportant) return 1;
      return a.label.localeCompare(b.label);
  });

  const systemCols: ColumnConfig[] = [
    { key: 'gradeName', label: '牌号', visible: true, isSystem: true },
    { key: 'manufacturer', label: '所属分类', visible: true, isSystem: true },
    { key: 'updatedAt', label: '更新时间', visible: false, isSystem: false },
  ];

  return [...systemCols, ...dynamicCols];
};

const Breadcrumbs: React.FC<{ categoryId: string | null, onReset: () => void }> = ({ categoryId, onReset }) => {
    const { t, language } = useLanguage();

    const path = useMemo(() => {
        if (!categoryId) return [];
        const findPath = (nodes: Category[], targetId: string, currentPath: Category[]): Category[] | null => {
            for (const node of nodes) {
                if (node.id === targetId) return [...currentPath, node];
                if (node.children) {
                    const childResult = findPath(node.children, targetId, [...currentPath, node]);
                    if (childResult) return childResult;
                }
            }
            return null;
        };
        return findPath(CATEGORY_TREE, categoryId, []) || [];
    }, [categoryId]);

    return (
        <nav className="flex items-center text-sm text-slate-500 dark:text-slate-400 mb-4 px-1">
            <div 
                className="flex items-center hover:text-emerald-600 dark:hover:text-emerald-400 transition-colors cursor-pointer group" 
                onClick={onReset}
            >
                <Home size={14} className="mr-1.5 transition-transform group-hover:scale-110" />
                <span className="font-medium">{t('home')}</span>
            </div>
            {path.map((cat) => (
                <React.Fragment key={cat.id}>
                    <ChevronRight size={14} className="mx-2 text-slate-300 dark:text-slate-600" />
                    <span className="font-medium text-slate-800 dark:text-slate-200 hover:text-emerald-600 dark:hover:text-emerald-400 transition-colors cursor-pointer">
                        {language === 'en' && cat.nameEn ? cat.nameEn : cat.name}
                    </span>
                </React.Fragment>
            ))}
        </nav>
    );
};

const SummaryStats: React.FC<{ data: Product[] }> = ({ data }) => {
    const { t, tProp } = useLanguage();

    const stats = useMemo(() => {
        const manufacturers = new Set(data.map(p => p.manufacturerId || p.manufacturer)).size;
        let densitySum = 0, densityCount = 0, mfrSum = 0, mfrCount = 0, totalPropsWithRefs = 0, totalPropsCount = 0;

        data.forEach(p => {
            const d = p.properties['密度']?.value;
            const dNum = typeof d === 'number' ? d : parseFloat(String(d));
            if (!isNaN(dNum)) { densitySum += dNum; densityCount++; }

            const m = p.properties['熔体质量流动速率']?.value;
            const mNum = typeof m === 'number' ? m : parseFloat(String(m));
            if (!isNaN(mNum)) { mfrSum += mNum; mfrCount++; }

            (Object.values(p.properties) as PropertyValue[]).forEach(prop => {
                totalPropsCount++;
                if (prop.referenceId) totalPropsWithRefs++;
            });
        });

        const coverage = totalPropsCount > 0 ? (totalPropsWithRefs / totalPropsCount) * 100 : 0;

        return {
            count: data.length,
            manufacturers,
            avgDensity: densityCount ? (densitySum / densityCount).toFixed(3) : '-',
            avgMfr: mfrCount ? (mfrSum / mfrCount).toFixed(2) : '-',
            refCoverage: coverage.toFixed(1)
        };
    }, [data]);

    return (
        <div className="grid grid-cols-2 xl:grid-cols-5 gap-4 mb-8">
            <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-4 rounded-2xl shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all group overflow-hidden relative">
