                    <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t('total')}</p>
                </div>
                <div className="flex items-baseline gap-1.5 pl-1"><span className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">{stats.count}</span><span className="text-[10px] font-bold text-slate-400 uppercase">{tProp('牌号')}</span></div>
            </div>
            <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-4 rounded-2xl shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all group overflow-hidden relative">
                <div className="absolute -right-4 -bottom-4 opacity-5 group-hover:scale-110 transition-transform"><Factory size={80} className="text-blue-600" /></div>
                <div className="flex items-center gap-3 mb-3">
                    <div className="w-9 h-9 rounded-xl bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 flex items-center justify-center shadow-inner"><Factory size={18} /></div>
                    <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t('manufacturers')}</p>
                </div>
                <div className="flex items-baseline gap-1.5 pl-1"><span className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">{stats.manufacturers}</span><span className="text-[10px] font-bold text-slate-400 uppercase">Entities</span></div>
            </div>
            <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-4 rounded-2xl shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all group overflow-hidden relative">
                <div className="absolute -right-4 -bottom-4 opacity-5 group-hover:scale-110 transition-transform"><FlaskConical size={80} className="text-emerald-600" /></div>
                <div className="flex items-center gap-3 mb-3">
                    <div className="w-9 h-9 rounded-xl bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 flex items-center justify-center shadow-inner"><Microscope size={18} /></div>
                    <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t('avg')} {tProp('密度')}</p>
                </div>
                <div className="flex items-baseline gap-1.5 pl-1"><span className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">{stats.avgDensity}</span><span className="text-[10px] font-bold text-emerald-600/60 font-mono">g/cm³</span></div>
            </div>
            <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-4 rounded-2xl shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all group overflow-hidden relative">
                <div className="absolute -right-4 -bottom-4 opacity-5 group-hover:scale-110 transition-transform"><TrendingUp size={80} className="text-amber-600" /></div>
                <div className="flex items-center gap-3 mb-3">
