                    <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t('avg')} MFR</p>
                </div>
                <div className="flex items-baseline gap-1.5 pl-1"><span className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">{stats.avgMfr}</span><span className="text-[10px] font-bold text-amber-600/60 font-mono">g/10min</span></div>
            </div>
