  const handleBatchUpdate = (ids: string[], updates: Partial<Product>) => {
    const { _propertyUpdates, ...directUpdates } = updates as any;
    setAllProducts(prev => prev.map(p => {
      if (!ids.includes(p.id)) return p;
      const newProps = { ...p.properties };
      if (_propertyUpdates) {
        Object.entries(_propertyUpdates).forEach(([key, val]) => {
