/**
 * 鲁棒的属性值格式化工具
 * 确保即使后端返回非预期结构，前端界面也不会崩溃
 */
const safeRenderValue = (val: any, unit?: string): string => {
    if (val === null || val === undefined) return '-';

    // 处理字符串
    if (typeof val === 'string') {
        const trimmed = val.trim();
        if (!trimmed) return '-';
        return `${trimmed}${unit ? ` ${unit}` : ''}`;
    }

    // 处理数值（防御 NaN）
    if (typeof val === 'number') {
        if (isNaN(val)) return '-';
        return `${val}${unit ? ` ${unit}` : ''}`;
    }

    // 处理日期对象
    if (val instanceof Date) {
        return val.toLocaleDateString();
    }

    // 处理复杂对象或递归 PropertyValue
    if (typeof val === 'object') {
        try {
            if ('value' in val) return safeRenderValue(val.value, val.unit);
            return JSON.stringify(val);
        } catch (e) {
            return '[数据解析错误]';
        }
    }

    return String(val);
};

