export const DataGrid: React.FC<DataGridProps> = ({ 
    data = [], 
    columns = [], 
    isLoading, 
    onDelete, 
    onUpdate, 
    onBatchUpdate, 
    onCategorySelect, 
    selectedIds: propSelectedIds, 
    onSelectionChange 
}) => {
  const { t, tProp } = useLanguage();

  // 防御性过滤可见列
  const visibleColumns = useMemo(() => (columns || []).filter((c) => c.visible), [columns]);

  const [localSelectedIds, setLocalSelectedIds] = useState<Set<string>>(new Set());
  const selectedIds = propSelectedIds || localSelectedIds;
  const handleSelectionChange = onSelectionChange || setLocalSelectedIds;

  const [sortConfig, setSortConfig] = useState<SortConfig | null>(null);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [deletingIds, setDeletingIds] = useState<string[]>([]);
  const [isBatchEditOpen, setIsBatchEditOpen] = useState(false);
  const [viewingProduct, setViewingProduct] = useState<Product | null>(null);
  const [isComparisonOpen, setIsComparisonOpen] = useState(false);

  const [isSelectMenuOpen, setIsSelectMenuOpen] = useState(false);
  const selectMenuRef = useRef<HTMLDivElement>(null);

  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 15;

  // 全局点击监听，关闭选择菜单
  useEffect(() => {
      const handleClickOutside = (e: MouseEvent) => {
          if (selectMenuRef.current && !selectMenuRef.current.contains(e.target as Node)) {
              setIsSelectMenuOpen(false);
          }
      };
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // 当搜索条件或数据集规模大幅变动时，重置页码防止页面越界
  useEffect(() => {
      setCurrentPage(1);
  }, [data?.length]);

  const handleSort = (key: string) => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const sortedData = useMemo(() => {
    if (!data || data.length === 0) return [];
    if (!sortConfig) return data;

    return [...data].sort((a, b) => {
      // 深度提取排序值
      let aVal: any = a.properties?.[sortConfig.key]?.value ?? (a as any)[sortConfig.key] ?? '';
      let bVal: any = b.properties?.[sortConfig.key]?.value ?? (b as any)[sortConfig.key] ?? '';

      // 智能识别数值类型进行精准排序
      const aNum = parseFloat(String(aVal));
      const bNum = parseFloat(String(bVal));
      const isANum = !isNaN(aNum) && String(aVal).trim() !== '';
      const isBNum = !isNaN(bNum) && String(bVal).trim() !== '';

      if (isANum && isBNum) {
          aVal = aNum;
          bVal = bNum;
      } else {
          aVal = String(aVal).toLowerCase();
          bVal = String(bVal).toLowerCase();
      }

      if (aVal < bVal) return sortConfig.direction === 'asc' ? -1 : 1;
      if (aVal > bVal) return sortConfig.direction === 'asc' ? 1 : -1;
      return 0;
    });
  }, [data, sortConfig]);

  const paginatedData = useMemo(() => {
      const start = (currentPage - 1) * pageSize;
      return (sortedData || []).slice(start, start + pageSize);
  }, [sortedData, currentPage]);

  const totalPages = Math.ceil((sortedData?.length || 0) / pageSize);

  const toggleSelection = (id: string) => {
    const newSelected = new Set(selectedIds);
    if (newSelected.has(id)) newSelected.delete(id);
    else newSelected.add(id);
    handleSelectionChange(newSelected);
  };

  const togglePageSelection = () => {
    if (!paginatedData.length) return;
    const pageIds = paginatedData.map(p => p.id);
    const allSelected = pageIds.every(id => selectedIds.has(id));

    const newSelected = new Set(selectedIds);
    if (allSelected) {
        pageIds.forEach(id => newSelected.delete(id));
    } else {
        pageIds.forEach(id => newSelected.add(id));
    }
    handleSelectionChange(newSelected);
  };

  const selectAllMatching = () => {
      if (!sortedData.length) return;
      const allIds = sortedData.map(p => p.id);
      handleSelectionChange(new Set(allIds));
      setIsSelectMenuOpen(false);
  };

  const deselectAll = () => {
      handleSelectionChange(new Set());
      setIsSelectMenuOpen(false);
  };

  const isPageSelected = paginatedData.length > 0 && paginatedData.every(p => selectedIds.has(p.id));
  const isIndeterminate = paginatedData.some(p => selectedIds.has(p.id)) && !isPageSelected;

  // 处理加载态
  if (isLoading) return <GridSkeleton columns={visibleColumns} pageSize={pageSize} />;

  return (
    <div className="h-full flex flex-col bg-transparent relative min-h-0">
        {/* 浮动批量操作工具栏 */}
        {selectedIds.size > 0 && (
            <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-50 animate-in slide-in-from-bottom-6 duration-300">
                <div className="flex items-center gap-1 p-1.5 bg-slate-900/90 dark:bg-slate-100/90 backdrop-blur-xl rounded-2xl shadow-float border border-white/10 dark:border-slate-300 text-white dark:text-slate-900 ring-1 ring-black/5">
                    <div className="flex items-center gap-2 pl-3 pr-4 border-r border-white/10 dark:border-slate-800/10 mr-1">
                        <div className="flex items-center justify-center w-5 h-5 rounded-full bg-primary-500 text-white text-[10px] font-bold">
                            {selectedIds.size}
                        </div>
                        <span className="text-xs font-bold whitespace-nowrap">{t('selected')}</span>
                    </div>

                    <button 
                        onClick={() => setIsComparisonOpen(true)}
                        className="flex flex-col items-center justify-center w-16 h-12 rounded-xl hover:bg-white/10 dark:hover:bg-slate-900/10 transition-colors group"
                    >
                        <GitCompare size={18} className="mb-0.5 group-hover:scale-110 transition-transform" />
                        <span className="text-[9px] font-medium opacity-80">对比</span>
                    </button>

                    <button 
                        onClick={() => setIsBatchEditOpen(true)}
                        className="flex flex-col items-center justify-center w-16 h-12 rounded-xl hover:bg-white/10 dark:hover:bg-slate-900/10 transition-colors group"
                    >
                        <Edit size={18} className="mb-0.5 group-hover:scale-110 transition-transform" />
                        <span className="text-[9px] font-medium opacity-80">编辑</span>
                    </button>

                    <button 
                        onClick={() => setDeletingIds(Array.from(selectedIds))}
                        className="flex flex-col items-center justify-center w-16 h-12 rounded-xl hover:bg-rose-500/20 text-rose-400 dark:text-rose-600 hover:text-rose-300 dark:hover:text-rose-700 transition-colors group"
                    >
                        <Trash2 size={18} className="mb-0.5 group-hover:scale-110 transition-transform" />
                        <span className="text-[9px] font-medium opacity-80">删除</span>
                    </button>

                    <div className="w-px h-8 bg-white/10 dark:bg-slate-800/10 mx-1"></div>

                    <button 
                        onClick={() => handleSelectionChange(new Set())}
                        className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-white/20 dark:hover:bg-slate-900/10 transition-colors mr-1"
                    >
                        <X size={14} />
                    </button>
                </div>
            </div>
        )}

      <div className="flex-1 overflow-auto custom-scrollbar relative min-h-0">
        <table className="w-full text-sm text-left border-separate border-spacing-0">
          <thead className="text-xs text-slate-500 dark:text-slate-400 uppercase bg-white/80 dark:bg-slate-900/80 sticky top-0 z-20 backdrop-blur-md shadow-sm">
            <tr>
              <th className="px-4 py-3 font-medium w-16 border-b border-slate-200 dark:border-slate-800 z-30">
                <div className="flex items-center" ref={selectMenuRef}>
                  <div className="flex items-center bg-slate-100 dark:bg-slate-800 rounded-lg p-0.5 border border-slate-200 dark:border-slate-700">
                      <button 
                        onClick={togglePageSelection} 
                        className={`p-1 rounded-md hover:bg-white dark:hover:bg-slate-700 transition-colors ${isPageSelected ? 'text-primary-600' : 'text-slate-400'}`}
                      >
                        {isPageSelected ? <CheckSquare size={16} /> : isIndeterminate ? <MinusSquare size={16} /> : <Square size={16} />}
                      </button>
                      <div className="w-px h-4 bg-slate-200 dark:bg-slate-700 mx-0.5"></div>
                      <button 
                        onClick={() => setIsSelectMenuOpen(!isSelectMenuOpen)}
                        className="p-1 rounded-md hover:bg-white dark:hover:bg-slate-700 text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200 transition-colors"
                      >
                        <ChevronDown size={12} />
                      </button>
                  </div>

                  {isSelectMenuOpen && (
                      <div className="absolute top-full left-2 mt-2 w-48 bg-white dark:bg-slate-900 rounded-xl shadow-xl border border-slate-200 dark:border-slate-700 p-1 z-50 animate-in fade-in zoom-in-95 origin-top-left">
                          <button 
                            onClick={() => { togglePageSelection(); setIsSelectMenuOpen(false); }}
                            className="w-full text-left px-3 py-2 text-xs font-medium text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-lg flex items-center gap-2"
                          >
                              {isPageSelected ? <CheckSquare size={14} className="text-primary-500" /> : <Square size={14} />}
                              选择本页 ({paginatedData.length})
                          </button>
                          <button 
                            onClick={selectAllMatching}
                            className="w-full text-left px-3 py-2 text-xs font-medium text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-lg flex items-center gap-2"
                          >
                              <Layers size={14} className={selectedIds.size === sortedData.length ? "text-primary-500" : "text-slate-400"} />
                              全选匹配项 ({sortedData.length})
                          </button>
                          <div className="h-px bg-slate-100 dark:bg-slate-800 my-1"></div>
                          <button 
                            onClick={deselectAll}
                            className="w-full text-left px-3 py-2 text-xs font-bold text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg flex items-center gap-2"
                          >
                              <X size={14} />
                              取消全选
                          </button>
                      </div>
                  )}
                </div>
              </th>
              {visibleColumns.map((col) => {
                  const isNumeric = !['gradeName', 'manufacturer', 'typicalApplication', '应用', '典型应用'].includes(col.key) && !col.isSystem;
                  return (
                    <th key={col.key} className={`px-4 py-3 font-bold border-b border-slate-200 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors cursor-pointer select-none whitespace-nowrap ${isNumeric ? 'text-right' : 'text-left'}`} onClick={() => handleSort(col.key)}>
                      <div className={`flex items-center gap-1.5 ${isNumeric ? 'justify-end' : 'justify-start'}`}>
                        {tProp(col.label)}
                        {sortConfig?.key === col.key && (
                          sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-primary-500" /> : <ArrowDown size={12} className="text-primary-500" />
                        )}
                      </div>
                    </th>
                  );
              })}
              <th className="px-4 py-3 font-medium text-right w-20 border-b border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 sticky right-0 z-30 shadow-[-4px_0_8px_-2px_rgba(0,0,0,0.05)] backdrop-blur-md">{t('actions')}</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 dark:divide-slate-800/50">
            {paginatedData.map((product) => {
                const isSelected = selectedIds.has(product.id);
                return (
                    <tr 
                        key={product.id} 
                        className={`group transition-all hover:bg-white dark:hover:bg-slate-800 ${isSelected ? 'bg-primary-50/50 dark:bg-primary-900/10' : ''}`}
                        onClick={() => toggleSelection(product.id)}
                    >
                        <td className="px-4 py-3 w-10 sticky left-0 z-10 bg-transparent" onClick={e => e.stopPropagation()}>
                            <div className="flex items-center justify-center">
                                <button onClick={() => toggleSelection(product.id)} className={`transition-colors ${isSelected ? 'text-primary-500' : 'text-slate-300 group-hover:text-slate-400'}`}>
                                    {isSelected ? <CheckSquare size={16} /> : <Square size={16} />}
                                </button>
                            </div>
                        </td>
                        {visibleColumns.map((col) => {
                            // 牌号列特殊逻辑
                            if (col.key === 'gradeName') {
                                return (
                                    <td key={col.key} className="px-4 py-3 font-bold text-slate-800 dark:text-white whitespace-nowrap">
                                        <div className="flex items-center gap-2 cursor-pointer hover:text-primary-600" onClick={(e) => { e.stopPropagation(); setViewingProduct(product); }}>
                                            {product.gradeName || <span className="text-slate-300 italic">未命名牌号</span>}
                                            {product.properties?.['密度']?.instrument && <FlaskConical size={10} className="text-emerald-500" title="包含实验室元数据" />}
                                        </div>
                                    </td>
                                );
                            }
                            // 厂家列特殊逻辑
                            if (col.key === 'manufacturer') {
                                return (
                                    <td key={col.key} className="px-4 py-3 text-slate-600 dark:text-slate-300 whitespace-nowrap">
                                        <div className="flex items-center gap-2 max-w-[180px]">
                                            <div className="p-1 rounded bg-slate-100 dark:bg-slate-800 text-slate-500 shrink-0"><Factory size={10} /></div>
                                            <span className="truncate" title={product.manufacturer}>{product.manufacturer || '-'}</span>
                                        </div>
                                    </td>
                                );
                            }

                            const prop = product.properties?.[col.key];
                            const isNumeric = typeof prop?.value === 'number';

                            return (
                                <td key={col.key} className={`px-4 py-3 text-slate-600 dark:text-slate-400 whitespace-nowrap relative group/cell ${isNumeric ? 'text-right' : 'text-left'}`}>
                                    {prop ? (
                                        <div className={`flex items-baseline gap-1 ${isNumeric ? 'justify-end' : 'justify-start'} max-w-[200px]`}>
                                            <span className={`block truncate ${isNumeric ? 'font-mono tabular-nums text-primary-600 dark:text-primary-400 font-bold' : ''}`} title={String(prop.value)}>
                                                {safeRenderValue(prop.value)}
                                            </span>
                                            {prop.unit && <span className="text-[10px] text-slate-400 select-none shrink-0">{prop.unit}</span>}

                                            {(prop.instrument || prop.standard) && (
                                                <div className="opacity-0 group-hover/cell:opacity-100 transition-opacity absolute right-2 top-1/2 -translate-y-1/2 z-20">
                                                     <Info size={12} className="text-slate-300 hover:text-primary-500 cursor-help" />
                                                </div>
                                            )}
                                            {(prop.instrument || prop.standard) && (
                                                <PropertyContextTooltip 
                                                    prop={prop} 
                                                    className="opacity-0 group-hover/cell:opacity-100 invisible group-hover/cell:visible scale-95 group-hover/cell:scale-100"
                                                />
                                            )}
                                        </div>
                                    ) : (
                                        <span className="text-slate-300 text-xs">-</span>
                                    )}
                                </td>
                            );
                        })}
                        <td className="px-4 py-3 text-right w-20 sticky right-0 z-10 bg-transparent group-hover:bg-white dark:group-hover:bg-slate-800 shadow-[-4px_0_8px_-2px_rgba(0,0,0,0.05)] transition-colors" onClick={e => e.stopPropagation()}>
                            <div className="flex items-center justify-end gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                <button onClick={() => setViewingProduct(product)} className="p-1.5 text-slate-400 hover:text-primary-500 hover:bg-primary-50 dark:hover:bg-primary-900/20 rounded-lg transition-colors" title={t('details')}><Eye size={14} /></button>
                                <button onClick={() => setEditingProduct(product)} className="p-1.5 text-slate-400 hover:text-amber-500 hover:bg-amber-50 dark:hover:bg-amber-900/20 rounded-lg transition-colors" title={t('editProduct')}><Edit size={14} /></button>
                                <button onClick={() => setDeletingIds([product.id])} className="p-1.5 text-slate-400 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg transition-colors" title={t('delete')}><Trash2 size={14} /></button>
                            </div>
                        </td>
                    </tr>
                );
            })}

            {/* 描述性空状态 */}
            {!isLoading && paginatedData.length === 0 && (
                <tr>
                    <td colSpan={visibleColumns.length + 2} className="py-24 text-center">
                        <div className="flex flex-col items-center justify-center gap-4 animate-in fade-in duration-500">
                             <div className="w-16 h-16 bg-slate-50 dark:bg-slate-800/50 rounded-full flex items-center justify-center border border-slate-100 dark:border-slate-800">
                                <AlertCircle size={32} className="text-slate-300" />
                             </div>
                             <div>
                                <p className="text-slate-500 font-bold">未找到匹配项</p>
                                <p className="text-xs text-slate-400 mt-1">请尝试调整搜索词或分类过滤器以检索树脂数据。</p>
                             </div>
                        </div>
                    </td>
                </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* 分页页脚 */}
      <div className="flex items-center justify-between px-4 py-3 border-t border-slate-200 dark:border-slate-800 bg-white/60 dark:bg-slate-900/60 backdrop-blur-sm shrink-0">
         <span className="text-xs text-slate-500 dark:text-slate-400 font-medium">
            {t('showing')} <span className="font-bold text-slate-800 dark:text-slate-200">{paginatedData.length > 0 ? (currentPage - 1) * pageSize + 1 : 0}-{Math.min(currentPage * pageSize, sortedData.length)}</span> of <span className="font-bold text-slate-800 dark:text-slate-200">{sortedData.length}</span>
         </span>
         <div className="flex items-center gap-2">
             <button 
                onClick={() => setCurrentPage(p => Math.max(1, p - 1))} 
                disabled={currentPage === 1}
                className="p-1.5 rounded-lg border border-slate-200 dark:border-slate-700 text-slate-500 hover:bg-white dark:hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
             >
                <ChevronLeft size={16} />
             </button>
             <span className="text-xs font-bold text-slate-700 dark:text-slate-300 min-w-[3rem] text-center">
                {currentPage} / {totalPages || 1}
             </span>
             <button 
                onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} 
                disabled={currentPage === totalPages || totalPages === 0}
                className="p-1.5 rounded-lg border border-slate-200 dark:border-slate-700 text-slate-500 hover:bg-white dark:hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
             >
                <ChevronRight size={16} />
             </button>
         </div>
      </div>

      {/* 弹窗组件群 */}
      <EditProductModal 
        isOpen={!!editingProduct} 
        onClose={() => setEditingProduct(null)} 
        product={editingProduct} 
        onSave={async (p) => { onUpdate(p); setEditingProduct(null); return true; }} 
      />
      <DeleteConfirmationModal 
        isOpen={deletingIds.length > 0} 
        onClose={() => setDeletingIds([])} 
        onConfirm={() => { onDelete(deletingIds); setDeletingIds([]); handleSelectionChange(new Set()); }} 
        productNames={deletingIds.map(id => data.find(p => p.id === id)?.gradeName || 'Unknown')} 
      />
      <BatchEditModal
        isOpen={isBatchEditOpen}
        onClose={() => setIsBatchEditOpen(false)}
        selectedProducts={data.filter(p => selectedIds.has(p.id))}
        onSave={(ids, updates) => { onBatchUpdate(ids, updates); handleSelectionChange(new Set()); }}
      />
      <ProductDetailDrawer 
        product={viewingProduct}
        onClose={() => setViewingProduct(null)}
        onCategoryClick={(id) => { onCategorySelect(id); setViewingProduct(null); }}
      />
      {isComparisonOpen && (
          <ComparisonView 
              products={data.filter(p => selectedIds.has(p.id))}
              onClose={() => setIsComparisonOpen(false)}
              onRemoveProduct={(id) => toggleSelection(id)}
          />
      )}
    </div>
  );
};

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Product, ColumnConfig, SortConfig, PropertyValue } from '../types';
import { Factory, Edit, Trash2, CheckSquare, Square, MinusSquare, ArrowUp, ArrowDown, ChevronLeft, ChevronRight, Eye, Info, BookOpen, X, GitCompare, FlaskConical, ChevronDown, Check, Layers, AlertCircle } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import { EditProductModal } from './EditProductModal';
import { DeleteConfirmationModal } from './DeleteConfirmationModal';
import { BatchEditModal } from './BatchEditModal';
import { REFERENCES } from '../constants';
import { ProductDetailDrawer } from './ProductDetailDrawer';
import { ComparisonView } from './ComparisonView';

interface DataGridProps {
  data: Product[];
  columns: ColumnConfig[];
  isLoading: boolean;
  onDelete: (ids: string[]) => void;
  onUpdate: (product: Product) => void;
  onBatchUpdate: (ids: string[], updates: Partial<Product>) => void;
  onCategorySelect: (id: string) => void;
  selectedIds?: Set<string>;
  onSelectionChange?: (ids: Set<string>) => void;
}

/**
 * 鲁棒的属性值格式化工具
 * 确保即使后端返回非预期结构，前端界面也不会崩溃
 */
const safeRenderValue = (val: any, unit?: string): string => {
    if (val === null || val === undefined) return '-';

    // 处理字符串
    if (typeof val === 'string') {
        const trimmed = val.trim();
        if (!trimmed) return '-';
        return `${trimmed}${unit ? ` ${unit}` : ''}`;
    }

    // 处理数值（防御 NaN）
    if (typeof val === 'number') {
        if (isNaN(val)) return '-';
        return `${val}${unit ? ` ${unit}` : ''}`;
    }

    // 处理日期对象
    if (val instanceof Date) {
        return val.toLocaleDateString();
    }

    // 处理复杂对象或递归 PropertyValue
    if (typeof val === 'object') {
        try {
            if ('value' in val) return safeRenderValue(val.value, val.unit);
            return JSON.stringify(val);
        } catch (e) {
            return '[数据解析错误]';
        }
    }

    return String(val);
};

const PropertyContextTooltip: React.FC<{ prop: PropertyValue; className?: string }> = ({ prop, className }) => {
    const { t } = useLanguage();
    if (!prop) return null;

    const reference = REFERENCES?.find(r => r.id === prop.referenceId);

    return (
        <div className={`absolute bottom-full left-1/2 -translate-x-1/2 mb-2 z-[100] w-64 bg-slate-900/95 dark:bg-white/95 backdrop-blur-xl text-white dark:text-slate-900 rounded-2xl shadow-2xl p-4 pointer-events-none border border-slate-700 dark:border-slate-200 transition-all duration-200 ease-out origin-bottom ${className}`}>
            <div className="flex items-center gap-2 mb-3 border-b border-white/10 dark:border-slate-900/10 pb-2">
                <Info size={14} className="text-primary-400 dark:text-primary-600" />
                <span className="text-[10px] font-black uppercase tracking-widest">{t('details')}</span>
            </div>
            <div className="space-y-3">
                {prop.instrument && (
                    <div>
                        <p className="text-[9px] opacity-60 font-bold uppercase tracking-tighter mb-0.5">测试设备 (Source)</p>
                        <div className="flex items-center gap-1.5 mt-0.5">
                            <FlaskConical size={10} className="text-emerald-400 dark:text-emerald-600" />
                            <p className="text-xs font-medium">{prop.instrument}</p>
                        </div>
                    </div>
                )}
                {prop.standard && (
                    <div>
                        <p className="text-[9px] opacity-60 font-bold uppercase tracking-tighter mb-0.5">执行标准 (Standard)</p>
                        <p className="text-xs font-medium">{prop.standard}</p>
                    </div>
                )}
                {prop.temperature && (
                    <div>
                        <p className="text-[9px] opacity-60 font-bold uppercase tracking-tighter mb-0.5">测试条件 (Conditions)</p>
                        <p className="text-xs font-medium">{prop.temperature}</p>
                    </div>
                )}
                {reference && (
                    <div>
                        <p className="text-[9px] opacity-60 font-bold uppercase tracking-tighter mb-0.5">数据引用自</p>
                        <div className="flex items-center gap-1.5 mt-0.5">
                            <BookOpen size={10} className="text-primary-400 dark:text-primary-600" />
                            <p className="text-[10px] italic opacity-80 truncate">{reference.name}</p>
                        </div>
                    </div>
                )}
            </div>
            <div className="absolute top-full left-1/2 -translate-x-1/2 w-3 h-3 bg-slate-900/95 dark:bg-white/95 rotate-45 -mt-1.5"></div>
        </div>
    );
};

/**
 * 镜像级骨架屏
 * 使用 table 布局确保与实际表格列宽一致，防止加载瞬间的布局坍塌
 */
const GridSkeleton: React.FC<{ columns: ColumnConfig[]; pageSize: number }> = ({ columns, pageSize }) => (
    <div className="animate-pulse bg-white dark:bg-slate-900/50 flex-1 flex flex-col min-h-0 overflow-hidden">
        {/* 表头占位 */}
        <div className="h-10 bg-slate-50 dark:bg-slate-800/50 border-b border-slate-100 dark:border-slate-800 flex items-center px-4">
             <div className="w-6 h-6 rounded bg-slate-200 dark:bg-slate-700 mr-4"></div>
             {columns.filter(c => c.visible).slice(0, 5).map((_, i) => (
                 <div key={i} className="h-4 bg-slate-200 dark:bg-slate-700 rounded w-24 mr-8"></div>
             ))}
        </div>
        {/* 行数据占位 */}
        <div className="flex-1 overflow-hidden divide-y divide-slate-100 dark:divide-slate-800">
            {[...Array(pageSize)].map((_, i) => (
                <div key={i} className="flex gap-4 items-center px-4 py-3 h-[53px]">
                    <div className="w-6 h-6 rounded-md bg-slate-200 dark:bg-slate-800 shrink-0"></div>
                    {columns.filter(c => c.visible).slice(0, 5).map((col, j) => (
                        <div key={j} className={`h-4 rounded bg-slate-100 dark:bg-slate-800 ${j === 0 ? 'w-32' : 'flex-1'}`}></div>
                    ))}
                    <div className="w-20 h-4 rounded bg-slate-200 dark:bg-slate-800 shrink-0 ml-auto"></div>
                </div>
            ))}
        </div>
    </div>
);

export const DataGrid: React.FC<DataGridProps> = ({ 
    data = [], 
    columns = [], 
    isLoading, 
    onDelete, 
    onUpdate, 
    onBatchUpdate, 
    onCategorySelect, 
    selectedIds: propSelectedIds, 
    onSelectionChange 
}) => {
  const { t, tProp } = useLanguage();

  // 防御性过滤可见列
  const visibleColumns = useMemo(() => (columns || []).filter((c) => c.visible), [columns]);

  const [localSelectedIds, setLocalSelectedIds] = useState<Set<string>>(new Set());
  const selectedIds = propSelectedIds || localSelectedIds;
  const handleSelectionChange = onSelectionChange || setLocalSelectedIds;

  const [sortConfig, setSortConfig] = useState<SortConfig | null>(null);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [deletingIds, setDeletingIds] = useState<string[]>([]);
  const [isBatchEditOpen, setIsBatchEditOpen] = useState(false);
  const [viewingProduct, setViewingProduct] = useState<Product | null>(null);
  const [isComparisonOpen, setIsComparisonOpen] = useState(false);

  const [isSelectMenuOpen, setIsSelectMenuOpen] = useState(false);
  const selectMenuRef = useRef<HTMLDivElement>(null);

  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 15;

  // 全局点击监听，关闭选择菜单
  useEffect(() => {
      const handleClickOutside = (e: MouseEvent) => {
          if (selectMenuRef.current && !selectMenuRef.current.contains(e.target as Node)) {
              setIsSelectMenuOpen(false);
          }
      };
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // 当搜索条件或数据集规模大幅变动时，重置页码防止页面越界
  useEffect(() => {
      setCurrentPage(1);
  }, [data?.length]);

  const handleSort = (key: string) => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const sortedData = useMemo(() => {
    if (!data || data.length === 0) return [];
    if (!sortConfig) return data;

    return [...data].sort((a, b) => {
      // 深度提取排序值
      let aVal: any = a.properties?.[sortConfig.key]?.value ?? (a as any)[sortConfig.key] ?? '';
      let bVal: any = b.properties?.[sortConfig.key]?.value ?? (b as any)[sortConfig.key] ?? '';

      // 智能识别数值类型进行精准排序
      const aNum = parseFloat(String(aVal));
      const bNum = parseFloat(String(bVal));
      const isANum = !isNaN(aNum) && String(aVal).trim() !== '';
      const isBNum = !isNaN(bNum) && String(bVal).trim() !== '';

      if (isANum && isBNum) {
          aVal = aNum;
          bVal = bNum;
      } else {
          aVal = String(aVal).toLowerCase();
          bVal = String(bVal).toLowerCase();
      }

      if (aVal < bVal) return sortConfig.direction === 'asc' ? -1 : 1;
      if (aVal > bVal) return sortConfig.direction === 'asc' ? 1 : -1;
      return 0;
    });
  }, [data, sortConfig]);

  const paginatedData = useMemo(() => {
      const start = (currentPage - 1) * pageSize;
      return (sortedData || []).slice(start, start + pageSize);
  }, [sortedData, currentPage]);

  const totalPages = Math.ceil((sortedData?.length || 0) / pageSize);

  const toggleSelection = (id: string) => {
    const newSelected = new Set(selectedIds);
    if (newSelected.has(id)) newSelected.delete(id);
    else newSelected.add(id);
    handleSelectionChange(newSelected);
  };

  const togglePageSelection = () => {
    if (!paginatedData.length) return;
    const pageIds = paginatedData.map(p => p.id);
    const allSelected = pageIds.every(id => selectedIds.has(id));

    const newSelected = new Set(selectedIds);
    if (allSelected) {
        pageIds.forEach(id => newSelected.delete(id));
    } else {
        pageIds.forEach(id => newSelected.add(id));
    }
    handleSelectionChange(newSelected);
  };

  const selectAllMatching = () => {
      if (!sortedData.length) return;
      const allIds = sortedData.map(p => p.id);
      handleSelectionChange(new Set(allIds));
      setIsSelectMenuOpen(false);
  };

  const deselectAll = () => {
      handleSelectionChange(new Set());
      setIsSelectMenuOpen(false);
  };

  const isPageSelected = paginatedData.length > 0 && paginatedData.every(p => selectedIds.has(p.id));
  const isIndeterminate = paginatedData.some(p => selectedIds.has(p.id)) && !isPageSelected;

  // 处理加载态
  if (isLoading) return <GridSkeleton columns={visibleColumns} pageSize={pageSize} />;

  return (
    <div className="h-full flex flex-col bg-transparent relative min-h-0">
        {/* 浮动批量操作工具栏 */}
        {selectedIds.size > 0 && (
            <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-50 animate-in slide-in-from-bottom-6 duration-300">
                <div className="flex items-center gap-1 p-1.5 bg-slate-900/90 dark:bg-slate-100/90 backdrop-blur-xl rounded-2xl shadow-float border border-white/10 dark:border-slate-300 text-white dark:text-slate-900 ring-1 ring-black/5">
                    <div className="flex items-center gap-2 pl-3 pr-4 border-r border-white/10 dark:border-slate-800/10 mr-1">
                        <div className="flex items-center justify-center w-5 h-5 rounded-full bg-primary-500 text-white text-[10px] font-bold">
                            {selectedIds.size}
                        </div>
                        <span className="text-xs font-bold whitespace-nowrap">{t('selected')}</span>
                    </div>

                    <button 
                        onClick={() => setIsComparisonOpen(true)}
                        className="flex flex-col items-center justify-center w-16 h-12 rounded-xl hover:bg-white/10 dark:hover:bg-slate-900/10 transition-colors group"
                    >
                        <GitCompare size={18} className="mb-0.5 group-hover:scale-110 transition-transform" />
                        <span className="text-[9px] font-medium opacity-80">对比</span>
                    </button>

                    <button 
                        onClick={() => setIsBatchEditOpen(true)}
                        className="flex flex-col items-center justify-center w-16 h-12 rounded-xl hover:bg-white/10 dark:hover:bg-slate-900/10 transition-colors group"
                    >
                        <Edit size={18} className="mb-0.5 group-hover:scale-110 transition-transform" />
                        <span className="text-[9px] font-medium opacity-80">编辑</span>
                    </button>

                    <button 
                        onClick={() => setDeletingIds(Array.from(selectedIds))}
                        className="flex flex-col items-center justify-center w-16 h-12 rounded-xl hover:bg-rose-500/20 text-rose-400 dark:text-rose-600 hover:text-rose-300 dark:hover:text-rose-700 transition-colors group"
                    >
                        <Trash2 size={18} className="mb-0.5 group-hover:scale-110 transition-transform" />
                        <span className="text-[9px] font-medium opacity-80">删除</span>
                    </button>

                    <div className="w-px h-8 bg-white/10 dark:bg-slate-800/10 mx-1"></div>

                    <button 
                        onClick={() => handleSelectionChange(new Set())}
                        className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-white/20 dark:hover:bg-slate-900/10 transition-colors mr-1"
                    >
                        <X size={14} />
                    </button>
                </div>
            </div>
        )}

      <div className="flex-1 overflow-auto custom-scrollbar relative min-h-0">
        <table className="w-full text-sm text-left border-separate border-spacing-0">
          <thead className="text-xs text-slate-500 dark:text-slate-400 uppercase bg-white/80 dark:bg-slate-900/80 sticky top-0 z-20 backdrop-blur-md shadow-sm">
            <tr>
              <th className="px-4 py-3 font-medium w-16 border-b border-slate-200 dark:border-slate-800 z-30">
                <div className="flex items-center" ref={selectMenuRef}>
                  <div className="flex items-center bg-slate-100 dark:bg-slate-800 rounded-lg p-0.5 border border-slate-200 dark:border-slate-700">
                      <button 
                        onClick={togglePageSelection} 
                        className={`p-1 rounded-md hover:bg-white dark:hover:bg-slate-700 transition-colors ${isPageSelected ? 'text-primary-600' : 'text-slate-400'}`}
                      >
                        {isPageSelected ? <CheckSquare size={16} /> : isIndeterminate ? <MinusSquare size={16} /> : <Square size={16} />}
                      </button>
                      <div className="w-px h-4 bg-slate-200 dark:bg-slate-700 mx-0.5"></div>
                      <button 
                        onClick={() => setIsSelectMenuOpen(!isSelectMenuOpen)}
                        className="p-1 rounded-md hover:bg-white dark:hover:bg-slate-700 text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200 transition-colors"
                      >
                        <ChevronDown size={12} />
                      </button>
                  </div>

                  {isSelectMenuOpen && (
                      <div className="absolute top-full left-2 mt-2 w-48 bg-white dark:bg-slate-900 rounded-xl shadow-xl border border-slate-200 dark:border-slate-700 p-1 z-50 animate-in fade-in zoom-in-95 origin-top-left">
                          <button 
                            onClick={() => { togglePageSelection(); setIsSelectMenuOpen(false); }}
                            className="w-full text-left px-3 py-2 text-xs font-medium text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-lg flex items-center gap-2"
                          >
                              {isPageSelected ? <CheckSquare size={14} className="text-primary-500" /> : <Square size={14} />}
                              选择本页 ({paginatedData.length})
                          </button>
                          <button 
                            onClick={selectAllMatching}
                            className="w-full text-left px-3 py-2 text-xs font-medium text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-lg flex items-center gap-2"
                          >
                              <Layers size={14} className={selectedIds.size === sortedData.length ? "text-primary-500" : "text-slate-400"} />
                              全选匹配项 ({sortedData.length})
                          </button>
                          <div className="h-px bg-slate-100 dark:bg-slate-800 my-1"></div>
                          <button 
                            onClick={deselectAll}
                            className="w-full text-left px-3 py-2 text-xs font-bold text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg flex items-center gap-2"
                          >
                              <X size={14} />
                              取消全选
                          </button>
                      </div>
                  )}
                </div>
              </th>
              {visibleColumns.map((col) => {
                  const isNumeric = !['gradeName', 'manufacturer', 'typicalApplication', '应用', '典型应用'].includes(col.key) && !col.isSystem;
                  return (
                    <th key={col.key} className={`px-4 py-3 font-bold border-b border-slate-200 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors cursor-pointer select-none whitespace-nowrap ${isNumeric ? 'text-right' : 'text-left'}`} onClick={() => handleSort(col.key)}>
                      <div className={`flex items-center gap-1.5 ${isNumeric ? 'justify-end' : 'justify-start'}`}>
                        {tProp(col.label)}
                        {sortConfig?.key === col.key && (
                          sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-primary-500" /> : <ArrowDown size={12} className="text-primary-500" />
                        )}
                      </div>
                    </th>
                  );
              })}
              <th className="px-4 py-3 font-medium text-right w-20 border-b border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 sticky right-0 z-30 shadow-[-4px_0_8px_-2px_rgba(0,0,0,0.05)] backdrop-blur-md">{t('actions')}</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 dark:divide-slate-800/50">
            {paginatedData.map((product) => {
                const isSelected = selectedIds.has(product.id);
                return (
                    <tr 
                        key={product.id} 
                        className={`group transition-all hover:bg-white dark:hover:bg-slate-800 ${isSelected ? 'bg-primary-50/50 dark:bg-primary-900/10' : ''}`}
                        onClick={() => toggleSelection(product.id)}
                    >
                        <td className="px-4 py-3 w-10 sticky left-0 z-10 bg-transparent" onClick={e => e.stopPropagation()}>
                            <div className="flex items-center justify-center">
                                <button onClick={() => toggleSelection(product.id)} className={`transition-colors ${isSelected ? 'text-primary-500' : 'text-slate-300 group-hover:text-slate-400'}`}>
                                    {isSelected ? <CheckSquare size={16} /> : <Square size={16} />}
                                </button>
                            </div>
                        </td>
                        {visibleColumns.map((col) => {
                            // 牌号列特殊逻辑
                            if (col.key === 'gradeName') {
                                return (
                                    <td key={col.key} className="px-4 py-3 font-bold text-slate-800 dark:text-white whitespace-nowrap">
                                        <div className="flex items-center gap-2 cursor-pointer hover:text-primary-600" onClick={(e) => { e.stopPropagation(); setViewingProduct(product); }}>
                                            {product.gradeName || <span className="text-slate-300 italic">未命名牌号</span>}
                                            {/* 
                                              * FIX: Lucide icons do not support the 'title' prop directly in TypeScript.
                                              * Wrapped FlaskConical in a span to provide the tooltip.
                                              */}
                                            {product.properties?.['密度']?.instrument && <span title="包含实验室元数据"><FlaskConical size={10} className="text-emerald-500" /></span>}
                                        </div>
                                    </td>
                                );
                            }
                            // 厂家列特殊逻辑
                            if (col.key === 'manufacturer') {
                                return (
                                    <td key={col.key} className="px-4 py-3 text-slate-600 dark:text-slate-300 whitespace-nowrap">
                                        <div className="flex items-center gap-2 max-w-[180px]">
                                            <div className="p-1 rounded bg-slate-100 dark:bg-slate-800 text-slate-500 shrink-0"><Factory size={10} /></div>
                                            <span className="truncate" title={product.manufacturer}>{product.manufacturer || '-'}</span>
                                        </div>
                                    </td>
                                );
                            }

                            const prop = product.properties?.[col.key];
                            const isNumeric = typeof prop?.value === 'number';

                            return (
                                <td key={col.key} className={`px-4 py-3 text-slate-600 dark:text-slate-400 whitespace-nowrap relative group/cell ${isNumeric ? 'text-right' : 'text-left'}`}>
                                    {prop ? (
                                        <div className={`flex items-baseline gap-1 ${isNumeric ? 'justify-end' : 'justify-start'} max-w-[200px]`}>
                                            <span className={`block truncate ${isNumeric ? 'font-mono tabular-nums text-primary-600 dark:text-primary-400 font-bold' : ''}`} title={String(prop.value)}>
                                                {safeRenderValue(prop.value)}
                                            </span>
                                            {prop.unit && <span className="text-[10px] text-slate-400 select-none shrink-0">{prop.unit}</span>}

                                            {(prop.instrument || prop.standard) && (
                                                <div className="opacity-0 group-hover/cell:opacity-100 transition-opacity absolute right-2 top-1/2 -translate-y-1/2 z-20">
                                                     <Info size={12} className="text-slate-300 hover:text-primary-500 cursor-help" />
                                                </div>
                                            )}
                                            {(prop.instrument || prop.standard) && (
                                                <PropertyContextTooltip 
                                                    prop={prop} 
                                                    className="opacity-0 group-hover/cell:opacity-100 invisible group-hover/cell:visible scale-95 group-hover/cell:scale-100"
                                                />
                                            )}
                                        </div>
                                    ) : (
                                        <span className="text-slate-300 text-xs">-</span>
                                    )}
                                </td>
                            );
                        })}
                        <td className="px-4 py-3 text-right w-20 sticky right-0 z-10 bg-transparent group-hover:bg-white dark:group-hover:bg-slate-800 shadow-[-4px_0_8px_-2px_rgba(0,0,0,0.05)] transition-colors" onClick={e => e.stopPropagation()}>
                            <div className="flex items-center justify-end gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                <button onClick={() => setViewingProduct(product)} className="p-1.5 text-slate-400 hover:text-primary-500 hover:bg-primary-50 dark:hover:bg-primary-900/20 rounded-lg transition-colors" title={t('details')}><Eye size={14} /></button>
                                <button onClick={() => setEditingProduct(product)} className="p-1.5 text-slate-400 hover:text-amber-500 hover:bg-amber-50 dark:hover:bg-amber-900/20 rounded-lg transition-colors" title={t('editProduct')}><Edit size={14} /></button>
                                <button onClick={() => setDeletingIds([product.id])} className="p-1.5 text-slate-400 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg transition-colors" title={t('delete')}><Trash2 size={14} /></button>
                            </div>
                        </td>
                    </tr>
                );
            })}

            {/* 描述性空状态 */}
            {!isLoading && paginatedData.length === 0 && (
                <tr>
                    <td colSpan={visibleColumns.length + 2} className="py-24 text-center">
                        <div className="flex flex-col items-center justify-center gap-4 animate-in fade-in duration-500">
                             <div className="w-16 h-16 bg-slate-50 dark:bg-slate-800/50 rounded-full flex items-center justify-center border border-slate-100 dark:border-slate-800">
                                <AlertCircle size={32} className="text-slate-300" />
                             </div>
                             <div>
                                <p className="text-slate-500 font-bold">未找到匹配项</p>
                                <p className="text-xs text-slate-400 mt-1">请尝试调整搜索词或分类过滤器以检索树脂数据。</p>
                             </div>
                        </div>
                    </td>
                </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* 分页页脚 */}
      <div className="flex items-center justify-between px-4 py-3 border-t border-slate-200 dark:border-slate-800 bg-white/60 dark:bg-slate-900/60 backdrop-blur-sm shrink-0">
         <span className="text-xs text-slate-500 dark:text-slate-400 font-medium">
            {t('showing')} <span className="font-bold text-slate-800 dark:text-slate-200">{paginatedData.length > 0 ? (currentPage - 1) * pageSize + 1 : 0}-{Math.min(currentPage * pageSize, sortedData.length)}</span> of <span className="font-bold text-slate-800 dark:text-slate-200">{sortedData.length}</span>
         </span>
         <div className="flex items-center gap-2">
             <button 
                onClick={() => setCurrentPage(p => Math.max(1, p - 1))} 
                disabled={currentPage === 1}
                className="p-1.5 rounded-lg border border-slate-200 dark:border-slate-700 text-slate-500 hover:bg-white dark:hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
             >
                <ChevronLeft size={16} />
             </button>
             <span className="text-xs font-bold text-slate-700 dark:text-slate-300 min-w-[3rem] text-center">
                {currentPage} / {totalPages || 1}
             </span>
             <button 
                onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} 
                disabled={currentPage === totalPages || totalPages === 0}
                className="p-1.5 rounded-lg border border-slate-200 dark:border-slate-700 text-slate-500 hover:bg-white dark:hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
             >
                <ChevronRight size={16} />
             </button>
         </div>
      </div>

      {/* 弹窗组件群 */}
      <EditProductModal 
        isOpen={!!editingProduct} 
        onClose={() => setEditingProduct(null)} 
        product={editingProduct} 
        onSave={async (p) => { onUpdate(p); setEditingProduct(null); return true; }} 
      />
      <DeleteConfirmationModal 
        isOpen={deletingIds.length > 0} 
        onClose={() => setDeletingIds([])} 
        onConfirm={() => { onDelete(deletingIds); setDeletingIds([]); handleSelectionChange(new Set()); }} 
        productNames={deletingIds.map(id => data.find(p => p.id === id)?.gradeName || 'Unknown')} 
      />
      <BatchEditModal
        isOpen={isBatchEditOpen}
        onClose={() => setIsBatchEditOpen(false)}
        selectedProducts={data.filter(p => selectedIds.has(p.id))}
        onSave={(ids, updates) => { onBatchUpdate(ids, updates); handleSelectionChange(new Set()); }}
      />
      <ProductDetailDrawer 
        product={viewingProduct}
        onClose={() => setViewingProduct(null)}
        onCategoryClick={(id) => { onCategorySelect(id); setViewingProduct(null); }}
      />
      {isComparisonOpen && (
          <ComparisonView 
              products={data.filter(p => selectedIds.has(p.id))}
              onClose={() => setIsComparisonOpen(false)}
              onRemoveProduct={(id) => toggleSelection(id)}
          />
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Search, SlidersHorizontal, Upload, LayoutGrid, BarChart2, Moon, Sun, Globe, User, LogOut, Settings, Shield, History, X, Trash2, Clock, Command, Download, Loader2, Maximize, Minimize, ArrowRight, Filter, ChevronDown, Sparkles } from 'lucide-react';
import { ColumnConfig, ViewMode, User as UserType } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import { useTheme } from '../contexts/ThemeContext';

interface TopBarProps {
  user: UserType | null;
  onLogout: () => void;
  onOpenProfile: () => void;
  onOpenAdmin: () => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  isSearching?: boolean;
  columns: ColumnConfig[];
  onToggleColumn: (key: string) => void;
  onToggleAllColumns: (visible: boolean) => void;
  onOpenImport: () => void;
  onExport: () => void;
  isExporting: boolean;
  viewMode: ViewMode;
  onViewModeChange: (mode: ViewMode) => void;
  showAdvancedFilters: boolean;
  onToggleFilters: () => void;
  activeFilterCount: number;
}

export const TopBar: React.FC<TopBarProps> = ({
  user, onLogout, onOpenProfile, onOpenAdmin, searchQuery, onSearchChange, isSearching, columns, onToggleColumn, onToggleAllColumns, onOpenImport, onExport, isExporting, viewMode, onViewModeChange, showAdvancedFilters, onToggleFilters, activeFilterCount
}) => {
  const [isColumnMenuOpen, setIsColumnMenuOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const { t, language, toggleLanguage, tProp } = useLanguage();
  const { theme, toggleTheme } = useTheme();
  const inputRef = useRef<HTMLInputElement>(null);

  const colMenuRef = useRef<HTMLDivElement>(null);
  const userMenuRef = useRef<HTMLDivElement>(null);

  const [searchHistory, setSearchHistory] = useState<string[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [historyIndex, setHistoryIndex] = useState(-1);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
            e.preventDefault();
            inputRef.current?.focus();
        }
    };
    const handleClickOutside = (e: MouseEvent) => {
        if (colMenuRef.current && !colMenuRef.current.contains(e.target as Node)) setIsColumnMenuOpen(false);
        if (userMenuRef.current && !userMenuRef.current.contains(e.target as Node)) setIsUserMenuOpen(false);
    };
    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);

    window.addEventListener('keydown', handleKeyDown);
    document.addEventListener('mousedown', handleClickOutside);
    document.addEventListener('fullscreenchange', handleFullscreenChange);

    const savedHistory = localStorage.getItem('resindb_search_history');
    if (savedHistory) try { setSearchHistory(JSON.parse(savedHistory)); } catch (e) {}

    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        document.removeEventListener('mousedown', handleClickOutside);
        document.removeEventListener('fullscreenchange', handleFullscreenChange);
    };
  }, []);

  const saveToHistory = (query: string) => {
      if (!query.trim()) return;
      const clean = query.trim();
      setSearchHistory(prev => {
          const filtered = prev.filter(item => item !== clean);
          const updated = [clean, ...filtered].slice(0, 5);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const handleInputKeyDown = (e: React.KeyboardEvent) => {
      if (showHistory && searchHistory.length > 0) {
          if (e.key === 'ArrowDown') { e.preventDefault(); setHistoryIndex(prev => (prev + 1) % searchHistory.length); return; }
          if (e.key === 'ArrowUp') { e.preventDefault(); setHistoryIndex(prev => (prev - 1 + searchHistory.length) % searchHistory.length); return; }
      }
      if (e.key === 'Enter') {
          e.preventDefault();
          const q = (historyIndex >= 0 && showHistory) ? searchHistory[historyIndex] : searchQuery;
          onSearchChange(q);
          saveToHistory(q);
          setShowHistory(false);
          setHistoryIndex(-1);
          inputRef.current?.blur();
      }
      if (e.key === 'Escape') { setShowHistory(false); inputRef.current?.blur(); }
  };

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) document.documentElement.requestFullscreen();
    else if (document.exitFullscreen) document.exitFullscreen();
  };

  const nonSystemCols = columns.filter(c => !c.isSystem);
  const visibleCount = nonSystemCols.filter(c => c.visible).length;
  const isAllSelected = nonSystemCols.length > 0 && visibleCount === nonSystemCols.length;
  const isIndeterminate = visibleCount > 0 && !isAllSelected;

  return (
    <div className="w-full flex flex-col gap-3 px-2 py-2">
      <div className="flex items-center justify-between gap-6 pointer-events-none">
        {/* Search Pill */}
        <div className="flex-1 max-w-2xl relative z-[60] pointer-events-auto">
            <div className="relative group transition-all duration-300 focus-within:scale-[1.01]">
                <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                    {isSearching ? <Loader2 className="text-primary-500 animate-spin" size={18} /> : <Search className="text-slate-400 group-focus-within:text-primary-500 transition-colors" size={18} />}
                </div>
                <input
                    ref={inputRef}
                    type="text"
                    value={historyIndex >= 0 && showHistory ? searchHistory[historyIndex] : searchQuery}
                    onChange={(e) => { onSearchChange(e.target.value); setHistoryIndex(-1); }}
                    onFocus={() => { setShowHistory(true); setHistoryIndex(-1); }}
                    onBlur={() => setTimeout(() => setShowHistory(false), 200)}
                    onKeyDown={handleInputKeyDown}
                    placeholder={t('searchPlaceholder')}
                    className="block w-full pl-12 pr-12 py-3.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl text-sm font-medium shadow-sm outline-none focus:ring-4 focus:ring-primary-500/10 focus:border-primary-500/30 transition-all text-slate-700 dark:text-slate-200 placeholder:text-slate-400"
                />
                <div className="absolute inset-y-0 right-5 flex items-center gap-2">
                    {searchQuery && (
                        <button onClick={() => onSearchChange('')} className="p-1 text-slate-400 hover:text-slate-600 transition-colors"><X size={14} /></button>
                    )}
                    <button 
                        onClick={onToggleFilters}
                        className={`flex items-center gap-1.5 px-2.5 py-1 rounded-lg border transition-all ${showAdvancedFilters ? 'bg-primary-50 border-primary-200 text-primary-600' : 'bg-slate-50 border-slate-200 text-slate-500 hover:border-slate-300'}`}
                    >
                        <Filter size={14} className={activeFilterCount > 0 ? "fill-primary-500" : ""} />
                        <span className="text-[10px] font-black uppercase tracking-widest">{t('analysis')}</span>
                        {activeFilterCount > 0 && <span className="w-4 h-4 bg-primary-600 text-white rounded-full flex items-center justify-center text-[8px] font-bold">{activeFilterCount}</span>}
                    </button>
                </div>

                {/* History Dropdown */}
                {showHistory && searchHistory.length > 0 && (
                    <div className="absolute top-full left-0 right-0 mt-2 bg-white dark:bg-slate-900 backdrop-blur-xl border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl overflow-hidden z-50 animate-in fade-in slide-in-from-top-2 duration-200">
                        <div className="flex items-center justify-between px-4 py-2 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50">
                            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1.5"><Clock size={10} /> {t('recentSearches')}</span>
                            <button onMouseDown={(e) => { e.preventDefault(); setSearchHistory([]); localStorage.removeItem('resindb_search_history'); }} className="text-[10px] text-rose-500 hover:underline font-bold uppercase">{t('clearHistory')}</button>
                        </div>
                        <div className="py-1">
                            {searchHistory.map((query, idx) => (
                                <div key={idx} onMouseDown={() => { onSearchChange(query); setShowHistory(false); }} className={`w-full flex items-center justify-between px-4 py-2.5 cursor-pointer transition-colors ${idx === historyIndex ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-700' : 'hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600'}`}>
                                    <div className="flex items-center gap-3"><History size={14} className="text-slate-400" /><span className="text-sm font-medium">{query}</span></div>
                                    <ArrowRight size={12} className="text-slate-300" />
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>

        {/* Right Actions */}
        <div className="flex items-center gap-1.5 p-1.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-[1.8rem] shadow-sm pointer-events-auto z-[60]">
            <div className="flex items-center bg-slate-100 dark:bg-slate-800 rounded-2xl p-1 border border-slate-200 dark:border-slate-700">
                <button onClick={() => onViewModeChange('grid')} className={`p-2 rounded-xl transition-all ${viewMode === 'grid' ? 'bg-white dark:bg-slate-700 text-primary-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}><LayoutGrid size={16} /></button>
                <button onClick={() => onViewModeChange('chart')} className={`p-2 rounded-xl transition-all ${viewMode === 'chart' ? 'bg-white dark:bg-slate-700 text-primary-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}><BarChart2 size={16} /></button>
            </div>

            <div className="h-5 w-px bg-slate-200 dark:bg-slate-700 mx-1"></div>

            <button onClick={onOpenImport} className="w-9 h-9 flex items-center justify-center text-slate-500 hover:text-primary-600 hover:bg-primary-50 dark:hover:bg-primary-900/20 rounded-full transition-all" title={t('importData')}><Upload size={18} /></button>
            <button onClick={onExport} disabled={isExporting} className="w-9 h-9 flex items-center justify-center text-slate-500 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-full transition-all disabled:opacity-50" title="Report">{isExporting ? <Loader2 size={18} className="animate-spin text-blue-500" /> : <Download size={18} />}</button>

            <div className="relative" ref={colMenuRef}>
                <button onClick={() => setIsColumnMenuOpen(!isColumnMenuOpen)} className={`w-9 h-9 flex items-center justify-center rounded-full transition-all ${isColumnMenuOpen ? 'bg-primary-50 text-primary-600' : 'text-slate-500 hover:text-primary-600 hover:bg-primary-50 dark:hover:bg-primary-900/20'}`}><SlidersHorizontal size={18} /></button>
                {isColumnMenuOpen && (
                    <div className="absolute top-full right-0 mt-3 w-64 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl p-3 z-[100] animate-in zoom-in-95 origin-top-right">
                        <h4 className="text-[10px] font-black uppercase text-slate-400 mb-2 px-2 tracking-widest">{t('visibleAttributes')}</h4>
                        <div className="max-h-60 overflow-y-auto custom-scrollbar space-y-0.5">
                            {columns.map(col => (
                                <label key={col.key} className="flex items-center gap-3 px-3 py-1.5 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 cursor-pointer transition-colors group">
                                    <div className={`w-4 h-4 rounded border flex items-center justify-center transition-colors ${col.visible ? 'bg-primary-600 border-primary-600' : 'border-slate-300 group-hover:border-primary-400'}`}>
                                        {col.visible && <div className="w-1.5 h-1.5 bg-white rounded-full"></div>}
                                    </div>
                                    <input type="checkbox" checked={col.visible} onChange={() => !col.isSystem && onToggleColumn(col.key)} disabled={col.isSystem} className="hidden" />
                                    <span className={`text-xs font-bold ${col.visible ? 'text-slate-800 dark:text-white' : 'text-slate-400'}`}>{tProp(col.label)}</span>
                                </label>
                            ))}
                        </div>
                    </div>
                )}
            </div>

            <button onClick={toggleTheme} className="w-9 h-9 flex items-center justify-center text-slate-500 hover:text-amber-500 hover:bg-amber-50 dark:hover:bg-amber-900/20 rounded-full transition-all">{theme === 'dark' ? <Sun size={18} /> : <Moon size={18} />}</button>
            <button onClick={toggleFullScreen} className="w-9 h-9 flex items-center justify-center text-slate-500 hover:text-indigo-500 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded-full transition-all">{isFullscreen ? <Minimize size={18} /> : <Maximize size={18} />}</button>

            <div className="h-5 w-px bg-slate-200 dark:bg-slate-700 mx-1"></div>

            <div className="relative" ref={userMenuRef}>
                <button onClick={() => setIsUserMenuOpen(!isUserMenuOpen)} className="flex items-center gap-2 pl-1 pr-3 py-1 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-full transition-all border border-slate-200 dark:border-slate-700">
                    <img src={user?.avatar} alt="" className="w-7 h-7 rounded-full border border-white dark:border-slate-600 shadow-sm" />
                    <span className="text-[11px] font-black text-slate-700 dark:text-slate-200">{user?.name.split(' ')[0]}</span>
                    <ChevronDown size={12} className={`text-slate-400 transition-transform ${isUserMenuOpen ? 'rotate-180' : ''}`} />
                </button>
                {isUserMenuOpen && (
                    <div className="absolute top-full right-0 mt-3 w-52 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl p-1.5 z-[100] animate-in zoom-in-95 origin-top-right flex flex-col gap-0.5">
                        <button onClick={() => { setIsUserMenuOpen(false); onOpenProfile(); }} className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 text-[11px] font-bold text-slate-700 dark:text-slate-200 transition-colors"><User size={14} /> {t('profile')}</button>
                        <button onClick={() => { setIsUserMenuOpen(false); onOpenAdmin(); }} className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 text-[11px] font-bold text-slate-700 dark:text-slate-200 transition-colors"><Shield size={14} /> {t('adminPanel')}</button>
                        <button onClick={() => { setIsUserMenuOpen(false); toggleLanguage(); }} className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 text-[11px] font-bold text-slate-700 dark:text-slate-200 transition-colors"><Globe size={14} /> {language === 'zh' ? 'English' : '中文'}</button>
                        <div className="h-px bg-slate-100 dark:bg-slate-800 my-1"></div>
                        <button onClick={onLogout} className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-rose-50 dark:hover:bg-rose-900/20 text-[11px] font-bold text-rose-600 transition-colors"><LogOut size={14} /> {t('logout')}</button>
                    </div>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

