const FormattedText: React.FC<{ text: string; className?: string }> = ({ text, className }) => {
  if (!text) return null;
  return (
    <div className={className}>
      {text.split('\n').map((line, i) => {
        const trimmed = line.trim();
        if (trimmed.startsWith('- ') || trimmed.startsWith('* ') || trimmed.match(/^\d+\./)) {
             const cleanLine = trimmed.replace(/^[-*]\s+|\d+\.\s+/, '');
             const parts = cleanLine.split(/(\*\*.*?\*\*)/g);
             return (
                <div key={i} className="flex gap-2.5 ml-1 mb-1.5 items-start">
                    <span className="text-emerald-500 dark:text-emerald-400 mt-1.5 shrink-0 text-[10px]">•</span>
                    <span className="leading-relaxed text-sm">
                        {parts.map((part, j) => {
                            if (part.startsWith('**') && part.endsWith('**')) return <strong key={j} className="font-bold text-slate-800 dark:text-white">{part.slice(2, -2)}</strong>;
                            return <span key={j}>{part}</span>;
                        })}
                    </span>
                </div>
             );
        }
        if (line.startsWith('##')) return <h3 key={i} className="font-bold text-emerald-700 dark:text-emerald-400 mt-4 mb-2 text-base">{line.replace(/#/g, '')}</h3>
        if (!trimmed) return <div key={i} className="h-2"></div>;
        const parts = line.split(/(\*\*.*?\*\*)/g);
        return (
          <p key={i} className="mb-2 last:mb-0 leading-relaxed text-sm">
            {parts.map((part, j) => {
              if (part.startsWith('**') && part.endsWith('**')) return <strong key={j} className="font-bold text-slate-800 dark:text-white">{part.slice(2, -2)}</strong>;
              return <span key={j}>{part}</span>;
            })}
          </p>
        );
      })}
    </div>
  );
};

export const AIAssistant: React.FC<AIAssistantProps> = ({ contextData, inlineView = false }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [input, setInput] = useState('');
  const { t } = useLanguage();
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [useThinking, setUseThinking] = useState(false);
  const [attachedImage, setAttachedImage] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (messages.length === 0) setMessages([{ id: 'welcome', role: 'model', text: t('welcomeMessage') }]);
  }, [t]);

  useEffect(() => {
    if (messagesEndRef.current) messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  const handleSendMessage = async (customInput?: string) => {
    const textToSend = customInput || input;
    if ((!textToSend.trim() && !attachedImage) || isLoading) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: textToSend, image: attachedImage || undefined };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setAttachedImage(null);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const parts: any[] = [];
      let systemInstruction = "You are ResinAI. A scientific technical assistant for synthetic resin data analysis. Be concise, expert-level, and use Markdown for structuring comparisons.";

      if (userMsg.image) {
         const base64Data = userMsg.image.split(',')[1];
         const mimeType = userMsg.image.split(';')[0].split(':')[1] || 'image/jpeg';
         parts.push({ inlineData: { mimeType, data: base64Data } });
         systemInstruction = `You are a Senior QC Specialist. Focus on identifying material form, detecting defects like gels/specks, and suggesting pass/fail.`;
         parts.push({ text: userMsg.text || "Analyze this sample image." });
      } else {
         parts.push({ text: userMsg.text });
         if (contextData.length > 0) {
            const contextStr = JSON.stringify(contextData.slice(0, 15).map(p => ({ grade: p.gradeName, mfr: p.properties['熔体质量流动速率']?.value, density: p.properties['密度']?.value })));
            parts.push({ text: `\n[Context: Top 15 Search Results]: ${contextStr}` });
         }
      }

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: parts }],
        config: { systemInstruction, thinkingConfig: useThinking ? { thinkingBudget: 2048 } : undefined }
      });

      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: response.text || "No response." }]);
    } catch (error) {
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: "⚠️ System Error: Unable to process analysis." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const renderInput = () => (
    <div className="max-w-4xl mx-auto w-full">
      {attachedImage && (
        <div className="flex items-center justify-between px-4 py-3 mb-3 bg-emerald-50 dark:bg-emerald-900/10 border border-emerald-100 dark:border-emerald-800 rounded-2xl shadow-inner">
