const QuickRadarPopup: React.FC<{ product: Product; anchorRef: React.RefObject<HTMLDivElement> }> = ({ product, anchorRef }) => {
    const chartRef = useRef<HTMLDivElement>(null);
    const { tProp } = useLanguage();

    useEffect(() => {
        if (!chartRef.current) return;
        const myChart = echarts.init(chartRef.current);
        const props = ['密度', '熔体质量流动速率', '拉伸屈服应力', '弯曲模量', '悬臂梁缺口冲击强度'];
        const values = props.map(p => {
            const v = product.properties[p]?.value;
            return typeof v === 'number' ? v : parseFloat(String(v)) || 0;
        });

        myChart.setOption({
            radar: {
                indicator: props.map(p => ({ name: tProp(p).slice(0,6), max: 100 })), // Simplified
                shape: 'circle', splitNumber: 3, axisName: { fontSize: 8, color: '#94a3b8' }
            },
            series: [{ type: 'radar', data: [{ value: values, areaStyle: { color: 'rgba(16, 185, 129, 0.4)' }, lineStyle: { color: '#10b981' } }], symbol: 'none' }]
        });
        return () => myChart.dispose();
    }, [product]);

    return (
        <div className="fixed z-[100] w-48 h-48 bg-white dark:bg-slate-900 rounded-2xl shadow-2xl border p-2 animate-in fade-in zoom-in-95 pointer-events-none" style={{ left: anchorRef.current?.getBoundingClientRect().left! + 40, top: anchorRef.current?.getBoundingClientRect().top! - 60 }}>
            <div ref={chartRef} className="w-full h-full" />
        </div>
    );
};

const safeRenderValue = (val: any, unit?: string): string => {
    if (val === null || val === undefined) return '-';
    if (typeof val === 'number') return isNaN(val) ? '-' : `${val}${unit ? ` ${unit}` : ''}`;
    return String(val) || '-';
};

