                <AlertCircle size={16} className={t.type === 'error' ? "text-rose-400" : "hidden"} />
                <span className="text-xs font-bold tracking-wide">{t.message}</span>
                <button onClick={() => removeToast(t.id)} className="ml-2 hover:bg-white/10 p-1 rounded-full transition-colors"><X size={12} /></button>
            </div>
        ))}
    </div>
);

const getDynamicColumns = (products: Product[]): ColumnConfig[] => {
  const propertyKeys = new Set<string>();
  products.forEach(p => {
    Object.keys(p.properties).forEach(k => propertyKeys.add(k));
  });

  const defaultVisible = ['密度', '熔体质量流动速率', '拉伸屈服应力', '弯曲模量', '悬臂梁缺口冲击强度', '典型应用'];

  const dynamicCols: ColumnConfig[] = Array.from(propertyKeys).map(key => ({
    key, label: key, visible: defaultVisible.includes(key), isSystem: false
  })).sort((a, b) => {
      const aIsLikelyImportant = defaultVisible.includes(a.key);
      const bIsLikelyImportant = defaultVisible.includes(b.key);
      if (aIsLikelyImportant && !bIsLikelyImportant) return -1;
      if (!aIsLikelyImportant && bIsLikelyImportant) return 1;
      return a.label.localeCompare(b.label);
  });

  const systemCols: ColumnConfig[] = [
    { key: 'gradeName', label: '牌号', visible: true, isSystem: true },
    { key: 'manufacturer', label: '所属分类', visible: true, isSystem: true },
    { key: 'updatedAt', label: '更新时间', visible: false, isSystem: false },
  ];

  return [...systemCols, ...dynamicCols];
};

type AppView = 'dashboard' | 'analytics' | 'ai';

const AppContent: React.FC = () => {
  const { t, tProp } = useLanguage();
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('resindb-session');
    return saved ? JSON.parse(saved) : null;
  });

  const [toasts, setToasts] = useState<Toast[]>([]);
  const addToast = useCallback((type: Toast['type'], message: string) => {
      const id = Date.now().toString();
      setToasts(prev => [...prev, { id, type, message }]);
      setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3000);
  }, []);

  const [allProducts, setAllProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [selectedCategoryId, setSelectedCategoryId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [columns, setColumns] = useState<ColumnConfig[]>([]);
  const [isImportOpen, setIsImportOpen] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [activeView, setActiveView] = useState<AppView>('dashboard');
  const [isExporting, setIsExporting] = useState(false);

  // Selection & Advanced Filter State
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [showFilters, setShowFilters] = useState(false);
  const [numericFilters, setNumericFilters] = useState<Record<string, { min: string; max: string }>>({});

  useEffect(() => {
    setColumns(getDynamicColumns(allProducts));
  }, []);

  // Utility to resolve property key from search label
  const resolvePropKey = (label: string): string | null => {
      const cleanLabel = label.toLowerCase();
      // Try direct match
      const directMatch = columns.find(c => c.key.toLowerCase() === cleanLabel || tProp(c.label).toLowerCase() === cleanLabel);
      if (directMatch) return directMatch.key;

      // Try propertyMap reverse lookup
      const reverseKey = Object.keys(propertyMap).find(k => 
        k.toLowerCase() === cleanLabel || propertyMap[k].toLowerCase() === cleanLabel
      );
      return reverseKey || null;
  };

  const filteredData = useMemo(() => {
    // 1. Parse Search Query into Text and Token Filters
    const tokens = searchQuery.split(' ').filter(t => t.trim());
    const textFilters: string[] = [];
    const syntaxFilters: { key: string, condition: string }[] = [];

    tokens.forEach(token => {
        if (token.includes(':')) {
            const [label, condition] = token.split(':');
            const key = resolvePropKey(label);
            if (key) syntaxFilters.push({ key, condition });
            else textFilters.push(token); // Treat as text if label unknown
        } else {
            textFilters.push(token);
        }
    });

    return allProducts.filter(product => {
      // 2. Category Filter
      const matchesCategory = selectedCategoryId ? product.categoryIds.includes(selectedCategoryId) : true;
      if (!matchesCategory) return false;

      // 3. Text Search (Matches grade, manufacturer or property keys)
      const matchesText = textFilters.every(query => {
          const lQuery = query.toLowerCase();
          return product.gradeName.toLowerCase().includes(lQuery) || 
                 product.manufacturer.toLowerCase().includes(lQuery) || 
                 Object.keys(product.properties).some(k => k.toLowerCase().includes(lQuery));
      });
      if (!matchesText) return false;

      // 4. Syntax Filters from Search Bar (e.g., density:>0.95)
      const matchesSyntax = syntaxFilters.every(f => {
          const propVal = product.properties[f.key]?.value;
          const val = typeof propVal === 'number' ? propVal : parseFloat(String(propVal));
          const cond = f.condition;

          if (isNaN(val)) return String(propVal).toLowerCase().includes(cond.toLowerCase());

          if (cond.startsWith('>')) return val > parseFloat(cond.slice(1));
          if (cond.startsWith('<')) return val < parseFloat(cond.slice(1));
          if (cond.includes('-')) {
              const [min, max] = cond.split('-').map(Number);
              return val >= min && val <= max;
          }
          return val === parseFloat(cond);
      });
      if (!matchesSyntax) return false;

      // 5. Explicit Sidebar Hub Filters
      return Object.entries(numericFilters).every(([key, range]) => {
          const propVal = product.properties[key]?.value;
          const num = typeof propVal === 'number' ? propVal : parseFloat(String(propVal));
          if (isNaN(num)) return true;
          const min = range.min === '' ? -Infinity : parseFloat(range.min);
          const max = range.max === '' ? Infinity : parseFloat(range.max);
          return num >= min && num <= max;
      });
    });
  }, [allProducts, selectedCategoryId, searchQuery, numericFilters, columns, tProp]);

  const availableNumericProps = useMemo(() => {
    const props = new Set<string>();
    allProducts.forEach(p => {
        Object.entries(p.properties).forEach(([k, v]) => {
            if (typeof v.value === 'number') props.add(k);
        });
    });
    return Array.from(props).sort();
  }, [allProducts]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('resindb-session', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('resindb-session');
  };

  const handleToggleColumn = (key: string) => {
    setColumns(cols => cols.map(c => c.key === key ? { ...c, visible: !c.visible } : c));
  };

  const handleExport = async () => {
    setIsExporting(true);
    await new Promise(r => setTimeout(r, 800));
    addToast('success', '报告生成成功，已开始下载');
    setIsExporting(false);
  };

  const handleBatchUpdate = (ids: string[], updates: any) => {
      setAllProducts(prev => prev.map(p => ids.includes(p.id) ? { ...p, ...updates, updatedAt: new Date().toISOString().split('T')[0] } : p));
      addToast('success', `批量更新了 ${ids.length} 条记录`);
  };

  const handleDelete = (ids: string[]) => {
      setAllProducts(prev => prev.filter(p => !ids.includes(p.id)));
      setSelectedIds(new Set());
      addToast('success', `已删除 ${ids.length} 条记录`);
  };

  const handleImportData = () => {
    const newProducts: Product[] = Array.from({ length: 5 }).map((_, i) => ({
      id: `imported-${Date.now()}-${i}`,
      gradeName: `New-Grade-${1000 + i} (Imported)`,
      manufacturer: 'China Petroleum (Imported)',
      manufacturerId: 'm-cnpc-1',
      categoryIds: [selectedCategoryId || 'root_plastic'],
      updatedAt: new Date().toISOString().split('T')[0],
      properties: {
        '密度': { value: 0.92 + (Math.random() * 0.05), unit: 'g/cm³' },
        '熔体质量流动速率': { value: 1 + (Math.random() * 5), unit: 'g/10min' },
        '典型应用': { value: 'Imported batch test' }
      }
    }));
    setAllProducts(prev => [...newProducts, ...prev]);
    addToast('success', `${newProducts.length} items imported successfully`);
    setIsImportOpen(false);
  };

  if (!currentUser) return <AuthScreen onLogin={handleLogin} />;

  return (
    <div className="flex h-screen bg-slate-50 dark:bg-slate-950 font-sans text-slate-900 dark:text-slate-100 overflow-hidden transition-colors duration-300">
      <ToastContainer toasts={toasts} removeToast={(id) => setToasts(prev => prev.filter(t => t.id !== id))} />

      {/* Primary Sidebar */}
      <nav className="w-16 md:w-20 bg-slate-900 dark:bg-slate-950 flex flex-col items-center py-6 gap-6 z-50 shrink-0 border-r border-white/5">
         <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center shadow-lg shadow-emerald-900/40 mb-2 overflow-hidden relative group">
            <Beaker size={20} className="text-white group-hover:scale-110 transition-transform" />
         </div>

         <div className="flex-1 flex flex-col gap-5">
            {[
                { id: 'dashboard', icon: LayoutDashboard, label: '仓库' },
                { id: 'analytics', icon: PieChart, label: '可视化' },
                { id: 'ai', icon: Bot, label: 'AI 空间' }
            ].map((btn) => (
                <button 
                    key={btn.id}
                    onClick={() => setActiveView(btn.id as AppView)}
                    className={`p-3 rounded-2xl transition-all duration-300 relative group ${activeView === btn.id ? 'bg-primary-600 text-white shadow-lg shadow-primary-500/20' : 'text-slate-500 hover:text-emerald-400 hover:bg-slate-800'}`}
                >
                    <btn.icon size={24} />
                    {activeView === btn.id && <div className="absolute -left-3 top-1/2 -translate-y-1/2 w-1 h-8 bg-primary-400 rounded-r-full"></div>}
                </button>
            ))}
         </div>

         <div className="flex flex-col gap-4 mb-2">
            <button onClick={() => setIsAdminOpen(true)} className="p-3 text-slate-500 hover:text-emerald-400 hover:bg-slate-800 rounded-2xl transition-all"><ShieldCheck size={24} /></button>
         </div>
      </nav>

      {/* Main Container */}
      <div className="flex-1 flex flex-col min-w-0 h-full relative">
        <TopBar 
            user={currentUser}
            onLogout={handleLogout}
            onOpenProfile={() => setIsProfileOpen(true)}
            onOpenAdmin={() => setIsAdminOpen(true)}
            searchQuery={searchQuery}
            onSearchChange={setSearchQuery}
            columns={columns}
            onToggleColumn={handleToggleColumn}
