const getDynamicColumns = (products: Product[]): ColumnConfig[] => {
  const propertyKeys = new Set<string>();
  products.forEach(p => {
    Object.keys(p.properties).forEach(k => propertyKeys.add(k));
  });

  const defaultVisible = ['密度', '熔体质量流动速率', '拉伸屈服应力', '弯曲模量', '悬臂梁缺口冲击强度', '典型应用'];

  const dynamicCols: ColumnConfig[] = Array.from(propertyKeys).map(key => ({
    key, label: key, visible: defaultVisible.includes(key), isSystem: false
  })).sort((a, b) => {
      const aIsLikelyImportant = defaultVisible.includes(a.key);
      const bIsLikelyImportant = defaultVisible.includes(b.key);
      if (aIsLikelyImportant && !bIsLikelyImportant) return -1;
      if (!aIsLikelyImportant && bIsLikelyImportant) return 1;
      return a.label.localeCompare(b.label);
  });

  const systemCols: ColumnConfig[] = [
    { key: 'gradeName', label: '牌号', visible: true, isSystem: true },
    { key: 'manufacturer', label: '所属分类', visible: true, isSystem: true },
    { key: 'updatedAt', label: '更新时间', visible: false, isSystem: false },
  ];

  return [...systemCols, ...dynamicCols];
};

type AppView = 'dashboard' | 'analytics' | 'ai';

const AppContent: React.FC = () => {
  const { t, tProp } = useLanguage();
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('resindb-session');
    return saved ? JSON.parse(saved) : null;
  });

  const [toasts, setToasts] = useState<Toast[]>([]);
  const addToast = useCallback((type: Toast['type'], message: string) => {
      const id = Date.now().toString();
      setToasts(prev => [...prev, { id, type, message }]);
      setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3000);
  }, []);

  const [allProducts, setAllProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [selectedCategoryId, setSelectedCategoryId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [columns, setColumns] = useState<ColumnConfig[]>([]);
  const [isImportOpen, setIsImportOpen] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [activeView, setActiveView] = useState<AppView>('dashboard');
  const [isExporting, setIsExporting] = useState(false);

  // Selection & Advanced Filter State
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [showFilters, setShowFilters] = useState(false);
  const [numericFilters, setNumericFilters] = useState<Record<string, { min: string; max: string }>>({});

  useEffect(() => {
    setColumns(getDynamicColumns(allProducts));
  }, []);

  // Utility to resolve property key from search label
  const resolvePropKey = useCallback((label: string): string | null => {
      const cleanLabel = label.toLowerCase();

      // 1. Direct match with standard properties (CN/EN)
      const directMatch = columns.find(c => 
        c.key.toLowerCase() === cleanLabel || 
        tProp(c.label).toLowerCase() === cleanLabel
      );
      if (directMatch) return directMatch.key;

      // 2. Lookup in propertyMap (including aliases)
      const reverseKey = Object.keys(propertyMap).find(k => 
        k.toLowerCase() === cleanLabel || 
        propertyMap[k].toLowerCase() === cleanLabel
      );
      if (reverseKey) return reverseKey;

      // 3. Common technical aliases
      const commonAliases: Record<string, string> = {
          'mfr': '熔体质量流动速率',
          '熔指': '熔体质量流动速率',
          'mfi': '熔体质量流动速率',
          '密度': '密度',
          'density': '密度',
          '屈服': '拉伸屈服应力',
          'impact': '悬臂梁缺口冲击强度',
          '冲击': '悬臂梁缺口冲击强度',
          '模量': '弯曲模量',
          'modulus': '弯曲模量'
      };

      return commonAliases[cleanLabel] || null;
  }, [columns, tProp]);

  const filteredData = useMemo(() => {
    // Advanced Query Parser using Regex
    // Pattern: (Property Name):(Operator/Value)
    // Operators: >, <, >=, <=, min-max
    const syntaxRegex = /([\u4e00-\u9fa5\w]+):([<>]=?|[-.0-9a-zA-Z]+)/g;
    const syntaxFilters: { key: string, operator: string, value: string | number, max?: number }[] = [];

    let processedQuery = searchQuery;
    let match;

    // Extract syntax filters and clean the query for text search
    while ((match = syntaxRegex.exec(searchQuery)) !== null) {
        const [full, label, condition] = match;
        const key = resolvePropKey(label);

        if (key) {
            processedQuery = processedQuery.replace(full, '');

            // Handle range: "100-200"
            if (condition.includes('-') && !condition.startsWith('-')) {
                const parts = condition.split('-');
                syntaxFilters.push({ 
                    key, 
                    operator: 'range', 
                    value: parseFloat(parts[0]), 
                    max: parseFloat(parts[1]) 
                });
            } 
            // Handle operators: ">10", "<5", ">=2"
            else if (condition.match(/^[<>]=?/)) {
                const op = condition.match(/^[<>]=?/)?.[0] || '';
                const val = parseFloat(condition.replace(op, ''));
                syntaxFilters.push({ key, operator: op, value: val });
            } 
            // Handle equality or text search within property: "grade:5000S"
            else {
                const numVal = parseFloat(condition);
                syntaxFilters.push({ 
                    key, 
                    operator: '=', 
                    value: isNaN(numVal) ? condition : numVal 
                });
            }
        }
    }

    const textKeywords = processedQuery.toLowerCase().split(' ').filter(k => k.trim());

    return allProducts.filter(product => {
      // 1. Category Filter
      const matchesCategory = selectedCategoryId ? product.categoryIds.includes(selectedCategoryId) : true;
      if (!matchesCategory) return false;

      // 2. Keyword Text Search
      const matchesText = textKeywords.every(query => {
          return product.gradeName.toLowerCase().includes(query) || 
                 product.manufacturer.toLowerCase().includes(query) || 
                 Object.keys(product.properties).some(k => k.toLowerCase().includes(query));
      });
      if (!matchesText) return false;

      // 3. Advanced Syntax Filters (Smart Range/Operator Search)
      const matchesSyntax = syntaxFilters.every(f => {
          const propVal = product.properties[f.key]?.value;
          const val = typeof propVal === 'number' ? propVal : parseFloat(String(propVal));

          // Non-numeric handling
          if (isNaN(val) || typeof f.value === 'string') {
              return String(propVal).toLowerCase().includes(String(f.value).toLowerCase());
          }

          // Numeric handling
          switch(f.operator) {
              case '>': return val > (f.value as number);
              case '<': return val < (f.value as number);
              case '>=': return val >= (f.value as number);
              case '<=': return val <= (f.value as number);
              case 'range': return val >= (f.value as number) && val <= (f.max || Infinity);
              case '=': return val === (f.value as number);
              default: return true;
          }
      });
      if (!matchesSyntax) return false;

      // 4. Sidebar Hub UI Filters (Manual Input)
      return Object.entries(numericFilters).every(([key, range]) => {
          const propVal = product.properties[key]?.value;
          const num = typeof propVal === 'number' ? propVal : parseFloat(String(propVal));
          if (isNaN(num)) return true;
          const min = range.min === '' ? -Infinity : parseFloat(range.min);
          const max = range.max === '' ? Infinity : parseFloat(range.max);
          return num >= min && num <= max;
      });
    });
  }, [allProducts, selectedCategoryId, searchQuery, numericFilters, resolvePropKey]);

  const availableNumericProps = useMemo(() => {
    const props = new Set<string>();
    allProducts.forEach(p => {
        Object.entries(p.properties).forEach(([k, v]) => {
            if (typeof v.value === 'number') props.add(k);
        });
    });
    return Array.from(props).sort();
  }, [allProducts]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('resindb-session', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('resindb-session');
  };

  const handleToggleColumn = (key: string) => {
    setColumns(cols => cols.map(c => c.key === key ? { ...c, visible: !c.visible } : c));
  };

  const handleExport = async () => {
    setIsExporting(true);
    await new Promise(r => setTimeout(r, 800));
    addToast('success', '报告生成成功，已开始下载');
    setIsExporting(false);
  };

  const handleBatchUpdate = (ids: string[], updates: any) => {
      setAllProducts(prev => prev.map(p => ids.includes(p.id) ? { ...p, ...updates, updatedAt: new Date().toISOString().split('T')[0] } : p));
      addToast('success', `批量更新了 ${ids.length} 条记录`);
  };

  const handleDelete = (ids: string[]) => {
      setAllProducts(prev => prev.filter(p => !ids.includes(p.id)));
      setSelectedIds(new Set());
      addToast('success', `已删除 ${ids.length} 条记录`);
  };

  const handleImportData = () => {
    const newProducts: Product[] = Array.from({ length: 5 }).map((_, i) => ({
      id: `imported-${Date.now()}-${i}`,
      gradeName: `New-Grade-${1000 + i} (Imported)`,
      manufacturer: 'China Petroleum (Imported)',
      manufacturerId: 'm-cnpc-1',
      categoryIds: [selectedCategoryId || 'root_plastic'],
      updatedAt: new Date().toISOString().split('T')[0],
      properties: {
        '密度': { value: 0.92 + (Math.random() * 0.05), unit: 'g/cm³' },
        '熔体质量流动速率': { value: 1 + (Math.random() * 5), unit: 'g/10min' },
        '典型应用': { value: 'Imported batch test' }
      }
    }));
    setAllProducts(prev => [...newProducts, ...prev]);
    addToast('success', `${newProducts.length} items imported successfully`);
    setIsImportOpen(false);
  };

  if (!currentUser) return <AuthScreen onLogin={handleLogin} />;

  return (
    <div className="flex h-screen bg-slate-50 dark:bg-slate-950 font-sans text-slate-900 dark:text-slate-100 overflow-hidden transition-colors duration-300">
      <ToastContainer toasts={toasts} removeToast={(id) => setToasts(prev => prev.filter(t => t.id !== id))} />

      {/* Primary Sidebar */}
      <nav className="w-16 md:w-20 bg-slate-900 dark:bg-slate-950 flex flex-col items-center py-6 gap-6 z-50 shrink-0 border-r border-white/5">
         <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center shadow-lg shadow-emerald-900/40 mb-2 overflow-hidden relative group">
            <Beaker size={20} className="text-white group-hover:scale-110 transition-transform" />
         </div>

         <div className="flex-1 flex flex-col gap-5">
            {[
                { id: 'dashboard', icon: LayoutDashboard, label: '仓库' },
                { id: 'analytics', icon: PieChart, label: '可视化' },
                { id: 'ai', icon: Bot, label: 'AI 空间' }
            ].map((btn) => (
                <button 
                    key={btn.id}
                    onClick={() => setActiveView(btn.id as AppView)}
                    className={`p-3 rounded-2xl transition-all duration-300 relative group ${activeView === btn.id ? 'bg-primary-600 text-white shadow-lg shadow-primary-500/20' : 'text-slate-500 hover:text-emerald-400 hover:bg-slate-800'}`}
                >
                    <btn.icon size={24} />
                    {activeView === btn.id && <div className="absolute -left-3 top-1/2 -translate-y-1/2 w-1 h-8 bg-primary-400 rounded-r-full"></div>}
                </button>
            ))}
         </div>

         <div className="flex flex-col gap-4 mb-2">
            <button onClick={() => setIsAdminOpen(true)} className="p-3 text-slate-500 hover:text-emerald-400 hover:bg-slate-800 rounded-2xl transition-all"><ShieldCheck size={24} /></button>
         </div>
      </nav>

      {/* Main Container */}
      <div className="flex-1 flex flex-col min-w-0 h-full relative">
        <TopBar 
            user={currentUser}
            onLogout={handleLogout}
            onOpenProfile={() => setIsProfileOpen(true)}
            onOpenAdmin={() => setIsAdminOpen(true)}
            searchQuery={searchQuery}
            onSearchChange={setSearchQuery}
            columns={columns}
            onToggleColumn={handleToggleColumn}
            onToggleAllColumns={() => {}}
            onOpenImport={() => setIsImportOpen(true)}
            onExport={handleExport}
            isExporting={isExporting}
            viewMode={activeView === 'analytics' ? 'chart' : 'grid'}
            onViewModeChange={(m) => setActiveView(m === 'chart' ? 'analytics' : 'dashboard')}
            showAdvancedFilters={showFilters}
            onToggleFilters={() => setShowFilters(!showFilters)}
            activeFilterCount={Object.keys(numericFilters).length}
        />

        {/* Advanced Filter Hub */}
        {showFilters && (
            <div className="px-6 pb-4 animate-in slide-in-from-top-2 duration-300">
                <div className="p-4 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-3xl shadow-xl flex flex-wrap gap-4 items-center">
                    <div className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest border-r pr-4 border-slate-100 dark:border-slate-800"><Filter size={14} /> 物性区间</div>
                    {availableNumericProps.slice(0, 4).map(prop => (
                        <div key={prop} className="flex items-center gap-2 bg-slate-50 dark:bg-slate-850 px-3 py-1.5 rounded-xl border border-slate-100 dark:border-slate-800">
                            <span className="text-[11px] font-bold text-slate-600 dark:text-slate-300">{tProp(prop)}</span>
                            <div className="flex items-center gap-1.5">
                                <input 
                                    type="text" placeholder="Min" 
                                    value={numericFilters[prop]?.min || ''}
                                    onChange={(e) => setNumericFilters({...numericFilters, [prop]: { min: e.target.value, max: numericFilters[prop]?.max || '' }})}
                                    className="w-12 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-md text-[10px] py-1 text-center font-mono outline-none focus:border-primary-500"
                                />
                                <span className="text-slate-300">—</span>
                                <input 
                                    type="text" placeholder="Max" 
                                    value={numericFilters[prop]?.max || ''}
                                    onChange={(e) => setNumericFilters({...numericFilters, [prop]: { min: numericFilters[prop]?.min || '', max: e.target.value }})}
                                    className="w-12 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-md text-[10px] py-1 text-center font-mono outline-none focus:border-primary-500"
                                />
                            </div>
                        </div>
                    ))}
                    <button onClick={() => setNumericFilters({})} className="text-[10px] font-bold text-slate-400 hover:text-rose-500 transition-colors uppercase tracking-widest ml-auto">重置所有</button>
                </div>
            </div>
        )}

        <div className="flex-1 flex overflow-hidden">
             {/* Category Sidebar */}
            {(activeView === 'dashboard' || activeView === 'analytics') && (
                <div className="w-72 shrink-0 border-r border-slate-200 dark:border-slate-800 bg-white/50 dark:bg-slate-900/50 backdrop-blur-sm flex flex-col">
                    <TreeSidebar 
                    categories={CATEGORY_TREE}
                    selectedCategoryId={selectedCategoryId}
                    onSelectCategory={setSelectedCategoryId}
                    totalCount={allProducts.length}
                    counts={{}}
                    />
                </div>
            )}

            {/* Content Area */}
            <div className="flex-1 flex flex-col p-6 min-h-0 relative">
                <div className="flex-1 w-full min-h-0 relative animate-in fade-in duration-500">
                    {activeView === 'dashboard' && (
                        <div className="absolute inset-0">
                            <DataGrid 
                                data={filteredData}
                                columns={columns}
                                isLoading={false}
                                onDelete={handleDelete}
                                onUpdate={(p) => { setAllProducts(prev => prev.map(old => old.id === p.id ? p : old)); addToast('success', '牌号已更新'); }}
                                onBatchUpdate={handleBatchUpdate}
                                onCategorySelect={setSelectedCategoryId}
                                selectedIds={selectedIds}
                                onSelectionChange={setSelectedIds}
                            />
                        </div>
                    )}
                    {activeView === 'analytics' && (
                        <div className="absolute inset-0"><DataVisualizer data={filteredData} /></div>
                    )}
                    {activeView === 'ai' && (
                        <div className="absolute inset-0 flex flex-col md:flex-row gap-6">
                            <div className="flex-1 bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 overflow-hidden shadow-2xl flex flex-col min-w-0">
                                <div className="p-5 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-950/50 flex items-center justify-between">
                                    <div className="flex items-center gap-4">
                                        <div className="p-3 bg-emerald-600 rounded-2xl text-white shadow-lg"><Bot size={24} /></div>
                                        <div>
                                            <h2 className="text-lg font-black text-slate-800 dark:text-white">ResinAI 分析空间</h2>
                                            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1.5"><Sparkles size={10} className="text-emerald-500" /> Deep Scientific Engine</p>
                                        </div>
                                    </div>
                                </div>
                                <div className="flex-1 relative">
                                    <AIAssistant contextData={filteredData} inlineView={true} />
                                </div>
                            </div>
                            <div className="hidden xl:flex w-[400px] bg-white/40 dark:bg-slate-900/40 backdrop-blur-xl rounded-[2.5rem] border border-slate-200 dark:border-slate-800 overflow-hidden shadow-xl flex-col">
                                <div className="p-5 border-b border-slate-100 dark:border-slate-800 flex items-center gap-3">
                                    <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 rounded-xl"><Layout size={20} /></div>
                                    <h2 className="text-sm font-black uppercase tracking-widest">实时映射结果</h2>
                                </div>
                                <div className="flex-1 relative p-4"><DataVisualizer data={filteredData} /></div>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>

        {/* Global Selection Tray */}
        {selectedIds.size > 0 && (
            <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[80] animate-in slide-in-from-bottom-10 duration-500 pointer-events-none">
                <div className="pointer-events-auto bg-slate-900/90 dark:bg-white/90 backdrop-blur-2xl px-6 py-4 rounded-[2.5rem] border border-white/10 dark:border-slate-200 shadow-2xl flex items-center gap-6">
                    <div className="flex items-center gap-3 pr-6 border-r border-white/10 dark:border-slate-200">
                        <div className="w-10 h-10 bg-primary-600 rounded-full flex items-center justify-center text-white font-black text-sm shadow-glow">{selectedIds.size}</div>
                        <div>
                            <p className="text-xs font-black text-white dark:text-slate-900 uppercase tracking-widest">{t('selected')}</p>
                            <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase">{t('recordsProcessed')}</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <button className="flex flex-col items-center gap-1 group">
                            <div className="p-3 bg-white/5 dark:bg-slate-100 rounded-2xl text-white dark:text-slate-700 hover:bg-primary-600 hover:text-white transition-all group-hover:scale-110 active:scale-95"><GitCompare size={20} /></div>
                            <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase">对比</span>
                        </button>
                        <button className="flex flex-col items-center gap-1 group">
                            <div className="p-3 bg-white/5 dark:bg-slate-100 rounded-2xl text-white dark:text-slate-700 hover:bg-primary-600 hover:text-white transition-all group-hover:scale-110 active:scale-95"><Download size={20} /></div>
                            <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase">导出</span>
                        </button>
                        <button onClick={() => handleDelete(Array.from(selectedIds))} className="flex flex-col items-center gap-1 group">
                            <div className="p-3 bg-rose-500/10 rounded-2xl text-rose-500 hover:bg-rose-500 hover:text-white transition-all group-hover:scale-110 active:scale-95"><Trash2 size={20} /></div>
                            <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase">删除</span>
                        </button>
                        <button onClick={() => setSelectedIds(new Set())} className="ml-4 p-2 text-slate-500 hover:text-white dark:hover:text-slate-900"><X size={20} /></button>
                    </div>
                </div>
            </div>
        )}
      </div>

      <ImportModal isOpen={isImportOpen} onClose={() => setIsImportOpen(false)} onImport={handleImportData} />
      <ProfileModal isOpen={isProfileOpen} onClose={() => setIsProfileOpen(false)} user={currentUser} onSave={(u) => setCurrentUser({...currentUser, ...u})} />
      <AdminModal isOpen={isAdminOpen} onClose={() => setIsAdminOpen(false)} />

      {activeView !== 'ai' && <AIAssistant contextData={filteredData} />}
    </div>
  );
};

const App: React.FC = () => (
    <LanguageProvider><ThemeProvider><AppContent /></ThemeProvider></LanguageProvider>
);

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Search, SlidersHorizontal, Upload, LayoutGrid, BarChart2, Moon, Sun, Globe, User, LogOut, Settings, Shield, History, X, Trash2, Clock, Command, Download, Loader2, Maximize, Minimize, ArrowRight, Filter, ChevronDown, Sparkles, Hash, Zap, Beaker, Info } from 'lucide-react';
import { ColumnConfig, ViewMode, User as UserType } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import { useTheme } from '../contexts/ThemeContext';

interface TopBarProps {
  user: UserType | null;
  onLogout: () => void;
  onOpenProfile: () => void;
  onOpenAdmin: () => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  isSearching?: boolean;
  columns: ColumnConfig[];
  onToggleColumn: (key: string) => void;
  onToggleAllColumns: (visible: boolean) => void;
  onOpenImport: () => void;
  onExport: () => void;
  isExporting: boolean;
  viewMode: ViewMode;
  onViewModeChange: (mode: ViewMode) => void;
  showAdvancedFilters: boolean;
  onToggleFilters: () => void;
  activeFilterCount: number;
}

export const TopBar: React.FC<TopBarProps> = ({
  user, onLogout, onOpenProfile, onOpenAdmin, searchQuery, onSearchChange, isSearching, columns, onToggleColumn, onToggleAllColumns, onOpenImport, onExport, isExporting, viewMode, onViewModeChange, showAdvancedFilters, onToggleFilters, activeFilterCount
}) => {
  const [isColumnMenuOpen, setIsColumnMenuOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const { t, language, toggleLanguage, tProp } = useLanguage();
  const { theme, toggleTheme } = useTheme();
  const inputRef = useRef<HTMLInputElement>(null);

  const colMenuRef = useRef<HTMLDivElement>(null);
  const userMenuRef = useRef<HTMLDivElement>(null);

  const [searchHistory, setSearchHistory] = useState<string[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Advanced Filtering Syntax Suggestions
  const filterSuggestions = useMemo(() => {
      const parts = searchQuery.split(' ');
      const lastToken = parts[parts.length - 1];

      // Only suggest if not already a complete filter
      if (lastToken.includes(':')) return [];

      const availableProps = columns
          .filter(c => !c.isSystem)
          .map(c => ({
              key: c.key,
              label: tProp(c.label),
              unit: columns.find(col => col.key === c.key)?.label.match(/\[(.*?)\]/)?.[1] || ''
          }));

      if (!lastToken) return availableProps.slice(0, 5);

      return availableProps.filter(p => 
          p.label.toLowerCase().includes(lastToken.toLowerCase()) ||
          p.key.toLowerCase().includes(lastToken.toLowerCase())
      ).slice(0, 5);
  }, [columns, searchQuery, tProp]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
            e.preventDefault();
            inputRef.current?.focus();
        }
    };
    const handleClickOutside = (e: MouseEvent) => {
        if (colMenuRef.current && !colMenuRef.current.contains(e.target as Node)) setIsColumnMenuOpen(false);
        if (userMenuRef.current && !userMenuRef.current.contains(e.target as Node)) setIsUserMenuOpen(false);
    };
    const handleFullscreenChange = () => setIsFullscreen(!!document.fullscreenElement);

    window.addEventListener('keydown', handleKeyDown);
    document.addEventListener('mousedown', handleClickOutside);
    document.addEventListener('fullscreenchange', handleFullscreenChange);

    const savedHistory = localStorage.getItem('resindb_search_history');
    if (savedHistory) try { setSearchHistory(JSON.parse(savedHistory)); } catch (e) {}

    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        document.removeEventListener('mousedown', handleClickOutside);
        document.removeEventListener('fullscreenchange', handleFullscreenChange);
    };
  }, []);

  const saveToHistory = (query: string) => {
      if (!query.trim() || query.includes(':')) return; // Don't save complex syntax to history
      const clean = query.trim();
      setSearchHistory(prev => {
          const filtered = prev.filter(item => item !== clean);
          const updated = [clean, ...filtered].slice(0, 5);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const handleInputKeyDown = (e: React.KeyboardEvent) => {
      const totalItems = searchHistory.length + filterSuggestions.length;
      if (showHistory && totalItems > 0) {
          if (e.key === 'ArrowDown') { e.preventDefault(); setHistoryIndex(prev => (prev + 1) % totalItems); return; }
          if (e.key === 'ArrowUp') { e.preventDefault(); setHistoryIndex(prev => (prev - 1 + totalItems) % totalItems); return; }
      }
      if (e.key === 'Enter') {
          e.preventDefault();
          if (historyIndex >= 0 && showHistory) {
              if (historyIndex < searchHistory.length) {
                  onSearchChange(searchHistory[historyIndex]);
              } else {
                  const sugg = filterSuggestions[historyIndex - searchHistory.length];
                  applySuggestion(sugg.label);
              }
              setHistoryIndex(-1);
              setShowHistory(false);
          } else {
              saveToHistory(searchQuery);
              setShowHistory(false);
              setHistoryIndex(-1);
              inputRef.current?.blur();
          }
      }
      if (e.key === 'Escape') { setShowHistory(false); inputRef.current?.blur(); }
  };

  const applySuggestion = (label: string) => {
      const parts = searchQuery.split(' ');
      parts[parts.length - 1] = `${label}:`;
      const newQuery = parts.join(' ');
      onSearchChange(newQuery);
      inputRef.current?.focus();
  };

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) document.documentElement.requestFullscreen();
    else if (document.exitFullscreen) document.exitFullscreen();
  };

  const hasAdvancedSyntax = searchQuery.includes(':');

  return (
    <div className="w-full flex flex-col gap-3 px-2 py-2">
      <div className="flex items-center justify-between gap-6 pointer-events-none">
        {/* Search Pill */}
        <div className="flex-1 max-w-2xl relative z-[60] pointer-events-auto">
            <div className="relative group transition-all duration-300 focus-within:scale-[1.01]">
                <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                    {isSearching ? <Loader2 className="text-primary-500 animate-spin" size={18} /> : <Search className="text-slate-400 group-focus-within:text-primary-500 transition-colors" size={18} />}
                </div>
                <input
                    ref={inputRef}
                    type="text"
                    value={searchQuery}
                    onChange={(e) => { onSearchChange(e.target.value); setHistoryIndex(-1); }}
                    onFocus={() => { setShowHistory(true); setHistoryIndex(-1); }}
                    onBlur={() => setTimeout(() => setShowHistory(false), 200)}
                    onKeyDown={handleInputKeyDown}
                    placeholder={t('searchPlaceholder')}
                    className="block w-full pl-12 pr-12 py-3.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl text-sm font-medium shadow-sm outline-none focus:ring-4 focus:ring-primary-500/10 focus:border-primary-500/30 transition-all text-slate-700 dark:text-slate-200 placeholder:text-slate-400"
                />
                <div className="absolute inset-y-0 right-5 flex items-center gap-2">
                    {hasAdvancedSyntax && (
                        <div className="flex items-center justify-center w-5 h-5 bg-emerald-100 dark:bg-emerald-900/30 rounded-full animate-in fade-in zoom-in" title="Syntax Aware">
                            <Zap size={10} className="text-emerald-600 dark:text-emerald-400 fill-current" />
                        </div>
                    )}
                    {searchQuery && (
                        <button onClick={() => onSearchChange('')} className="p-1 text-slate-400 hover:text-slate-600 transition-colors"><X size={14} /></button>
                    )}
                    <button 
                        onClick={onToggleFilters}
                        className={`flex items-center gap-1.5 px-2.5 py-1 rounded-lg border transition-all ${showAdvancedFilters ? 'bg-primary-50 border-primary-200 text-primary-600' : 'bg-slate-50 border-slate-200 text-slate-500 hover:border-slate-300'}`}
                    >
                        <Filter size={14} className={activeFilterCount > 0 ? "fill-primary-500" : ""} />
                        <span className="text-[10px] font-black uppercase tracking-widest">{t('analysis')}</span>
                        {activeFilterCount > 0 && <span className="w-4 h-4 bg-primary-600 text-white rounded-full flex items-center justify-center text-[8px] font-bold">{activeFilterCount}</span>}
                    </button>
                </div>

                {/* History & Smart Suggestions Dropdown */}
                {showHistory && (searchHistory.length > 0 || filterSuggestions.length > 0) && (
                    <div className="absolute top-full left-0 right-0 mt-2 bg-white dark:bg-slate-900 backdrop-blur-xl border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl overflow-hidden z-50 animate-in fade-in slide-in-from-top-2 duration-200">
                        {/* 1. Filtering Syntax Suggestions */}
                        {filterSuggestions.length > 0 && (
                            <div className="py-1">
                                <div className="px-4 py-2 bg-slate-50/50 dark:bg-slate-800/30 border-b border-slate-100 dark:border-slate-800">
                                    <span className="text-[10px] font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest flex items-center gap-1.5">
                                        <Beaker size={10} /> {t('properties')} 语法建议
                                    </span>
                                </div>
                                {filterSuggestions.map((sugg, idx) => {
                                    const isSelected = (idx + searchHistory.length) === historyIndex;
                                    return (
                                        <div 
                                            key={`sugg-${sugg.key}`} 
                                            onMouseDown={(e) => { e.preventDefault(); applySuggestion(sugg.label); }} 
                                            className={`w-full flex items-center justify-between px-4 py-2.5 cursor-pointer transition-colors ${isSelected ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-700 dark:text-emerald-300' : 'hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400'}`}
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className="w-6 h-6 rounded bg-emerald-100 dark:bg-emerald-900/40 flex items-center justify-center shrink-0">
                                                    <Hash size={12} className="text-emerald-600 dark:text-emerald-400" />
                                                </div>
                                                <div className="flex flex-col">
                                                    <span className="text-sm font-bold leading-none">{sugg.label}</span>
                                                    <span className="text-[9px] opacity-60 font-mono mt-1">用法示例: {sugg.label}:>5.0</span>
                                                </div>
                                            </div>
                                            <ArrowRight size={12} className="text-emerald-300" />
                                        </div>
                                    );
                                })}
                            </div>
                        )}

                        {/* 2. Search History */}
                        {searchHistory.length > 0 && (
                            <div className="py-1 border-t border-slate-100 dark:border-slate-800">
                                <div className="flex items-center justify-between px-4 py-2 bg-slate-50/50 dark:bg-slate-800/30 border-b border-slate-100 dark:border-slate-800">
                                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1.5"><Clock size={10} /> {t('recentSearches')}</span>
                                    <button onMouseDown={(e) => { e.preventDefault(); setSearchHistory([]); localStorage.removeItem('resindb_search_history'); }} className="text-[10px] text-rose-500 hover:underline font-bold uppercase">{t('clearHistory')}</button>
                                </div>
                                {searchHistory.map((query, idx) => (
                                    <div 
                                        key={`hist-${idx}`} 
                                        onMouseDown={() => { onSearchChange(query); setShowHistory(false); }} 
                                        className={`w-full flex items-center justify-between px-4 py-2.5 cursor-pointer transition-colors ${idx === historyIndex ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300' : 'hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400'}`}
                                    >
                                        <div className="flex items-center gap-3"><History size={14} className="text-slate-400" /><span className="text-sm font-medium">{query}</span></div>
                                        <ArrowRight size={12} className="text-slate-300" />
                                    </div>
                                ))}
                            </div>
                        )}

                        {/* Syntax Tip Footer */}
                        <div className="px-4 py-3 bg-slate-100/50 dark:bg-slate-950/50 border-t border-slate-100 dark:border-slate-800">
                            <div className="flex items-start gap-2">
                                <Info size={12} className="text-primary-500 mt-0.5 shrink-0" />
                                <div className="text-[9px] text-slate-500 dark:text-slate-400 font-medium leading-normal">
                                    支持高级语法：使用 <kbd className="px-1 bg-white dark:bg-slate-800 border rounded shadow-sm font-mono text-[8px]">属性:条件</kbd> 进行过滤。<br/>
                                    示例：<span className="text-primary-600 font-bold">密度:>0.95</span> (范围), <span className="text-primary-600 font-bold">熔指:5-10</span> (区间), <span className="text-primary-600 font-bold">熔指:mfr</span> (别名支持)
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>

        {/* Right Actions */}
        <div className="flex items-center gap-1.5 p-1.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-[1.8rem] shadow-sm pointer-events-auto z-[60]">
            <div className="flex items-center bg-slate-100 dark:bg-slate-800 rounded-2xl p-1 border border-slate-200 dark:border-slate-700">
                <button onClick={() => onViewModeChange('grid')} className={`p-2 rounded-xl transition-all ${viewMode === 'grid' ? 'bg-white dark:bg-slate-700 text-primary-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}><LayoutGrid size={16} /></button>
                <button onClick={() => onViewModeChange('chart')} className={`p-2 rounded-xl transition-all ${viewMode === 'chart' ? 'bg-white dark:bg-slate-700 text-primary-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}><BarChart2 size={16} /></button>
            </div>

            <div className="h-5 w-px bg-slate-200 dark:bg-slate-700 mx-1"></div>

            <button onClick={onOpenImport} className="w-9 h-9 flex items-center justify-center text-slate-500 hover:text-primary-600 hover:bg-primary-50 dark:hover:bg-primary-900/20 rounded-full transition-all" title={t('importData')}><Upload size={18} /></button>
            <button onClick={onExport} disabled={isExporting} className="w-9 h-9 flex items-center justify-center text-slate-500 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-full transition-all disabled:opacity-50" title="Report">{isExporting ? <Loader2 size={18} className="animate-spin text-blue-500" /> : <Download size={18} />}</button>

            <div className="relative" ref={colMenuRef}>
                <button onClick={() => setIsColumnMenuOpen(!isColumnMenuOpen)} className={`w-9 h-9 flex items-center justify-center rounded-full transition-all ${isColumnMenuOpen ? 'bg-primary-50 text-primary-600' : 'text-slate-500 hover:text-primary-600 hover:bg-primary-50 dark:hover:bg-primary-900/20'}`}><SlidersHorizontal size={18} /></button>
                {isColumnMenuOpen && (
                    <div className="absolute top-full right-0 mt-3 w-64 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl p-3 z-[100] animate-in zoom-in-95 origin-top-right">
                        <h4 className="text-[10px] font-black uppercase text-slate-400 mb-2 px-2 tracking-widest">{t('visibleAttributes')}</h4>
                        <div className="max-h-60 overflow-y-auto custom-scrollbar space-y-0.5">
                            {columns.map(col => (
                                <label key={col.key} className="flex items-center gap-3 px-3 py-1.5 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 cursor-pointer transition-colors group">
                                    <div className={`w-4 h-4 rounded border flex items-center justify-center transition-colors ${col.visible ? 'bg-primary-600 border-primary-600' : 'border-slate-300 group-hover:border-primary-400'}`}>
