                        <button onClick={() => { setIsUserMenuOpen(false); onOpenProfile(); }} className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 text-[11px] font-bold text-slate-700 dark:text-slate-200 transition-colors"><User size={14} /> {t('profile')}</button>
                        <button onClick={() => { setIsUserMenuOpen(false); onOpenAdmin(); }} className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 text-[11px] font-bold text-slate-700 dark:text-slate-200 transition-colors"><Shield size={14} /> {t('adminPanel')}</button>
                        <button onClick={() => { setIsUserMenuOpen(false); toggleLanguage(); }} className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 text-[11px] font-bold text-slate-700 dark:text-slate-200 transition-colors"><Globe size={14} /> {language === 'zh' ? 'English' : '中文'}</button>
                        <div className="h-px bg-slate-100 dark:bg-slate-800 my-1"></div>
                        <button onClick={onLogout} className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-rose-50 dark:hover:bg-rose-900/20 text-[11px] font-bold text-rose-600 transition-colors"><LogOut size={14} /> {t('logout')}</button>
                    </div>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

