  const handleToggleColumn = (key: string) => { setColumns(cols => cols.map(c => c.key === key ? { ...c, visible: !c.visible } : c)); };
  const handleExport = async () => { setIsExporting(true); await new Promise(r => setTimeout(r, 800)); addToast('success', '报告生成成功'); setIsExporting(false); };
  const handleDelete = (ids: string[]) => { setAllProducts(prev => prev.filter(p => !ids.includes(p.id))); setSelectedIds(new Set()); addToast('success', `已删除 ${ids.length} 条记录`); };
