                                <span className="text-slate-300">—</span>
                                <input type="text" placeholder="Max" value={numericFilters[prop]?.max || ''} onChange={(e) => setNumericFilters({...numericFilters, [prop]: { min: numericFilters[prop]?.min || '', max: e.target.value }})} className="w-12 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-md text-[10px] py-1 text-center outline-none" />
                            </div>
                        </div>
                    ))}
                    <button onClick={() => setNumericFilters({})} className="text-[10px] font-bold text-slate-400 hover:text-rose-500 transition-colors ml-auto uppercase">重置所有</button>
                </div>
            </div>
