const QuickRadarPopup: React.FC<{ product: Product; anchorRef: React.RefObject<HTMLDivElement> }> = ({ product, anchorRef }) => {
    const chartRef = useRef<HTMLDivElement>(null);
    const { tProp } = useLanguage();

    useEffect(() => {
        if (!chartRef.current) return;
        const myChart = echarts.init(chartRef.current);
        const props = ['密度', '熔体质量流动速率', '拉伸屈服应力', '弯曲模量', '悬臂梁缺口冲击强度'];
        const values = props.map(p => {
            const v = product.properties?.[p]?.value;
            return typeof v === 'number' ? v : parseFloat(String(v)) || 0;
        });

        myChart.setOption({
            radar: {
                indicator: props.map(p => ({ name: tProp(p).slice(0,6), max: 100 })), 
                shape: 'circle', splitNumber: 3, axisName: { fontSize: 8, color: '#94a3b8' }
            },
            series: [{ type: 'radar', data: [{ value: values, areaStyle: { color: 'rgba(99, 102, 241, 0.3)' }, lineStyle: { color: '#6366f1' } }], symbol: 'none' }]
        });
        return () => myChart.dispose();
    }, [product, tProp]);

    const rect = anchorRef.current?.getBoundingClientRect();
    if (!rect) return null;

    return (
        <div className="fixed z-[100] w-48 h-48 bg-white dark:bg-slate-900 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-800 p-2 animate-in fade-in zoom-in-95 pointer-events-none" 
             style={{ left: rect.left + 40, top: rect.top - 60 }}>
            <div ref={chartRef} className="w-full h-full" />
        </div>
    );
};

/**
 * Robust Safe Rendering Utility
 * Handles all primitive types, potential NaNs, and provides standardized fallback UI
 */
const renderCellContent = (val: any, unit?: string): React.ReactNode => {
    if (val === null || val === undefined || val === '') {
        return <span className="text-slate-300 dark:text-slate-700 font-mono">-</span>;
    }

    if (typeof val === 'number') {
        if (isNaN(val)) return <span className="text-slate-300 dark:text-slate-700 font-mono">-</span>;
        return (
            <div className="flex items-baseline gap-1">
                <span className="font-mono font-bold text-primary-600 dark:text-primary-400 tracking-tight">{val}</span>
                {unit && <span className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">{unit}</span>}
            </div>
        );
    }

    // Handle string or unexpected object/array by forcing string conversion
    const displayStr = typeof val === 'object' ? JSON.stringify(val) : String(val);
    return <span className="text-slate-700 dark:text-slate-300 font-medium truncate max-w-[200px]" title={displayStr}>{displayStr}</span>;
};

export const DataGrid: React.FC<DataGridProps> = ({ 
    data = [], 
    columns = [], 
    isLoading, 
    onDelete, 
    onUpdate, 
    onBatchUpdate, 
    onCategorySelect, 
    selectedIds = new Set(), 
    onSelectionChange 
}) => {
  const { t, tProp } = useLanguage();
  const visibleColumns = useMemo(() => (columns || []).filter((c) => c.visible), [columns]);
  const [sortConfig, setSortConfig] = useState<SortConfig | null>(null);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [deletingIds, setDeletingIds] = useState<string[]>([]);
  const [viewingProduct, setViewingProduct] = useState<Product | null>(null);
  const [hoveredProduct, setHoveredProduct] = useState<Product | null>(null);
  const radarAnchorRef = useRef<HTMLDivElement>(null);

  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 15;

  const sortedData = useMemo(() => {
    if (!data) return [];
    if (!sortConfig) return data;
    return [...data].sort((a, b) => {
      const aProp = a.properties?.[sortConfig.key];
      const bProp = b.properties?.[sortConfig.key];

      let aV = aProp?.value ?? (a as any)[sortConfig.key] ?? '';
      let bV = bProp?.value ?? (b as any)[sortConfig.key] ?? '';

      const aN = parseFloat(String(aV)), bN = parseFloat(String(bV));
      if (!isNaN(aN) && !isNaN(bN)) return sortConfig.direction === 'asc' ? aN - bN : bN - aN;
      return sortConfig.direction === 'asc' 
        ? String(aV).localeCompare(String(bV)) 
        : String(bV).localeCompare(String(aV));
    });
  }, [data, sortConfig]);

  const paginatedData = useMemo(() => {
    const start = (currentPage - 1) * pageSize;
    return sortedData.slice(start, start + pageSize);
  }, [sortedData, currentPage]);

  const totalPages = Math.ceil(sortedData.length / pageSize);

  // Reset page when data changes significantly
  useEffect(() => {
    if (currentPage > totalPages && totalPages > 0) {
        setCurrentPage(totalPages);
    }
  }, [totalPages, currentPage]);

  const toggleSelection = (id: string) => {
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id); else next.add(id);
    onSelectionChange(next);
  };

  const toggleAllSelection = () => {
    if (selectedIds.size === paginatedData.length && paginatedData.length > 0) {
        onSelectionChange(new Set());
    } else {
        onSelectionChange(new Set(paginatedData.map(p => p.id)));
    }
  };

  if (isLoading) {
    return <GridSkeleton rows={10} cols={visibleColumns.length || 5} />;
  }

  if (!isLoading && data.length === 0) {
      return (
          <div className="h-full flex flex-col items-center justify-center p-12 text-center bg-slate-50/50 dark:bg-slate-900/30 rounded-[3rem] border border-dashed border-slate-200 dark:border-slate-800">
              <div className="w-20 h-20 bg-white dark:bg-slate-800 rounded-full flex items-center justify-center shadow-glass mb-6">
                  <SearchX size={32} className="text-slate-300 dark:text-slate-600" />
              </div>
              <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100 mb-2">未找到匹配结果</h3>
              <p className="text-sm text-slate-500 max-w-xs mx-auto">尝试调整您的过滤条件或搜索关键词以获取更多结果。</p>
          </div>
      );
  }

  return (
    <div className="h-full flex flex-col relative overflow-hidden group/grid">
      <div className="flex-1 overflow-auto custom-scrollbar">
        <table className="w-full text-sm text-left border-separate border-spacing-0">
          <thead className="sticky top-0 z-30 bg-white/90 dark:bg-slate-950/90 backdrop-blur-xl">
            <tr>
              <th className="px-4 py-4 w-12 border-b border-slate-100 dark:border-slate-800">
                <button onClick={toggleAllSelection} className="text-slate-400 hover:text-primary-500 transition-colors">
                    {selectedIds.size > 0 && selectedIds.size === paginatedData.length 
                        ? <CheckSquare size={18} className="text-primary-500" /> 
                        : <Square size={18} />}
                </button>
              </th>
              {visibleColumns.map((col) => (
                <th key={col.key} 
                    className="px-4 py-4 font-black text-[10px] text-slate-400 uppercase tracking-[0.15em] border-b border-slate-100 dark:border-slate-800 cursor-pointer hover:text-primary-600 transition-colors group/head" 
                    onClick={() => setSortConfig({ key: col.key, direction: sortConfig?.key === col.key && sortConfig.direction === 'asc' ? 'desc' : 'asc' })}>
                  <div className="flex items-center gap-1.5">
                    {tProp(col.label)}
                    <span className={`transition-all duration-300 ${sortConfig?.key === col.key ? 'opacity-100 scale-100' : 'opacity-0 scale-75 group-hover/head:opacity-40'}`}>
                        {sortConfig?.key === col.key && sortConfig.direction === 'desc' ? <ArrowDown size={12} /> : <ArrowUp size={12} />}
                    </span>
                  </div>
                </th>
              ))}
              <th className="px-4 py-4 border-b border-slate-100 dark:border-slate-800 text-right w-24 font-black text-[10px] text-slate-400 uppercase tracking-widest">操作</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50 dark:divide-slate-900">
            {paginatedData.map((p) => (
                <tr key={p.id} 
                    className={`group transition-all duration-200 cursor-pointer ${selectedIds.has(p.id) ? 'bg-primary-50/40 dark:bg-primary-950/20' : 'hover:bg-slate-50/50 dark:hover:bg-slate-900/40'}`} 
                    onClick={() => toggleSelection(p.id)}>
                    <td className="px-4 py-3.5" onClick={e => e.stopPropagation()}>
                        <button onClick={() => toggleSelection(p.id)} className={`transition-colors ${selectedIds.has(p.id) ? "text-primary-500" : "text-slate-300 group-hover:text-slate-400"}`}>
                            {selectedIds.has(p.id) ? <CheckSquare size={16} /> : <Square size={16} />}
                        </button>
                    </td>
                    {visibleColumns.map((col) => (
                        <td key={col.key} className="px-4 py-3.5 whitespace-nowrap">
                            {col.key === 'gradeName' ? (
                                <div className="flex items-center gap-2">
                                    <span className="font-bold text-slate-800 dark:text-white group-hover:text-primary-600 dark:group-hover:text-primary-400 transition-colors">{p.gradeName}</span>
                                    <div 
                                        onMouseEnter={(e) => { e.stopPropagation(); setHoveredProduct(p); }} 
                                        onMouseLeave={() => setHoveredProduct(null)} 
                                        className="cursor-help text-indigo-500 opacity-0 group-hover:opacity-100 transition-all scale-75 group-hover:scale-100"
                                    >
                                        <Radar size={14} />
                                    </div>
                                </div>
                            ) : col.key === 'manufacturer' ? (
                                <div className="flex items-center gap-1.5">
                                    <Factory size={12} className="text-slate-300 dark:text-slate-600" />
                                    <span className="text-slate-500 dark:text-slate-400 font-medium text-xs">{p.manufacturer}</span>
                                </div>
                            ) : (
                                renderCellContent(p.properties?.[col.key]?.value, p.properties?.[col.key]?.unit)
                            )}
                        </td>
                    ))}
                    <td className="px-4 py-3.5 text-right" onClick={e => e.stopPropagation()}>
                        <div className="flex items-center justify-end gap-1 opacity-0 group-hover:opacity-100 transition-all translate-x-2 group-hover:translate-x-0">
                            <button onClick={() => setViewingProduct(p)} 
                                    className="p-1.5 text-slate-400 hover:text-primary-500 hover:bg-primary-50 dark:hover:bg-primary-900/30 rounded-lg transition-all"
                                    title={t('details')}>
                                <Eye size={14} />
                            </button>
                            <button onClick={() => setEditingProduct(p)} 
                                    className="p-1.5 text-slate-400 hover:text-amber-500 hover:bg-amber-50 dark:hover:bg-amber-900/30 rounded-lg transition-all"
                                    title={t('editProduct')}>
                                <Edit size={14} />
                            </button>
                        </div>
                    </td>
                </tr>
            ))}
          </tbody>
        </table>
      </div>

      {hoveredProduct && <QuickRadarPopup product={hoveredProduct} anchorRef={radarAnchorRef} />}
      <div ref={radarAnchorRef} className="hidden" />

      {/* Pagination Footer */}
      <div className="flex items-center justify-between px-6 py-4 bg-white/80 dark:bg-slate-950/80 border-t border-slate-100 dark:border-slate-800 backdrop-blur-xl z-20">
         <div className="flex items-center gap-4">
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                {t('showing')} <span className="text-slate-700 dark:text-slate-200">{paginatedData.length}</span> / <span className="text-slate-700 dark:text-slate-200">{sortedData.length}</span>
            </span>
            {selectedIds.size > 0 && (
                <div className="h-4 w-px bg-slate-200 dark:bg-slate-800" />
            )}
            {selectedIds.size > 0 && (
                <span className="text-[10px] font-black text-primary-500 uppercase tracking-widest animate-in fade-in slide-in-from-left-2">
                    {selectedIds.size} {t('selected')}
                </span>
            )}
         </div>
         <div className="flex items-center gap-4">
             <div className="flex items-center gap-1">
                <button 
                    onClick={() => setCurrentPage(p => Math.max(1, p - 1))} 
                    disabled={currentPage === 1} 
                    className="p-2 border border-slate-200 dark:border-slate-800 rounded-xl disabled:opacity-20 hover:bg-slate-50 dark:hover:bg-slate-900 text-slate-500 transition-all active:scale-95"
                >
                    <ChevronLeft size={16} />
                </button>
                <div className="px-4 flex items-center gap-2">
                    <span className="text-xs font-black tabular-nums text-slate-700 dark:text-slate-200">{currentPage}</span>
                    <span className="text-[10px] font-bold text-slate-300 dark:text-slate-700">/</span>
                    <span className="text-xs font-bold text-slate-400 tabular-nums">{totalPages || 1}</span>
                </div>
                <button 
                    onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} 
                    disabled={currentPage === totalPages || totalPages === 0} 
                    className="p-2 border border-slate-200 dark:border-slate-800 rounded-xl disabled:opacity-20 hover:bg-slate-50 dark:hover:bg-slate-900 text-slate-500 transition-all active:scale-95"
                >
                    <ChevronRight size={16} />
                </button>
             </div>
         </div>
      </div>

      {/* Modals & Overlays */}
      <EditProductModal 
        isOpen={!!editingProduct} 
        onClose={() => setEditingProduct(null)} 
        product={editingProduct} 
