        </div>

        {/* Global Selection Tray */}
        {selectedIds.size > 0 && (
            <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[80] animate-in slide-in-from-bottom-10 duration-500 pointer-events-none">
                <div className="pointer-events-auto bg-slate-900/90 dark:bg-white/90 backdrop-blur-2xl px-6 py-4 rounded-[2.5rem] border border-white/10 dark:border-slate-200 shadow-2xl flex items-center gap-6">
                    <div className="flex items-center gap-3 pr-6 border-r border-white/10 dark:border-slate-200">
