const FormattedText: React.FC<{ text: string; onGradeClick?: (name: string) => void; className?: string }> = ({ text, onGradeClick, className }) => {
  if (!text) return null;
  return (
    <div className={className}>
      {text.split('\n').map((line, i) => {
        const trimmed = line.trim();
        if (trimmed.startsWith('- ') || trimmed.startsWith('* ') || trimmed.match(/^\d+\./)) {
             const cleanLine = trimmed.replace(/^[-*]\s+|\d+\.\s+/, '');
             // Highlight potential grade names (simplified regex for mock)
             const parts = cleanLine.split(/(\*\*.*?\*\*)/g);
             return (
                <div key={i} className="flex gap-2.5 ml-1 mb-1.5 items-start">
                    <span className="text-emerald-500 dark:text-emerald-400 mt-1.5 shrink-0 text-[10px]">•</span>
                    <span className="leading-relaxed text-sm">
                        {parts.map((part, j) => {
                            if (part.startsWith('**') && part.endsWith('**')) {
                                const val = part.slice(2, -2);
                                return (
                                    <strong 
                                        key={j} 
                                        onClick={() => onGradeClick?.(val)}
                                        className="font-bold text-slate-800 dark:text-white hover:text-emerald-600 dark:hover:text-emerald-400 cursor-pointer decoration-dotted underline-offset-4 decoration-emerald-500/30 hover:decoration-emerald-500"
                                    >
                                        {val}
                                    </strong>
                                );
                            }
                            return <span key={j}>{part}</span>;
                        })}
                    </span>
                </div>
             );
        }
        if (line.startsWith('##')) return <h3 key={i} className="font-bold text-emerald-700 dark:text-emerald-400 mt-5 mb-2 text-base border-l-2 border-emerald-500 pl-3">{line.replace(/#/g, '')}</h3>
        if (!trimmed) return <div key={i} className="h-3"></div>;
        const parts = line.split(/(\*\*.*?\*\*)/g);
        return (
          <p key={i} className="mb-2 last:mb-0 leading-relaxed text-sm">
            {parts.map((part, j) => {
                if (part.startsWith('**') && part.endsWith('**')) {
                    const val = part.slice(2, -2);
                    return <strong key={j} onClick={() => onGradeClick?.(val)} className="font-bold text-slate-800 dark:text-white hover:underline cursor-pointer">{val}</strong>;
                }
                return <span key={j}>{part}</span>;
            })}
          </p>
        );
      })}
    </div>
  );
};

export const AIAssistant: React.FC<AIAssistantProps> = ({ contextData, inlineView = false, onGradeClick }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [input, setInput] = useState('');
  const { t } = useLanguage();
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [useThinking, setUseThinking] = useState(false);
  const [attachedImage, setAttachedImage] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (messages.length === 0) setMessages([{ id: 'welcome', role: 'model', text: t('welcomeMessage') }]);
  }, [t]);

  useEffect(() => {
    if (messagesEndRef.current) messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  const handleSendMessage = async (customInput?: string) => {
    const textToSend = customInput || input;
    if ((!textToSend.trim() && !attachedImage) || isLoading) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: textToSend, image: attachedImage || undefined };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setAttachedImage(null);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const parts: any[] = [];
      let systemInstruction = "You are ResinAI Expert. A senior petrochemical engineer and data analyst at PetroChina Research Institute. Your goal is to provide precise, data-driven answers using Markdown. When mentioning specific grade names, always wrap them in **double asterisks** so the user can interact with them.";

      if (userMsg.image) {
         const base64Data = userMsg.image.split(',')[1];
         const mimeType = userMsg.image.split(';')[0].split(':')[1] || 'image/jpeg';
         parts.push({ inlineData: { mimeType, data: base64Data } });
         systemInstruction += "\nFocus on QC analysis, detecting defects like gels or specks, and assessing sample quality.";
         parts.push({ text: userMsg.text || "Perform visual quality inspection." });
      } else {
         parts.push({ text: userMsg.text });
         if (contextData.length > 0) {
            const contextStr = JSON.stringify(contextData.slice(0, 15).map(p => ({ 
                grade: p.gradeName, 
                mfr: p.properties['熔体质量流动速率']?.value, 
                density: p.properties['密度']?.value,
                modulus: p.properties['弯曲模量']?.value,
                impact: p.properties['悬臂梁缺口冲击强度']?.value,
                apps: p.properties['典型应用']?.value
            })));
            parts.push({ text: `\n[Experimental Data Context (Top 15)]: ${contextStr}` });
         }
      }

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: parts }],
        config: { 
            systemInstruction, 
            thinkingConfig: useThinking ? { thinkingBudget: 2048 } : undefined 
        }
      });

      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: response.text || "Report generated but no text content was returned." }]);
    } catch (error) {
      console.error("AI Analysis Error:", error);
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: "⚠️ **系统链接异常**：ResinAI 无法访问石化院核心计算集群。请检查 API 配置或网络隔离状态。" }]);
    } finally {
      setIsLoading(false);
    }
  };

  const renderInput = () => (
    <div className="max-w-4xl mx-auto w-full">
      {attachedImage && (
        <div className="flex items-center justify-between px-4 py-3 mb-3 bg-emerald-50 dark:bg-emerald-900/10 border border-emerald-100 dark:border-emerald-800 rounded-2xl shadow-inner animate-in slide-in-from-bottom-1">
          <div className="flex items-center gap-3 overflow-hidden">
            <img src={attachedImage} alt="" className="w-10 h-10 rounded-lg object-cover border border-white shadow-sm" />
            <div className="flex flex-col">
                <span className="text-[10px] text-emerald-600 dark:text-emerald-400 font-black uppercase flex items-center gap-1.5"><ShieldCheck size={12} /> QC Protocol Active</span>
                <span className="text-[9px] text-slate-400 font-bold">Image ready for scanning...</span>
            </div>
          </div>
          <button onClick={() => setAttachedImage(null)} className="p-1.5 text-slate-400 hover:text-rose-500 transition-colors"><Trash2 size={16} /></button>
        </div>
      )}
      <div className="flex items-end gap-2 bg-slate-100 dark:bg-slate-800/50 p-2 rounded-[1.8rem] border border-slate-200 dark:border-slate-700 focus-within:border-emerald-500/50 focus-within:ring-4 focus-within:ring-emerald-500/5 transition-all shadow-inner">
        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={(e) => { 
            const f = e.target.files?.[0]; 
            if(f){ const r = new FileReader(); r.onloadend = () => setAttachedImage(r.result as string); r.readAsDataURL(f); } 
        }} />
        <button 
            onClick={() => fileInputRef.current?.click()} 
            className={`p-3 rounded-2xl transition-all ${attachedImage ? 'text-emerald-600 bg-emerald-100 dark:bg-emerald-900/30' : 'text-slate-400 hover:text-slate-600 hover:bg-slate-200 dark:hover:bg-slate-800'}`}
            title="Attach Experimental Sample"
        >
            <ImageIcon size={22} />
        </button>
        <textarea
          value={input} onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => { if(e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSendMessage(); }}}
          placeholder={attachedImage ? "描述此样本的分析重点..." : t('aiPlaceholder')}
          className="w-full max-h-48 min-h-[44px] py-3 bg-transparent text-sm text-slate-800 dark:text-slate-200 outline-none resize-none leading-relaxed"
          rows={1}
        />
        <div className="flex items-center gap-2 self-center">
            <button 
                onClick={() => setUseThinking(!useThinking)}
                className={`p-3 rounded-2xl transition-all ${useThinking ? 'text-primary-600 bg-primary-100 dark:bg-primary-900/30 ring-2 ring-primary-500/20' : 'text-slate-400 hover:text-slate-600 hover:bg-slate-200 dark:hover:bg-slate-800'}`}
                title="Cognitive Reasoning Mode"
            >
                <BrainCircuit size={22} />
            </button>
            <button 
                onClick={() => handleSendMessage()} 
                disabled={isLoading || (!input.trim() && !attachedImage)} 
                className="p-3 bg-slate-900 dark:bg-emerald-600 hover:scale-105 disabled:opacity-30 disabled:scale-100 text-white rounded-2xl shadow-xl transition-all active:scale-95 flex items-center justify-center shrink-0"
            >
                {isLoading ? <Loader2 size={22} className="animate-spin" /> : <Send size={22} />}
            </button>
        </div>
      </div>
      <p className="mt-3 text-center text-[9px] text-slate-400 font-bold uppercase tracking-wider">
        AI 生成的科研建议仅供参考，生产决策请以标准 TDS 指标为准。
      </p>
    </div>
  );

  if (inlineView) {
    return (
      <div className="flex flex-col h-full w-full bg-slate-50/50 dark:bg-transparent">
        <div className="flex-1 overflow-y-auto p-6 space-y-8 custom-scrollbar" ref={chatContainerRef}>
          <div className="max-w-4xl mx-auto space-y-8">
            {messages.map((msg) => (
                <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}>
                    <div className={`flex gap-4 max-w-[90%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                        <div className={`w-10 h-10 rounded-2xl flex items-center justify-center shrink-0 shadow-sm ${msg.role === 'user' ? 'bg-white dark:bg-slate-800 border' : 'bg-emerald-600 text-white shadow-lg shadow-emerald-500/20'}`}>
                            {msg.role === 'user' ? <User size={18} className="text-slate-400" /> : <Bot size={18} />}
                        </div>
                        <div className={`rounded-[2rem] px-6 py-4 text-sm shadow-glass leading-relaxed ${msg.role === 'user' ? 'bg-slate-900 text-white rounded-tr-sm' : 'bg-white dark:bg-slate-850 border border-slate-100 dark:border-slate-800 rounded-tl-sm text-slate-700 dark:text-slate-200'}`}>
                            {msg.image && <img src={msg.image} className="max-w-full h-auto max-h-96 rounded-2xl mb-5 shadow-2xl border border-white/50" />}
                            <FormattedText text={msg.text} onGradeClick={onGradeClick} />
                        </div>
                    </div>
                </div>
            ))}
            {isLoading && (
                <div className="flex justify-start">
