  const handleToggleColumn = (key: string) => { setColumns(cols => cols.map(c => c.key === key ? { ...c, visible: !c.visible } : c)); };
  const handleExport = async () => { setIsExporting(true); await new Promise(r => setTimeout(r, 800)); addToast('success', '分析报告已生成并发送至邮箱'); setIsExporting(false); };
  const handleDelete = (ids: string[]) => { setAllProducts(prev => prev.filter(p => !ids.includes(p.id))); setSelectedIds(new Set()); addToast('success', `已同步删除 ${ids.length} 条记录`); };
  const handleImportData = () => { setIsImportOpen(false); addToast('success', 'TDS 数据解析入库成功'); };

  // AI Assistant Grade Click Bridge
  const handleAIGradeClick = (gradeName: string) => {
      const p = allProducts.find(prod => prod.gradeName.toLowerCase() === gradeName.toLowerCase());
      if (p) setViewingProduct(p);
      else addToast('info', `未能在当前库中定位牌号: ${gradeName}`);
  };

  if (!currentUser) return <AuthScreen onLogin={handleLogin} />;

  return (
    <div className="flex h-screen bg-slate-50 dark:bg-slate-950 font-sans text-slate-900 dark:text-slate-100 overflow-hidden transition-colors duration-300">
      <ToastContainer toasts={toasts} removeToast={(id) => setToasts(prev => prev.filter(t => t.id !== id))} />

      {/* Primary Sidebar Dock */}
      <nav className="w-16 md:w-20 bg-slate-900 dark:bg-slate-950 flex flex-col items-center py-6 gap-6 z-50 shrink-0 border-r border-white/5">
         <div className="w-12 h-12 bg-emerald-600 rounded-2xl flex items-center justify-center shadow-lg shadow-emerald-900/40 mb-2 overflow-hidden relative group cursor-pointer" onClick={() => setActiveView('dashboard')}>
            <Beaker size={24} className="text-white group-hover:rotate-12 transition-transform" />
            <div className="absolute inset-0 bg-white/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
         </div>

         <div className="flex-1 flex flex-col gap-6">
            {[
                { id: 'dashboard', icon: LayoutDashboard, label: '数据仓库' },
                { id: 'analytics', icon: PieChart, label: '趋势分析' },
                { id: 'ai', icon: Bot, label: 'AI 分析空间' }
            ].map((btn) => (
                <button 
                    key={btn.id}
                    onClick={() => setActiveView(btn.id as AppView)}
                    className={`w-12 h-12 rounded-2xl transition-all duration-300 relative group flex items-center justify-center ${activeView === btn.id ? 'bg-primary-600 text-white shadow-lg shadow-primary-500/20 scale-105' : 'text-slate-500 hover:text-emerald-400 hover:bg-slate-800'}`}
                    title={btn.label}
                >
                    <btn.icon size={22} />
                    {activeView === btn.id && <div className="absolute -left-3 top-1/2 -translate-y-1/2 w-1.5 h-8 bg-primary-400 rounded-r-full shadow-glow"></div>}
                </button>
            ))}
         </div>

         <div className="flex flex-col gap-4 mb-2">
            <button onClick={() => setIsAdminOpen(true)} className="w-12 h-12 flex items-center justify-center text-slate-500 hover:text-emerald-400 hover:bg-slate-800 rounded-2xl transition-all"><ShieldCheck size={22} /></button>
         </div>
      </nav>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col min-w-0 h-full relative">
        <TopBar 
            user={currentUser}
            onLogout={handleLogout}
            onOpenProfile={() => setIsProfileOpen(true)}
