                    <div className="w-px h-3 bg-slate-200 dark:bg-slate-800"></div>
                    <div className="flex items-center gap-2">平均 密度: <span className="text-teal-500">{stats.avgDensity}</span></div>
                </div>
            </div>
        )}

        {/* Advanced Filter Hub */}
        {showFilters && (
            <div className="px-6 pb-4 animate-in slide-in-from-top-2 duration-300">
