                                <input type="text" placeholder="Min" value={numericFilters[prop]?.min || ''} onChange={(e) => setNumericFilters({...numericFilters, [prop]: { min: e.target.value, max: numericFilters[prop]?.max || '' }})} className="w-12 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-md text-[10px] py-1 text-center outline-none focus:border-primary-500" />
                                <span className="text-slate-300">—</span>
                                <input type="text" placeholder="Max" value={numericFilters[prop]?.max || ''} onChange={(e) => setNumericFilters({...numericFilters, [prop]: { min: numericFilters[prop]?.min || '', max: e.target.value }})} className="w-12 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-md text-[10px] py-1 text-center outline-none focus:border-primary-500" />
                            </div>
                        </div>
                    ))}
                    <button onClick={() => setNumericFilters({})} className="text-[10px] font-bold text-slate-400 hover:text-rose-500 transition-colors ml-auto uppercase tracking-tighter">重置</button>
