                                    </div>
                                    <div className="flex items-center gap-2">
                                        <button onClick={handleExport} className="flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-800 rounded-xl text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 transition-all shadow-sm">
                                            <Download size={14} /> {t('lab_report_btn')}
                                        </button>
                                    </div>
                                </div>
                                <div className="flex-1 relative bg-slate-50/30 dark:bg-transparent overflow-hidden">
                                    <AIAssistant contextData={filteredData} inlineView={true} onGradeClick={handleAIGradeClick} />
                                </div>
                            </div>

                            <div className="w-full lg:w-[380px] bg-white/40 dark:bg-slate-900/40 backdrop-blur-xl rounded-[2.5rem] border border-slate-200 dark:border-slate-800 overflow-hidden shadow-xl flex flex-col shrink-0">
                                <div className="p-5 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-white/20">
                                    <div className="flex items-center gap-3">
                                        <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 rounded-xl"><Database size={18} /></div>
                                        <h2 className="text-xs font-black uppercase tracking-widest text-slate-600 dark:text-slate-300">{t('lab_context')}</h2>
                                    </div>
                                    <span className="text-[10px] font-bold text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-full">{filteredData.length} Samples</span>
                                </div>

                                <div className="flex-1 overflow-y-auto p-4 custom-scrollbar space-y-3">
                                    <p className="text-[10px] text-slate-400 font-bold uppercase px-1 mb-2 tracking-tighter opacity-60">实时同步过滤结果</p>
                                    {filteredData.slice(0, 15).map(p => (
                                        <div key={p.id} onClick={() => setViewingProduct(p)} className="p-3 bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl hover:border-indigo-400 hover:shadow-md transition-all group cursor-pointer">
                                            <div className="flex justify-between items-start mb-2">
                                                <span className="text-xs font-bold text-slate-800 dark:text-white truncate pr-2 group-hover:text-primary-600 transition-colors">{p.gradeName}</span>
                                                <ChevronRight size={12} className="text-slate-300 group-hover:text-primary-400 group-hover:translate-x-0.5 transition-all" />
                                            </div>
                                            <div className="flex flex-wrap gap-1">
                                                <span className="text-[9px] px-1.5 py-0.5 bg-slate-50 dark:bg-slate-900 rounded border border-slate-100 dark:border-slate-800 text-slate-500 font-mono">MFR: {p.properties['熔体质量流动速率']?.value || '-'}</span>
                                                <span className="text-[9px] px-1.5 py-0.5 bg-slate-50 dark:bg-slate-900 rounded border border-slate-100 dark:border-slate-800 text-slate-500 font-mono">Den: {p.properties['密度']?.value || '-'}</span>
                                            </div>
                                        </div>
                                    ))}
                                    {filteredData.length > 15 && <div className="py-4 text-center"><span className="text-[10px] font-bold text-slate-400 italic">... 及另外 {filteredData.length - 15} 条记录</span></div>}
                                </div>

                                <div className="p-4 bg-slate-50/50 dark:bg-slate-950/50 border-t border-slate-100 dark:border-slate-800">
                                    <div className="flex items-center gap-2 mb-3">
                                        <BrainCircuit size={14} className="text-indigo-500" />
                                        <span className="text-[10px] font-black uppercase text-slate-500">{t('lab_suggestions')}</span>
                                    </div>
                                    <div className="grid grid-cols-2 gap-2">
                                        <div className="p-2 bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-xl flex flex-col gap-1">
                                            <span className="text-[9px] font-bold text-slate-400">Context Window</span>
                                            <span className="text-xs font-black text-slate-700 dark:text-slate-200">128k Tokens</span>
                                        </div>
                                        <div className="p-2 bg-emerald-50 dark:bg-emerald-900/10 border border-emerald-100 dark:border-emerald-800/20 rounded-xl flex flex-col gap-1">
                                            <span className="text-[9px] font-bold text-emerald-600">Model Rank</span>
                                            <span className="text-xs font-black text-emerald-700">Scientific-SOTA</span>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>

        {/* Selection Tray */}
        {selectedIds.size > 0 && (
            <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[80] animate-in slide-in-from-bottom-10 duration-500 pointer-events-none">
                <div className="pointer-events-auto bg-slate-900/90 dark:bg-white/90 backdrop-blur-2xl px-6 py-4 rounded-[2.5rem] border border-white/10 dark:border-slate-200 shadow-2xl flex items-center gap-6">
                    <div className="flex items-center gap-3 pr-6 border-r border-white/10 dark:border-slate-200">
                        <div className="w-10 h-10 bg-primary-600 rounded-full flex items-center justify-center text-white font-black text-sm shadow-glow">{selectedIds.size}</div>
                        <div>
                            <p className="text-xs font-black text-white dark:text-slate-900 uppercase tracking-widest">{t('selected')}</p>
                            <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase">{t('recordsProcessed')}</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <button className="flex flex-col items-center gap-1 group">
                            <div className="p-3 bg-white/5 dark:bg-slate-100 rounded-2xl text-white dark:text-slate-700 hover:bg-primary-600 hover:text-white transition-all group-hover:scale-110 active:scale-95"><GitCompare size={20} /></div>
                            <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase">对比</span>
                        </button>
                        <button onClick={handleExport} className="flex flex-col items-center gap-1 group">
                            <div className="p-3 bg-white/5 dark:bg-slate-100 rounded-2xl text-white dark:text-slate-700 hover:bg-primary-600 hover:text-white transition-all group-hover:scale-110 active:scale-95"><Download size={20} /></div>
                            <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase">分析报告</span>
                        </button>
                        <button onClick={() => handleDelete(Array.from(selectedIds))} className="flex flex-col items-center gap-1 group">
                            <div className="p-3 bg-rose-500/10 rounded-2xl text-rose-500 hover:bg-rose-500 hover:text-white transition-all group-hover:scale-110 active:scale-95"><Trash2 size={20} /></div>
                            <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase">移除</span>
                        </button>
                        <button onClick={() => setSelectedIds(new Set())} className="ml-4 p-2 text-slate-500 hover:text-white dark:hover:text-slate-900"><X size={20} /></button>
                    </div>
                </div>
            </div>
        )}
      </div>

      <ImportModal isOpen={isImportOpen} onClose={() => setIsImportOpen(false)} onImport={handleImportData} />
      <ProfileModal isOpen={isProfileOpen} onClose={() => setIsProfileOpen(false)} user={currentUser} onSave={(u) => setCurrentUser({...currentUser, ...u})} />
      <AdminModal isOpen={isAdminOpen} onClose={() => setIsAdminOpen(false)} />
      <ProductDetailDrawer product={viewingProduct} onClose={() => setViewingProduct(null)} onCategoryClick={setSelectedCategoryId} />

      {activeView !== 'ai' && <AIAssistant contextData={filteredData} onGradeClick={handleAIGradeClick} />}
    </div>
  );
};

const App: React.FC = () => (
    <LanguageProvider><ThemeProvider><AppContent /></ThemeProvider></LanguageProvider>
);

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Search, SlidersHorizontal, Upload, LayoutGrid, BarChart2, Moon, Sun, Globe, User, LogOut, Settings, Shield, History, X, Trash2, Clock, Command, Download, Loader2, Maximize, Minimize, ArrowRight, Filter, ChevronDown, Sparkles, Hash, Zap, Beaker, Info, BookOpen } from 'lucide-react';
import { ColumnConfig, ViewMode, User as UserType } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import { useTheme } from '../contexts/ThemeContext';

interface TopBarProps {
  user: UserType | null;
  onLogout: () => void;
  onOpenProfile: () => void;
  onOpenAdmin: () => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  isSearching?: boolean;
  columns: ColumnConfig[];
  onToggleColumn: (key: string) => void;
  onToggleAllColumns: (visible: boolean) => void;
  onOpenImport: () => void;
  onExport: () => void;
  isExporting: boolean;
  viewMode: ViewMode;
  onViewModeChange: (mode: ViewMode) => void;
  showAdvancedFilters: boolean;
  onToggleFilters: () => void;
  activeFilterCount: number;
}

export const TopBar: React.FC<TopBarProps> = ({
  user, onLogout, onOpenProfile, onOpenAdmin, searchQuery, onSearchChange, isSearching, columns, onToggleColumn, onToggleAllColumns, onOpenImport, onExport, isExporting, viewMode, onViewModeChange, showAdvancedFilters, onToggleFilters, activeFilterCount
}) => {
  const [isColumnMenuOpen, setIsColumnMenuOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const { t, language, toggleLanguage, tProp } = useLanguage();
  const { theme, toggleTheme } = useTheme();
  const inputRef = useRef<HTMLInputElement>(null);

  const colMenuRef = useRef<HTMLDivElement>(null);
  const userMenuRef = useRef<HTMLDivElement>(null);

  const [searchHistory, setSearchHistory] = useState<string[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Advanced Filtering Syntax Suggestions
  const filterSuggestions = useMemo(() => {
      const parts = searchQuery.split(' ');
      const lastToken = parts[parts.length - 1];
      if (lastToken.includes(':')) return [];

      const availableProps = columns
          .filter(c => !c.isSystem)
          .map(c => ({
              key: c.key,
              label: tProp(c.label),
              unit: columns.find(col => col.key === c.key)?.label.match(/\[(.*?)\]/)?.[1] || ''
          }));

      if (!lastToken) return availableProps.slice(0, 5);

      return availableProps.filter(p => 
          p.label.toLowerCase().includes(lastToken.toLowerCase()) ||
          p.key.toLowerCase().includes(lastToken.toLowerCase())
      ).slice(0, 5);
  }, [columns, searchQuery, tProp]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); inputRef.current?.focus(); }
    };
    const handleClickOutside = (e: MouseEvent) => {
        if (colMenuRef.current && !colMenuRef.current.contains(e.target as Node)) setIsColumnMenuOpen(false);
        if (userMenuRef.current && !userMenuRef.current.contains(e.target as Node)) setIsUserMenuOpen(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    document.addEventListener('mousedown', handleClickOutside);
    const savedHistory = localStorage.getItem('resindb_search_history');
    if (savedHistory) try { setSearchHistory(JSON.parse(savedHistory)); } catch (e) {}
    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const saveToHistory = (query: string) => {
      const clean = query.trim();
      if (!clean) return;
      setSearchHistory(prev => {
          const filtered = prev.filter(item => item !== clean);
          const updated = [clean, ...filtered].slice(0, 8);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const removeFromHistory = (e: React.MouseEvent, query: string) => {
      e.stopPropagation();
      setSearchHistory(prev => {
          const updated = prev.filter(item => item !== query);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const handleInputKeyDown = (e: React.KeyboardEvent) => {
      const totalItems = searchHistory.length + filterSuggestions.length;
      if (showHistory && totalItems > 0) {
          if (e.key === 'ArrowDown') { 
              e.preventDefault(); 
              setHistoryIndex(prev => (prev + 1) % totalItems); 
              return; 
          }
          if (e.key === 'ArrowUp') { 
              e.preventDefault(); 
              setHistoryIndex(prev => (prev - 1 + totalItems) % totalItems); 
              return; 
          }
      }
      if (e.key === 'Enter') {
          e.preventDefault();
          if (historyIndex >= 0 && showHistory) {
              if (historyIndex < filterSuggestions.length) { 
                  applySuggestion(filterSuggestions[historyIndex].label); 
              } else { 
                  const histItem = searchHistory[historyIndex - filterSuggestions.length];
                  onSearchChange(histItem);
              }
              setHistoryIndex(-1); 
              setShowHistory(false);
          } else { 
              saveToHistory(searchQuery); 
              setShowHistory(false); 
              setHistoryIndex(-1); 
              inputRef.current?.blur(); 
          }
      }
      if (e.key === 'Escape') { 
          setShowHistory(false); 
          setHistoryIndex(-1); 
          inputRef.current?.blur(); 
      }
  };

  const applySuggestion = (label: string) => {
      const parts = searchQuery.split(' ');
      parts[parts.length - 1] = `${label}:`;
      const newQuery = parts.join(' ');
      onSearchChange(newQuery);
      inputRef.current?.focus();
      setHistoryIndex(-1);
  };

  return (
    <div className="w-full flex flex-col gap-2">
      <div className="flex items-center justify-between gap-6">
        {/* Search & Intelligence Integration */}
        <div className="flex-1 max-w-2xl relative z-[60]">
            <div className="relative group transition-all duration-300">
                <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                    {isSearching ? <Loader2 className="text-primary-500 animate-spin" size={18} /> : <Search className="text-slate-400 group-focus-within:text-primary-500 transition-colors" size={18} />}
                </div>
                <input
                    ref={inputRef}
                    type="text"
                    value={searchQuery}
                    onChange={(e) => { onSearchChange(e.target.value); setHistoryIndex(-1); }}
                    onFocus={() => { setShowHistory(true); setHistoryIndex(-1); }}
                    onBlur={() => setTimeout(() => setShowHistory(false), 200)}
                    onKeyDown={handleInputKeyDown}
                    placeholder={t('searchPlaceholder')}
                    className="block w-full pl-12 pr-12 py-3.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl text-sm font-medium shadow-sm outline-none focus:ring-4 focus:ring-primary-500/10 focus:border-primary-500/30 transition-all text-slate-700 dark:text-slate-200 placeholder:text-slate-400"
                />
                <div className="absolute inset-y-0 right-5 flex items-center gap-2">
                    {searchQuery && (
                        <button onClick={() => onSearchChange('')} className="p-1 text-slate-400 hover:text-slate-600 transition-colors"><X size={14} /></button>
                    )}
                    <button 
                        onClick={onToggleFilters}
                        className={`flex items-center gap-1.5 px-2.5 py-1 rounded-lg border transition-all ${showAdvancedFilters ? 'bg-primary-50 border-primary-200 text-primary-600 shadow-inner' : 'bg-slate-50 border-slate-200 text-slate-500 hover:border-slate-300'}`}
                    >
                        <Filter size={14} className={activeFilterCount > 0 ? "fill-primary-500" : ""} />
                        <span className="text-[10px] font-black uppercase tracking-widest">{t('analysis')}</span>
                        {activeFilterCount > 0 && <span className="w-4 h-4 bg-primary-600 text-white rounded-full flex items-center justify-center text-[8px] font-bold">{activeFilterCount}</span>}
                    </button>
                </div>

                {/* History & Smart Suggestions Dropdown */}
                {showHistory && (searchHistory.length > 0 || filterSuggestions.length > 0) && (
                    <div className="absolute top-full left-0 right-0 mt-2 bg-white dark:bg-slate-900 backdrop-blur-xl border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl overflow-hidden z-50 animate-in fade-in slide-in-from-top-2 duration-200">
                        {filterSuggestions.length > 0 && (
                            <div className="py-1">
                                <div className="px-4 py-2 bg-slate-50/50 dark:bg-slate-800/30 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center">
                                    <span className="text-[10px] font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest flex items-center gap-1.5">
                                        <Beaker size={10} /> {t('properties')} 科研语法建议
                                    </span>
                                </div>
                                {filterSuggestions.map((sugg, idx) => {
                                    const isSelected = idx === historyIndex;
                                    return (
                                        <div 
                                            key={`sugg-${sugg.key}`} 
                                            onMouseDown={(e) => { e.preventDefault(); applySuggestion(sugg.label); }} 
                                            className={`w-full flex items-center justify-between px-4 py-2.5 cursor-pointer transition-colors ${isSelected ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-700 dark:text-emerald-300' : 'hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400'}`}
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className="w-6 h-6 rounded bg-emerald-100 dark:bg-emerald-900/40 flex items-center justify-center shrink-0">
                                                    <Hash size={12} className="text-emerald-600 dark:text-emerald-400" />
                                                </div>
                                                <div className="flex flex-col">
                                                    <span className="text-sm font-bold leading-none">{sugg.label}</span>
                                                    <span className="text-[9px] opacity-60 font-mono mt-1">用法: {sugg.label}:>5.0</span>
                                                </div>
                                            </div>
                                            <ArrowRight size={12} className="text-emerald-300" />
                                        </div>
                                    );
                                })}
                            </div>
                        )}

                        {searchHistory.length > 0 && (
                            <div className="py-1 border-t border-slate-100 dark:border-slate-800">
                                <div className="flex items-center justify-between px-4 py-2 bg-slate-50/50 dark:bg-slate-800/30 border-b border-slate-100 dark:border-slate-800">
                                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1.5"><Clock size={10} /> {t('recentSearches')}</span>
                                    <button onMouseDown={(e) => { e.preventDefault(); setSearchHistory([]); localStorage.removeItem('resindb_search_history'); }} className="text-[10px] text-rose-500 hover:underline font-bold uppercase">{t('clearHistory')}</button>
                                </div>
                                {searchHistory.map((query, idx) => {
                                    const actualIdx = idx + filterSuggestions.length;
                                    const isSelected = actualIdx === historyIndex;
                                    return (
                                        <div 
                                            key={`hist-${idx}`} 
                                            onMouseDown={() => { onSearchChange(query); setShowHistory(false); }} 
                                            className={`group/item w-full flex items-center justify-between px-4 py-2.5 cursor-pointer transition-colors ${isSelected ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300' : 'hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400'}`}
                                        >
                                            <div className="flex items-center gap-3">
                                                <History size={14} className="text-slate-400" />
                                                <span className="text-sm font-medium">{query}</span>
                                            </div>
                                            <button 
                                                onMouseDown={(e) => removeFromHistory(e, query)}
                                                className="p-1.5 text-slate-300 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg transition-all opacity-0 group-hover/item:opacity-100"
                                            >
                                                <X size={14} />
                                            </button>
                                        </div>
                                    );
                                })}
                            </div>
                        )}

                        <div className="px-4 py-3 bg-slate-100/50 dark:bg-slate-950/50 border-t border-slate-100 dark:border-slate-800">
                            <div className="flex items-center gap-3">
                                <div className="p-1.5 bg-white dark:bg-slate-800 rounded-lg shadow-sm"><Info size={12} className="text-primary-500" /></div>
                                <div className="text-[10px] text-slate-500 dark:text-slate-400 font-medium leading-relaxed">
                                    按 <kbd className="px-1 bg-white dark:bg-slate-800 border rounded font-mono text-[9px]">Enter</kbd> 提交搜索并保存到历史记录。
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>

        {/* Global Toolbar Actions */}
        <div className="flex items-center gap-1.5 p-1.5 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border border-slate-200 dark:border-slate-800 rounded-[2rem] shadow-glass shrink-0">
            <div className="flex items-center bg-slate-100 dark:bg-slate-800 rounded-2xl p-1 border border-slate-200 dark:border-slate-700">
                <button onClick={() => onViewModeChange('grid')} className={`p-2 rounded-xl transition-all ${viewMode === 'grid' ? 'bg-white dark:bg-slate-700 text-primary-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`} title={t('viewList')}><LayoutGrid size={16} /></button>
                <button onClick={() => onViewModeChange('chart')} className={`p-2 rounded-xl transition-all ${viewMode === 'chart' ? 'bg-white dark:bg-slate-700 text-primary-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`} title={t('viewChart')}><BarChart2 size={16} /></button>
            </div>

            <div className="h-5 w-px bg-slate-200 dark:bg-slate-700 mx-1"></div>

            <button onClick={onOpenImport} className="w-9 h-9 flex items-center justify-center text-slate-500 hover:text-primary-600 hover:bg-primary-50 dark:hover:bg-primary-900/20 rounded-full transition-all" title={t('importData')}><Upload size={18} /></button>
            <button onClick={onExport} disabled={isExporting} className="w-9 h-9 flex items-center justify-center text-slate-500 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-full transition-all disabled:opacity-50" title="Download Report">{isExporting ? <Loader2 size={18} className="animate-spin text-blue-500" /> : <Download size={18} />}</button>

            <div className="relative" ref={colMenuRef}>
                <button onClick={() => setIsColumnMenuOpen(!isColumnMenuOpen)} className={`w-9 h-9 flex items-center justify-center rounded-full transition-all ${isColumnMenuOpen ? 'bg-primary-50 text-primary-600' : 'text-slate-500 hover:text-primary-600 hover:bg-primary-50 dark:hover:bg-primary-900/20'}`} title={t('configureColumns')}><SlidersHorizontal size={18} /></button>
                {isColumnMenuOpen && (
                    <div className="absolute top-full right-0 mt-3 w-64 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl p-3 z-[100] animate-in zoom-in-95 origin-top-right">
                        <div className="flex items-center justify-between mb-3 px-1">
                            <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{t('visibleAttributes')}</h4>
                            <span className="text-[9px] font-bold text-primary-500 bg-primary-50 px-1.5 py-0.5 rounded uppercase">Config</span>
                        </div>
                        <div className="max-h-64 overflow-y-auto custom-scrollbar space-y-0.5">
                            {columns.map(col => (
                                <label key={col.key} className="flex items-center gap-3 px-3 py-1.5 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 cursor-pointer transition-colors group">
                                    <div className={`w-4 h-4 rounded border flex items-center justify-center transition-all ${col.visible ? 'bg-primary-600 border-primary-600' : 'border-slate-300 group-hover:border-primary-400'}`}>
                                        {col.visible && <div className="w-1.5 h-1.5 bg-white rounded-full"></div>}
                                    </div>
                                    <input type="checkbox" checked={col.visible} onChange={() => !col.isSystem && onToggleColumn(col.key)} disabled={col.isSystem} className="hidden" />
                                    <span className={`text-[11px] font-bold ${col.visible ? 'text-slate-800 dark:text-white' : 'text-slate-400'}`}>{tProp(col.label)}</span>
                                </label>
                            ))}
                        </div>
                    </div>
                )}
            </div>

            <div className="flex items-center gap-1 ml-1 pr-1">
                <button onClick={toggleTheme} className="w-9 h-9 flex items-center justify-center text-slate-500 hover:text-amber-500 hover:bg-amber-50 dark:hover:bg-amber-900/20 rounded-full transition-all">{theme === 'dark' ? <Sun size={18} /> : <Moon size={18} />}</button>
                <button onClick={toggleLanguage} className="w-9 h-9 flex items-center justify-center text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded-full transition-all" title="Switch Language"><Globe size={18} /></button>
            </div>

            <div className="h-5 w-px bg-slate-200 dark:bg-slate-700 mx-1"></div>

            <div className="relative" ref={userMenuRef}>
                <button onClick={() => setIsUserMenuOpen(!isUserMenuOpen)} className="flex items-center gap-2 pl-1 pr-3 py-1 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-full transition-all border border-slate-200 dark:border-slate-700">
                    <img src={user?.avatar} alt="" className="w-7 h-7 rounded-full border border-white dark:border-slate-600 shadow-sm object-cover" />
                    <span className="text-[11px] font-black text-slate-700 dark:text-slate-200">{user?.name.split(' ')[0]}</span>
                    <ChevronDown size={12} className={`text-slate-400 transition-transform ${isUserMenuOpen ? 'rotate-180' : ''}`} />
                </button>
                {isUserMenuOpen && (
                    <div className="absolute top-full right-0 mt-3 w-56 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl p-1.5 z-[100] animate-in zoom-in-95 origin-top-right flex flex-col gap-0.5">
                        <button onClick={() => { setIsUserMenuOpen(false); onOpenProfile(); }} className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 text-[11px] font-bold text-slate-700 dark:text-slate-200 transition-colors"><User size={14} className="text-primary-500" /> {t('profile')}</button>
                        <button onClick={() => { setIsUserMenuOpen(false); onOpenAdmin(); }} className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 text-[11px] font-bold text-slate-700 dark:text-slate-200 transition-colors"><Shield size={14} className="text-amber-500" /> {t('adminPanel')}</button>
                        <div className="h-px bg-slate-100 dark:bg-slate-800 my-1"></div>
                        <button onClick={onLogout} className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-rose-50 dark:hover:bg-rose-900/20 text-[11px] font-bold text-rose-600 transition-colors"><LogOut size={14} /> {t('logout')}</button>
                    </div>
                )}
            </div>
        </div>
      </div>

      {/* Dynamic Status Tickers */}
      <div className="flex items-center gap-4 px-2 overflow-hidden whitespace-nowrap">
         <div className="flex items-center gap-1.5">
             <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
             <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{t('systemOnline')}</span>
         </div>
         <span className="text-slate-200 dark:text-slate-800">|</span>
         <div className="flex gap-3">
             {['密度:>0.95', '熔指:5-10', '厂家:燕山'].map(syntax => (
                 <button 
                    key={syntax}
                    onClick={() => onSearchChange(syntax)}
                    className="text-[9px] font-bold text-primary-500 hover:text-primary-600 flex items-center gap-1 transition-colors"
                 >
                    <Zap size={10} className="fill-current" /> {syntax}
                 </button>
             ))}
         </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Search, SlidersHorizontal, Upload, LayoutGrid, BarChart2, Moon, Sun, Globe, User, LogOut, Settings, Shield, History, X, Trash2, Clock, Command, Download, Loader2, ArrowRight, Filter, ChevronDown, Sparkles, Hash, Zap, Beaker, Info } from 'lucide-react';
import { ColumnConfig, ViewMode, User as UserType } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import { useTheme } from '../contexts/ThemeContext';

interface TopBarProps {
  user: UserType | null;
  onLogout: () => void;
  onOpenProfile: () => void;
  onOpenAdmin: () => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  isSearching?: boolean;
  columns: ColumnConfig[];
  onToggleColumn: (key: string) => void;
  onToggleAllColumns: (visible: boolean) => void;
  onOpenImport: () => void;
  onExport: () => void;
  isExporting: boolean;
  viewMode: ViewMode;
  onViewModeChange: (mode: ViewMode) => void;
  showAdvancedFilters: boolean;
  onToggleFilters: () => void;
  activeFilterCount: number;
}

export const TopBar: React.FC<TopBarProps> = ({
  user, onLogout, onOpenProfile, onOpenAdmin, searchQuery, onSearchChange, isSearching, columns, onToggleColumn, onToggleAllColumns, onOpenImport, onExport, isExporting, viewMode, onViewModeChange, showAdvancedFilters, onToggleFilters, activeFilterCount
}) => {
  const [isColumnMenuOpen, setIsColumnMenuOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const { t, language, toggleLanguage, tProp } = useLanguage();
  const { theme, toggleTheme } = useTheme();
  const inputRef = useRef<HTMLInputElement>(null);

  const colMenuRef = useRef<HTMLDivElement>(null);
  const userMenuRef = useRef<HTMLDivElement>(null);

  const [searchHistory, setSearchHistory] = useState<string[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Advanced Filtering Syntax Suggestions
  const filterSuggestions = useMemo(() => {
      const parts = searchQuery.split(' ');
      const lastToken = parts[parts.length - 1];
      if (lastToken.includes(':')) return [];

      const availableProps = columns
          .filter(c => !c.isSystem)
          .map(c => ({
              key: c.key,
              label: tProp(c.label),
              unit: columns.find(col => col.key === c.key)?.label.match(/\[(.*?)\]/)?.[1] || ''
          }));

      if (!lastToken) return availableProps.slice(0, 5);

      return availableProps.filter(p => 
          p.label.toLowerCase().includes(lastToken.toLowerCase()) ||
          p.key.toLowerCase().includes(lastToken.toLowerCase())
      ).slice(0, 5);
  }, [columns, searchQuery, tProp]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); inputRef.current?.focus(); }
    };
    const handleClickOutside = (e: MouseEvent) => {
        if (colMenuRef.current && !colMenuRef.current.contains(e.target as Node)) setIsColumnMenuOpen(false);
        if (userMenuRef.current && !userMenuRef.current.contains(e.target as Node)) setIsUserMenuOpen(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    document.addEventListener('mousedown', handleClickOutside);
    const savedHistory = localStorage.getItem('resindb_search_history');
    if (savedHistory) try { setSearchHistory(JSON.parse(savedHistory)); } catch (e) {}
    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const saveToHistory = (query: string) => {
      const clean = query.trim();
      if (!clean) return;
      setSearchHistory(prev => {
          const filtered = prev.filter(item => item !== clean);
          const updated = [clean, ...filtered].slice(0, 8);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const removeFromHistory = (e: React.MouseEvent, query: string) => {
      e.stopPropagation();
      setSearchHistory(prev => {
          const updated = prev.filter(item => item !== query);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const handleInputKeyDown = (e: React.KeyboardEvent) => {
      const totalItems = searchHistory.length + filterSuggestions.length;
      if (showHistory && totalItems > 0) {
          if (e.key === 'ArrowDown') { 
              e.preventDefault(); 
              setHistoryIndex(prev => (prev + 1) % totalItems); 
              return; 
          }
          if (e.key === 'ArrowUp') { 
              e.preventDefault(); 
              setHistoryIndex(prev => (prev - 1 + totalItems) % totalItems); 
              return; 
          }
      }
      if (e.key === 'Enter') {
          e.preventDefault();
          if (historyIndex >= 0 && showHistory) {
              if (historyIndex < filterSuggestions.length) { 
                  applySuggestion(filterSuggestions[historyIndex].label); 
              } else { 
                  const histItem = searchHistory[historyIndex - filterSuggestions.length];
                  onSearchChange(histItem);
                  saveToHistory(histItem);
              }
              setHistoryIndex(-1); 
              setShowHistory(false);
          } else { 
              saveToHistory(searchQuery); 
              setShowHistory(false); 
              setHistoryIndex(-1); 
              inputRef.current?.blur(); 
          }
      }
      if (e.key === 'Escape') { 
          setShowHistory(false); 
          setHistoryIndex(-1); 
          inputRef.current?.blur(); 
      }
  };

  const applySuggestion = (label: string) => {
      const parts = searchQuery.split(' ');
      parts[parts.length - 1] = `${label}:`;
      const newQuery = parts.join(' ');
      onSearchChange(newQuery);
      inputRef.current?.focus();
      setHistoryIndex(-1);
  };

  return (
    <div className="w-full flex flex-col gap-2 px-2 py-2">
      <div className="flex items-center justify-between gap-6">
        {/* Search & Intelligence Integration */}
        <div className="flex-1 max-w-2xl relative z-[60]">
            <div className="relative group transition-all duration-300">
                <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                    {isSearching ? <Loader2 className="text-primary-500 animate-spin" size={18} /> : <Search className="text-slate-400 group-focus-within:text-primary-500 transition-colors" size={18} />}
                </div>
                <input
                    ref={inputRef}
                    type="text"
                    value={searchQuery}
                    onChange={(e) => { onSearchChange(e.target.value); setHistoryIndex(-1); }}
                    onFocus={() => { setShowHistory(true); setHistoryIndex(-1); }}
                    onBlur={() => setTimeout(() => setShowHistory(false), 200)}
                    onKeyDown={handleInputKeyDown}
                    placeholder={t('searchPlaceholder')}
                    className="block w-full pl-12 pr-12 py-3.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl text-sm font-medium shadow-sm outline-none focus:ring-4 focus:ring-primary-500/10 focus:border-primary-500/30 transition-all text-slate-700 dark:text-slate-200 placeholder:text-slate-400"
                />
                <div className="absolute inset-y-0 right-5 flex items-center gap-2">
                    {searchQuery && (
                        <button onClick={() => onSearchChange('')} className="p-1 text-slate-400 hover:text-slate-600 transition-colors"><X size={14} /></button>
                    )}
                    <button 
                        onClick={onToggleFilters}
                        className={`flex items-center gap-1.5 px-2.5 py-1 rounded-lg border transition-all ${showAdvancedFilters ? 'bg-primary-50 border-primary-200 text-primary-600 shadow-inner' : 'bg-slate-50 border-slate-200 text-slate-500 hover:border-slate-300'}`}
                    >
                        <Filter size={14} className={activeFilterCount > 0 ? "fill-primary-500" : ""} />
                        <span className="text-[10px] font-black uppercase tracking-widest">{t('analysis')}</span>
                        {activeFilterCount > 0 && <span className="w-4 h-4 bg-primary-600 text-white rounded-full flex items-center justify-center text-[8px] font-bold">{activeFilterCount}</span>}
                    </button>
                </div>

                {/* History & Smart Suggestions Dropdown */}
                {showHistory && (searchHistory.length > 0 || filterSuggestions.length > 0) && (
                    <div className="absolute top-full left-0 right-0 mt-2 bg-white dark:bg-slate-900 backdrop-blur-xl border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl overflow-hidden z-50 animate-in fade-in slide-in-from-top-2 duration-200">
                        {filterSuggestions.length > 0 && (
                            <div className="py-1">
                                <div className="px-4 py-2 bg-slate-50/50 dark:bg-slate-800/30 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center">
                                    <span className="text-[10px] font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest flex items-center gap-1.5">
                                        <Beaker size={10} /> {t('properties')} 科研语法建议
                                    </span>
                                </div>
                                {filterSuggestions.map((sugg, idx) => {
                                    const isSelected = idx === historyIndex;
                                    return (
                                        <div 
                                            key={`sugg-${sugg.key}`} 
                                            onMouseDown={(e) => { e.preventDefault(); applySuggestion(sugg.label); }} 
                                            className={`w-full flex items-center justify-between px-4 py-2.5 cursor-pointer transition-colors ${isSelected ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-700 dark:text-emerald-300' : 'hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400'}`}
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className="w-6 h-6 rounded bg-emerald-100 dark:bg-emerald-900/40 flex items-center justify-center shrink-0">
                                                    <Hash size={12} className="text-emerald-600 dark:text-emerald-400" />
                                                </div>
                                                <div className="flex flex-col">
                                                    <span className="text-sm font-bold leading-none">{sugg.label}</span>
                                                    <span className="text-[9px] opacity-60 font-mono mt-1">用法: {sugg.label}:>5.0</span>
                                                </div>
                                            </div>
                                            <ArrowRight size={12} className="text-emerald-300" />
                                        </div>
                                    );
                                })}
                            </div>
                        )}

                        {searchHistory.length > 0 && (
                            <div className="py-1 border-t border-slate-100 dark:border-slate-800">
                                <div className="flex items-center justify-between px-4 py-2 bg-slate-50/50 dark:bg-slate-800/30 border-b border-slate-100 dark:border-slate-800">
                                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1.5"><Clock size={10} /> {t('recentSearches')}</span>
                                    <button onMouseDown={(e) => { e.preventDefault(); setSearchHistory([]); localStorage.removeItem('resindb_search_history'); }} className="text-[10px] text-rose-500 hover:underline font-bold uppercase">{t('clearHistory')}</button>
                                </div>
                                {searchHistory.map((query, idx) => {
                                    const actualIdx = idx + filterSuggestions.length;
                                    const isSelected = actualIdx === historyIndex;
                                    return (
                                        <div 
                                            key={`hist-${idx}`} 
                                            onMouseDown={() => { onSearchChange(query); setShowHistory(false); saveToHistory(query); }} 
                                            className={`group/item w-full flex items-center justify-between px-4 py-2.5 cursor-pointer transition-colors ${isSelected ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300' : 'hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400'}`}
                                        >
                                            <div className="flex items-center gap-3">
                                                <History size={14} className="text-slate-400" />
                                                <span className="text-sm font-medium">{query}</span>
                                            </div>
                                            <button 
                                                onMouseDown={(e) => removeFromHistory(e, query)}
                                                className="p-1.5 text-slate-300 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg transition-all opacity-0 group-hover/item:opacity-100"
                                            >
                                                <X size={14} />
                                            </button>
                                        </div>
                                    );
                                })}
                            </div>
                        )}

                        <div className="px-4 py-3 bg-slate-100/50 dark:bg-slate-950/50 border-t border-slate-100 dark:border-slate-800">
                            <div className="flex items-center gap-3">
                                <div className="p-1.5 bg-white dark:bg-slate-800 rounded-lg shadow-sm"><Info size={12} className="text-primary-500" /></div>
                                <div className="text-[10px] text-slate-500 dark:text-slate-400 font-medium leading-relaxed">
                                    按 <kbd className="px-1 bg-white dark:bg-slate-800 border rounded font-mono text-[9px]">Enter</kbd> 提交搜索并保存到历史记录。使用 <kbd className="px-1 bg-white dark:bg-slate-800 border rounded font-mono text-[9px]">Cmd+K</kbd> 快速对焦。
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>

        {/* Global Toolbar Actions */}
        <div className="flex items-center gap-1.5 p-1.5 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border border-slate-200 dark:border-slate-800 rounded-[2rem] shadow-glass shrink-0">
            <div className="flex items-center bg-slate-100 dark:bg-slate-800 rounded-2xl p-1 border border-slate-200 dark:border-slate-700">
                <button onClick={() => onViewModeChange('grid')} className={`p-2 rounded-xl transition-all ${viewMode === 'grid' ? 'bg-white dark:bg-slate-700 text-primary-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`} title={t('viewList')}><LayoutGrid size={16} /></button>
                <button onClick={() => onViewModeChange('chart')} className={`p-2 rounded-xl transition-all ${viewMode === 'chart' ? 'bg-white dark:bg-slate-700 text-primary-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`} title={t('viewChart')}><BarChart2 size={16} /></button>
            </div>

            <div className="h-5 w-px bg-slate-200 dark:bg-slate-700 mx-1"></div>

            <button onClick={onOpenImport} className="w-9 h-9 flex items-center justify-center text-slate-500 hover:text-primary-600 hover:bg-primary-50 dark:hover:bg-primary-900/20 rounded-full transition-all" title={t('importData')}><Upload size={18} /></button>
            <button onClick={onExport} disabled={isExporting} className="w-9 h-9 flex items-center justify-center text-slate-500 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-full transition-all disabled:opacity-50" title="Download Report">{isExporting ? <Loader2 size={18} className="animate-spin text-blue-500" /> : <Download size={18} />}</button>

            <div className="relative" ref={colMenuRef}>
                <button onClick={() => setIsColumnMenuOpen(!isColumnMenuOpen)} className={`w-9 h-9 flex items-center justify-center rounded-full transition-all ${isColumnMenuOpen ? 'bg-primary-50 text-primary-600' : 'text-slate-500 hover:text-primary-600 hover:bg-primary-50 dark:hover:bg-primary-900/20'}`} title={t('configureColumns')}><SlidersHorizontal size={18} /></button>
                {isColumnMenuOpen && (
                    <div className="absolute top-full right-0 mt-3 w-64 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl p-3 z-[100] animate-in zoom-in-95 origin-top-right">
                        <div className="flex items-center justify-between mb-3 px-1">
                            <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{t('visibleAttributes')}</h4>
                            <span className="text-[9px] font-bold text-primary-500 bg-primary-50 px-1.5 py-0.5 rounded uppercase">Config</span>
                        </div>
                        <div className="max-h-64 overflow-y-auto custom-scrollbar space-y-0.5">
                            {columns.map(col => (
                                <label key={col.key} className="flex items-center gap-3 px-3 py-1.5 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 cursor-pointer transition-colors group">
                                    <div className={`w-4 h-4 rounded border flex items-center justify-center transition-all ${col.visible ? 'bg-primary-600 border-primary-600' : 'border-slate-300 group-hover:border-primary-400'}`}>
                                        {col.visible && <div className="w-1.5 h-1.5 bg-white rounded-full"></div>}
                                    </div>
                                    <input type="checkbox" checked={col.visible} onChange={() => !col.isSystem && onToggleColumn(col.key)} disabled={col.isSystem} className="hidden" />
                                    <span className={`text-[11px] font-bold ${col.visible ? 'text-slate-800 dark:text-white' : 'text-slate-400'}`}>{tProp(col.label)}</span>
                                </label>
                            ))}
                        </div>
                    </div>
                )}
            </div>

            <div className="flex items-center gap-1 ml-1 pr-1">
                <button onClick={toggleTheme} className="w-9 h-9 flex items-center justify-center text-slate-500 hover:text-amber-500 hover:bg-amber-50 dark:hover:bg-amber-900/20 rounded-full transition-all">{theme === 'dark' ? <Sun size={18} /> : <Moon size={18} />}</button>
                <button onClick={toggleLanguage} className="w-9 h-9 flex items-center justify-center text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded-full transition-all" title="Switch Language"><Globe size={18} /></button>
            </div>

            <div className="h-5 w-px bg-slate-200 dark:bg-slate-700 mx-1"></div>

            <div className="relative" ref={userMenuRef}>
                <button onClick={() => setIsUserMenuOpen(!isUserMenuOpen)} className="flex items-center gap-2 pl-1 pr-3 py-1 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-full transition-all border border-slate-200 dark:border-slate-700">
                    <img src={user?.avatar} alt="" className="w-7 h-7 rounded-full border border-white dark:border-slate-600 shadow-sm object-cover" />
                    <span className="text-[11px] font-black text-slate-700 dark:text-slate-200">{user?.name.split(' ')[0]}</span>
                    <ChevronDown size={12} className={`text-slate-400 transition-transform ${isUserMenuOpen ? 'rotate-180' : ''}`} />
                </button>
                {isUserMenuOpen && (
                    <div className="absolute top-full right-0 mt-3 w-56 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl p-1.5 z-[100] animate-in zoom-in-95 origin-top-right flex flex-col gap-0.5">
                        <button onClick={() => { setIsUserMenuOpen(false); onOpenProfile(); }} className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 text-[11px] font-bold text-slate-700 dark:text-slate-200 transition-colors"><User size={14} className="text-primary-500" /> {t('profile')}</button>
                        <button onClick={() => { setIsUserMenuOpen(false); onOpenAdmin(); }} className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 text-[11px] font-bold text-slate-700 dark:text-slate-200 transition-colors"><Shield size={14} className="text-amber-500" /> {t('adminPanel')}</button>
                        <div className="h-px bg-slate-100 dark:bg-slate-800 my-1"></div>
                        <button onClick={onLogout} className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-rose-50 dark:hover:bg-rose-900/20 text-[11px] font-bold text-rose-600 transition-colors"><LogOut size={14} /> {t('logout')}</button>
                    </div>
                )}
            </div>
        </div>
      </div>

      {/* Dynamic Status Tickers */}
      <div className="flex items-center gap-4 px-2 overflow-hidden whitespace-nowrap">
         <div className="flex items-center gap-1.5">
             <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
             <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{t('systemOnline')}</span>
         </div>
         <span className="text-slate-200 dark:text-slate-800">|</span>
         <div className="flex gap-3">
             {['密度:>0.95', '熔指:5-10', '厂家:燕山'].map(syntax => (
                 <button 
                    key={syntax}
                    onClick={() => { onSearchChange(syntax); saveToHistory(syntax); }}
                    className="text-[9px] font-bold text-primary-500 hover:text-primary-600 flex items-center gap-1 transition-colors"
                 >
                    <Zap size={10} className="fill-current" /> {syntax}
                 </button>
             ))}
         </div>
      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";
import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Send, Image as ImageIcon, Sparkles, X, Loader2, BrainCircuit, Bot, User, ScanEye, Trash2, Maximize2, Minimize2, ShieldCheck, PieChart, BarChart3, TrendingUp, Search, Database, ChevronRight, Zap } from 'lucide-react';
