        if(!isNaN(d)) { denSum += d; denCount++; }
    });
    return { avgMfr: mfrCount ? (mfrSum/mfrCount).toFixed(2) : '-', avgDensity: denCount ? (denSum/denCount).toFixed(3) : '-' };
