const FormattedText: React.FC<{ 
    text: string; 
    onNavigateToChart?: (type: string) => void;
    onGradeClick?: (name: string) => void;
    className?: string 
}> = ({ text, onNavigateToChart, onGradeClick, className }) => {
  if (!text) return null;

  return (
    <div className={className}>
      {text.split('\n').map((line, i) => {
        const trimmed = line.trim();
        if (trimmed.startsWith('- ') || trimmed.startsWith('* ') || trimmed.match(/^\d+\./)) {
             const cleanLine = trimmed.replace(/^[-*]\s+|\d+\.\s+/, '');
             const parts = cleanLine.split(/(\*\*.*?\*\*)/g);
             return (
                <div key={i} className="flex gap-2.5 ml-1 mb-1.5 items-start">
                    <span className="text-emerald-500 dark:text-emerald-400 mt-1.5 shrink-0 text-[10px]">•</span>
                    <span className="leading-relaxed text-sm">
                        {parts.map((part, j) => {
                            if (part.startsWith('**') && part.endsWith('**')) {
                                const grade = part.slice(2, -2);
                                return <strong key={j} onClick={() => onGradeClick?.(grade)} className="font-bold text-slate-800 dark:text-white hover:text-primary-600 hover:underline cursor-pointer transition-colors">{grade}</strong>;
                            }
                            return <span key={j}>{part}</span>;
                        })}
                    </span>
                </div>
             );
        }

        const parts = line.split(/(\*\*.*?\*\*)/g);
        if (line.startsWith('##')) {
             return <h3 key={i} className="font-bold text-emerald-700 dark:text-emerald-400 mt-5 mb-2 text-base border-l-2 border-emerald-500 pl-3">{line.replace(/#/g, '')}</h3>
        }

        if (!trimmed) return <div key={i} className="h-4"></div>;

        return (
          <p key={i} className="mb-2 last:mb-0 leading-relaxed text-sm">
            {parts.map((part, j) => {
              if (part.startsWith('**') && part.endsWith('**')) {
                const grade = part.slice(2, -2);
                return <strong key={j} onClick={() => onGradeClick?.(grade)} className="font-bold text-slate-800 dark:text-white hover:text-primary-600 hover:underline cursor-pointer transition-colors">{grade}</strong>;
              }
              return <span key={j}>{part}</span>;
            })}
          </p>
        );
      })}

      {/* Dynamic Chart Triggers */}
      <div className="flex flex-wrap gap-2 mt-4 pt-4 border-t border-slate-100 dark:border-slate-800">
          {(text.includes('Ashby') || text.includes('散点') || text.includes('构效')) && (
              <ChartSuggestion type="Ashby" onClick={() => onNavigateToChart?.('ashby')} />
          )}
          {(text.includes('Radar') || text.includes('雷达') || text.includes('指纹')) && (
              <ChartSuggestion type="Radar" onClick={() => onNavigateToChart?.('radar')} />
          )}
          {(text.includes('GPC') || text.includes('分布')) && (
              <ChartSuggestion type="GPC" onClick={() => onNavigateToChart?.('gpc')} />
          )}
      </div>
    </div>
  );
};

