import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Product, ColumnConfig, SortConfig, PropertyValue } from '../types';
import { Factory, Edit, Trash2, CheckSquare, Square, ArrowUp, ArrowDown, ChevronLeft, ChevronRight, Eye, Radar, Loader2, AlertCircle, SearchX } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import { EditProductModal } from './EditProductModal';
import { DeleteConfirmationModal } from './DeleteConfirmationModal';
import { ProductDetailDrawer } from './ProductDetailDrawer';
import * as echarts from 'echarts';

interface DataGridProps {
  data: Product[];
  columns: ColumnConfig[];
  isLoading: boolean;
  onDelete: (ids: string[]) => void;
  onUpdate: (product: Product) => void;
  onBatchUpdate: (ids: string[], updates: Partial<Product>) => void;
  onCategorySelect: (id: string) => void;
  selectedIds: Set<string>;
  onSelectionChange: (ids: Set<string>) => void;
}

const QuickRadarPopup: React.FC<{ product: Product; anchorRef: React.RefObject<HTMLDivElement> }> = ({ product, anchorRef }) => {
    const chartRef = useRef<HTMLDivElement>(null);
    const { tProp } = useLanguage();

    useEffect(() => {
        if (!chartRef.current) return;
        const myChart = echarts.init(chartRef.current);
        const props = ['密度', '熔体质量流动速率', '拉伸屈服应力', '弯曲模量', '悬臂梁缺口冲击强度'];
        const values = props.map(p => {
            const v = product.properties?.[p]?.value;
            return typeof v === 'number' ? v : parseFloat(String(v)) || 0;
        });

        myChart.setOption({
            radar: {
                indicator: props.map(p => ({ name: tProp(p).slice(0,6), max: 100 })), 
                shape: 'circle', splitNumber: 3, axisName: { fontSize: 8, color: '#94a3b8' }
            },
            series: [{ type: 'radar', data: [{ value: values, areaStyle: { color: 'rgba(79, 70, 229, 0.3)' }, lineStyle: { color: '#4f46e5' } }], symbol: 'none' }]
        });
        return () => myChart.dispose();
    }, [product, tProp]);

    const rect = anchorRef.current?.getBoundingClientRect();
    if (!rect) return null;

    return (
        <div className="fixed z-[100] w-48 h-48 bg-white dark:bg-slate-900 rounded-2xl shadow-2xl border border-primary-500/20 p-2 animate-in fade-in zoom-in-95 pointer-events-none" 
             style={{ left: rect.left + 40, top: rect.top - 60 }}>
            <div ref={chartRef} className="w-full h-full" />
        </div>
    );
};

const renderCellContent = (val: any, unit?: string): React.ReactNode => {
    if (val === null || val === undefined || val === '') {
        return <span className="text-slate-300 dark:text-slate-700 font-mono">-</span>;
    }

    if (typeof val === 'number') {
        return (
            <div className="flex items-baseline gap-1">
                <span className="font-mono font-bold text-primary-600 dark:text-primary-400 tracking-tight">{val}</span>
                {unit && <span className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">{unit}</span>}
            </div>
        );
    }

    const displayStr = typeof val === 'object' ? JSON.stringify(val) : String(val);
    return <span className="text-slate-700 dark:text-slate-300 font-medium truncate max-w-[200px]">{displayStr}</span>;
};

export const DataGrid: React.FC<DataGridProps> = ({ 
    data = [], 
    columns = [], 
    isLoading, 
    onDelete, 
    onUpdate, 
    onBatchUpdate, 
    onCategorySelect, 
    selectedIds = new Set(), 
    onSelectionChange 
}) => {
  const { t, tProp } = useLanguage();
  const visibleColumns = useMemo(() => (columns || []).filter((c) => c.visible), [columns]);
  const [sortConfig, setSortConfig] = useState<SortConfig | null>(null);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [deletingIds, setDeletingIds] = useState<string[]>([]);
  const [viewingProduct, setViewingProduct] = useState<Product | null>(null);
  const [hoveredProduct, setHoveredProduct] = useState<Product | null>(null);
  const radarAnchorRef = useRef<HTMLDivElement>(null);

  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 15;

  const sortedData = useMemo(() => {
    if (!data) return [];
    if (!sortConfig) return data;

    const { key, direction } = sortConfig;

    return [...data].sort((a, b) => {
      // 1. Extract values based on whether key is a system field or a dynamic property
      let aVal: string | number | undefined;
      let bVal: string | number | undefined;

      if (key === 'gradeName' || key === 'manufacturer' || key === 'updatedAt') {
          aVal = (a as any)[key];
          bVal = (b as any)[key];
      } else {
          aVal = a.properties?.[key]?.value;
          bVal = b.properties?.[key]?.value;
      }

      // 2. Handle nulls/undefined for consistent sorting
      const aRaw = aVal ?? '';
      const bRaw = bVal ?? '';

      // 3. Intelligent Comparison (Numerical vs String)
      const aNum = typeof aRaw === 'number' ? aRaw : parseFloat(String(aRaw));
      const bNum = typeof bRaw === 'number' ? bRaw : parseFloat(String(bRaw));

      if (!isNaN(aNum) && !isNaN(bNum)) {
          return direction === 'asc' ? aNum - bNum : bNum - aNum;
      }

      // Default to locale-aware string comparison
      return direction === 'asc' 
        ? String(aRaw).localeCompare(String(bRaw)) 
        : String(bRaw).localeCompare(String(aRaw));
    });
  }, [data, sortConfig]);

  const paginatedData = useMemo(() => {
    const start = (currentPage - 1) * pageSize;
    return sortedData.slice(start, start + pageSize);
  }, [sortedData, currentPage]);

  const totalPages = Math.ceil(sortedData.length / pageSize);

  useEffect(() => {
    if (currentPage > totalPages && totalPages > 0) {
        setCurrentPage(totalPages);
    }
  }, [totalPages, currentPage]);

  const toggleSelection = (id: string) => {
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id); else next.add(id);
    onSelectionChange(next);
  };

  const toggleAllSelection = () => {
    if (selectedIds.size === paginatedData.length && paginatedData.length > 0) {
        onSelectionChange(new Set());
    } else {
        onSelectionChange(new Set(paginatedData.map(p => p.id)));
    }
  };

  if (isLoading) {
    return <div className="h-full flex items-center justify-center"><Loader2 className="animate-spin text-primary-600" size={32} /></div>;
  }

  if (data.length === 0) {
      return (
          <div className="h-full flex flex-col items-center justify-center p-12 text-center bg-slate-50/50 dark:bg-slate-900/30 rounded-[3rem] border border-dashed border-slate-200 dark:border-slate-800">
              <SearchX size={32} className="text-slate-300 dark:text-slate-600 mb-4" />
              <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100 mb-2">未找到匹配结果</h3>
              <p className="text-sm text-slate-500">尝试调整过滤条件或搜索关键词。</p>
          </div>
      );
  }

  return (
    <div className="h-full flex flex-col relative overflow-hidden">
      <div className="flex-1 overflow-auto custom-scrollbar">
        <table className="w-full text-sm text-left border-separate border-spacing-0">
          <thead className="sticky top-0 z-30 bg-white/90 dark:bg-slate-950/90 backdrop-blur-xl">
            <tr>
              <th className="px-4 py-4 w-12 border-b border-slate-100 dark:border-slate-800">
                <button onClick={toggleAllSelection} className="text-slate-400 hover:text-primary-600 transition-colors">
                    {selectedIds.size > 0 && selectedIds.size === paginatedData.length 
                        ? <CheckSquare size={18} className="text-primary-600" /> 
                        : <Square size={18} />}
                </button>
              </th>
              {visibleColumns.map((col) => {
                const isSorted = sortConfig?.key === col.key;
                return (
                  <th key={col.key} 
                      className={`px-4 py-4 font-black text-[10px] uppercase tracking-[0.15em] border-b border-slate-100 dark:border-slate-800 cursor-pointer transition-all hover:text-primary-600 group/head ${isSorted ? 'text-primary-600 dark:text-primary-400 bg-primary-50/20 dark:bg-primary-900/10' : 'text-slate-400'}`} 
                      onClick={() => setSortConfig({ key: col.key, direction: isSorted && sortConfig.direction === 'asc' ? 'desc' : 'asc' })}>
                    <div className="flex items-center gap-1.5">
                      {tProp(col.label)}
                      <span className={`transition-all duration-300 ${isSorted ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-1 group-hover/head:opacity-40 group-hover/head:translate-y-0'}`}>
                          {isSorted && sortConfig.direction === 'desc' ? <ArrowDown size={12} /> : <ArrowUp size={12} />}
                      </span>
                    </div>
                  </th>
                );
              })}
              <th className="px-4 py-4 border-b border-slate-100 dark:border-slate-800 text-right w-24 font-black text-[10px] text-slate-400 uppercase tracking-widest">操作</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50 dark:divide-slate-900">
            {paginatedData.map((p) => (
                <tr key={p.id} 
                    className={`group transition-all duration-200 cursor-pointer ${selectedIds.has(p.id) ? 'bg-primary-50/40 dark:bg-primary-950/20' : 'hover:bg-slate-50/50 dark:hover:bg-slate-900/40'}`} 
                    onClick={() => toggleSelection(p.id)}>
                    <td className="px-4 py-3.5" onClick={e => e.stopPropagation()}>
                        <button onClick={() => toggleSelection(p.id)} className={`transition-colors ${selectedIds.has(p.id) ? "text-primary-600" : "text-slate-300 group-hover:text-slate-400"}`}>
                            {selectedIds.has(p.id) ? <CheckSquare size={16} /> : <Square size={16} />}
                        </button>
                    </td>
                    {visibleColumns.map((col) => (
                        <td key={col.key} className={`px-4 py-3.5 whitespace-nowrap ${sortConfig?.key === col.key ? 'bg-primary-50/10 dark:bg-primary-900/5' : ''}`}>
                            {col.key === 'gradeName' ? (
                                <div className="flex items-center gap-2">
                                    <span className="font-bold text-slate-800 dark:text-white group-hover:text-primary-600 transition-colors">{p.gradeName}</span>
                                    <div onMouseEnter={() => setHoveredProduct(p)} onMouseLeave={() => setHoveredProduct(null)} className="text-primary-500 opacity-0 group-hover:opacity-100 transition-all scale-75 group-hover:scale-100"><Radar size={14} /></div>
                                </div>
                            ) : col.key === 'manufacturer' ? (
                                <div className="flex items-center gap-1.5"><Factory size={12} className="text-slate-300 dark:text-slate-600" /><span className="text-slate-500 dark:text-slate-400 font-medium text-xs">{p.manufacturer}</span></div>
                            ) : (
                                renderCellContent(p.properties?.[col.key]?.value, p.properties?.[col.key]?.unit)
                            )}
                        </td>
                    ))}
                    <td className="px-4 py-3.5 text-right" onClick={e => e.stopPropagation()}>
                        <div className="flex items-center justify-end gap-1 opacity-0 group-hover:opacity-100 transition-all">
                            <button onClick={() => setViewingProduct(p)} className="p-1.5 text-slate-400 hover:text-primary-600 hover:bg-primary-50 dark:hover:bg-primary-900/30 rounded-lg transition-all"><Eye size={14} /></button>
                            <button onClick={() => setEditingProduct(p)} className="p-1.5 text-slate-400 hover:text-amber-500 hover:bg-amber-50 dark:hover:bg-amber-900/30 rounded-lg transition-all"><Edit size={14} /></button>
                        </div>
                    </td>
                </tr>
            ))}
          </tbody>
        </table>
      </div>

      {hoveredProduct && <QuickRadarPopup product={hoveredProduct} anchorRef={radarAnchorRef} />}
      <div ref={radarAnchorRef} className="hidden" />

      <div className="flex items-center justify-between px-6 py-4 border-t border-slate-100 dark:border-slate-800 bg-white/80 dark:bg-slate-950/80 backdrop-blur-xl">
         <div className="flex items-center gap-4">
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{t('showing')} <span className="text-slate-700 dark:text-slate-200">{paginatedData.length}</span> / {sortedData.length}</span>
            {selectedIds.size > 0 && <span className="text-[10px] font-black text-primary-600 uppercase tracking-widest">{selectedIds.size} {t('selected')}</span>}
         </div>
         <div className="flex items-center gap-2">
            <button onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} className="p-2 border border-slate-200 dark:border-slate-800 rounded-xl disabled:opacity-20 hover:bg-primary-50 dark:hover:bg-primary-900/20 text-primary-600 transition-all"><ChevronLeft size={16} /></button>
            <span className="text-xs font-black tabular-nums">{currentPage} / {totalPages || 1}</span>
            <button onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages || totalPages === 0} className="p-2 border border-slate-200 dark:border-slate-800 rounded-xl disabled:opacity-20 hover:bg-primary-50 dark:hover:bg-primary-900/20 text-primary-600 transition-all"><ChevronRight size={16} /></button>
         </div>
      </div>

      <EditProductModal isOpen={!!editingProduct} onClose={() => setEditingProduct(null)} product={editingProduct} onSave={async p => { onUpdate(p); return true; }} />
      <DeleteConfirmationModal isOpen={deletingIds.length > 0} onClose={() => setDeletingIds([])} onConfirm={() => { onDelete(deletingIds); }} productNames={deletingIds.map(id => data.find(p => p.id === id)?.gradeName || 'Unknown')} />
      <ProductDetailDrawer product={viewingProduct} onClose={() => setViewingProduct(null)} onCategoryClick={onCategorySelect} />
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Search, SlidersHorizontal, Upload, LayoutGrid, BarChart2, Moon, Sun, Globe, User, LogOut, Settings, Shield, History, X, Trash2, Clock, Command, Download, Loader2, ArrowRight, Filter, ChevronDown, Sparkles, Hash, Zap, Beaker, Info } from 'lucide-react';
import { ColumnConfig, ViewMode, User as UserType } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import { useTheme } from '../contexts/ThemeContext';

interface TopBarProps {
  user: UserType | null;
  onLogout: () => void;
  onOpenProfile: () => void;
  onOpenAdmin: () => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  isSearching?: boolean;
  columns: ColumnConfig[];
  onToggleColumn: (key: string) => void;
  onToggleAllColumns: (visible: boolean) => void;
  onOpenImport: () => void;
  onExport: () => void;
  isExporting: boolean;
  viewMode: ViewMode;
  onViewModeChange: (mode: ViewMode) => void;
  showAdvancedFilters: boolean;
  onToggleFilters: () => void;
  activeFilterCount: number;
}

export const TopBar: React.FC<TopBarProps> = ({
  user, onLogout, onOpenProfile, onOpenAdmin, searchQuery, onSearchChange, isSearching, columns, onToggleColumn, onToggleAllColumns, onOpenImport, onExport, isExporting, viewMode, onViewModeChange, showAdvancedFilters, onToggleFilters, activeFilterCount
}) => {
  const [isColumnMenuOpen, setIsColumnMenuOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const { t, language, toggleLanguage, tProp } = useLanguage();
  const { theme, toggleTheme } = useTheme();
  const inputRef = useRef<HTMLInputElement>(null);

  const colMenuRef = useRef<HTMLDivElement>(null);
  const userMenuRef = useRef<HTMLDivElement>(null);

  const [searchHistory, setSearchHistory] = useState<string[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [historyIndex, setHistoryIndex] = useState(-1);

  const filterSuggestions = useMemo(() => {
      const parts = searchQuery.split(' ');
      const lastToken = parts[parts.length - 1];
      if (lastToken.includes(':')) return [];

      const availableProps = columns
          .filter(c => !c.isSystem)
          .map(c => ({
              key: c.key,
              label: tProp(c.label),
              unit: columns.find(col => col.key === c.key)?.label.match(/\[(.*?)\]/)?.[1] || ''
          }));

      if (!lastToken) return availableProps.slice(0, 5);

      return availableProps.filter(p => 
          p.label.toLowerCase().includes(lastToken.toLowerCase()) ||
          p.key.toLowerCase().includes(lastToken.toLowerCase())
      ).slice(0, 5);
  }, [columns, searchQuery, tProp]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); inputRef.current?.focus(); }
    };
    const handleClickOutside = (e: MouseEvent) => {
        if (colMenuRef.current && !colMenuRef.current.contains(e.target as Node)) setIsColumnMenuOpen(false);
        if (userMenuRef.current && !userMenuRef.current.contains(e.target as Node)) setIsUserMenuOpen(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    document.addEventListener('mousedown', handleClickOutside);
    const savedHistory = localStorage.getItem('resindb_search_history');
    if (savedHistory) try { setSearchHistory(JSON.parse(savedHistory)); } catch (e) {}
    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const saveToHistory = (query: string) => {
      const clean = query.trim();
      if (!clean) return;
      setSearchHistory(prev => {
          const filtered = prev.filter(item => item !== clean);
          const updated = [clean, ...filtered].slice(0, 8);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const removeFromHistory = (e: React.MouseEvent, query: string) => {
      e.stopPropagation();
      setSearchHistory(prev => {
          const updated = prev.filter(item => item !== query);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const handleInputKeyDown = (e: React.KeyboardEvent) => {
      const totalItems = searchHistory.length + filterSuggestions.length;
      if (showHistory && totalItems > 0) {
          if (e.key === 'ArrowDown') { 
              e.preventDefault(); 
              setHistoryIndex(prev => (prev + 1) % totalItems); 
              return; 
          }
          if (e.key === 'ArrowUp') { 
              e.preventDefault(); 
              setHistoryIndex(prev => (prev - 1 + totalItems) % totalItems); 
              return; 
          }
      }
      if (e.key === 'Enter') {
          e.preventDefault();
          if (historyIndex >= 0 && showHistory) {
              if (historyIndex < filterSuggestions.length) { 
                  applySuggestion(filterSuggestions[historyIndex].label); 
              } else { 
                  const histItem = searchHistory[historyIndex - filterSuggestions.length];
                  onSearchChange(histItem);
                  saveToHistory(histItem);
              }
              setHistoryIndex(-1); 
              setShowHistory(false);
          } else { 
              saveToHistory(searchQuery); 
              setShowHistory(false); 
              setHistoryIndex(-1); 
              inputRef.current?.blur(); 
          }
      }
      if (e.key === 'Escape') { 
          setShowHistory(false); 
          setHistoryIndex(-1); 
          inputRef.current?.blur(); 
      }
  };

  const applySuggestion = (label: string) => {
      const parts = searchQuery.split(' ');
      parts[parts.length - 1] = `${label}:`;
      const newQuery = parts.join(' ');
      onSearchChange(newQuery);
      inputRef.current?.focus();
      setHistoryIndex(-1);
  };

  return (
    <div className="w-full flex flex-col gap-3 px-2 py-2">
      <div className="flex items-center justify-between gap-6">
        <div className="flex-1 max-w-2xl relative z-[60]">
            <div className="relative group transition-all duration-300">
                <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                    {isSearching ? <Loader2 className="text-primary-600 animate-spin" size={18} /> : <Search className="text-slate-400 group-focus-within:text-primary-600 transition-colors" size={18} />}
                </div>
                <input
                    ref={inputRef}
                    type="text"
                    value={searchQuery}
                    onChange={(e) => { onSearchChange(e.target.value); setHistoryIndex(-1); }}
                    onFocus={() => { setShowHistory(true); setHistoryIndex(-1); }}
                    onBlur={() => setTimeout(() => setShowHistory(false), 200)}
                    onKeyDown={handleInputKeyDown}
                    placeholder={t('searchPlaceholder')}
                    className="block w-full pl-12 pr-12 py-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur-2xl border border-slate-200 dark:border-slate-800 rounded-2xl text-sm font-bold shadow-glass outline-none focus:ring-4 focus:ring-primary-500/15 focus:border-primary-500/40 transition-all text-slate-700 dark:text-slate-100 placeholder:text-slate-400"
                />
                <div className="absolute inset-y-0 right-5 flex items-center gap-2">
                    {searchQuery && (
                        <button onClick={() => onSearchChange('')} className="p-1 text-slate-400 hover:text-rose-500 transition-colors"><X size={14} /></button>
                    )}
                    <button 
                        onClick={onToggleFilters}
                        className={`flex items-center gap-1.5 px-3 py-1.5 rounded-xl border transition-all ${showAdvancedFilters ? 'bg-primary-600 border-primary-600 text-white shadow-glow' : 'bg-slate-50 dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-500 hover:border-primary-400 hover:text-primary-600'}`}
                    >
                        <Filter size={14} className={activeFilterCount > 0 && !showAdvancedFilters ? "fill-white" : ""} />
                        <span className="text-[10px] font-black uppercase tracking-widest">{t('analysis')}</span>
                        {activeFilterCount > 0 && <span className={`w-4 h-4 rounded-full flex items-center justify-center text-[8px] font-black ${showAdvancedFilters ? 'bg-white text-primary-600' : 'bg-primary-600 text-white'}`}>{activeFilterCount}</span>}
                    </button>
                </div>

                {showHistory && (searchHistory.length > 0 || filterSuggestions.length > 0) && (
                    <div className="absolute top-full left-0 right-0 mt-3 bg-white/95 dark:bg-slate-900/95 backdrop-blur-3xl border border-primary-500/10 dark:border-primary-500/20 rounded-[2rem] shadow-float overflow-hidden z-50 animate-in fade-in slide-in-from-top-4 duration-300">
                        {filterSuggestions.length > 0 && (
                            <div className="py-2">
                                <div className="px-6 py-2 flex justify-between items-center">
                                    <span className="text-[10px] font-black text-primary-600 uppercase tracking-[0.2em] flex items-center gap-2">
                                        <Sparkles size={12} className="animate-pulse" /> {t('properties')} 技术语法建议
                                    </span>
                                </div>
                                {filterSuggestions.map((sugg, idx) => {
                                    const isSelected = idx === historyIndex;
                                    return (
                                        <div key={idx} onMouseDown={(e) => { e.preventDefault(); applySuggestion(sugg.label); }} 
                                            className={`w-full flex items-center justify-between px-6 py-3 cursor-pointer transition-all duration-200 ${isSelected ? 'bg-primary-600 text-white shadow-glow' : 'hover:bg-primary-50 dark:hover:bg-primary-900/20 text-slate-600 dark:text-slate-300'}`}>
                                            <div className="flex items-center gap-4">
                                                <div className={`w-8 h-8 rounded-xl flex items-center justify-center shrink-0 ${isSelected ? 'bg-white/20' : 'bg-primary-50 dark:bg-primary-900/40 text-primary-600'}`}><Hash size={14} /></div>
                                                <div className="flex flex-col">
                                                    <span className="text-sm font-black leading-none">{sugg.label}</span>
                                                    <span className={`text-[9px] font-mono mt-1 opacity-60 ${isSelected ? 'text-white' : ''}`}>示例: {sugg.label}:>1.0</span>
                                                </div>
                                            </div>
                                            <ArrowRight size={14} className={isSelected ? 'text-white' : 'text-primary-300'} />
                                        </div>
                                    );
                                })}
                            </div>
                        )}
                        {searchHistory.length > 0 && (
                            <div className="py-2 border-t border-slate-100 dark:border-slate-800">
                                <div className="flex items-center justify-between px-6 py-2">
                                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2"><Clock size={12} /> {t('recentSearches')}</span>
                                    <button onMouseDown={(e) => { e.preventDefault(); setSearchHistory([]); localStorage.removeItem('resindb_search_history'); }} className="text-[10px] text-rose-600 hover:text-rose-500 font-black uppercase tracking-widest underline decoration-2 underline-offset-4">{t('clearHistory')}</button>
                                </div>
                                {searchHistory.map((query, idx) => {
                                    const actualIdx = idx + filterSuggestions.length;
                                    const isSelected = actualIdx === historyIndex;
                                    return (
                                        <div key={idx} onMouseDown={() => { onSearchChange(query); setShowHistory(false); saveToHistory(query); }} 
                                            className={`group/item w-full flex items-center justify-between px-6 py-3 cursor-pointer transition-all duration-200 ${isSelected ? 'bg-primary-600 text-white' : 'hover:bg-slate-50 dark:hover:bg-slate-800/50 text-slate-600 dark:text-slate-300'}`}>
                                            <div className="flex items-center gap-4">
                                                <History size={16} className={isSelected ? 'text-white' : 'text-slate-400 group-hover/item:text-primary-600'} />
                                                <span className="text-sm font-bold tracking-tight">{query}</span>
                                            </div>
                                            <button onMouseDown={(e) => removeFromHistory(e, query)} className={`p-2 rounded-xl transition-all opacity-0 group-hover/item:opacity-100 ${isSelected ? 'hover:bg-white/20 text-white' : 'hover:bg-rose-50 dark:hover:bg-rose-900/20 text-slate-300 hover:text-rose-600'}`}><X size={16} /></button>
                                        </div>
                                    );
                                })}
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>

        <div className="flex items-center gap-2 p-2 bg-white/70 dark:bg-slate-900/70 backdrop-blur-3xl border border-primary-500/10 rounded-[2rem] shadow-glass shrink-0">
            <div className="flex items-center bg-slate-100 dark:bg-slate-800 rounded-2xl p-1 border border-slate-200 dark:border-slate-700">
                <button onClick={() => onViewModeChange('grid')} className={`p-2.5 rounded-xl transition-all ${viewMode === 'grid' ? 'bg-primary-600 text-white shadow-indigo-glow scale-105' : 'text-slate-400 hover:text-primary-600'}`}><LayoutGrid size={18} /></button>
                <button onClick={() => onViewModeChange('chart')} className={`p-2.5 rounded-xl transition-all ${viewMode === 'chart' ? 'bg-primary-600 text-white shadow-indigo-glow scale-105' : 'text-slate-400 hover:text-primary-600'}`}><BarChart2 size={18} /></button>
            </div>
            <div className="h-6 w-px bg-slate-200 dark:bg-slate-700 mx-1"></div>
            <button onClick={onOpenImport} className="w-10 h-10 flex items-center justify-center text-slate-500 hover:text-primary-600 hover:bg-primary-50 dark:hover:bg-primary-900/20 rounded-full transition-all"><Upload size={20} /></button>
            <button onClick={onExport} disabled={isExporting} className="w-10 h-10 flex items-center justify-center text-slate-500 hover:text-primary-600 hover:bg-primary-50 dark:hover:bg-primary-900/20 rounded-full transition-all disabled:opacity-50">{isExporting ? <Loader2 size={20} className="animate-spin" /> : <Download size={20} />}</button>
            <div className="relative" ref={colMenuRef}>
                <button onClick={() => setIsColumnMenuOpen(!isColumnMenuOpen)} className={`w-10 h-10 flex items-center justify-center rounded-full transition-all ${isColumnMenuOpen ? 'bg-primary-600 text-white shadow-glow' : 'text-slate-500 hover:text-primary-600'}`}><SlidersHorizontal size={20} /></button>
                {isColumnMenuOpen && (
                    <div className="absolute top-full right-0 mt-4 w-72 bg-white/95 dark:bg-slate-900/95 backdrop-blur-3xl border border-primary-500/10 rounded-3xl shadow-float p-4 z-[100] animate-in zoom-in-95 origin-top-right">
                        <div className="flex items-center justify-between mb-4">
                            <h4 className="text-[11px] font-black uppercase text-slate-400 tracking-[0.2em]">{t('visibleAttributes')}</h4>
                        </div>
                        <div className="max-h-80 overflow-y-auto custom-scrollbar space-y-1">
                            {columns.map(col => (
                                <label key={col.key} className="flex items-center gap-3 px-4 py-2 rounded-[1.2rem] hover:bg-primary-50 dark:hover:bg-primary-900/10 cursor-pointer transition-all group">
                                    <div className={`w-5 h-5 rounded-lg border-2 flex items-center justify-center transition-all ${col.visible ? 'bg-primary-600 border-primary-600 shadow-indigo-glow' : 'border-slate-300 group-hover:border-primary-400'}`}>
                                        {col.visible && <div className="w-2 h-2 bg-white rounded-full"></div>}
                                    </div>
                                    <input type="checkbox" checked={col.visible} onChange={() => !col.isSystem && onToggleColumn(col.key)} disabled={col.isSystem} className="hidden" />
                                    <span className={`text-xs font-bold ${col.visible ? 'text-slate-800 dark:text-white' : 'text-slate-400'}`}>{tProp(col.label)}</span>
                                </label>
                            ))}
                        </div>
                    </div>
                )}
            </div>
            <div className="h-6 w-px bg-slate-200 dark:bg-slate-700 mx-1"></div>
            <div className="relative" ref={userMenuRef}>
                <button onClick={() => setIsUserMenuOpen(!isUserMenuOpen)} className={`flex items-center gap-3 pl-1.5 pr-4 py-1.5 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-full transition-all border border-slate-200 dark:border-slate-700 ${isUserMenuOpen ? 'ring-4 ring-primary-500/15 border-primary-500/40 shadow-glow' : ''}`}>
                    <img src={user?.avatar} alt="" className="w-8 h-8 rounded-full border border-white dark:border-slate-600 object-cover" />
                    <span className="text-[11px] font-black text-slate-700 dark:text-slate-100 uppercase tracking-widest">{user?.name.split(' ')[0]}</span>
                    <ChevronDown size={14} className={`text-slate-400 transition-transform duration-300 ${isUserMenuOpen ? 'rotate-180 text-primary-600' : ''}`} />
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect, ReactNode, useCallback } from 'react';
import { CATEGORY_TREE, MOCK_PRODUCTS } from './constants';
import { Product, ColumnConfig, ViewMode, Category, User, PropertyValue } from './types';
import { TreeSidebar } from './components/TreeSidebar';
import { DataGrid } from './components/DataGrid';
