import { AdminModal } from './components/AdminModal';
import { ProductDetailDrawer } from './components/ProductDetailDrawer';
import { LayoutDashboard, Database, Activity, Home, ChevronRight, Package, Factory, BarChart3, FlaskConical, TrendingUp, AlertCircle, RefreshCw, ShieldCheck, Microscope, Info, Zap, Sparkles, PieChart, Bot, MessageSquare, Beaker, Layout, Filter, Trash2, X, Download, GitCompare, CheckCircle2, BrainCircuit, LineChart, Table2, ListFilter, TrendingDown } from 'lucide-react';
