// --- Toast Component ---
interface Toast { id: string; type: 'success' | 'error' | 'info'; message: string; }
const ToastContainer: React.FC<{ toasts: Toast[], removeToast: (id: string) => void }> = ({ toasts, removeToast }) => (
    <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] flex flex-col gap-2 pointer-events-none">
        {toasts.map(t => (
            <div key={t.id} className={`pointer-events-auto flex items-center gap-3 px-4 py-3 rounded-2xl shadow-2xl animate-in slide-in-from-top-5 fade-in duration-300 border backdrop-blur-md ${
                t.type === 'success' ? 'bg-emerald-950/80 text-emerald-100 border-emerald-800' :
                t.type === 'error' ? 'bg-rose-950/80 text-rose-100 border-rose-800' :
                'bg-slate-900/80 text-slate-100 border-slate-700'
            }`}>
                <CheckCircle2 size={16} className={t.type === 'success' ? "text-emerald-400" : "hidden"} />
                <AlertCircle size={16} className={t.type === 'error' ? "text-rose-400" : "hidden"} />
                <span className="text-xs font-bold tracking-wide">{t.message}</span>
                <button onClick={() => removeToast(t.id)} className="ml-2 hover:bg-white/10 p-1 rounded-full transition-colors"><X size={12} /></button>
            </div>
        ))}
    </div>
);

const getDynamicColumns = (products: Product[]): ColumnConfig[] => {
  const propertyKeys = new Set<string>();
  products.forEach(p => { Object.keys(p.properties).forEach(k => propertyKeys.add(k)); });
  const defaultVisible = ['密度', '熔体质量流动速率', '拉伸屈服应力', '弯曲模量', '典型应用'];
  const dynamicCols: ColumnConfig[] = Array.from(propertyKeys).map(key => ({
    key, label: key, visible: defaultVisible.includes(key), isSystem: false
  })).sort((a, b) => {
      const aIsLikelyImportant = defaultVisible.includes(a.key);
      const bIsLikelyImportant = defaultVisible.includes(b.key);
      if (aIsLikelyImportant && !bIsLikelyImportant) return -1;
      if (!aIsLikelyImportant && bIsLikelyImportant) return 1;
      return a.label.localeCompare(b.label);
  });
  return [{ key: 'gradeName', label: '牌号', visible: true, isSystem: true }, { key: 'manufacturer', label: '所属分类', visible: true, isSystem: true }, ...dynamicCols];
};

type AppView = 'dashboard' | 'analytics' | 'ai';

const AppContent: React.FC = () => {
  const { t, tProp } = useLanguage();
  const { theme } = useTheme();
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('resindb-session');
    return saved ? JSON.parse(saved) : null;
  });

  const [toasts, setToasts] = useState<Toast[]>([]);
  const addToast = useCallback((type: Toast['type'], message: string) => {
      const id = Date.now().toString();
      setToasts(prev => [...prev, { id, type, message }]);
      setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3000);
  }, []);

  const [allProducts, setAllProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [selectedCategoryId, setSelectedCategoryId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [columns, setColumns] = useState<ColumnConfig[]>([]);
  const [isImportOpen, setIsImportOpen] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [viewingProduct, setViewingProduct] = useState<Product | null>(null);
  const [activeView, setActiveView] = useState<AppView>('dashboard');
  const [isExporting, setIsExporting] = useState(false);
  const [compactMode, setCompactMode] = useState(() => localStorage.getItem('resindb-compact') === 'true');

  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [showFilters, setShowFilters] = useState(false);
  const [numericFilters, setNumericFilters] = useState<Record<string, { min: string; max: string }>>({});

  useEffect(() => { setColumns(getDynamicColumns(allProducts)); }, []);

  // Update body background pattern based on theme
  useEffect(() => {
    document.body.style.setProperty('--parallax-pattern', theme === 'dark' 
      ? 'radial-gradient(circle at 2px 2px, rgba(79, 70, 229, 0.15) 1px, transparent 0)'
      : 'radial-gradient(circle at 2px 2px, rgba(79, 70, 229, 0.05) 1px, transparent 0)'
    );
  }, [theme]);

  // Sync compact mode preference
  useEffect(() => {
    localStorage.setItem('resindb-compact', String(compactMode));
  }, [compactMode]);

  const resolvePropKey = useCallback((label: string): string | null => {
      const cleanLabel = label.toLowerCase();
      const directMatch = columns.find(c => c.key.toLowerCase() === cleanLabel || tProp(c.label).toLowerCase() === cleanLabel);
      if (directMatch) return directMatch.key;
      const reverseKey = Object.keys(propertyMap).find(k => k.toLowerCase() === cleanLabel || propertyMap[k].toLowerCase() === cleanLabel);
      if (reverseKey) return reverseKey;
      return null;
  }, [columns, tProp]);

  const filteredData = useMemo(() => {
    const syntaxRegex = /([\u4e00-\u9fa5\w]+):([<>]=?|[-.0-9a-zA-Z]+)/g;
    const syntaxFilters: { key: string, operator: string, value: string | number, max?: number }[] = [];
    let processedQuery = searchQuery;
    let match;
    while ((match = syntaxRegex.exec(searchQuery)) !== null) {
        const [full, label, condition] = match;
        const key = resolvePropKey(label);
        if (key) {
            processedQuery = processedQuery.replace(full, '');
            if (condition.includes('-') && !condition.startsWith('-')) {
                const parts = condition.split('-');
                syntaxFilters.push({ key, operator: 'range', value: parseFloat(parts[0]), max: parseFloat(parts[1]) });
            } else if (condition.match(/^[<>]=?/)) {
                const op = condition.match(/^[<>]=?/)?.[0] || '';
                const val = parseFloat(condition.replace(op, ''));
                syntaxFilters.push({ key, operator: op, value: val });
            } else {
                const numVal = parseFloat(condition);
                syntaxFilters.push({ key, operator: '=', value: isNaN(numVal) ? condition : numVal });
            }
        }
    }
    const textKeywords = processedQuery.toLowerCase().split(' ').filter(k => k.trim());
    return allProducts.filter(product => {
      if (selectedCategoryId && !product.categoryIds.includes(selectedCategoryId)) return false;
      const matchesText = textKeywords.every(query => product.gradeName.toLowerCase().includes(query) || product.manufacturer.toLowerCase().includes(query) || Object.keys(product.properties).some(k => k.toLowerCase().includes(query)));
      if (!matchesText) return false;
      const matchesSyntax = syntaxFilters.every(f => {
          const propVal = product.properties[f.key]?.value;
          const val = typeof propVal === 'number' ? propVal : parseFloat(String(propVal));
          if (isNaN(val) || typeof f.value === 'string') return String(propVal).toLowerCase().includes(String(f.value).toLowerCase());
          switch(f.operator) {
              case '>': return val > (f.value as number);
              case '<': return val < (f.value as number);
              case '>=': return val >= (f.value as number);
              case '<=': return val <= (f.value as number);
              case 'range': return val >= (f.value as number) && val <= (f.max || Infinity);
              case '=': return val === (f.value as number);
              default: return true;
          }
      });
      if (!matchesSyntax) return false;
      return Object.entries(numericFilters).every(([key, range]) => {
          const propVal = product.properties[key]?.value;
          const num = typeof propVal === 'number' ? propVal : parseFloat(String(propVal));
          if (isNaN(num)) return true;
          const min = range.min === '' ? -Infinity : parseFloat(range.min);
          const max = range.max === '' ? Infinity : parseFloat(range.max);
          return num >= min && num <= max;
      });
    });
  }, [allProducts, selectedCategoryId, searchQuery, numericFilters, resolvePropKey]);

  const stats = useMemo(() => {
    if (filteredData.length === 0) return { avgMfr: 0, avgDensity: 0 };
    let mfrSum = 0, mfrCount = 0, denSum = 0, denCount = 0;
    filteredData.forEach(p => {
        const m = parseFloat(String(p.properties['熔体质量流动速率']?.value));
        const d = parseFloat(String(p.properties['密度']?.value));
        if(!isNaN(m)) { mfrSum += m; mfrCount++; }
        if(!isNaN(d)) { denSum += d; denCount++; }
    });
    return { avgMfr: mfrCount ? (mfrSum/mfrCount).toFixed(2) : '-', avgDensity: denCount ? (denSum/denCount).toFixed(3) : '-' };
  }, [filteredData]);

  const availableNumericProps = useMemo(() => {
    const props = new Set<string>();
    allProducts.forEach(p => Object.entries(p.properties).forEach(([k, v]) => { if (typeof v.value === 'number') props.add(k); }));
    return Array.from(props).sort();
  }, [allProducts]);

  const handleLogin = (user: User) => { setCurrentUser(user); localStorage.setItem('resindb-session', JSON.stringify(user)); };
  const handleLogout = () => { setCurrentUser(null); localStorage.removeItem('resindb-session'); };
  const handleToggleColumn = (key: string) => { setColumns(cols => cols.map(c => c.key === key ? { ...c, visible: !c.visible } : c)); };
  const handleExport = async () => { setIsExporting(true); await new Promise(r => setTimeout(r, 800)); addToast('success', '分析报告已生成并发送至邮箱'); setIsExporting(false); };
  const handleDelete = (ids: string[]) => { setAllProducts(prev => prev.filter(p => !ids.includes(p.id))); setSelectedIds(new Set()); addToast('success', `已同步删除 ${ids.length} 条记录`); };
  const handleImportData = () => { setIsImportOpen(false); addToast('success', 'TDS 数据解析入库成功'); };

  const handleAIGradeClick = (gradeName: string) => {
      const p = allProducts.find(prod => prod.gradeName.toLowerCase() === gradeName.toLowerCase());
      if (p) setViewingProduct(p);
      else addToast('info', `库中未找到牌号: ${gradeName}`);
  };

  if (!currentUser) return <AuthScreen onLogin={handleLogin} />;

  return (
    <div className="flex h-screen overflow-hidden transition-colors duration-300 relative z-10">
      <ToastContainer toasts={toasts} removeToast={(id) => setToasts(prev => prev.filter(t => t.id !== id))} />

      {/* Main Sidebar Nav - More prominent indigo accents */}
      <nav className="w-16 md:w-20 bg-slate-900/95 dark:bg-slate-950/95 backdrop-blur-3xl flex flex-col items-center py-6 gap-6 z-50 shrink-0 border-r border-indigo-500/10 shadow-2xl">
         <div className="w-12 h-12 bg-primary-600 rounded-2xl flex items-center justify-center shadow-indigo-600/30 shadow-xl mb-2 overflow-hidden relative group cursor-pointer" onClick={() => setActiveView('dashboard')}>
            <Microscope size={24} className="text-white group-hover:rotate-12 transition-transform" />
            <div className="absolute inset-0 bg-white/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
         </div>

         <div className="flex-1 flex flex-col gap-6">
            {[
                { id: 'dashboard', icon: LayoutDashboard, label: '数据仓库' },
                { id: 'analytics', icon: PieChart, label: '科研可视化' },
                { id: 'ai', icon: Bot, label: 'AI 实验室' }
            ].map((btn) => (
                <button 
                    key={btn.id}
                    onClick={() => setActiveView(btn.id as AppView)}
                    className={`w-12 h-12 rounded-2xl transition-all duration-300 relative group flex items-center justify-center ${activeView === btn.id ? 'bg-primary-600 text-white shadow-indigo-500/40 shadow-glow scale-110' : 'text-slate-500 hover:text-primary-400 hover:bg-slate-800'}`}
                    title={btn.label}
                >
                    <btn.icon size={22} />
                    {activeView === btn.id && (
                      <div className="absolute -left-3 top-1/2 -translate-y-1/2 w-1.5 h-8 bg-primary-400 rounded-r-full shadow-[0_0_10px_#818cf8]"></div>
                    )}
                </button>
            ))}
         </div>

         <div className="flex flex-col gap-4 mb-2">
            <button onClick={() => setIsAdminOpen(true)} className="w-12 h-12 flex items-center justify-center text-slate-500 hover:text-indigo-400 hover:bg-slate-800 rounded-2xl transition-all"><ShieldCheck size={22} /></button>
         </div>
      </nav>

      <div className="flex-1 flex flex-col min-w-0 h-full relative">
        <TopBar 
            user={currentUser}
            onLogout={handleLogout}
            onOpenProfile={() => setIsProfileOpen(true)}
            onOpenAdmin={() => setIsAdminOpen(true)}
            searchQuery={searchQuery}
            onSearchChange={setSearchQuery}
            columns={columns}
            onToggleColumn={handleToggleColumn}
            onToggleAllColumns={() => {}}
            onOpenImport={() => setIsImportOpen(true)}
            onExport={handleExport}
            isExporting={isExporting}
            viewMode={activeView === 'analytics' ? 'chart' : 'grid'}
            onViewModeChange={(m) => setActiveView(m === 'chart' ? 'analytics' : 'dashboard')}
            showAdvancedFilters={showFilters}
            onToggleFilters={() => setShowFilters(!showFilters)}
            activeFilterCount={Object.keys(numericFilters).length}
            compactMode={compactMode}
            onToggleCompact={() => setCompactMode(!compactMode)}
        />

        {/* Realtime Context Ticker with enhanced visibility */}
        {searchQuery && (
            <div className="px-6 pb-2 animate-in slide-in-from-top-1 duration-300">
                <div className="flex items-center gap-6 px-4 py-2 bg-white/70 dark:bg-slate-900/70 backdrop-blur-xl rounded-2xl border border-indigo-500/10 dark:border-indigo-500/5 text-[10px] font-black uppercase tracking-widest text-slate-400 shadow-glass">
                    <div className="flex items-center gap-2">命中: <span className="text-primary-600 font-black">{filteredData.length}</span></div>
                    <div className="w-px h-3 bg-slate-200 dark:bg-slate-800"></div>
                    <div className="flex items-center gap-2">均值 MFR: <span className="text-amber-500 font-black">{stats.avgMfr}</span></div>
                    <div className="w-px h-3 bg-slate-200 dark:bg-slate-800"></div>
                    <div className="flex items-center gap-2">均值 密度: <span className="text-teal-500 font-black">{stats.avgDensity}</span></div>
                    <div className="ml-auto flex items-center gap-2 text-primary-600 cursor-pointer hover:underline" onClick={() => setActiveView('ai')}>
                        <Sparkles size={10} className="fill-primary-500 animate-pulse" /> 询问 ResinAI 解析结果
                    </div>
                </div>
            </div>
        )}

        {showFilters && (
            <div className="px-6 pb-4 animate-in slide-in-from-top-2 duration-300">
                <div className="p-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur-3xl border border-indigo-500/10 rounded-3xl shadow-float flex flex-wrap gap-4 items-center">
                    <div className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest border-r pr-4 border-slate-100 dark:border-slate-800"><Filter size={14} className="text-primary-600" /> 物性精细化过滤</div>
                    {availableNumericProps.slice(0, 5).map(prop => (
                        <div key={prop} className="flex items-center gap-2 bg-slate-50 dark:bg-slate-850 px-3 py-1.5 rounded-xl border border-slate-100 dark:border-slate-800 group focus-within:border-primary-500/30 transition-all">
                            <span className="text-[11px] font-bold text-slate-600 dark:text-slate-300">{tProp(prop)}</span>
                            <div className="flex items-center gap-1.5">
                                <input type="text" placeholder="Min" value={numericFilters[prop]?.min || ''} onChange={(e) => setNumericFilters({...numericFilters, [prop]: { min: e.target.value, max: numericFilters[prop]?.max || '' }})} className="w-12 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-md text-[10px] py-1 text-center outline-none focus:border-primary-500 focus:ring-4 focus:ring-primary-500/10" />
                                <span className="text-slate-300">—</span>
                                <input type="text" placeholder="Max" value={numericFilters[prop]?.max || ''} onChange={(e) => setNumericFilters({...numericFilters, [prop]: { min: numericFilters[prop]?.min || '', max: e.target.value }})} className="w-12 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-md text-[10px] py-1 text-center outline-none focus:border-primary-500 focus:ring-4 focus:ring-primary-500/10" />
                            </div>
                        </div>
                    ))}
                    <button onClick={() => setNumericFilters({})} className="text-[10px] font-bold text-slate-400 hover:text-rose-500 transition-colors ml-auto uppercase tracking-widest">重置</button>
                </div>
            </div>
        )}

        <div className="flex-1 flex overflow-hidden">
            {(activeView === 'dashboard' || activeView === 'analytics') && (
                <div className="w-72 shrink-0 border-r border-indigo-500/5 bg-white/40 dark:bg-slate-900/40 backdrop-blur-xl flex flex-col">
                    <TreeSidebar categories={CATEGORY_TREE} selectedCategoryId={selectedCategoryId} onSelectCategory={setSelectedCategoryId} totalCount={allProducts.length} counts={{}} />
                </div>
            )}

            <div className="flex-1 flex flex-col p-6 min-h-0 relative">
                <div className="flex-1 w-full min-h-0 relative animate-in fade-in duration-500">
                    {activeView === 'dashboard' && (
                        <div className="absolute inset-0 bg-white/50 dark:bg-slate-950/20 border border-white/40 dark:border-slate-800 rounded-[2.5rem] shadow-glass overflow-hidden">
                            <DataGrid 
                                data={filteredData} 
                                columns={columns} 
                                isLoading={false} 
                                onDelete={handleDelete} 
                                onUpdate={(p) => { setAllProducts(prev => prev.map(old => old.id === p.id ? p : old)); addToast('success', '牌号物性已更新'); }} 
                                onBatchUpdate={(ids, u) => { setAllProducts(prev => prev.map(p => ids.includes(p.id) ? {...p, ...u} : p)); addToast('success', '批量更新完成'); }} 
                                onCategorySelect={setSelectedCategoryId} 
                                selectedIds={selectedIds} 
                                onSelectionChange={setSelectedIds} 
                                compactMode={compactMode}
                            />
                        </div>
                    )}
                    {activeView === 'analytics' && (
                        <div className="absolute inset-0">
                            <DataVisualizer data={filteredData} />
                        </div>
                    )}

                    {activeView === 'ai' && (
                        <div className="absolute inset-0 flex flex-col lg:flex-row gap-6 animate-in fade-in zoom-in-95 duration-500">
                            <div className="flex-1 bg-white/80 dark:bg-slate-900/80 backdrop-blur-3xl rounded-[2.5rem] border border-indigo-500/10 overflow-hidden shadow-float flex flex-col min-w-0">
                                <div className="p-6 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-950/50 flex items-center justify-between">
                                    <div className="flex items-center gap-4">
                                        <div className="p-3 bg-primary-600 rounded-2xl text-white shadow-lg shadow-indigo-500/40"><Bot size={24} /></div>
                                        <div>
                                            <h2 className="text-xl font-black text-slate-800 dark:text-white tracking-tight">ResinAI Lab</h2>
                                            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1.5"><Sparkles size={10} className="text-primary-500" /> Deep Scientific Engine Active</p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <button onClick={handleExport} className="flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-800 rounded-xl text-xs font-bold text-slate-600 dark:text-slate-300 hover:text-primary-600 hover:border-primary-300 transition-all shadow-sm">
                                            <Download size={14} /> {t('lab_report_btn')}
                                        </button>
                                    </div>
                                </div>
                                <div className="flex-1 relative bg-slate-50/10 dark:bg-transparent overflow-hidden">
                                    <AIAssistant 
                                        contextData={filteredData} 
                                        inlineView={true} 
                                        onGradeClick={handleAIGradeClick} 
                                        onNavigateToChart={(type) => setActiveView('analytics')}
                                    />
                                </div>
                            </div>

                            <div className="w-full lg:w-[380px] bg-white/60 dark:bg-slate-900/60 backdrop-blur-2xl rounded-[2.5rem] border border-indigo-500/10 overflow-hidden shadow-glass flex flex-col shrink-0">
                                <div className="p-5 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-white/30">
                                    <div className="flex items-center gap-3">
                                        <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 rounded-xl"><Database size={18} /></div>
                                        <h2 className="text-xs font-black uppercase tracking-widest text-slate-600 dark:text-slate-300">{t('lab_context')}</h2>
                                    </div>
                                    <span className="text-[10px] font-bold text-indigo-600 bg-indigo-100/50 dark:bg-indigo-900/30 px-2 py-0.5 rounded-full">{filteredData.length} Samples</span>
                                </div>

                                <div className="flex-1 overflow-y-auto p-4 custom-scrollbar space-y-3">
                                    {filteredData.slice(0, 15).map(p => (
                                        <div key={p.id} onClick={() => setViewingProduct(p)} className="p-3 bg-white/70 dark:bg-slate-800/70 border border-slate-100 dark:border-slate-700 rounded-2xl hover:border-indigo-400 hover:shadow-md transition-all group cursor-pointer">
                                            <div className="flex justify-between items-start mb-2">
                                                <span className="text-xs font-bold text-slate-800 dark:text-white truncate pr-2 group-hover:text-primary-600 transition-colors">{p.gradeName}</span>
                                                <ChevronRight size={12} className="text-slate-300 group-hover:text-primary-600 group-hover:translate-x-0.5 transition-all" />
                                            </div>
                                            <div className="flex flex-wrap gap-1">
                                                <span className="text-[9px] px-1.5 py-0.5 bg-slate-100 dark:bg-slate-900 rounded border border-slate-200 dark:border-slate-800 text-slate-500 font-mono">MFR: {p.properties['熔体质量流动速率']?.value || '-'}</span>
                                                <span className="text-[9px] px-1.5 py-0.5 bg-slate-100 dark:bg-slate-900 rounded border border-slate-200 dark:border-slate-800 text-slate-500 font-mono">Den: {p.properties['密度']?.value || '-'}</span>
                                            </div>
                                        </div>
                                    ))}
                                    {filteredData.length > 15 && <div className="py-4 text-center"><span className="text-[10px] font-bold text-slate-400 italic">... 及另外 {filteredData.length - 15} 条记录</span></div>}
                                </div>

                                <div className="p-4 bg-slate-50/50 dark:bg-slate-950/50 border-t border-slate-100 dark:border-slate-800">
                                    <div className="flex items-center gap-2 mb-3">
                                        <BrainCircuit size={14} className="text-indigo-600" />
                                        <span className="text-[10px] font-black uppercase text-slate-500">{t('lab_suggestions')}</span>
                                    </div>
                                    <div className="grid grid-cols-2 gap-2">
                                        <div className="p-2 bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-xl flex flex-col gap-1">
                                            <span className="text-[9px] font-bold text-slate-400">Context Window</span>
