const getDynamicColumns = (products: Product[]): ColumnConfig[] => {
  const propertyKeys = new Set<string>();
  products.forEach(p => Object.keys(p.properties).forEach(k => propertyKeys.add(k)));
  const defaultVisible = ['密度', '熔体质量流动速率', '拉伸屈服应力', '弯曲模量', '悬臂梁缺口冲击强度', '热变形温度', '典型应用'];
  const dynamicCols: ColumnConfig[] = Array.from(propertyKeys).map(key => ({
    key, label: key, visible: defaultVisible.includes(key), isSystem: false
  })).sort((a, b) => {
      const aPrio = defaultVisible.includes(a.key);
      const bPrio = defaultVisible.includes(b.key);
      if (aPrio && !bPrio) return -1;
      if (!aPrio && bPrio) return 1;
      return a.label.localeCompare(b.label);
  });
  return [
    { key: 'gradeName', label: '牌号', visible: true, isSystem: true },
    { key: 'manufacturer', label: '所属分类', visible: true, isSystem: true },
    { key: 'updatedAt', label: '更新时间', visible: false, isSystem: false },
    ...dynamicCols
  ];
};

const Breadcrumbs: React.FC<{ categoryId: string | null, onReset: () => void }> = ({ categoryId, onReset }) => {
    const { t, language } = useLanguage();

    const path = useMemo(() => {
        if (!categoryId) return [];
        const findPath = (nodes: Category[], targetId: string, currentPath: Category[]): Category[] | null => {
            for (const node of nodes) {
                if (node.id === targetId) return [...currentPath, node];
                if (node.children) {
                    const childResult = findPath(node.children, targetId, [...currentPath, node]);
                    if (childResult) return childResult;
                }
            }
            return null;
        };
        return findPath(CATEGORY_TREE, categoryId, []) || [];
    }, [categoryId]);

    return (
        <nav className="flex items-center text-sm text-slate-500 dark:text-slate-400 mb-6 px-1 animate-in fade-in slide-in-from-left-2">
            <button 
                className="flex items-center hover:text-primary-600 dark:hover:text-primary-400 transition-colors cursor-pointer group focus:outline-none" 
                onClick={onReset}
            >
                <div className="p-1.5 rounded-lg group-hover:bg-primary-50 dark:group-hover:bg-primary-900/20 transition-colors">
                    <Home size={16} className="transition-transform group-hover:scale-110" />
                </div>
                <span className="font-bold ml-1">{t('home')}</span>
            </button>
            {path.map((cat) => (
                <React.Fragment key={cat.id}>
                    <ChevronRight size={14} className="mx-1 text-slate-300 dark:text-slate-600" />
                    <span className="font-bold text-slate-800 dark:text-slate-200 hover:text-primary-600 dark:hover:text-primary-400 transition-colors cursor-pointer">
                        {language === 'en' && cat.nameEn ? cat.nameEn : cat.name}
                    </span>
                </React.Fragment>
            ))}
        </nav>
    );
};

const SummaryStats: React.FC<{ data: Product[] }> = ({ data }) => {
    const { t, tProp } = useLanguage();
    const [isExpanded, setIsExpanded] = useState(true);

    const stats = useMemo(() => {
        if (!data || data.length === 0) return {
            count: 0, manufacturers: 0, avgDensity: '-', avgMfr: '-', refCoverage: '0'
        };

        const manufacturers = new Set(data.map(p => p.manufacturerId || p.manufacturer)).size;
        let densitySum = 0, densityCount = 0, mfrSum = 0, mfrCount = 0, totalPropsWithRefs = 0, totalPropsCount = 0;

        data.forEach(p => {
            const dVal = p.properties['密度']?.value;
            const d = dVal === undefined || dVal === null ? NaN : parseFloat(String(dVal));
            if (!isNaN(d)) { densitySum += d; densityCount++; }

            const mVal = p.properties['熔体质量流动速率']?.value;
            const m = mVal === undefined || mVal === null ? NaN : parseFloat(String(mVal));
            if (!isNaN(m)) { mfrSum += m; mfrCount++; }

            const props = p.properties || {};
            (Object.values(props) as PropertyValue[]).forEach(prop => {
                totalPropsCount++;
                if (prop?.referenceId) totalPropsWithRefs++;
            });
        });

        return {
            count: data.length,
            manufacturers,
            avgDensity: densityCount ? (densitySum / densityCount).toFixed(3) : '-',
            avgMfr: mfrCount ? (mfrSum / mfrCount).toFixed(2) : '-',
            refCoverage: totalPropsCount > 0 ? ((totalPropsWithRefs / totalPropsCount) * 100).toFixed(1) : '0'
