                            <div className="p-1.5 bg-white/10 rounded-lg text-emerald-400 border border-white/5"><ShieldCheck size={16} /></div>
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Confidence</span>
                        </div>
                        <div>
                            <div className="flex items-baseline gap-1">
                                <span className="text-3xl font-black text-white tracking-tighter tabular-nums">{stats.refCoverage}<span className="text-lg text-slate-500">%</span></span>
                            </div>
                            <div className="w-full h-1 bg-slate-700 rounded-full mt-3 overflow-hidden">
                                <div className="h-full bg-emerald-500 rounded-full transition-all duration-1000 group-hover:shadow-[0_0_10px_rgba(16,185,129,0.5)]" style={{ width: `${Math.max(0, Math.min(100, Number(stats.refCoverage)))}%` }}></div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

type AppView = 'dashboard' | 'analytics' | 'ai';

const AppContent: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('resindb-session');
    return saved ? JSON.parse(saved) : null;
  });

