};

import { GoogleGenAI } from "@google/genai";
import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Send, Image as ImageIcon, Sparkles, X, Loader2, BrainCircuit, Bot, User, ScanEye, Trash2, Maximize2, Minimize2, ShieldCheck, PieChart, BarChart3, TrendingUp, Search, Database, ChevronRight, Zap, LineChart, AreaChart } from 'lucide-react';
import { Product } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import { useTheme } from '../contexts/ThemeContext';

interface AIAssistantProps {
  contextData: Product[];
  inlineView?: boolean;
  onNavigateToChart?: (chartType: string) => void;
  onGradeClick?: (gradeName: string) => void;
}

interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  image?: string;
}

const ChartSuggestion: React.FC<{ type: string, label: string, icon: React.ReactNode, onClick: () => void }> = ({ type, label, icon, onClick }) => {
    return (
        <button 
            onClick={onClick}
            className="flex items-center gap-2 px-4 py-2 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-300 rounded-xl border border-indigo-200 dark:border-indigo-800 hover:bg-indigo-600 hover:text-white hover:border-indigo-600 transition-all text-xs font-black uppercase tracking-wider group shadow-sm active:scale-95"
        >
            <div className="group-hover:scale-110 transition-transform">{icon}</div>
            {label}
        </button>
    );
};

const FormattedText: React.FC<{ 
    text: string; 
    onNavigateToChart?: (type: string) => void;
    onGradeClick?: (name: string) => void;
    className?: string 
}> = ({ text, onNavigateToChart, onGradeClick, className }) => {
  const { t } = useLanguage();
  if (!text) return null;

  // Pattern detection for chart suggestions
  const hasAshby = text.toLowerCase().includes('ashby') || text.includes('散点') || text.includes('相关性') || text.includes('构效');
  const hasRadar = text.toLowerCase().includes('radar') || text.includes('雷达') || text.includes('指纹') || text.includes('平衡');
  const hasGpc = text.toLowerCase().includes('gpc') || text.includes('分布') || text.includes('分子量');
  const hasRheology = text.toLowerCase().includes('rheology') || text.includes('流变') || text.includes('粘度');
  const hasTernary = text.toLowerCase().includes('ternary') || text.includes('三元') || text.includes('相图');

  return (
    <div className={className}>
      {text.split('\n').map((line, i) => {
        const trimmed = line.trim();
        if (trimmed.startsWith('- ') || trimmed.startsWith('* ') || trimmed.match(/^\d+\./)) {
             const cleanLine = trimmed.replace(/^[-*]\s+|\d+\.\s+/, '');
             const parts = cleanLine.split(/(\*\*.*?\*\*)/g);
             return (
                <div key={i} className="flex gap-2.5 ml-1 mb-1.5 items-start">
                    <span className="text-indigo-500 dark:text-indigo-400 mt-1.5 shrink-0 text-[10px]">•</span>
                    <span className="leading-relaxed text-sm">
                        {parts.map((part, j) => {
                            if (part.startsWith('**') && part.endsWith('**')) {
                                const grade = part.slice(2, -2);
                                return <strong key={j} onClick={() => onGradeClick?.(grade)} className="font-bold text-slate-800 dark:text-white hover:text-primary-600 hover:underline cursor-pointer transition-colors">{grade}</strong>;
                            }
                            return <span key={j}>{part}</span>;
                        })}
                    </span>
                </div>
             );
        }

        const parts = line.split(/(\*\*.*?\*\*)/g);
        if (line.startsWith('##')) {
             return <h3 key={i} className="font-bold text-indigo-700 dark:text-indigo-400 mt-5 mb-2 text-base border-l-4 border-indigo-600 pl-3 uppercase tracking-tight">{line.replace(/#/g, '')}</h3>
        }

        if (!trimmed) return <div key={i} className="h-4"></div>;

        return (
          <p key={i} className="mb-2 last:mb-0 leading-relaxed text-sm">
            {parts.map((part, j) => {
              if (part.startsWith('**') && part.endsWith('**')) {
                const grade = part.slice(2, -2);
                return <strong key={j} onClick={() => onGradeClick?.(grade)} className="font-bold text-slate-800 dark:text-white hover:text-primary-600 hover:underline cursor-pointer transition-colors">{grade}</strong>;
              }
              return <span key={j}>{part}</span>;
            })}
          </p>
        );
      })}

      {/* Interactive Chart Suggestion Dock */}
      {(hasAshby || hasRadar || hasGpc || hasRheology || hasTernary) && (
          <div className="mt-6 pt-4 border-t border-indigo-100 dark:border-indigo-900/30">
              <div className="flex items-center gap-2 mb-3">
                  <Sparkles size={12} className="text-indigo-500 animate-pulse" />
                  <span className="text-[10px] font-black uppercase text-slate-400 tracking-[0.2em]">实验室可视化建议</span>
              </div>
              <div className="flex flex-wrap gap-2">
                  {hasAshby && (
                      <ChartSuggestion 
                        type="ashby" 
                        label="Ashby Plot" 
                        icon={<Zap size={14} />} 
                        onClick={() => onNavigateToChart?.('ashby')} 
                      />
                  )}
                  {hasRadar && (
                      <ChartSuggestion 
                        type="radar" 
                        label="Fingerprint" 
                        icon={<PieChart size={14} />} 
                        onClick={() => onNavigateToChart?.('radar')} 
                      />
                  )}
                  {hasGpc && (
                      <ChartSuggestion 
                        type="gpc" 
                        label="MWD Analysis" 
                        icon={<AreaChart size={14} />} 
                        onClick={() => onNavigateToChart?.('gpc')} 
                      />
                  )}
                  {hasRheology && (
                      <ChartSuggestion 
                        type="rheology" 
                        label="Rheology" 
                        icon={<LineChart size={14} />} 
                        onClick={() => onNavigateToChart?.('rheology')} 
                      />
                  )}
                  {hasTernary && (
                      <ChartSuggestion 
                        type="ternary" 
                        label="Ternary Map" 
                        icon={<ScanEye size={14} />} 
                        onClick={() => onNavigateToChart?.('ternary')} 
                      />
                  )}
              </div>
          </div>
      )}
    </div>
  );
};

export const AIAssistant: React.FC<AIAssistantProps> = ({ contextData, inlineView = false, onNavigateToChart, onGradeClick }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [input, setInput] = useState('');
  const { t, language } = useLanguage();
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [useThinking, setUseThinking] = useState(true);
  const [attachedImage, setAttachedImage] = useState<string | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (messages.length === 0) {
        setMessages([{ 
            id: 'welcome', 
            role: 'model', 
            text: t('welcomeMessage') 
        }]);
    }
  }, [t]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading, isOpen]);

  const handleSendMessage = async (customInput?: string) => {
    const textToSend = customInput || input;
    if ((!textToSend.trim() && !attachedImage) || isLoading) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend,
      image: attachedImage || undefined
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setAttachedImage(null);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const parts: any[] = [];
      let systemInstruction = "You are ResinAI. A senior materials scientist at PetroChina Research Institute. Your goal is to analyze data specifically and precisely. Use Markdown formatting. When you mention a grade name, wrap it in **double asterisks** like **HDPE 5000S**. \n\nIMPORTANT: If the analysis involves comparing performance trade-offs, processing behavior, or molecular structure, EXPLICITLY recommend using one of our laboratory charts: 'Ashby plot' (for flow/toughness trade-offs), 'Fingerprint Radar' (for overall balance), 'GPC Distribution' (for molecular weight), 'Rheology curve' (for viscosity), or 'Ternary phase map' (for blends). This will trigger interactive buttons for the user.";

      if (userMsg.image) {
         const base64Data = userMsg.image.split(',')[1];
         const mimeType = userMsg.image.split(';')[0].split(':')[1] || 'image/jpeg';
         parts.push({ inlineData: { mimeType, data: base64Data } });
         systemInstruction += "\nYou are now focused on image-based QC analysis. Look for defects like specks or gels.";
         parts.push({ text: userMsg.text || "Analyze this resin sample." });
      } else {
         parts.push({ text: userMsg.text });
         if (contextData.length > 0) {
            const contextStr = JSON.stringify(contextData.slice(0, 20).map(p => ({
                grade: p.gradeName,
                manufacturer: p.manufacturer,
                mfr: p.properties['熔体质量流动速率']?.value,
                density: p.properties['密度']?.value,
                flex: p.properties['弯曲模量']?.value,
                impact: p.properties['悬臂梁缺口冲击强度']?.value,
                app: p.properties['典型应用']?.value
            })));
            parts.push({ text: `\n[Experimental Context - Currently Filtered List]: ${contextStr}` });
         }
      }

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: parts }],
        config: {
            systemInstruction: systemInstruction,
            thinkingConfig: useThinking ? { thinkingBudget: 2048 } : undefined,
        }
      });

      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        text: response.text || "Analysis result empty."
      }]);

    } catch (error) {
      console.error("AI Error:", error);
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        text: "## 连接异常\nResinAI 暂时无法访问中心计算节点。请检查网络状态或系统授权。"
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const renderInput = () => (
    <div className="flex items-end gap-2 bg-slate-100 dark:bg-slate-800/50 p-2 rounded-[2.5rem] border border-slate-200 dark:border-slate-700 focus-within:ring-4 focus-within:ring-indigo-500/10 focus-within:border-indigo-500 transition-all shadow-inner">
        <input type="file" ref={fileInputRef} accept="image/*" className="hidden" onChange={(e) => {
            const f = e.target.files?.[0];
            if(f){ const r = new FileReader(); r.onloadend = () => setAttachedImage(r.result as string); r.readAsDataURL(f); }
        }} />
        <button 
            onClick={() => fileInputRef.current?.click()} 
            className={`p-3 rounded-2xl transition-all shrink-0 ${attachedImage ? 'text-emerald-600 bg-emerald-100 dark:bg-emerald-900/30' : 'text-slate-400 hover:text-indigo-600 hover:bg-white dark:hover:bg-slate-800'}`}
        >
            <ImageIcon size={22} />
        </button>
        <textarea
            value={input} onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => { if(e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSendMessage(); }}}
            placeholder={t('aiPlaceholder')}
            className="w-full max-h-48 min-h-[44px] py-3 bg-transparent text-sm text-slate-800 dark:text-slate-200 outline-none resize-none leading-relaxed px-2 font-medium"
            rows={1}
        />
        <div className="flex items-center gap-2 self-center pr-1">
            <button 
                onClick={() => setUseThinking(!useThinking)}
                className={`p-3 rounded-2xl transition-all ${useThinking ? 'text-indigo-600 bg-indigo-100 dark:bg-indigo-900/30' : 'text-slate-400 hover:text-indigo-600'}`}
                title="深度逻辑引擎"
            >
                <BrainCircuit size={22} />
            </button>
            <button 
                onClick={() => handleSendMessage()} 
                disabled={isLoading || (!input.trim() && !attachedImage)} 
                className="p-3 bg-slate-900 dark:bg-indigo-600 hover:bg-slate-800 dark:hover:bg-indigo-700 disabled:opacity-20 text-white rounded-2xl shadow-xl transition-all active:scale-95 flex items-center justify-center shrink-0"
            >
                {isLoading ? <Loader2 size={22} className="animate-spin" /> : <Send size={22} />}
            </button>
        </div>
    </div>
  );

  if (inlineView) {
      return (
          <div className="flex flex-col h-full w-full bg-slate-50/30 dark:bg-transparent">
              <div className="flex-1 overflow-y-auto p-6 space-y-10 custom-scrollbar" ref={chatContainerRef}>
                <div className="max-w-4xl mx-auto space-y-8">
                  {messages.map(m => (
                      <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}>
                         <div className={`flex gap-4 max-w-[90%] ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                            <div className={`w-10 h-10 rounded-2xl flex items-center justify-center shrink-0 shadow-sm ${m.role === 'user' ? 'bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700' : 'bg-indigo-600 text-white shadow-indigo-500/20 shadow-lg'}`}>
                                {m.role === 'user' ? <User size={18} className="text-slate-400" /> : <Bot size={18} />}
                            </div>
                            <div className={`rounded-[2.5rem] px-8 py-6 shadow-glass ${m.role === 'user' ? 'bg-slate-900 text-white rounded-tr-sm' : 'bg-white dark:bg-slate-850 border border-slate-100 dark:border-slate-800 rounded-tl-sm text-slate-700 dark:text-slate-200'}`}>
                                {m.image && <img src={m.image} className="max-w-full h-auto max-h-96 rounded-2xl mb-4 shadow-2xl border border-white/50" />}
                                <FormattedText text={m.text} onNavigateToChart={onNavigateToChart} onGradeClick={onGradeClick} />
                            </div>
                         </div>
                      </div>
                  ))}
                  {isLoading && (
                      <div className="flex justify-start">
                          <div className="flex gap-4">
                            <div className="w-10 h-10 bg-indigo-100 dark:bg-indigo-900/30 rounded-2xl flex items-center justify-center animate-pulse"><Sparkles size={18} className="text-indigo-600" /></div>
                            <div className="flex items-center gap-3 bg-white dark:bg-slate-850 border border-slate-200 dark:border-slate-800 px-6 py-4 rounded-[2rem] shadow-sm">
                                <div className="flex gap-1.5">
                                    <span className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                                    <span className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                                    <span className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce"></span>
                                </div>
                                <span className="text-xs font-black text-indigo-600 uppercase tracking-widest">{useThinking ? 'Reasoning...' : 'Analyzing...'}</span>
                            </div>
                          </div>
                      </div>
                  )}
                </div>
                <div ref={messagesEndRef} className="h-4" />
              </div>
              <div className="p-8 bg-white/50 dark:bg-slate-900/50 backdrop-blur-xl border-t border-slate-100 dark:border-slate-800 shadow-float">
                  <div className="max-w-4xl mx-auto">
                    <div className="flex gap-2 mb-4 overflow-x-auto no-scrollbar pb-1">
                        {['对比当前筛选结果', '推荐刚韧平衡最佳牌号', '分析熔融流动分布规律', '查看三元相图优化建议'].map(q => (
                            <button key={q} onClick={() => handleSendMessage(q)} className="whitespace-nowrap px-4 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl text-[10px] font-black text-slate-500 hover:text-indigo-600 hover:border-indigo-300 transition-all shadow-sm hover:shadow-indigo-500/10">#{q}</button>
                        ))}
                    </div>
                    {renderInput()}
                  </div>
              </div>
          </div>
      );
  }

  return (
    <>
      <button
        onClick={() => setIsOpen(true)}
        className={`fixed bottom-8 right-8 z-40 w-16 h-16 bg-indigo-600 rounded-full shadow-2xl flex items-center justify-center text-white hover:scale-110 active:scale-95 transition-all hover:shadow-indigo-500/40 ${isOpen ? 'scale-0' : 'scale-100'}`}
      >
        <Sparkles size={28} />
      </button>

      <div 
        className={`fixed bottom-8 right-8 z-50 bg-white dark:bg-slate-900 rounded-[2.5rem] shadow-2xl ring-1 ring-slate-200 dark:ring-slate-800 flex flex-col overflow-hidden transition-all duration-500 origin-bottom-right ${isOpen ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 translate-y-10 scale-95 pointer-events-none'} ${isExpanded ? 'w-[700px] h-[85vh]' : 'w-[440px] h-[650px]'}`}
      >
        <div className="flex items-center justify-between px-6 py-5 border-b border-indigo-100 dark:border-indigo-900/30 bg-slate-50/80 dark:bg-slate-950/80 backdrop-blur-md">
            <div className="flex items-center gap-3">
                <div className="p-1.5 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 rounded-lg shadow-sm"><Bot size={18} /></div>
                <span className="font-black text-sm tracking-tight text-slate-800 dark:text-white uppercase">ResinAI Lab</span>
            </div>
            <div className="flex gap-1">
                <button onClick={() => setIsExpanded(!isExpanded)} className="p-2 text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-800 rounded-xl transition-colors">{isExpanded ? <Minimize2 size={18} /> : <Maximize2 size={18} />}</button>
                <button onClick={() => setIsOpen(false)} className="p-2 text-slate-400 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-xl transition-colors"><X size={20} /></button>
            </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-6 custom-scrollbar bg-slate-50/30 dark:bg-transparent" ref={chatContainerRef}>
            {messages.map(m => (
                <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in`}>
                    <div className={`max-w-[90%] p-5 rounded-3xl text-sm shadow-sm ${m.role === 'user' ? 'bg-slate-900 text-white rounded-tr-none' : 'bg-white dark:bg-slate-850 border border-indigo-50 dark:border-indigo-900/20 rounded-tl-none text-slate-700 dark:text-slate-200'}`}>
                        {m.image && <img src={m.image} className="max-w-full h-auto max-h-48 rounded-xl mb-3 shadow-md border border-slate-100" />}
                        <FormattedText text={m.text} onNavigateToChart={onNavigateToChart} onGradeClick={onGradeClick} />
                    </div>
                </div>
            ))}
            {isLoading && (
                <div className="flex justify-start animate-pulse">
                    <div className="flex gap-3 bg-white dark:bg-slate-850 border border-indigo-50 dark:border-indigo-900/20 px-6 py-4 rounded-3xl rounded-tl-none shadow-sm">
                        <Sparkles size={16} className="text-indigo-600 animate-spin" />
                        <span className="text-[10px] font-black uppercase text-indigo-600 tracking-widest">{useThinking ? 'Reasoning...' : 'Analysing...'}</span>
                    </div>
                </div>
            )}
        </div>

        <div className="p-4 border-t border-indigo-100 dark:border-indigo-900/30 bg-white dark:bg-slate-900">
            {attachedImage && (
                <div className="flex items-center justify-between p-2 mb-3 bg-indigo-50 dark:bg-indigo-900/20 border border-indigo-100 dark:border-indigo-800 rounded-2xl animate-in slide-in-from-bottom-2">
                    <div className="flex items-center gap-2">
                        <img src={attachedImage} className="w-10 h-10 rounded-lg object-cover shadow-sm border border-white" />
                        <span className="text-[10px] font-black uppercase text-indigo-700 dark:text-indigo-400 tracking-widest">Image Data Loaded</span>
                    </div>
                    <button onClick={() => setAttachedImage(null)} className="p-2 text-slate-400 hover:text-rose-500 transition-colors"><X size={16} /></button>
                </div>
            )}
            {renderInput()}
        </div>
      </div>
    </>
  );
};

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { 
  Settings, Activity, X, FileJson, Image as ImageIcon, 
  Hexagon, ScatterChart, Waves, Triangle, Info, Loader2,
  Filter, Plus, Trash2, ChevronDown, Check, AlertTriangle,
  Thermometer
} from 'lucide-react';
import * as echarts from 'echarts';
import { Product } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import { ScientificChart, ChartType } from './ScientificChart';

interface DataVisualizerProps {
  data: Product[];
  selectedProducts?: Product[];
  initialChartType?: string;
}

export const DataVisualizer: React.FC<DataVisualizerProps> = ({ data, selectedProducts, initialChartType }) => {
  const { t, tProp } = useLanguage();
  const [chartInstance, setChartInstance] = useState<echarts.ECharts | null>(null);
  const [activeChart, setActiveChart] = useState<ChartType>('radar');
  const [showConfig, setShowConfig] = useState(true);
  const [isExporting, setIsExporting] = useState(false);

  // Rheology specific configuration
  const [selectedRheologyTemps, setSelectedRheologyTemps] = useState<number[]>([190, 210, 230]);

  // Sync with initialChartType from props (navigation from AI)
  useEffect(() => {
    if (initialChartType && ['radar', 'ashby', 'gpc', 'rheology', 'ternary'].includes(initialChartType)) {
      setActiveChart(initialChartType as ChartType);
    }
  }, [initialChartType]);

  // Filter State
  const [filters, setFilters] = useState<Record<string, { min: string; max: string }>>({});
  const [isFilterDropdownOpen, setIsFilterDropdownOpen] = useState(false);
  const filterDropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
      const handleClickOutside = (event: MouseEvent) => {
          if (filterDropdownRef.current && !filterDropdownRef.current.contains(event.target as Node)) {
              setIsFilterDropdownOpen(false);
          }
      };
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Determine base data set
  const baseData = useMemo(() => {
    return (selectedProducts && selectedProducts.length > 0) ? selectedProducts : data;
  }, [data, selectedProducts]);

  // Extract available numeric properties for filtering - Memoized to prevent heavy loop on every render
  const numericProperties = useMemo(() => {
      if (!baseData) return [];
      const props = new Set<string>();
      baseData.forEach(p => {
          Object.entries(p.properties).forEach(([key, val]) => {
              const num = parseFloat(String(val.value));
              if (!isNaN(num)) props.add(key);
          });
      });
      return Array.from(props).sort();
  }, [baseData]);

  // Apply filters to baseData
  const filteredData = useMemo(() => {
      if (!baseData) return [];
      if (Object.keys(filters).length === 0) return baseData;

      return baseData.filter(p => {
          return Object.entries(filters).every(([key, { min, max }]) => {
              const val = p.properties[key]?.value;
              const numVal = parseFloat(String(val));

              if (isNaN(numVal)) return false; 

              const minVal = min === '' ? -Infinity : parseFloat(min);
              const maxVal = max === '' ? Infinity : parseFloat(max);

              return numVal >= minVal && numVal <= maxVal;
          });
      });
  }, [baseData, filters]);

  const handleAddFilter = (key: string) => {
      if (!filters[key]) {
          setFilters(prev => ({ ...prev, [key]: { min: '', max: '' } }));
      }
      setIsFilterDropdownOpen(false);
  };

  const updateFilter = (key: string, field: 'min' | 'max', val: string) => {
      // Allow only numbers and decimals
      if (val && !/^-?\d*\.?\d*$/.test(val)) return;
      setFilters(prev => ({
          ...prev,
          [key]: { ...prev[key], [field]: val }
      }));
  };

  const removeFilter = (key: string) => {
      setFilters(prev => {
          const next = { ...prev };
          delete next[key];
          return next;
      });
  };

  // Helper: Safe Float Parser (Layer 1: Anti-Crash)
  const safeParse = (val: any, fallback = 0): number => {
      if (val === undefined || val === null || val === '') return fallback;
      const num = parseFloat(String(val));
      return isNaN(num) ? fallback : num;
  };

  // --- Data Preparation Logic (Defensive) using filteredData ---

  // 1. Radar Data: Compare top 5 (or selected) products
  const radarData = useMemo(() => {
    if (!filteredData) return [];
    try {
        const source = filteredData.slice(0, 5); 
        return source.map(p => ({
          name: p.gradeName,
          value: [
            safeParse(p.properties['熔体质量流动速率']?.value),
            safeParse(p.properties['密度']?.value),
            safeParse(p.properties['弯曲模量']?.value),
            safeParse(p.properties['悬臂梁缺口冲击强度']?.value),
            safeParse(p.properties['热变形温度']?.value)
          ]
        }));
    } catch (e) {
        console.error("Radar Prep Error:", e);
        return [];
    }
  }, [filteredData]);

  // 2. Ashby Data: MFR vs Impact
  const ashbyData = useMemo(() => {
    if (!filteredData) return [];
    try {
        const groups: Record<string, any[]> = {};
        filteredData.forEach(p => {
          const man = p.manufacturer || 'Unknown';
          if (!groups[man]) groups[man] = [];

          const mfr = safeParse(p.properties['熔体质量流动速率']?.value, -1);
          const impact = safeParse(p.properties['悬臂梁缺口冲击强度']?.value, -1);

          if (mfr > 0 && impact > 0) {
            groups[man].push([mfr, impact, p.gradeName]);
          }
        });

        return Object.entries(groups).map(([name, points]) => ({
          name,
          data: points
        }));
    } catch(e) {
        console.error("Ashby Prep Error:", e);
        return [];
    }
  }, [filteredData]);

  // 5. Ternary Data: Mock Formulation (Simulated based on properties)
  const ternaryData = useMemo(() => {
    if (!filteredData) return [];
    try {
        const source = filteredData.length > 0 ? filteredData : [];
        return source.slice(0, 100).map((p, i) => {
            // Simulation logic to create 3 clusters based on density/MFR
            const mfr = safeParse(p.properties['熔体质量流动速率']?.value, 1);
            let a, b, c;

            if (mfr < 1) {
                a = 0.6 + Math.random() * 0.3;
                b = Math.random() * (0.9 - a);
                c = 1 - a - b;
            } else if (mfr > 10) {
                b = 0.6 + Math.random() * 0.3;
                a = Math.random() * (0.9 - b);
                c = 1 - a - b;
            } else {
                c = 0.5 + Math.random() * 0.4;
                a = Math.random() * (0.9 - c);
                b = 1 - a - c;
            }

            const sum = a + b + c;
            a = a / sum;
            b = b / sum;
            c = c / sum;

            return {
                a, b, c,
                name: p.gradeName,
                value: safeParse(p.properties['拉伸强度']?.value, 50) + (Math.random() * 10 - 5)
            };
        });
    } catch(e) {
        return [];
    }
  }, [filteredData]);

  // Select the correct data based on chart type to pass to ScientificChart
  const currentChartData = useMemo(() => {
      switch(activeChart) {
          case 'radar': return radarData;
          case 'ashby': return ashbyData;
          case 'gpc': return filteredData; 
          case 'rheology': return { products: filteredData, temps: selectedRheologyTemps }; 
          case 'ternary': return ternaryData;
          default: return [];
      }
  }, [activeChart, radarData, ashbyData, filteredData, ternaryData, selectedRheologyTemps]);

  const handleExport = async (format: 'png' | 'json') => {
      setIsExporting(true);
      if (format === 'png' && chartInstance) {
          try {
            const dataUrl = chartInstance.getDataURL({
                type: 'png',
                pixelRatio: 2,
                backgroundColor: '#fff'
            });
            const a = document.createElement('a');
            a.href = dataUrl;
            a.download = `resindb_${activeChart}_analysis.png`;
            a.click();
          } catch(e) { console.error(e); }
      } else if (format === 'json') {
          const jsonStr = JSON.stringify(currentChartData, null, 2);
          const blob = new Blob([jsonStr], {type: 'application/json'});
          const url = URL.createObjectURL(blob);
          const a = document.createElement('a');
          a.href = url;
          a.download = `resindb_${activeChart}_data.json`;
          a.click();
      }
      setIsExporting(false);
  };

  const chartDescriptions = {
      radar: t('desc_radar'),
      ashby: t('desc_ashby'),
      gpc: t('desc_gpc'),
      rheology: t('desc_rheology'),
      ternary: t('desc_ternary')
  };

  const toggleRheologyTemp = (temp: number) => {
    setSelectedRheologyTemps(prev => 
      prev.includes(temp) 
        ? prev.filter(t => t !== temp) 
        : [...prev, temp].sort()
    );
  };

  // Check if we have valid data for the current view to show improved empty state
  const hasValidData = filteredData.length > 0 && currentChartData && (Array.isArray(currentChartData) ? currentChartData.length > 0 : true);

  return (
    <div className="flex flex-col md:flex-row h-full gap-4 overflow-hidden">
      {/* Scientific Controls Sidebar */}
      <div className={`flex flex-col bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-3xl transition-all duration-500 ease-out shrink-0 overflow-hidden shadow-xl ${showConfig ? 'w-full md:w-72 opacity-100 translate-x-0' : 'w-0 opacity-0 -translate-x-10 border-0 pointer-events-none'}`}>
        <div className="p-5 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-slate-50/80 dark:bg-slate-950/50 backdrop-blur-sm">
          <div className="flex items-center gap-2 font-black text-sm text-slate-800 dark:text-white uppercase tracking-widest">
            <Activity size={16} className="text-emerald-500" />
            {t('analysisMode')}
          </div>
          <button onClick={() => setShowConfig(false)} className="md:hidden text-slate-400 hover:text-slate-600">
            <X size={20} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar">
            <div className="p-4 space-y-2">
                {[
                    { id: 'radar', label: t('chart_radar'), icon: Hexagon, color: 'text-indigo-500' },
                    { id: 'ashby', label: t('chart_ashby'), icon: ScatterChart, color: 'text-rose-500' },
                    { id: 'gpc', label: t('chart_gpc'), icon: Waves, color: 'text-blue-500' },
                    { id: 'rheology', label: t('chart_rheology'), icon: Activity, color: 'text-amber-500' },
                    { id: 'ternary', label: t('chart_ternary'), icon: Triangle, color: 'text-emerald-500' },
                ].map(item => (
                    <button 
                        key={item.id}
                        onClick={() => setActiveChart(item.id as ChartType)}
                        className={`w-full flex items-center gap-3 p-3 rounded-2xl border transition-all duration-200 group relative overflow-hidden ${
                            activeChart === item.id 
                            ? 'bg-slate-900 dark:bg-white text-white dark:text-slate-900 border-transparent shadow-lg' 
                            : 'bg-white dark:bg-slate-800/50 border-slate-100 dark:border-slate-800 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800'
                        }`}
                    >
                        <div className={`p-2 rounded-xl bg-slate-100 dark:bg-slate-700/50 ${activeChart === item.id ? 'bg-white/20 text-white' : item.color}`}>
                            <item.icon size={18} />
                        </div>
                        <span className="text-xs font-bold uppercase tracking-wide">{item.label}</span>
                        {activeChart === item.id && <div className="absolute right-0 top-0 bottom-0 w-1 bg-emerald-500"></div>}
                    </button>
                ))}
            </div>

            {/* --- Rheology Specific Settings --- */}
            {activeChart === 'rheology' && filteredData.length === 1 && (
