  const axisColor = isDark ? '#94a3b8' : '#333333';

  return {
    backgroundColor: 'transparent',
    color: colorPalette,
    title: {
      text: '熔体指数与密度关联图 (MFR vs Density)',
      subtext: 'Distribution Analysis of Processability and Crystallinity',
      left: 'center',
      textStyle: { color: isDark ? '#e2e8f0' : '#333333', fontSize: 16, fontFamily: 'Arial, sans-serif' }
