                    { id: 'ashby', label: t('chart_ashby'), icon: ScatterChart, color: 'text-rose-500' },
                    { id: 'mfr_density', label: t('chart_mfr_density'), icon: Target, color: 'text-sky-500' },
                    { id: 'gpc', label: t('chart_gpc'), icon: Waves, color: 'text-blue-500' },
                    { id: 'rheology', label: t('chart_rheology'), icon: Activity, color: 'text-amber-500' },
                    { id: 'ternary', label: t('chart_ternary'), icon: Triangle, color: 'text-emerald-500' },
                ].map(item => (
                    <button 
                        key={item.id}
                        onClick={() => setActiveChart(item.id as ChartType)}
                        className={`w-full flex items-center gap-3 p-3 rounded-2xl border transition-all duration-200 group relative overflow-hidden ${
                            activeChart === item.id 
                            ? 'bg-slate-900 dark:bg-white text-white dark:text-slate-900 border-transparent shadow-lg' 
                            : 'bg-white dark:bg-slate-800/50 border-slate-100 dark:border-slate-800 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800'
                        }`}
                    >
                        <div className={`p-2 rounded-xl bg-slate-100 dark:bg-slate-700/50 ${activeChart === item.id ? 'bg-white/20 text-white' : item.color}`}>
                            <item.icon size={18} />
