    return saved ? JSON.parse(saved) : null;
  });

  const [toasts, setToasts] = useState<Toast[]>([]);
  const addToast = useCallback((type: Toast['type'], message: string) => {
      const id = Date.now().toString();
      setToasts(prev => [...prev, { id, type, message }]);
      setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3000);
  }, []);

  const [allProducts, setAllProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [selectedCategoryId, setSelectedCategoryId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [columns, setColumns] = useState<ColumnConfig[]>([]);
  const [isImportOpen, setIsImportOpen] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [viewingProduct, setViewingProduct] = useState<Product | null>(null);
  const [activeView, setActiveView] = useState<AppView>('dashboard');
  const [isExporting, setIsExporting] = useState(false);

  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [showFilters, setShowFilters] = useState(false);
  const [numericFilters, setNumericFilters] = useState<Record<string, { min: string; max: string }>>({});

  useEffect(() => { setColumns(getDynamicColumns(allProducts)); }, []);

  const resolvePropKey = useCallback((label: string): string | null => {
      const cleanLabel = label.toLowerCase();
      const directMatch = columns.find(c => c.key.toLowerCase() === cleanLabel || tProp(c.label).toLowerCase() === cleanLabel);
      if (directMatch) return directMatch.key;
      const reverseKey = Object.keys(propertyMap).find(k => k.toLowerCase() === cleanLabel || propertyMap[k].toLowerCase() === cleanLabel);
      if (reverseKey) return reverseKey;
      return null;
  }, [columns, tProp]);

  const filteredData = useMemo(() => {
    const syntaxRegex = /([\u4e00-\u9fa5\w]+):([<>]=?|[-.0-9a-zA-Z]+)/g;
    const syntaxFilters: { key: string, operator: string, value: string | number, max?: number }[] = [];
    let processedQuery = searchQuery;
    let match;
    while ((match = syntaxRegex.exec(searchQuery)) !== null) {
        const [full, label, condition] = match;
        const key = resolvePropKey(label);
        if (key) {
            processedQuery = processedQuery.replace(full, '');
            if (condition.includes('-') && !condition.startsWith('-')) {
                const parts = condition.split('-');
                syntaxFilters.push({ key, operator: 'range', value: parseFloat(parts[0]), max: parseFloat(parts[1]) });
            } else if (condition.match(/^[<>]=?/)) {
                const op = condition.match(/^[<>]=?/)?.[0] || '';
                const val = parseFloat(condition.replace(op, ''));
                syntaxFilters.push({ key, operator: op, value: val });
            } else {
                const numVal = parseFloat(condition);
                syntaxFilters.push({ key, operator: '=', value: isNaN(numVal) ? condition : numVal });
            }
        }
    }
    const textKeywords = processedQuery.toLowerCase().split(' ').filter(k => k.trim());
    return allProducts.filter(product => {
      if (selectedCategoryId && !product.categoryIds.includes(selectedCategoryId)) return false;
      const matchesText = textKeywords.every(query => product.gradeName.toLowerCase().includes(query) || product.manufacturer.toLowerCase().includes(query) || Object.keys(product.properties).some(k => k.toLowerCase().includes(query)));
      if (!matchesText) return false;
      const matchesSyntax = syntaxFilters.every(f => {
          const propVal = product.properties[f.key]?.value;
          const val = typeof propVal === 'number' ? propVal : parseFloat(String(propVal));
          if (isNaN(val) || typeof f.value === 'string') return String(propVal).toLowerCase().includes(String(f.value).toLowerCase());
          switch(f.operator) {
              case '>': return val > (f.value as number);
              case '<': return val < (f.value as number);
              case '>=': return val >= (f.value as number);
              case '<=': return val <= (f.value as number);
              case 'range': return val >= (f.value as number) && val <= (f.max || Infinity);
              case '=': return val === (f.value as number);
              default: return true;
          }
      });
      if (!matchesSyntax) return false;
      return Object.entries(numericFilters).every(([key, range]) => {
          const propVal = product.properties[key]?.value;
          const num = typeof propVal === 'number' ? propVal : parseFloat(String(propVal));
          if (isNaN(num)) return true;
          const min = range.min === '' ? -Infinity : parseFloat(range.min);
          const max = range.max === '' ? Infinity : parseFloat(range.max);
          return num >= min && num <= max;
      });
    });
  }, [allProducts, selectedCategoryId, searchQuery, numericFilters, resolvePropKey]);

  const handleLogin = (user: User) => { setCurrentUser(user); localStorage.setItem('resindb-session', JSON.stringify(user)); };
  const handleLogout = () => { setCurrentUser(null); localStorage.removeItem('resindb-session'); };
  const handleToggleColumn = (key: string) => { setColumns(cols => cols.map(c => c.key === key ? { ...c, visible: !c.visible } : c)); };
  const handleExport = async () => { setIsExporting(true); await new Promise(r => setTimeout(r, 800)); addToast('success', '分析报告已生成并发送至邮箱'); setIsExporting(false); };
  const handleDelete = (ids: string[]) => { setAllProducts(prev => prev.filter(p => !ids.includes(p.id))); setSelectedIds(new Set()); addToast('success', `已同步删除 ${ids.length} 条记录`); };
  const handleImportData = () => { setIsImportOpen(false); addToast('success', 'TDS 数据解析入库成功'); };

  const handleAIGradeClick = (gradeName: string) => {
      const p = allProducts.find(prod => prod.gradeName.toLowerCase() === gradeName.toLowerCase());
      if (p) setViewingProduct(p);
      else addToast('info', `库中未找到牌号: ${gradeName}`);
  };

  if (!currentUser) return <AuthScreen onLogin={handleLogin} />;

  return (
    <div className="flex h-screen bg-slate-50 dark:bg-slate-950 font-sans text-slate-900 dark:text-slate-100 overflow-hidden transition-colors duration-300">
      <ToastContainer toasts={toasts} removeToast={(id) => setToasts(prev => prev.filter(t => t.id !== id))} />

      {/* Main Sidebar Nav */}
      <nav className="w-16 md:w-20 bg-slate-900 dark:bg-slate-950 flex flex-col items-center py-6 gap-6 z-[70] shrink-0 border-r border-white/5 shadow-2xl">
         <div className="w-12 h-12 bg-primary-600 rounded-2xl flex items-center justify-center shadow-lg shadow-primary-900/40 mb-2 overflow-hidden relative group cursor-pointer" onClick={() => setActiveView('dashboard')}>
            <Microscope size={24} className="text-white group-hover:rotate-12 transition-transform" />
            <div className="absolute inset-0 bg-white/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
         </div>

         <div className="flex-1 flex flex-col gap-6">
            {[
                { id: 'dashboard', icon: LayoutDashboard, label: '数据仓库' },
                { id: 'analytics', icon: PieChart, label: '科研可视化' },
                { id: 'ai', icon: Bot, label: 'AI 实验室' }
            ].map((btn) => (
                <button 
                    key={btn.id}
                    onClick={() => setActiveView(btn.id as AppView)}
                    className={`w-12 h-12 rounded-2xl transition-all duration-300 relative group flex items-center justify-center ${activeView === btn.id ? 'bg-primary-600 text-white shadow-lg shadow-primary-500/20 scale-105' : 'text-slate-500 hover:text-primary-400 hover:bg-slate-800'}`}
                    title={btn.label}
                >
                    <btn.icon size={22} />
                    {activeView === btn.id && <div className="absolute -left-3 top-1/2 -translate-y-1/2 w-1.5 h-8 bg-primary-400 rounded-r-full"></div>}
                </button>
            ))}
         </div>

         <div className="flex flex-col gap-4 mb-2">
            <button onClick={() => setIsAdminOpen(true)} className="w-12 h-12 flex items-center justify-center text-slate-500 hover:text-amber-400 hover:bg-slate-800 rounded-2xl transition-all"><ShieldCheck size={22} /></button>
         </div>
      </nav>

      <div className="flex-1 flex flex-col min-w-0 h-full relative">
        {/* CRITICAL: Increased z-index of the TopBar container to ensure its dropdowns stay above DataGrid headers */}
        <div className="shrink-0 z-[60] relative">
            <TopBar 
                user={currentUser}
                onLogout={handleLogout}
                onOpenProfile={() => setIsProfileOpen(true)}
                onOpenAdmin={() => setIsAdminOpen(true)}
                searchQuery={searchQuery}
                onSearchChange={setSearchQuery}
                columns={columns}
                onToggleColumn={handleToggleColumn}
                onToggleAllColumns={() => {}}
                onOpenImport={() => setIsImportOpen(true)}
                onExport={handleExport}
                isExporting={isExporting}
                viewMode={activeView === 'analytics' ? 'chart' : 'grid'}
                onViewModeChange={(m) => setActiveView(m === 'chart' ? 'analytics' : 'dashboard')}
                showAdvancedFilters={showFilters}
                onToggleFilters={() => setShowFilters(!showFilters)}
                activeFilterCount={Object.keys(numericFilters).length}
            />
        </div>

        <div className="flex-1 flex overflow-hidden">
            {(activeView === 'dashboard' || activeView === 'analytics') && (
                <div className="w-72 shrink-0 border-r border-slate-200 dark:border-slate-800 bg-white/50 dark:bg-slate-900/50 backdrop-blur-sm flex flex-col">
                    <TreeSidebar categories={CATEGORY_TREE} selectedCategoryId={selectedCategoryId} onSelectCategory={setSelectedCategoryId} totalCount={allProducts.length} counts={{}} />
                </div>
            )}

            <div className="flex-1 flex flex-col p-6 min-h-0 relative">
                <div className="flex-1 w-full min-h-0 relative animate-in fade-in duration-500">
                    {activeView === 'dashboard' && (
                        <div className="absolute inset-0 bg-white/40 dark:bg-slate-950/20 border border-white/20 dark:border-slate-800 rounded-[2.5rem] shadow-inner overflow-hidden">
                            <DataGrid 
                                data={filteredData} 
                                columns={columns} 
                                isLoading={false} 
                                onDelete={handleDelete} 
                                onUpdate={(p) => { setAllProducts(prev => prev.map(old => old.id === p.id ? p : old)); addToast('success', '牌号物性已更新'); }} 
                                onBatchUpdate={(ids, u) => { setAllProducts(prev => prev.map(p => ids.includes(p.id) ? {...p, ...u} : p)); addToast('success', '批量更新完成'); }} 
                                onCategorySelect={setSelectedCategoryId} 
                                selectedIds={selectedIds} 
                                onSelectionChange={setSelectedIds} 
                            />
                        </div>
                    )}
                    {activeView === 'analytics' && (
                        <div className="absolute inset-0">
                            <DataVisualizer data={filteredData} selectedProducts={allProducts.filter(p => selectedIds.has(p.id))} />
                        </div>
                    )}

                    {activeView === 'ai' && (
                        <div className="absolute inset-0 flex flex-col lg:flex-row gap-6">
                            <div className="flex-1 bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 overflow-hidden shadow-2xl flex flex-col min-w-0">
                                <div className="p-6 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-950/50 flex items-center justify-between">
                                    <div className="flex items-center gap-4">
                                        <div className="p-3 bg-primary-600 rounded-2xl text-white shadow-lg shadow-primary-500/20"><Bot size={24} /></div>
                                        <div>
                                            <h2 className="text-xl font-black text-slate-800 dark:text-white tracking-tight">ResinAI Lab</h2>
                                            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1.5"><Sparkles size={10} className="text-primary-500" /> Deep Scientific Engine Active</p>
                                        </div>
                                    </div>
                                </div>
                                <div className="flex-1 relative bg-slate-50/30 dark:bg-transparent overflow-hidden">
                                    <AIAssistant 
                                        contextData={filteredData} 
                                        inlineView={true} 
                                        onGradeClick={handleAIGradeClick} 
                                        onNavigateToChart={() => setActiveView('analytics')}
                                    />
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>

        {/* Global Selection Tray */}
        {selectedIds.size > 0 && (
            <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[80] animate-in slide-in-from-bottom-10 duration-500 pointer-events-none">
                <div className="pointer-events-auto bg-slate-900/90 dark:bg-white/90 backdrop-blur-2xl px-6 py-4 rounded-[2.5rem] border border-white/10 dark:border-slate-200 shadow-2xl flex items-center gap-6">
                    <div className="flex items-center gap-3 pr-6 border-r border-white/10 dark:border-slate-200">
                        <div className="w-10 h-10 bg-primary-600 rounded-full flex items-center justify-center text-white font-black text-sm shadow-glow">{selectedIds.size}</div>
                        <div>
                            <p className="text-xs font-black text-white dark:text-slate-900 uppercase tracking-widest">{t('selected')}</p>
                            <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase">项记录已入选</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <button onClick={handleExport} className="flex flex-col items-center gap-1 group">
                            <div className="p-3 bg-white/5 dark:bg-slate-100 rounded-2xl text-white dark:text-slate-700 hover:bg-primary-600 hover:text-white transition-all group-hover:scale-110 active:scale-95"><Download size={20} /></div>
                            <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase">生成报告</span>
                        </button>
                        <button onClick={() => handleDelete(Array.from(selectedIds))} className="flex flex-col items-center gap-1 group">
                            <div className="p-3 bg-rose-500/10 rounded-2xl text-rose-500 hover:bg-rose-500 hover:text-white transition-all group-hover:scale-110 active:scale-95"><Trash2 size={20} /></div>
                            <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase">同步删除</span>
                        </button>
                        <button onClick={() => setSelectedIds(new Set())} className="ml-4 p-2 text-slate-500 hover:text-white dark:hover:text-slate-900"><X size={20} /></button>
                    </div>
                </div>
            </div>
        )}
      </div>

      <ImportModal isOpen={isImportOpen} onClose={() => setIsImportOpen(false)} onImport={handleImportData} />
      <ProfileModal isOpen={isProfileOpen} onClose={() => setIsProfileOpen(false)} user={currentUser} onSave={(u) => setCurrentUser({...currentUser, ...u})} />
      <AdminModal isOpen={isAdminOpen} onClose={() => setIsAdminOpen(false)} />
      <ProductDetailDrawer product={viewingProduct} onClose={() => setViewingProduct(null)} onCategoryClick={setSelectedCategoryId} />

      {activeView !== 'ai' && (
          <AIAssistant 
            contextData={filteredData} 
            onGradeClick={handleAIGradeClick} 
            onNavigateToChart={() => setActiveView('analytics')}
          />
      )}
    </div>
  );
};

const App: React.FC = () => (
    <LanguageProvider><ThemeProvider><AppContent /></ThemeProvider></LanguageProvider>
);

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Search, SlidersHorizontal, Upload, Moon, Sun, Globe, User, LogOut, Settings, Shield, History, X, Clock, Download, Loader2, ArrowRight, Filter, ChevronDown, Sparkles, Hash, Beaker, Check, LayoutGrid, BarChart2 } from 'lucide-react';
import { ColumnConfig, ViewMode, User as UserType } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import { useTheme } from '../contexts/ThemeContext';

interface TopBarProps {
  user: UserType | null;
  onLogout: () => void;
  onOpenProfile: () => void;
  onOpenAdmin: () => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  isSearching?: boolean;
  columns: ColumnConfig[];
  onToggleColumn: (key: string) => void;
  onToggleAllColumns: (visible: boolean) => void;
  onOpenImport: () => void;
  onExport: () => void;
  isExporting: boolean;
  viewMode: ViewMode;
  onViewModeChange: (mode: ViewMode) => void;
  showAdvancedFilters: boolean;
  onToggleFilters: () => void;
  activeFilterCount: number;
}

export const TopBar: React.FC<TopBarProps> = ({
  user, onLogout, onOpenProfile, onOpenAdmin, searchQuery, onSearchChange, isSearching, columns, onToggleColumn, onToggleAllColumns, onOpenImport, onExport, isExporting, viewMode, onViewModeChange, showAdvancedFilters, onToggleFilters, activeFilterCount
}) => {
  const [isColumnMenuOpen, setIsColumnMenuOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const { t, language, toggleLanguage, tProp } = useLanguage();
  const { theme, toggleTheme } = useTheme();
  const inputRef = useRef<HTMLInputElement>(null);

  const colMenuRef = useRef<HTMLDivElement>(null);
  const userMenuRef = useRef<HTMLDivElement>(null);

  const [searchHistory, setSearchHistory] = useState<string[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Advanced Filtering Syntax Suggestions
  const filterSuggestions = useMemo(() => {
      const parts = searchQuery.split(' ');
      const lastToken = parts[parts.length - 1];
      if (lastToken.includes(':')) return [];

      const availableProps = columns
          .filter(c => !c.isSystem)
          .map(c => ({
              key: c.key,
              label: tProp(c.label)
          }));

      if (!lastToken) return availableProps.slice(0, 5);

      return availableProps.filter(p => 
          p.label.toLowerCase().includes(lastToken.toLowerCase()) ||
          p.key.toLowerCase().includes(lastToken.toLowerCase())
      ).slice(0, 5);
  }, [columns, searchQuery, tProp]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); inputRef.current?.focus(); }
    };
    const handleClickOutside = (e: MouseEvent) => {
        if (colMenuRef.current && !colMenuRef.current.contains(e.target as Node)) setIsColumnMenuOpen(false);
        if (userMenuRef.current && !userMenuRef.current.contains(e.target as Node)) setIsUserMenuOpen(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    document.addEventListener('mousedown', handleClickOutside);
    const savedHistory = localStorage.getItem('resindb_search_history');
    if (savedHistory) try { setSearchHistory(JSON.parse(savedHistory)); } catch (e) {}
    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const saveToHistory = (query: string) => {
      const clean = query.trim();
      if (!clean) return;
      setSearchHistory(prev => {
          const filtered = prev.filter(item => item !== clean);
          const updated = [clean, ...filtered].slice(0, 8);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const removeFromHistory = (e: React.MouseEvent, query: string) => {
      e.stopPropagation();
      setSearchHistory(prev => {
          const updated = prev.filter(item => item !== query);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const handleInputKeyDown = (e: React.KeyboardEvent) => {
      const totalItems = searchHistory.length + filterSuggestions.length;
      if (showHistory && totalItems > 0) {
          if (e.key === 'ArrowDown') { e.preventDefault(); setHistoryIndex(prev => (prev + 1) % totalItems); return; }
          if (e.key === 'ArrowUp') { e.preventDefault(); setHistoryIndex(prev => (prev - 1 + totalItems) % totalItems); return; }
      }
      if (e.key === 'Enter') {
          e.preventDefault();
          if (historyIndex >= 0 && showHistory) {
              if (historyIndex < filterSuggestions.length) { 
                  applySuggestion(filterSuggestions[historyIndex].label); 
              } else { 
                  const histItem = searchHistory[historyIndex - filterSuggestions.length];
                  onSearchChange(histItem);
                  saveToHistory(histItem);
              }
              setHistoryIndex(-1); setShowHistory(false);
          } else { 
              saveToHistory(searchQuery); setShowHistory(false); setHistoryIndex(-1); inputRef.current?.blur(); 
          }
      }
      if (e.key === 'Escape') { setShowHistory(false); setHistoryIndex(-1); inputRef.current?.blur(); }
  };

  const applySuggestion = (label: string) => {
      const parts = searchQuery.split(' ');
      parts[parts.length - 1] = `${label}:`;
      const newQuery = parts.join(' ');
      onSearchChange(newQuery);
      inputRef.current?.focus();
      setHistoryIndex(-1);
  };

  return (
    <div className="w-full flex flex-col gap-2 px-6 py-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl border-b border-slate-200 dark:border-slate-800 shadow-sm relative z-[100]">
      <div className="flex items-center justify-between gap-6">
        {/* Search Bar Container */}
        <div className="flex-1 max-w-3xl relative z-[150]">
            <div className="relative group transition-all duration-300">
                <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                    {isSearching ? <Loader2 className="text-primary-500 animate-spin" size={18} /> : <Search className="text-slate-400 group-focus-within:text-primary-500 transition-colors" size={18} />}
                </div>
                <input
                    ref={inputRef}
                    type="text"
                    value={searchQuery}
                    onChange={(e) => { onSearchChange(e.target.value); setHistoryIndex(-1); }}
                    onFocus={() => { setShowHistory(true); setHistoryIndex(-1); }}
                    onBlur={() => setTimeout(() => setShowHistory(false), 200)}
                    onKeyDown={handleInputKeyDown}
                    placeholder={t('searchPlaceholder')}
                    className="block w-full pl-12 pr-12 py-3.5 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-2xl text-sm font-medium shadow-inner outline-none focus:ring-4 focus:ring-primary-500/10 focus:border-primary-500/30 transition-all text-slate-700 dark:text-slate-200 placeholder:text-slate-400"
                />
                <div className="absolute inset-y-0 right-5 flex items-center gap-2">
                    {searchQuery && (
                        <button onClick={() => onSearchChange('')} className="p-1 text-slate-400 hover:text-slate-600 transition-colors"><X size={14} /></button>
                    )}
                </div>

                {/* Search History & Suggestions Popover - CRITICAL: High Z-Index */}
                {showHistory && (searchHistory.length > 0 || filterSuggestions.length > 0) && (
                    <div className="absolute top-full left-0 right-0 mt-3 bg-white dark:bg-slate-900 backdrop-blur-2xl border border-slate-200 dark:border-slate-800 rounded-[2rem] shadow-2xl overflow-hidden z-[200] animate-in fade-in slide-in-from-top-2 duration-300 ring-1 ring-slate-200 dark:ring-slate-700">
                        {filterSuggestions.length > 0 && (
                            <div className="py-2">
                                <div className="px-5 py-2 flex justify-between items-center">
                                    <span className="text-[10px] font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest flex items-center gap-1.5">
                                        <Beaker size={10} /> {t('properties')} 语法助手
                                    </span>
                                </div>
                                {filterSuggestions.map((sugg, idx) => (
                                    <div 
                                        key={`sugg-${idx}`} 
                                        onMouseDown={(e) => { e.preventDefault(); applySuggestion(sugg.label); }} 
                                        className={`w-full flex items-center justify-between px-5 py-2.5 cursor-pointer transition-colors ${idx === historyIndex ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-700 dark:text-emerald-300' : 'hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400'}`}
                                    >
                                        <div className="flex items-center gap-3">
                                            <Hash size={14} className="text-emerald-400" />
                                            <span className="text-sm font-bold">{sugg.label}</span>
                                        </div>
                                        <ArrowRight size={14} className="text-emerald-200 opacity-0 group-hover:opacity-100 transition-opacity" />
                                    </div>
                                ))}
                            </div>
                        )}
                        {searchHistory.length > 0 && (
                            <div className="py-2 border-t border-slate-100 dark:border-slate-800">
                                <div className="px-5 py-2 flex justify-between items-center text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                                    <span>{t('recentSearches')}</span>
                                    <button onMouseDown={(e) => { e.preventDefault(); setSearchHistory([]); localStorage.removeItem('resindb_search_history'); }} className="text-rose-500 hover:underline">{t('clearHistory')}</button>
                                </div>
                                {searchHistory.map((query, idx) => {
                                    const actualIdx = idx + filterSuggestions.length;
                                    return (
                                        <div 
                                            key={`hist-${idx}`} 
                                            onMouseDown={() => { onSearchChange(query); setShowHistory(false); saveToHistory(query); }} 
