import * as echarts from 'echarts';

// Chart 4: Rheology Viscosity Curve Option Configuration
// Fix: Updated signature to accept optional 'temps' array to match usage in ScientificChart
export const getRheologyChartOption = (products: any[], theme: 'light' | 'dark', temps: number[] = [190, 210, 230]): echarts.EChartsOption => {
  const isDark = theme === 'dark';
  const colorPalette = ['#0284c7', '#06b6d4', '#14b8a6', '#6366f1', '#f59e0b'];
  const gridColor = isDark ? '#334155' : '#e0e0e0';
  const axisColor = isDark ? '#94a3b8' : '#333333';

  // Cross Model Simulation based on MFR
  const generateData = (mfr: number, tempOffset: number) => {
    const data = [];
    // Base Zero Shear Viscosity modified by Temp
    const eta0 = (30000 * Math.pow(mfr, -0.8)) * Math.exp(tempOffset * -0.02);
    const n = 0.45; // Shear thinning index

    for (let i = 0; i <= 4; i += 0.2) { // 10^0 to 10^4
      const rate = Math.pow(10, i);
      const viscosity = eta0 / (1 + Math.pow(rate * 0.05, 1 - n));
      data.push([rate, viscosity]);
    }
    return data;
  };

  const series = products.flatMap((p: any, idx: number) => {
      const mfr = parseFloat(p.properties['熔体质量流动速率']?.value || 5);
      const safeMfr = isNaN(mfr) ? 5 : mfr;
      const baseColor = colorPalette[idx % colorPalette.length];

      // Fix: Use provided temps. If multiple products, typically only the first temperature is shown to maintain chart clarity
      const tempsToUse = products.length === 1 ? temps : [temps[0] || 190];

      return tempsToUse.map((temp, tIdx) => ({
          name: `${p.gradeName} @ ${temp}°C`,
          type: 'line',
          smooth: true,
          showSymbol: false,
          data: generateData(safeMfr, temp - 190),
          lineStyle: { 
            width: tIdx === 0 ? 3 : 2, 
            type: tIdx === 0 ? 'solid' : (tIdx === 1 ? 'dashed' : 'dotted'), 
            color: baseColor, 
            opacity: tIdx === 0 ? 1 : (tIdx === 1 ? 0.7 : 0.5) 
          }
      }));
  });

  return {
    backgroundColor: 'transparent',
    color: colorPalette,
    title: {
      text: '流变行为曲线 (Rheology Curve)',
      subtext: 'Double Log Plot: Shear Rate vs Viscosity',
      left: 'center',
      textStyle: { color: isDark ? '#e2e8f0' : '#333333', fontSize: 16 }
    },
    tooltip: {
      trigger: 'axis',
      confine: true,
      formatter: (params: any) => {
        let html = `<div>Shear Rate: <b>${params[0].value[0].toExponential(2)}</b> s⁻¹</div>`;
        params.forEach((item: any) => {
          html += `<div style="color:${item.color}">${item.seriesName}: <b>${item.value[1].toExponential(2)}</b> Pa·s</div>`;
        });
        return html;
      }
    },
    legend: {
      bottom: 5,
      type: 'scroll',
      textStyle: { color: axisColor }
    },
    grid: {
      containLabel: true,
      left: '8%',
      right: '15%',
      bottom: '12%'
    },
    dataZoom: [
        { type: 'inside', xAxisIndex: 0 },
        { type: 'inside', yAxisIndex: 0 }
    ],
    xAxis: {
      type: 'log',
      name: 'Shear Rate (γ̇) [s⁻¹]',
      nameLocation: 'middle',
      nameGap: 30,
      min: 1,
      max: 10000,
      logBase: 10,
      splitLine: { show: true, lineStyle: { color: gridColor, type: 'dashed' } },
      axisLabel: { color: axisColor, formatter: (v: number) => `10^${Math.log10(v)}` },
      axisLine: { lineStyle: { color: '#888' } }
    },
    yAxis: {
      type: 'log',
      name: 'Viscosity (η) [Pa·s]',
      nameLocation: 'middle',
      nameGap: 50,
      logBase: 10,
      splitLine: { show: true, lineStyle: { color: gridColor, type: 'dashed' } },
      axisLabel: { color: axisColor, formatter: (v: number) => `10^${Math.log10(v)}` },
      axisLine: { lineStyle: { color: '#888' } }
    },
    series: series as any[]
  };
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Search, SlidersHorizontal, Upload, Moon, Sun, Globe, User, LogOut, Settings, Shield, History, X, Clock, Download, Loader2, ArrowRight, Filter, ChevronDown, Sparkles, Hash, Beaker, Check, LayoutGrid, BarChart2, CheckSquare, Square } from 'lucide-react';
import { ColumnConfig, ViewMode, User as UserType } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import { useTheme } from '../contexts/ThemeContext';

interface TopBarProps {
  user: UserType | null;
  onLogout: () => void;
  onOpenProfile: () => void;
  onOpenAdmin: () => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  isSearching?: boolean;
  columns: ColumnConfig[];
  onToggleColumn: (key: string) => void;
  onToggleAllColumns: (visible: boolean) => void;
  onOpenImport: () => void;
  onExport: () => void;
  isExporting: boolean;
  viewMode: ViewMode;
  onViewModeChange: (mode: ViewMode) => void;
  showAdvancedFilters: boolean;
  onToggleFilters: () => void;
  activeFilterCount: number;
}

export const TopBar: React.FC<TopBarProps> = ({
  user, onLogout, onOpenProfile, onOpenAdmin, searchQuery, onSearchChange, isSearching, columns, onToggleColumn, onToggleAllColumns, onOpenImport, onExport, isExporting, viewMode, onViewModeChange, showAdvancedFilters, onToggleFilters, activeFilterCount
}) => {
  const [isColumnMenuOpen, setIsColumnMenuOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const { t, language, toggleLanguage, tProp } = useLanguage();
  const { theme, toggleTheme } = useTheme();
  const inputRef = useRef<HTMLInputElement>(null);

  const colMenuRef = useRef<HTMLDivElement>(null);
  const userMenuRef = useRef<HTMLDivElement>(null);

  const [searchHistory, setSearchHistory] = useState<string[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Advanced Filtering Syntax Suggestions
  const filterSuggestions = useMemo(() => {
      const parts = searchQuery.split(' ');
      const lastToken = parts[parts.length - 1];
      if (lastToken.includes(':')) return [];

      const availableProps = columns
          .filter(c => !c.isSystem)
          .map(c => ({
              key: c.key,
              label: tProp(c.label)
          }));

      if (!lastToken) return availableProps.slice(0, 5);

      return availableProps.filter(p => 
          p.label.toLowerCase().includes(lastToken.toLowerCase()) ||
          p.key.toLowerCase().includes(lastToken.toLowerCase())
      ).slice(0, 5);
  }, [columns, searchQuery, tProp]);

  // Check if all dynamic columns are currently visible
  const areAllDynamicVisible = useMemo(() => {
    const dynamicCols = columns.filter(c => !c.isSystem);
    return dynamicCols.length > 0 && dynamicCols.every(c => c.visible);
  }, [columns]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); inputRef.current?.focus(); }
    };
    const handleClickOutside = (e: MouseEvent) => {
        if (colMenuRef.current && !colMenuRef.current.contains(e.target as Node)) setIsColumnMenuOpen(false);
        if (userMenuRef.current && !userMenuRef.current.contains(e.target as Node)) setIsUserMenuOpen(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    document.addEventListener('mousedown', handleClickOutside);
    const savedHistory = localStorage.getItem('resindb_search_history');
    if (savedHistory) try { setSearchHistory(JSON.parse(savedHistory)); } catch (e) {}
    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const saveToHistory = (query: string) => {
      const clean = query.trim();
      if (!clean) return;
      setSearchHistory(prev => {
          const filtered = prev.filter(item => item !== clean);
          const updated = [clean, ...filtered].slice(0, 8);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const removeFromHistory = (e: React.MouseEvent, query: string) => {
      e.stopPropagation();
      setSearchHistory(prev => {
          const updated = prev.filter(item => item !== query);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const handleInputKeyDown = (e: React.KeyboardEvent) => {
      const totalItems = searchHistory.length + filterSuggestions.length;
      if (showHistory && totalItems > 0) {
          if (e.key === 'ArrowDown') { e.preventDefault(); setHistoryIndex(prev => (prev + 1) % totalItems); return; }
          if (e.key === 'ArrowUp') { e.preventDefault(); setHistoryIndex(prev => (prev - 1 + totalItems) % totalItems); return; }
      }
      if (e.key === 'Enter') {
          e.preventDefault();
          if (historyIndex >= 0 && showHistory) {
              if (historyIndex < filterSuggestions.length) { 
                  applySuggestion(filterSuggestions[historyIndex].label); 
              } else { 
                  const histItem = searchHistory[historyIndex - filterSuggestions.length];
                  onSearchChange(histItem);
                  saveToHistory(histItem);
              }
              setHistoryIndex(-1); setShowHistory(false);
          } else { 
              saveToHistory(searchQuery); setShowHistory(false); setHistoryIndex(-1); inputRef.current?.blur(); 
          }
      }
      if (e.key === 'Escape') { setShowHistory(false); setHistoryIndex(-1); inputRef.current?.blur(); }
  };

  const applySuggestion = (label: string) => {
      const parts = searchQuery.split(' ');
      parts[parts.length - 1] = `${label}:`;
      const newQuery = parts.join(' ');
      onSearchChange(newQuery);
      inputRef.current?.focus();
      setHistoryIndex(-1);
  };

  return (
    <div className="w-full flex flex-col gap-2 px-6 py-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl border-b border-slate-200 dark:border-slate-800 shadow-sm relative z-[100]">
      <div className="flex items-center justify-between gap-6">
        {/* Search Bar Container */}
        <div className="flex-1 max-w-3xl relative z-[150]">
            <div className="relative group transition-all duration-300">
                <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                    {isSearching ? <Loader2 className="text-primary-500 animate-spin" size={18} /> : <Search className="text-slate-400 group-focus-within:text-primary-500 transition-colors" size={18} />}
                </div>
                <input
                    ref={inputRef}
                    type="text"
                    value={searchQuery}
                    onChange={(e) => { onSearchChange(e.target.value); setHistoryIndex(-1); }}
                    onFocus={() => { setShowHistory(true); setHistoryIndex(-1); }}
                    onBlur={() => setTimeout(() => setShowHistory(false), 200)}
                    onKeyDown={handleInputKeyDown}
                    placeholder={t('searchPlaceholder')}
                    className="block w-full pl-12 pr-12 py-3.5 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-2xl text-sm font-medium shadow-inner outline-none focus:ring-4 focus:ring-primary-500/10 focus:border-primary-500/30 transition-all text-slate-700 dark:text-slate-200 placeholder:text-slate-400"
                />
                <div className="absolute inset-y-0 right-5 flex items-center gap-2">
                    {searchQuery && (
                        <button onClick={() => onSearchChange('')} className="p-1 text-slate-400 hover:text-slate-600 transition-colors"><X size={14} /></button>
                    )}
                </div>

                {/* Search History & Suggestions Popover */}
                {showHistory && (searchHistory.length > 0 || filterSuggestions.length > 0) && (
                    <div className="absolute top-full left-0 right-0 mt-3 bg-white dark:bg-slate-900 backdrop-blur-2xl border border-slate-200 dark:border-slate-800 rounded-[2rem] shadow-2xl overflow-hidden z-[200] animate-in fade-in slide-in-from-top-2 duration-300 ring-1 ring-slate-200 dark:ring-slate-700">
                        {filterSuggestions.length > 0 && (
                            <div className="py-2">
                                <div className="px-5 py-2 flex justify-between items-center">
                                    <span className="text-[10px] font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest flex items-center gap-1.5">
                                        <Beaker size={10} /> {t('properties')} 语法助手
                                    </span>
                                </div>
                                {filterSuggestions.map((sugg, idx) => (
                                    <div 
                                        key={`sugg-${idx}`} 
                                        onMouseDown={(e) => { e.preventDefault(); applySuggestion(sugg.label); }} 
                                        className={`w-full flex items-center justify-between px-5 py-2.5 cursor-pointer transition-colors ${idx === historyIndex ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-700 dark:text-emerald-300' : 'hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400'}`}
                                    >
                                        <div className="flex items-center gap-3">
                                            <Hash size={14} className="text-emerald-400" />
                                            <span className="text-sm font-bold">{sugg.label}</span>
                                        </div>
                                        <ArrowRight size={14} className="text-emerald-200 opacity-0 group-hover:opacity-100 transition-opacity" />
                                    </div>
                                ))}
                            </div>
                        )}
                        {searchHistory.length > 0 && (
                            <div className="py-2 border-t border-slate-100 dark:border-slate-800">
                                <div className="px-5 py-2 flex justify-between items-center text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                                    <span>{t('recentSearches')}</span>
                                    <button onMouseDown={(e) => { e.preventDefault(); setSearchHistory([]); localStorage.removeItem('resindb_search_history'); }} className="text-rose-500 hover:underline">{t('clearHistory')}</button>
                                </div>
                                {searchHistory.map((query, idx) => {
                                    const actualIdx = idx + filterSuggestions.length;
                                    return (
                                        <div 
                                            key={`hist-${idx}`} 
                                            onMouseDown={() => { onSearchChange(query); setShowHistory(false); saveToHistory(query); }} 
                                            className={`group w-full flex items-center justify-between px-5 py-2.5 cursor-pointer transition-colors ${actualIdx === historyIndex ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300' : 'hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400'}`}
                                        >
                                            <div className="flex items-center gap-3">
                                                <History size={14} className="text-slate-400" />
                                                <span className="text-sm font-medium">{query}</span>
                                            </div>
                                            <button onMouseDown={(e) => removeFromHistory(e, query)} className="p-1.5 opacity-0 group-hover:opacity-100 text-slate-300 hover:text-rose-500 rounded-lg"><X size={14}/></button>
                                        </div>
                                    );
                                })}
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>

        {/* Action Controls */}
        <div className="flex items-center gap-3">
            <div className="h-10 bg-slate-100 dark:bg-slate-800 rounded-2xl p-1 flex items-center shadow-inner">
                <button onClick={() => onViewModeChange('grid')} className={`px-4 py-1.5 rounded-xl text-xs font-black transition-all flex items-center gap-2 ${viewMode === 'grid' ? 'bg-white dark:bg-slate-900 text-primary-600 shadow-md scale-[1.02]' : 'text-slate-400 hover:text-slate-600'}`}>
                    <LayoutGrid size={14}/> {t('viewList')}
                </button>
                <button onClick={() => onViewModeChange('chart')} className={`px-4 py-1.5 rounded-xl text-xs font-black transition-all flex items-center gap-2 ${viewMode === 'chart' ? 'bg-white dark:bg-slate-900 text-primary-600 shadow-md scale-[1.02]' : 'text-slate-400 hover:text-slate-600'}`}>
                    <BarChart2 size={14}/> {t('viewChart')}
                </button>
            </div>

            <div className="relative" ref={colMenuRef}>
                <button onClick={() => setIsColumnMenuOpen(!isColumnMenuOpen)} className={`h-10 px-4 flex items-center gap-2 rounded-2xl border transition-all ${isColumnMenuOpen ? 'bg-primary-50 border-primary-200 text-primary-600' : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 text-slate-600 dark:text-slate-300 hover:border-primary-300 shadow-sm'}`}>
                    <SlidersHorizontal size={16} />
                    <span className="text-xs font-bold">{t('configureColumns')}</span>
                    <ChevronDown size={14} className={`transition-transform duration-300 ${isColumnMenuOpen ? 'rotate-180' : ''}`} />
                </button>

                {/* Column Popover - CRITICAL: High Z-Index */}
                {isColumnMenuOpen && (
                    <div className="absolute right-0 top-full mt-3 w-80 bg-white dark:bg-slate-900 backdrop-blur-2xl border border-slate-200 dark:border-slate-800 rounded-[2rem] shadow-2xl overflow-hidden z-[200] animate-in zoom-in-95 duration-200 ring-1 ring-slate-200 dark:ring-slate-700">
                        <div className="p-5 border-b border-slate-50 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-950/50 flex items-center justify-between">
                            <h4 className="text-xs font-black text-slate-500 uppercase tracking-widest">{t('configureColumns')}</h4>
                            <button 
                                onClick={() => onToggleAllColumns(!areAllDynamicVisible)}
                                className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-[10px] font-black uppercase tracking-wider text-primary-600 hover:border-primary-300 transition-all"
                            >
                                {areAllDynamicVisible ? <Square size={12} /> : <CheckSquare size={12} />}
                                {areAllDynamicVisible ? t('deselectAll') : t('selectAll')}
                            </button>
                        </div>
                        <div className="max-h-80 overflow-y-auto custom-scrollbar p-2">
                            {columns.map(col => (
                                <button key={col.key} onClick={() => onToggleColumn(col.key)} className="w-full flex items-center justify-between p-3 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors group">
                                    <span className={`text-xs font-medium ${col.visible ? 'text-slate-800 dark:text-slate-200' : 'text-slate-400'}`}>{tProp(col.label)}</span>
                                    <div className={`w-5 h-5 rounded-md border flex items-center justify-center transition-all ${col.visible ? 'bg-primary-600 border-primary-600 text-white' : 'border-slate-200 dark:border-slate-700'}`}>
                                        {col.visible && <Check size={14} />}
                                    </div>
                                </button>
                            ))}
                        </div>
                    </div>
                )}
            </div>

            <button onClick={onOpenImport} className="h-10 px-4 bg-primary-600 hover:bg-primary-500 text-white rounded-2xl flex items-center gap-2 shadow-lg shadow-primary-500/20 transition-all active:scale-95">
                <Upload size={16} />
                <span className="text-xs font-bold uppercase tracking-tight">{t('importData')}</span>
            </button>

            {/* User Menu */}
            <div className="relative ml-2" ref={userMenuRef}>
                <button onClick={() => setIsUserMenuOpen(!isUserMenuOpen)} className="w-10 h-10 rounded-2xl bg-slate-100 dark:bg-slate-800 border-2 border-white dark:border-slate-700 overflow-hidden shadow-sm hover:scale-105 transition-all focus:ring-4 focus:ring-primary-500/10">
                    <img src={user?.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user?.name}`} alt="" className="w-full h-full object-cover" />
                </button>
                {isUserMenuOpen && (
                    <div className="absolute right-0 top-full mt-3 w-56 bg-white dark:bg-slate-900 backdrop-blur-2xl border border-slate-200 dark:border-slate-800 rounded-[2rem] shadow-2xl overflow-hidden z-[200] animate-in slide-in-from-top-2 duration-200 ring-1 ring-slate-200 dark:ring-slate-700">
                        <div className="p-5 border-b border-slate-50 dark:border-slate-800">
                            <p className="text-sm font-black text-slate-800 dark:text-white leading-none">{user?.name}</p>
                            <p className="text-[10px] text-slate-400 mt-1 font-bold uppercase tracking-widest">{user?.role}</p>
                        </div>
                        <div className="p-2 space-y-1">
                            <button onClick={() => { onOpenProfile(); setIsUserMenuOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-xs font-bold text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
                                <Settings size={14} /> {t('profile')}
                            </button>
                            {user?.role === 'admin' && (
                                <button onClick={() => { onOpenAdmin(); setIsUserMenuOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-xs font-bold text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
                                    <Shield size={14} /> {t('adminPanel')}
                                </button>
                            )}
                            <div className="flex items-center justify-between px-4 py-2 text-xs font-bold text-slate-600 dark:text-slate-400 border-t border-slate-50 dark:border-slate-800 mt-1 pt-3">
                                <button onClick={toggleTheme} className="flex-1 flex items-center justify-center p-2 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
                                    {theme === 'dark' ? <Sun size={16} /> : <Moon size={16} />}
                                </button>
                                <button onClick={toggleLanguage} className="flex-1 flex items-center justify-center p-2 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
                                    <Globe size={16} />
                                </button>
                            </div>
                            <button onClick={onLogout} className="w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-xs font-bold text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 transition-colors">
                                <LogOut size={14} /> {t('logout')}
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Search, SlidersHorizontal, Upload, Moon, Sun, Globe, User, LogOut, Settings, Shield, History, X, Clock, Download, Loader2, ArrowRight, Filter, ChevronDown, Sparkles, Hash, Beaker, Check, LayoutGrid, BarChart2, CheckSquare, Square } from 'lucide-react';
import { ColumnConfig, ViewMode, User as UserType } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import { useTheme } from '../contexts/ThemeContext';

interface TopBarProps {
  user: UserType | null;
  onLogout: () => void;
  onOpenProfile: () => void;
  onOpenAdmin: () => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  isSearching?: boolean;
  columns: ColumnConfig[];
  onToggleColumn: (key: string) => void;
  onToggleAllColumns: (visible: boolean) => void;
  onOpenImport: () => void;
  onExport: () => void;
  isExporting: boolean;
  viewMode: ViewMode;
  onViewModeChange: (mode: ViewMode) => void;
  showAdvancedFilters: boolean;
  onToggleFilters: () => void;
  activeFilterCount: number;
}

export const TopBar: React.FC<TopBarProps> = ({
  user, onLogout, onOpenProfile, onOpenAdmin, searchQuery, onSearchChange, isSearching, columns, onToggleColumn, onToggleAllColumns, onOpenImport, onExport, isExporting, viewMode, onViewModeChange, showAdvancedFilters, onToggleFilters, activeFilterCount
}) => {
  const [isColumnMenuOpen, setIsColumnMenuOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const { t, language, toggleLanguage, tProp } = useLanguage();
  const { theme, toggleTheme } = useTheme();
  const inputRef = useRef<HTMLInputElement>(null);

  const colMenuRef = useRef<HTMLDivElement>(null);
  const userMenuRef = useRef<HTMLDivElement>(null);

  const [searchHistory, setSearchHistory] = useState<string[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Advanced Filtering Syntax Suggestions
  const filterSuggestions = useMemo(() => {
      const parts = searchQuery.split(' ');
      const lastToken = parts[parts.length - 1];
      if (lastToken.includes(':')) return [];

      const availableProps = columns
          .filter(c => !c.isSystem)
          .map(c => ({
              key: c.key,
              label: tProp(c.label)
          }));

      if (!lastToken) return availableProps.slice(0, 5);

      return availableProps.filter(p => 
          p.label.toLowerCase().includes(lastToken.toLowerCase()) ||
          p.key.toLowerCase().includes(lastToken.toLowerCase())
      ).slice(0, 5);
  }, [columns, searchQuery, tProp]);

  // Check if all dynamic columns are currently visible
  const areAllDynamicVisible = useMemo(() => {
    const dynamicCols = columns.filter(c => !c.isSystem);
    return dynamicCols.length > 0 && dynamicCols.every(c => c.visible);
  }, [columns]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); inputRef.current?.focus(); }
    };
    const handleClickOutside = (e: MouseEvent) => {
        if (colMenuRef.current && !colMenuRef.current.contains(e.target as Node)) setIsColumnMenuOpen(false);
        if (userMenuRef.current && !userMenuRef.current.contains(e.target as Node)) setIsUserMenuOpen(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    document.addEventListener('mousedown', handleClickOutside);
    const savedHistory = localStorage.getItem('resindb_search_history');
    if (savedHistory) try { setSearchHistory(JSON.parse(savedHistory)); } catch (e) {}
    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const saveToHistory = (query: string) => {
      const clean = query.trim();
      if (!clean) return;
      setSearchHistory(prev => {
          const filtered = prev.filter(item => item !== clean);
          const updated = [clean, ...filtered].slice(0, 8);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const removeFromHistory = (e: React.MouseEvent, query: string) => {
      e.stopPropagation();
      setSearchHistory(prev => {
          const updated = prev.filter(item => item !== query);
          localStorage.setItem('resindb_search_history', JSON.stringify(updated));
          return updated;
      });
  };

  const handleInputKeyDown = (e: React.KeyboardEvent) => {
      const totalItems = searchHistory.length + filterSuggestions.length;
      if (showHistory && totalItems > 0) {
          if (e.key === 'ArrowDown') { e.preventDefault(); setHistoryIndex(prev => (prev + 1) % totalItems); return; }
          if (e.key === 'ArrowUp') { e.preventDefault(); setHistoryIndex(prev => (prev - 1 + totalItems) % totalItems); return; }
      }
      if (e.key === 'Enter') {
          e.preventDefault();
          if (historyIndex >= 0 && showHistory) {
              if (historyIndex < filterSuggestions.length) { 
                  applySuggestion(filterSuggestions[historyIndex].label); 
              } else { 
                  const histItem = searchHistory[historyIndex - filterSuggestions.length];
                  onSearchChange(histItem);
                  saveToHistory(histItem);
              }
              setHistoryIndex(-1); setShowHistory(false);
          } else { 
              saveToHistory(searchQuery); setShowHistory(false); setHistoryIndex(-1); inputRef.current?.blur(); 
          }
      }
      if (e.key === 'Escape') { setShowHistory(false); setHistoryIndex(-1); inputRef.current?.blur(); }
  };

  const applySuggestion = (label: string) => {
      const parts = searchQuery.split(' ');
      parts[parts.length - 1] = `${label}:`;
      const newQuery = parts.join(' ');
      onSearchChange(newQuery);
      inputRef.current?.focus();
      setHistoryIndex(-1);
  };

  return (
    <div className="w-full flex flex-col gap-2 px-6 py-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl border-b border-slate-200 dark:border-slate-800 shadow-sm relative z-[100]">
      <div className="flex items-center justify-between gap-6">
        {/* Search Bar Container */}
        <div className="flex-1 max-w-3xl relative z-[150]">
            <div className="relative group transition-all duration-300">
                <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                    {isSearching ? <Loader2 className="text-primary-500 animate-spin" size={18} /> : <Search className="text-slate-400 group-focus-within:text-primary-500 transition-colors" size={18} />}
                </div>
                <input
                    ref={inputRef}
                    type="text"
                    value={searchQuery}
                    onChange={(e) => { onSearchChange(e.target.value); setHistoryIndex(-1); }}
                    onFocus={() => { setShowHistory(true); setHistoryIndex(-1); }}
                    onBlur={() => setTimeout(() => setShowHistory(false), 200)}
                    onKeyDown={handleInputKeyDown}
                    placeholder={t('searchPlaceholder')}
                    className="block w-full pl-12 pr-12 py-3.5 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-2xl text-sm font-medium shadow-inner outline-none focus:ring-4 focus:ring-primary-500/10 focus:border-primary-500/30 transition-all text-slate-700 dark:text-slate-200 placeholder:text-slate-400"
                />
                <div className="absolute inset-y-0 right-5 flex items-center gap-2">
                    {searchQuery && (
                        <button onClick={() => onSearchChange('')} className="p-1 text-slate-400 hover:text-slate-600 transition-colors"><X size={14} /></button>
                    )}
                </div>

                {/* Search History & Suggestions Popover */}
                {showHistory && (searchHistory.length > 0 || filterSuggestions.length > 0) && (
                    <div className="absolute top-full left-0 right-0 mt-3 bg-white dark:bg-slate-900 backdrop-blur-2xl border border-slate-200 dark:border-slate-800 rounded-[2rem] shadow-2xl overflow-hidden z-[200] animate-in fade-in slide-in-from-top-2 duration-300 ring-1 ring-slate-200 dark:ring-slate-700">
                        {filterSuggestions.length > 0 && (
                            <div className="py-2">
                                <div className="px-5 py-2 flex justify-between items-center">
                                    <span className="text-[10px] font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest flex items-center gap-1.5">
                                        <Beaker size={10} /> {t('properties')} 语法助手
                                    </span>
                                </div>
                                {filterSuggestions.map((sugg, idx) => (
                                    <div 
                                        key={`sugg-${idx}`} 
                                        onMouseDown={(e) => { e.preventDefault(); applySuggestion(sugg.label); }} 
                                        className={`w-full flex items-center justify-between px-5 py-2.5 cursor-pointer transition-colors ${idx === historyIndex ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-700 dark:text-emerald-300' : 'hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400'}`}
                                    >
                                        <div className="flex items-center gap-3">
                                            <Hash size={14} className="text-emerald-400" />
                                            <span className="text-sm font-bold">{sugg.label}</span>
                                        </div>
                                        <ArrowRight size={14} className="text-emerald-200 opacity-0 group-hover:opacity-100 transition-opacity" />
                                    </div>
                                ))}
                            </div>
                        )}
                        {searchHistory.length > 0 && (
                            <div className="py-2 border-t border-slate-100 dark:border-slate-800">
                                <div className="px-5 py-2 flex justify-between items-center text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                                    <span>{t('recentSearches')}</span>
                                    <button onMouseDown={(e) => { e.preventDefault(); setSearchHistory([]); localStorage.removeItem('resindb_search_history'); }} className="text-rose-500 hover:underline">{t('clearHistory')}</button>
                                </div>
                                {searchHistory.map((query, idx) => {
                                    const actualIdx = idx + filterSuggestions.length;
                                    return (
                                        <div 
                                            key={`hist-${idx}`} 
                                            onMouseDown={() => { onSearchChange(query); setShowHistory(false); saveToHistory(query); }} 
                                            className={`group w-full flex items-center justify-between px-5 py-2.5 cursor-pointer transition-colors ${actualIdx === historyIndex ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300' : 'hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400'}`}
                                        >
                                            <div className="flex items-center gap-3">
                                                <History size={14} className="text-slate-400" />
                                                <span className="text-sm font-medium">{query}</span>
                                            </div>
                                            <button onMouseDown={(e) => removeFromHistory(e, query)} className="p-1.5 opacity-0 group-hover:opacity-100 text-slate-300 hover:text-rose-500 rounded-lg"><X size={14}/></button>
                                        </div>
                                    );
                                })}
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>

        {/* Action Controls */}
        <div className="flex items-center gap-3">
            <div className="h-10 bg-slate-100 dark:bg-slate-800 rounded-2xl p-1 flex items-center shadow-inner">
                <button onClick={() => onViewModeChange('grid')} className={`px-4 py-1.5 rounded-xl text-xs font-black transition-all flex items-center gap-2 ${viewMode === 'grid' ? 'bg-white dark:bg-slate-900 text-primary-600 shadow-md scale-[1.02]' : 'text-slate-400 hover:text-slate-600'}`}>
                    <LayoutGrid size={14}/> {t('viewList')}
                </button>
                <button onClick={() => onViewModeChange('chart')} className={`px-4 py-1.5 rounded-xl text-xs font-black transition-all flex items-center gap-2 ${viewMode === 'chart' ? 'bg-white dark:bg-slate-900 text-primary-600 shadow-md scale-[1.02]' : 'text-slate-400 hover:text-slate-600'}`}>
                    <BarChart2 size={14}/> {t('viewChart')}
                </button>
            </div>

            <div className="relative" ref={colMenuRef}>
                <button onClick={() => setIsColumnMenuOpen(!isColumnMenuOpen)} className={`h-10 px-4 flex items-center gap-2 rounded-2xl border transition-all ${isColumnMenuOpen ? 'bg-primary-50 border-primary-200 text-primary-600' : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 text-slate-600 dark:text-slate-300 hover:border-primary-300 shadow-sm'}`}>
                    <SlidersHorizontal size={16} />
                    <span className="text-xs font-bold">{t('configureColumns')}</span>
                    <ChevronDown size={14} className={`transition-transform duration-300 ${isColumnMenuOpen ? 'rotate-180' : ''}`} />
                </button>

                {/* Column Popover - CRITICAL: High Z-Index */}
                {isColumnMenuOpen && (
                    <div className="absolute right-0 top-full mt-3 w-80 bg-white dark:bg-slate-900 backdrop-blur-2xl border border-slate-200 dark:border-slate-800 rounded-[2rem] shadow-2xl overflow-hidden z-[200] animate-in zoom-in-95 duration-200 ring-1 ring-slate-200 dark:ring-slate-700">
                        <div className="p-5 border-b border-slate-50 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-950/50 flex items-center justify-between">
                            <h4 className="text-xs font-black text-slate-500 uppercase tracking-widest">{t('configureColumns')}</h4>
                            <button 
                                onClick={() => onToggleAllColumns(!areAllDynamicVisible)}
                                className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-primary-600 text-white shadow-lg shadow-primary-500/20 text-[10px] font-black uppercase tracking-wider hover:bg-primary-500 transition-all active:scale-95"
                            >
                                {areAllDynamicVisible ? <Square size={12} /> : <CheckSquare size={12} />}
                                {areAllDynamicVisible ? t('deselectAll') : t('selectAll')}
                            </button>
                        </div>
                        <div className="max-h-80 overflow-y-auto custom-scrollbar p-2">
                            {/* Permanent "Toggle All" Row at the top of scrollable area */}
                            <button 
                                onClick={() => onToggleAllColumns(!areAllDynamicVisible)}
                                className="w-full flex items-center justify-between p-3 rounded-xl bg-slate-50 dark:bg-slate-800/80 mb-1 hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors group"
                            >
                                <span className="text-xs font-black text-primary-600 dark:text-primary-400 uppercase tracking-wider">
                                    {areAllDynamicVisible ? t('deselectAll') : t('selectAll')} 所有指标
                                </span>
                                <div className={`w-5 h-5 rounded-md border-2 flex items-center justify-center transition-all ${areAllDynamicVisible ? 'bg-primary-600 border-primary-600 text-white' : 'border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-900'}`}>
                                    {areAllDynamicVisible && <Check size={14} strokeWidth={3} />}
                                </div>
                            </button>

                            <div className="h-px bg-slate-100 dark:bg-slate-800 my-1 mx-2"></div>

                            {columns.map(col => (
                                <button key={col.key} onClick={() => onToggleColumn(col.key)} className="w-full flex items-center justify-between p-3 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors group">
                                    <span className={`text-xs font-medium ${col.visible ? 'text-slate-800 dark:text-slate-200' : 'text-slate-400'}`}>{tProp(col.label)}</span>
                                    <div className={`w-5 h-5 rounded-md border flex items-center justify-center transition-all ${col.visible ? 'bg-primary-600 border-primary-600 text-white' : 'border-slate-200 dark:border-slate-700'}`}>
                                        {col.visible && <Check size={14} />}
                                    </div>
                                </button>
                            ))}
                        </div>
                    </div>
                )}
            </div>

            <button onClick={onOpenImport} className="h-10 px-4 bg-primary-600 hover:bg-primary-500 text-white rounded-2xl flex items-center gap-2 shadow-lg shadow-primary-500/20 transition-all active:scale-95">
                <Upload size={16} />
                <span className="text-xs font-bold uppercase tracking-tight">{t('importData')}</span>
            </button>

            {/* User Menu */}
            <div className="relative ml-2" ref={userMenuRef}>
                <button onClick={() => setIsUserMenuOpen(!isUserMenuOpen)} className="w-10 h-10 rounded-2xl bg-slate-100 dark:bg-slate-800 border-2 border-white dark:border-slate-700 overflow-hidden shadow-sm hover:scale-105 transition-all focus:ring-4 focus:ring-primary-500/10">
                    <img src={user?.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user?.name}`} alt="" className="w-full h-full object-cover" />
                </button>
                {isUserMenuOpen && (
                    <div className="absolute right-0 top-full mt-3 w-56 bg-white dark:bg-slate-900 backdrop-blur-2xl border border-slate-200 dark:border-slate-800 rounded-[2rem] shadow-2xl overflow-hidden z-[200] animate-in slide-in-from-top-2 duration-200 ring-1 ring-slate-200 dark:ring-slate-700">
                        <div className="p-5 border-b border-slate-50 dark:border-slate-800">
                            <p className="text-sm font-black text-slate-800 dark:text-white leading-none">{user?.name}</p>
                            <p className="text-[10px] text-slate-400 mt-1 font-bold uppercase tracking-widest">{user?.role}</p>
                        </div>
                        <div className="p-2 space-y-1">
                            <button onClick={() => { onOpenProfile(); setIsUserMenuOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-xs font-bold text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
                                <Settings size={14} /> {t('profile')}
                            </button>
                            {user?.role === 'admin' && (
                                <button onClick={() => { onOpenAdmin(); setIsUserMenuOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-xs font-bold text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
                                    <Shield size={14} /> {t('adminPanel')}
                                </button>
                            )}
                            <div className="flex items-center justify-between px-4 py-2 text-xs font-bold text-slate-600 dark:text-slate-400 border-t border-slate-50 dark:border-slate-800 mt-1 pt-3">
                                <button onClick={toggleTheme} className="flex-1 flex items-center justify-center p-2 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
                                    {theme === 'dark' ? <Sun size={16} /> : <Moon size={16} />}
                                </button>
                                <button onClick={toggleLanguage} className="flex-1 flex items-center justify-center p-2 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
                                    <Globe size={16} />
                                </button>
                            </div>
                            <button onClick={onLogout} className="w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-xs font-bold text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 transition-colors">
                                <LogOut size={14} /> {t('logout')}
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

