const SummaryStats: React.FC<{ data: Product[] }> = ({ data }) => {
    const { t, tProp } = useLanguage();
    const [isExpanded, setIsExpanded] = useState(true);

    const stats = useMemo(() => {
        if (!data || data.length === 0) return {
            count: 0, manufacturers: 0, avgDensity: '-', avgMfr: '-', refCoverage: '0'
        };

        const manufacturers = new Set(data.map(p => p.manufacturerId || p.manufacturer)).size;
        let densitySum = 0, densityCount = 0, mfrSum = 0, mfrCount = 0, totalPropsWithRefs = 0, totalPropsCount = 0;

        data.forEach(p => {
            const dVal = p.properties['密度']?.value;
            const d = dVal === undefined || dVal === null ? NaN : parseFloat(String(dVal));
            if (!isNaN(d)) { densitySum += d; densityCount++; }

            const mVal = p.properties['熔体质量流动速率']?.value;
            const m = mVal === undefined || mVal === null ? NaN : parseFloat(String(mVal));
            if (!isNaN(m)) { mfrSum += m; mfrCount++; }

            const props = p.properties || {};
            (Object.values(props) as PropertyValue[]).forEach(prop => {
                totalPropsCount++;
                if (prop?.referenceId) totalPropsWithRefs++;
            });
        });

        return {
            count: data.length,
            manufacturers,
            avgDensity: densityCount ? (densitySum / densityCount).toFixed(3) : '-',
            avgMfr: mfrCount ? (mfrSum / mfrCount).toFixed(2) : '-',
            refCoverage: totalPropsCount > 0 ? ((totalPropsWithRefs / totalPropsCount) * 100).toFixed(1) : '0'
        };
    }, [data]);

    const Card = ({ icon: Icon, colorClass, label, value, sub, delay }: any) => (
        <div className={`relative overflow-hidden bg-white dark:bg-slate-850 rounded-[1.8rem] p-5 shadow-sm border border-slate-100 dark:border-slate-800 transition-all hover:border-primary-200 dark:hover:border-primary-800 hover:shadow-glow group animate-in fade-in slide-in-from-bottom-4 duration-700`} style={{ animationDelay: delay }}>
            <div className={`absolute -top-4 -right-4 p-8 opacity-[0.03] dark:opacity-[0.05] group-hover:scale-110 group-hover:rotate-6 transition-transform duration-500`}>
                <Icon size={100} />
            </div>
            <div className="relative z-10 flex flex-col h-full justify-between">
                <div className="flex items-center gap-3 mb-4">
                    <div className={`w-10 h-10 rounded-2xl flex items-center justify-center ${colorClass} bg-opacity-10 dark:bg-opacity-20`}>
                        <Icon size={18} className={colorClass.replace('bg-', 'text-').replace('text-white', '')} />
                    </div>
                    <span className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">{label}</span>
                </div>
                <div>
                    <div className="text-2xl font-black text-slate-800 dark:text-slate-100 tracking-tighter tabular-nums">{value}</div>
                    <div className="text-[10px] font-bold text-slate-400 mt-1">{sub}</div>
                </div>
            </div>
        </div>
    );

    return (
        <div className="mb-8">
            <div className="flex items-center justify-between mb-4 select-none">
                <button 
                    onClick={() => setIsExpanded(!isExpanded)}
                    className="flex items-center gap-2 group focus:outline-none"
                >
                    <div className={`p-1.5 rounded-lg bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-400 group-hover:text-primary-500 transition-all`}>
                        <ChevronDown size={14} className={`transition-transform duration-300 ${isExpanded ? 'rotate-0' : '-rotate-90'}`} />
                    </div>
                    <span className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest group-hover:text-slate-600 dark:group-hover:text-slate-300 transition-colors">
                        Analytics Overview
                    </span>
                </button>

                {!isExpanded && (
                    <div className="flex items-center gap-2 animate-in fade-in slide-in-from-left-2 duration-300">
                        <div className="px-3 py-1 bg-white dark:bg-slate-800 rounded-full border border-slate-200 dark:border-slate-700 flex items-center gap-2 shadow-sm">
                            <Database size={12} className="text-primary-500" />
                            <span className="text-[10px] font-bold text-slate-600 dark:text-slate-300">{stats.count}</span>
                        </div>
                    </div>
                )}
            </div>

            <div className={`grid grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 gap-4 transition-all duration-500 ease-in-out overflow-hidden ${isExpanded ? 'opacity-100 max-h-[400px]' : 'opacity-0 max-h-0'}`}>
                <Card icon={Database} colorClass="bg-primary-600 text-primary-600" label={t('total')} value={stats.count} sub={tProp('牌号')} delay="0ms" />
                <Card icon={Factory} colorClass="bg-indigo-600 text-indigo-600" label={t('manufacturers')} value={stats.manufacturers} sub="Active Entities" delay="75ms" />
                <Card icon={FlaskConical} colorClass="bg-teal-500 text-teal-500" label={`${t('avg')} ${tProp('密度')}`} value={stats.avgDensity} sub="g/cm³" delay="150ms" />
                <Card icon={TrendingUp} colorClass="bg-amber-500 text-amber-500" label={`${t('avg')} MFR`} value={stats.avgMfr} sub="g/10min" delay="225ms" />

                <div className="hidden xl:flex relative overflow-hidden bg-gradient-to-br from-slate-800 to-slate-900 rounded-[1.8rem] p-5 shadow-lg border border-slate-700 group animate-in fade-in slide-in-from-bottom-4 duration-700" style={{ animationDelay: '300ms' }}>
                    <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20"></div>
                    <div className="relative z-10 w-full flex flex-col justify-between">
                        <div className="flex items-center justify-between">
                            <div className="p-1.5 bg-white/10 rounded-lg text-emerald-400 border border-white/5"><ShieldCheck size={16} /></div>
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Confidence</span>
                        </div>
                        <div>
                            <div className="flex items-baseline gap-1">
                                <span className="text-3xl font-black text-white tracking-tighter tabular-nums">{stats.refCoverage}<span className="text-lg text-slate-500">%</span></span>
                            </div>
                            <div className="w-full h-1 bg-slate-700 rounded-full mt-3 overflow-hidden">
                                <div className="h-full bg-emerald-500 rounded-full transition-all duration-1000 group-hover:shadow-[0_0_10px_rgba(16,185,129,0.5)]" style={{ width: `${Math.max(0, Math.min(100, Number(stats.refCoverage)))}%` }}></div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

type AppView = 'dashboard' | 'analytics' | 'ai';

const AppContent: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('resindb-session');
    return saved ? JSON.parse(saved) : null;
  });

  const [toasts, setToasts] = useState<Toast[]>([]);
  const addToast = useCallback((type: Toast['type'], message: string) => {
      const id = Date.now().toString();
      setToasts(prev => [...prev, { id, type, message }]);
      setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 4000);
  }, []);

  const [allProducts, setAllProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [displayedProducts, setDisplayedProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [selectedCategoryId, setSelectedCategoryId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [columns, setColumns] = useState<ColumnConfig[]>([]);
  const [isImportOpen, setIsImportOpen] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [activeView, setActiveView] = useState<AppView>('dashboard');
  const [isNavCollapsed, setIsNavCollapsed] = useState(false);

  const [selectedProductIds, setSelectedProductIds] = useState<Set<string>>(new Set());

  const [isSearching, setIsSearching] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  // Added missing states to fix TopBarProps errors
  const [showFilters, setShowFilters] = useState(false);
  const [numericFilters, setNumericFilters] = useState<Record<string, { min: string; max: string }>>({});

