// --- Error Boundary Component ---
class ErrorBoundary extends React.Component<{children?: ReactNode, fallback?: ReactNode}, {hasError: boolean}> {
  constructor(props: any) { super(props); this.state = { hasError: false }; }
  static getDerivedStateFromError() { return { hasError: true }; }
  componentDidCatch(error: any, errorInfo: any) { console.error("ErrorBoundary caught:", error, errorInfo); }
  render() {
    if (this.state.hasError) return this.props.fallback || <div className="p-8 text-center text-slate-400">Component Error</div>;
    return this.props.children;
  }
}

// --- Toast Component ---
interface Toast { id: string; type: 'success' | 'error' | 'info'; message: string; }
const ToastContainer: React.FC<{ toasts: Toast[], removeToast: (id: string) => void }> = ({ toasts, removeToast }) => (
    <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-[100] flex flex-col gap-2 pointer-events-none">
        {toasts.map(t => (
            <div key={t.id} className={`pointer-events-auto flex items-center gap-3 px-4 py-3 rounded-2xl shadow-2xl animate-in slide-in-from-bottom-5 fade-in duration-300 border backdrop-blur-md ${
                t.type === 'success' ? 'bg-emerald-950/80 text-emerald-100 border-emerald-800' :
                t.type === 'error' ? 'bg-rose-950/80 text-rose-100 border-rose-800' :
                'bg-slate-900/80 text-slate-100 border-slate-700'
            }`}>
                {t.type === 'success' && <CheckCircle2 size={18} className="text-emerald-400" />}
                {t.type === 'error' && <AlertCircle size={18} className="text-rose-400" />}
                {t.type === 'info' && <Info size={18} className="text-primary-400" />}
                <span className="text-sm font-medium tracking-wide">{t.message}</span>
                <button onClick={() => removeToast(t.id)} className="ml-2 hover:bg-white/10 p-1 rounded-full transition-colors"><X size={14} /></button>
            </div>
        ))}
    </div>
);

