const getDynamicColumns = (products: Product[]): ColumnConfig[] => {
  const propertyKeys = new Set<string>();
  products.forEach(p => Object.keys(p.properties).forEach(k => propertyKeys.add(k)));
  const defaultVisible = ['密度', '熔体质量流动速率', '拉伸屈服应力', '弯曲模量', '悬臂梁缺口冲击强度', '热变形温度', '典型应用'];
  const dynamicCols: ColumnConfig[] = Array.from(propertyKeys).map(key => ({
    key, label: key, visible: defaultVisible.includes(key), isSystem: false
  })).sort((a, b) => {
      const aPrio = defaultVisible.includes(a.key);
      const bPrio = defaultVisible.includes(b.key);
      if (aPrio && !bPrio) return -1;
      if (!aPrio && bPrio) return 1;
      return a.label.localeCompare(b.label);
  });
  return [
    { key: 'gradeName', label: '牌号', visible: true, isSystem: true },
    { key: 'manufacturer', label: '所属分类', visible: true, isSystem: true },
    { key: 'updatedAt', label: '更新时间', visible: false, isSystem: false },
    ...dynamicCols
  ];
};

const Breadcrumbs: React.FC<{ categoryId: string | null, onReset: () => void }> = ({ categoryId, onReset }) => {
    const { t, language } = useLanguage();

    const path = useMemo(() => {
        if (!categoryId) return [];
        const findPath = (nodes: Category[], targetId: string, currentPath: Category[]): Category[] | null => {
            for (const node of nodes) {
                if (node.id === targetId) return [...currentPath, node];
                if (node.children) {
                    const childResult = findPath(node.children, targetId, [...currentPath, node]);
                    if (childResult) return childResult;
                }
            }
            return null;
        };
        return findPath(CATEGORY_TREE, categoryId, []) || [];
    }, [categoryId]);

    return (
        <nav className="flex items-center text-sm text-slate-500 dark:text-slate-400 mb-6 px-1 animate-in fade-in slide-in-from-left-2">
            <button 
                className="flex items-center hover:text-primary-600 dark:hover:text-primary-400 transition-colors cursor-pointer group focus:outline-none" 
                onClick={onReset}
            >
                <div className="p-1.5 rounded-lg group-hover:bg-primary-50 dark:group-hover:bg-primary-900/20 transition-colors">
                    <Home size={16} className="transition-transform group-hover:scale-110" />
                </div>
                <span className="font-bold ml-1">{t('home')}</span>
            </button>
            {path.map((cat) => (
                <React.Fragment key={cat.id}>
                    <ChevronRight size={14} className="mx-1 text-slate-300 dark:text-slate-600" />
                    <span className="font-bold text-slate-800 dark:text-slate-200 hover:text-primary-600 dark:hover:text-primary-400 transition-colors cursor-pointer">
                        {language === 'en' && cat.nameEn ? cat.nameEn : cat.name}
                    </span>
                </React.Fragment>
            ))}
        </nav>
    );
};

const SummaryStats: React.FC<{ data: Product[] }> = ({ data }) => {
    const { t, tProp } = useLanguage();
    const [isExpanded, setIsExpanded] = useState(true);

    const stats = useMemo(() => {
        if (!data || data.length === 0) return {
            count: 0, manufacturers: 0, avgDensity: '-', avgMfr: '-', refCoverage: '0'
        };

        const manufacturers = new Set(data.map(p => p.manufacturerId || p.manufacturer)).size;
        let densitySum = 0, densityCount = 0, mfrSum = 0, mfrCount = 0, totalPropsWithRefs = 0, totalPropsCount = 0;

        data.forEach(p => {
            const dVal = p.properties['密度']?.value;
            const d = dVal === undefined || dVal === null ? NaN : parseFloat(String(dVal));
            if (!isNaN(d)) { densitySum += d; densityCount++; }

            const mVal = p.properties['熔体质量流动速率']?.value;
            const m = mVal === undefined || mVal === null ? NaN : parseFloat(String(mVal));
            if (!isNaN(m)) { mfrSum += m; mfrCount++; }

            const props = p.properties || {};
            (Object.values(props) as PropertyValue[]).forEach(prop => {
                totalPropsCount++;
                if (prop?.referenceId) totalPropsWithRefs++;
            });
        });

        return {
            count: data.length,
            manufacturers,
            avgDensity: densityCount ? (densitySum / densityCount).toFixed(3) : '-',
            avgMfr: mfrCount ? (mfrSum / mfrCount).toFixed(2) : '-',
            refCoverage: totalPropsCount > 0 ? ((totalPropsWithRefs / totalPropsCount) * 100).toFixed(1) : '0'
        };
    }, [data]);

    const Card = ({ icon: Icon, colorClass, label, value, sub, delay }: any) => (
        <div className={`relative overflow-hidden bg-white dark:bg-slate-850 rounded-[1.8rem] p-5 shadow-sm border border-slate-100 dark:border-slate-800 transition-all hover:border-primary-200 dark:hover:border-primary-800 hover:shadow-glow group animate-in fade-in slide-in-from-bottom-4 duration-700`} style={{ animationDelay: delay }}>
            <div className={`absolute -top-4 -right-4 p-8 opacity-[0.03] dark:opacity-[0.05] group-hover:scale-110 group-hover:rotate-6 transition-transform duration-500`}>
                <Icon size={100} />
            </div>
            <div className="relative z-10 flex flex-col h-full justify-between">
                <div className="flex items-center gap-3 mb-4">
                    <div className={`w-10 h-10 rounded-2xl flex items-center justify-center ${colorClass} bg-opacity-10 dark:bg-opacity-20`}>
                        <Icon size={18} className={colorClass.replace('bg-', 'text-').replace('text-white', '')} />
                    </div>
                    <span className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">{label}</span>
                </div>
                <div>
                    <div className="text-2xl font-black text-slate-800 dark:text-slate-100 tracking-tighter tabular-nums">{value}</div>
                    <div className="text-[10px] font-bold text-slate-400 mt-1">{sub}</div>
                </div>
            </div>
        </div>
    );

    return (
        <div className="mb-8">
            <div className="flex items-center justify-between mb-4 select-none">
                <button 
                    onClick={() => setIsExpanded(!isExpanded)}
                    className="flex items-center gap-2 group focus:outline-none"
                >
                    <div className={`p-1.5 rounded-lg bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-400 group-hover:text-primary-500 transition-all`}>
                        <ChevronDown size={14} className={`transition-transform duration-300 ${isExpanded ? 'rotate-0' : '-rotate-90'}`} />
                    </div>
                    <span className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest group-hover:text-slate-600 dark:group-hover:text-slate-300 transition-colors">
                        Analytics Overview
                    </span>
                </button>

                {!isExpanded && (
                    <div className="flex items-center gap-2 animate-in fade-in slide-in-from-left-2 duration-300">
                        <div className="px-3 py-1 bg-white dark:bg-slate-800 rounded-full border border-slate-200 dark:border-slate-700 flex items-center gap-2 shadow-sm">
                            <Database size={12} className="text-primary-500" />
                            <span className="text-[10px] font-bold text-slate-600 dark:text-slate-300">{stats.count}</span>
                        </div>
                    </div>
                )}
            </div>

            <div className={`grid grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 gap-4 transition-all duration-500 ease-in-out overflow-hidden ${isExpanded ? 'opacity-100 max-h-[400px]' : 'opacity-0 max-h-0'}`}>
                <Card icon={Database} colorClass="bg-primary-600 text-primary-600" label={t('total')} value={stats.count} sub={tProp('牌号')} delay="0ms" />
                <Card icon={Factory} colorClass="bg-indigo-600 text-indigo-600" label={t('manufacturers')} value={stats.manufacturers} sub="Active Entities" delay="75ms" />
                <Card icon={FlaskConical} colorClass="bg-teal-500 text-teal-500" label={`${t('avg')} ${tProp('密度')}`} value={stats.avgDensity} sub="g/cm³" delay="150ms" />
                <Card icon={TrendingUp} colorClass="bg-amber-500 text-amber-500" label={`${t('avg')} MFR`} value={stats.avgMfr} sub="g/10min" delay="225ms" />

                <div className="hidden xl:flex relative overflow-hidden bg-gradient-to-br from-slate-800 to-slate-900 rounded-[1.8rem] p-5 shadow-lg border border-slate-700 group animate-in fade-in slide-in-from-bottom-4 duration-700" style={{ animationDelay: '300ms' }}>
                    <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20"></div>
                    <div className="relative z-10 w-full flex flex-col justify-between">
                        <div className="flex items-center justify-between">
                            <div className="p-1.5 bg-white/10 rounded-lg text-emerald-400 border border-white/5"><ShieldCheck size={16} /></div>
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Confidence</span>
                        </div>
                        <div>
                            <div className="flex items-baseline gap-1">
                                <span className="text-3xl font-black text-white tracking-tighter tabular-nums">{stats.refCoverage}<span className="text-lg text-slate-500">%</span></span>
                            </div>
                            <div className="w-full h-1 bg-slate-700 rounded-full mt-3 overflow-hidden">
                                <div className="h-full bg-emerald-500 rounded-full transition-all duration-1000 group-hover:shadow-[0_0_10px_rgba(16,185,129,0.5)]" style={{ width: `${Math.max(0, Math.min(100, Number(stats.refCoverage)))}%` }}></div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

type AppView = 'dashboard' | 'analytics' | 'ai';

const AppContent: React.FC = () => {
  const { t, tProp } = useLanguage();
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('resindb-session');
    return saved ? JSON.parse(saved) : null;
  });

  const [toasts, setToasts] = useState<Toast[]>([]);
  const addToast = useCallback((type: Toast['type'], message: string) => {
      const id = Date.now().toString();
      setToasts(prev => [...prev, { id, type, message }]);
      setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 4000);
  }, []);

  const [allProducts, setAllProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [displayedProducts, setDisplayedProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [selectedCategoryId, setSelectedCategoryId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [columns, setColumns] = useState<ColumnConfig[]>([]);
  const [isImportOpen, setIsImportOpen] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [activeView, setActiveView] = useState<AppView>('dashboard');
  const [isNavCollapsed, setIsNavCollapsed] = useState(false);

  const [selectedProductIds, setSelectedProductIds] = useState<Set<string>>(new Set());

  const [isSearching, setIsSearching] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  // Advanced filters state
  const [showFilters, setShowFilters] = useState(false);
  const [numericFilters, setNumericFilters] = useState<Record<string, { min: string; max: string }>>({});

  useEffect(() => { setColumns(getDynamicColumns(allProducts)); }, []);
  useEffect(() => {
     const newCols = getDynamicColumns(allProducts);
     if (newCols.length !== columns.length) setColumns(newCols);
  }, [allProducts.length]);

  // Debounced Search Effect
  useEffect(() => {
    const timer = setTimeout(async () => {
      setIsSearching(true);
      try {
        const results = await api.search(searchQuery, selectedCategoryId);
        setDisplayedProducts(results);
      } catch (err: any) {
        console.error("Search failed:", err);
        setDisplayedProducts([]); 
        addToast('error', `Search Failed: ${err.message}`);
      } finally {
        setIsSearching(false);
      }
    }, 400); 

    return () => clearTimeout(timer);
  }, [searchQuery, selectedCategoryId, addToast]);

  const categoryCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    allProducts.forEach(product => {
        product.categoryIds.forEach(catId => {
            counts[catId] = (counts[catId] || 0) + 1;
        });
    });
    return counts;
  }, [allProducts]);

  const handleImportData = () => {
      const newProducts: Product[] = Array.from({ length: 5 }).map((_, i) => ({
        id: `imported-${Date.now()}-${i}`,
        gradeName: `New-Grade-${1000 + i} (Imported)`,
        manufacturer: 'China Petroleum (Imported)',
        manufacturerId: 'm-cnpc-1',
        categoryIds: ['cat_epdm_path_1'],
        updatedAt: new Date().toISOString().split('T')[0],
        properties: {
          '密度': { value: 0.92 + (Math.random() * 0.05), unit: 'g/cm³' },
          '熔体质量流动速率': { value: 1 + (Math.random() * 5), unit: 'g/10min' },
          '应用': { value: 'Imported batch test' }
        }
      }));
      setAllProducts(prev => [...newProducts, ...prev]);
      setDisplayedProducts(prev => [...newProducts, ...prev]);
      addToast('success', `${newProducts.length} items imported successfully`);
      setIsImportOpen(false);
  };

  const handleUpdateProduct = async (updatedProduct: Product) => {
    try {
      const result = await api.update(updatedProduct);
      setAllProducts(prev => prev.map(p => p.id === result.id ? result : p));
      setDisplayedProducts(prev => prev.map(p => p.id === result.id ? result : p));
      addToast('success', 'Product updated successfully');
      return true;
    } catch (err: any) {
      addToast('error', `Update Failed: ${err.message}`);
      throw err;
    }
  };

  const handleExport = async () => {
    if (isExporting) return;
    setIsExporting(true);
    try {
        const blob = await api.exportReport(displayedProducts, 'csv');
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `resin_report_${new Date().toISOString().slice(0,10)}.csv`;
        document.body.appendChild(a);
        a.click();
        window.URL.revokeObjectURL(url);
        document.body.removeChild(a);
        addToast('success', 'Report exported successfully');
    } catch (err: any) {
        addToast('error', `Export Failed: ${err.message}`);
    } finally {
        setIsExporting(false);
    }
  };

  const handleDeleteProducts = async (ids: string[]) => {
    try {
        await api.delete(ids);
        setAllProducts(prev => prev.filter(p => !ids.includes(p.id)));
        setDisplayedProducts(prev => prev.filter(p => !ids.includes(p.id)));
        setSelectedProductIds(new Set());
        addToast('success', `${ids.length} products deleted`);
    } catch (err: any) {
        addToast('error', `Delete Failed: ${err.message}`);
    }
  };

  const handleToggleAllColumns = (visible: boolean) => {
    setColumns(cols => cols.map(c => c.isSystem ? c : { ...c, visible }));
  };

  const handleBatchUpdate = async (ids: string[], updates: Partial<Product>) => {
    try {
        await api.batchUpdate(ids, updates);

        const updater = (prev: Product[]) => prev.map(p => {
            if (!ids.includes(p.id)) return p;

            const { _propertyUpdates, ...directUpdates } = updates as any;
            let newProperties = { ...p.properties };

            if (_propertyUpdates) {
                Object.entries(_propertyUpdates).forEach(([key, val]) => {
                    newProperties[key] = val as PropertyValue;
                });
            }

            return { 
                ...p, 
                ...directUpdates, 
                properties: newProperties, 
                updatedAt: new Date().toISOString().split('T')[0] 
            };
        });

        setAllProducts(updater);
        setDisplayedProducts(updater);
        addToast('success', 'Batch update completed');
    } catch (err: any) {
        addToast('error', `Batch Update Failed: ${err.message}`);
    }
  };

  const handleUpdateUserProfile = (updatedInfo: any) => {
    if (!currentUser) return;
    const newUser = { ...currentUser, ...updatedInfo };
    setCurrentUser(newUser);
    localStorage.setItem('resindb-session', JSON.stringify(newUser));
    addToast('success', 'Profile updated');
  };

  if (!currentUser) return <AuthScreen onLogin={(u) => { setCurrentUser(u); localStorage.setItem('resindb-session', JSON.stringify(u)); }} />;

  return (
    <div className="flex h-screen bg-[#f8fafc] dark:bg-[#020617] font-sans text-slate-900 dark:text-slate-100 overflow-hidden transition-colors duration-500">
      <ToastContainer toasts={toasts} removeToast={(id) => setToasts(prev => prev.filter(t => t.id !== id))} />

      {/* Floating Navigation Dock */}
      <nav className={`fixed left-4 top-1/2 -translate-y-1/2 z-[60] flex flex-col items-center py-5 gap-6 bg-slate-900/90 dark:bg-slate-950/90 backdrop-blur-2xl border border-slate-700/50 dark:border-slate-800/50 shadow-2xl shadow-slate-900/20 rounded-[2.5rem] transition-all duration-500 ease-out ${isNavCollapsed ? 'w-0 opacity-0 overflow-hidden py-0 border-0 pointer-events-none' : 'w-20'}`}>
         <div className="w-12 h-12 bg-white/10 rounded-full flex items-center justify-center shadow-glow shadow-white/5 mb-2 group cursor-pointer hover:scale-110 active:scale-95 transition-transform overflow-hidden relative">
            <PolymerLogo className="w-8 h-8" />
         </div>

         <div className="flex flex-col gap-5 w-full px-3 items-center">
            {[
                { id: 'dashboard', icon: LayoutDashboard },
                { id: 'analytics', icon: PieChart },
                { id: 'ai', icon: Bot }
            ].map((item) => (
                <button 
                    key={item.id}
                    onClick={() => setActiveView(item.id as AppView)}
                    className={`relative w-12 h-12 rounded-2xl flex items-center justify-center transition-all duration-300 group ${activeView === item.id ? 'bg-primary-600 text-white shadow-lg shadow-primary-900/50 scale-110' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
                >
                    <item.icon size={22} />
                    {activeView === item.id && <div className="absolute -right-3 top-1/2 -translate-y-1/2 w-1 h-3 bg-primary-400 rounded-l-full shadow-glow"></div>}
                </button>
            ))}
         </div>

         <div className="mt-auto flex flex-col gap-3 w-full px-3 items-center">
            <button onClick={() => setIsAdminOpen(true)} className="w-12 h-12 rounded-2xl text-slate-500 hover:bg-slate-800 hover:text-white transition-all flex items-center justify-center hover:scale-105 active:scale-95">
                <ShieldCheck size={22} />
            </button>
         </div>
      </nav>

      <div className={`flex-1 flex flex-col h-full transition-all duration-500 p-4 gap-4 ${isNavCollapsed ? 'ml-0' : 'ml-24'}`}>

        <div className="shrink-0 z-[50]">
            <TopBar 
                user={currentUser}
                onLogout={() => { setCurrentUser(null); localStorage.removeItem('resindb-session'); }}
                onOpenProfile={() => setIsProfileOpen(true)}
                onOpenAdmin={() => setIsAdminOpen(true)}
                searchQuery={searchQuery}
                onSearchChange={setSearchQuery}
                isSearching={isSearching}
                columns={columns}
                onToggleColumn={(k) => setColumns(c => c.map(col => col.key === k ? {...col, visible: !col.visible} : col))}
                onToggleAllColumns={handleToggleAllColumns}
                onOpenImport={() => setIsImportOpen(true)}
                onExport={handleExport}
                isExporting={isExporting}
                viewMode={activeView === 'analytics' ? 'chart' : 'grid'}
                onViewModeChange={(m) => setActiveView(m === 'chart' ? 'analytics' : 'dashboard')}
                showAdvancedFilters={showFilters}
                onToggleFilters={() => setShowFilters(!showFilters)}
                activeFilterCount={Object.keys(numericFilters).length}
            />
        </div>

        <div className="flex-1 flex min-h-0 gap-6">
            {(activeView === 'dashboard' || activeView === 'analytics') && (
                <div className="w-72 shrink-0 flex flex-col animate-in fade-in slide-in-from-left-4 duration-500">
                    <div className="flex-1 bg-white/60 dark:bg-slate-900/60 backdrop-blur-2xl border border-white/40 dark:border-slate-800 rounded-[2.5rem] shadow-sm overflow-hidden flex flex-col transition-all hover:shadow-lg">
                        <TreeSidebar 
                            categories={CATEGORY_TREE}
                            selectedCategoryId={selectedCategoryId}
                            onSelectCategory={setSelectedCategoryId}
                            totalCount={allProducts.length}
                            counts={categoryCounts}
                        />
                    </div>
                </div>
            )}

            <div className="flex-1 flex flex-col min-w-0 bg-white/40 dark:bg-slate-900/40 backdrop-blur-3xl border border-white/40 dark:border-slate-800 rounded-[3rem] shadow-glass overflow-hidden relative transition-all duration-500">
                <div className="flex-1 overflow-hidden p-8 flex flex-col relative">
                    <div className="absolute inset-0 opacity-[0.03] dark:opacity-[0.05] pointer-events-none" style={{ backgroundImage: 'radial-gradient(#64748b 1px, transparent 1px)', backgroundSize: '32px 32px' }}></div>

                    {activeView !== 'ai' && (
                        <div className="mb-6 shrink-0 z-10">
                            <Breadcrumbs categoryId={selectedCategoryId} onReset={() => setSelectedCategoryId(null)} />
                        </div>
                    )}

                    {activeView === 'dashboard' && (
                        <div className="shrink-0 z-10">
                            <SummaryStats data={displayedProducts} />
                        </div>
                    )}

                    <div className="flex-1 min-h-0 relative rounded-[2.5rem] overflow-hidden bg-white/60 dark:bg-slate-950/40 border border-white/50 dark:border-slate-800 shadow-inner z-0">
                        <ErrorBoundary>
                            {activeView === 'dashboard' && (
                                <div className="absolute inset-0 p-1">
