}

const ChartSuggestion: React.FC<{ type: string, onClick: () => void }> = ({ type, onClick }) => {
    const { t } = useLanguage();
    return (
        <button 
            onClick={onClick}
            className="flex items-center gap-2 px-3 py-1.5 bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 rounded-lg border border-primary-200 dark:border-primary-800 hover:bg-primary-100 transition-all text-[10px] font-bold uppercase tracking-wider group"
        >
            <TrendingUp size={12} className="group-hover:translate-y-[-1px] transition-transform" />
            查看{type}分析
        </button>
    );
};

const FormattedText: React.FC<{ 
    text: string; 
    onNavigateToChart?: (type: string) => void;
    onGradeClick?: (name: string) => void;
    className?: string 
}> = ({ text, onNavigateToChart, onGradeClick, className }) => {
  if (!text) return null;

  return (
    <div className={className}>
      {text.split('\n').map((line, i) => {
        const trimmed = line.trim();
        if (trimmed.startsWith('- ') || trimmed.startsWith('* ') || trimmed.match(/^\d+\./)) {
             const cleanLine = trimmed.replace(/^[-*]\s+|\d+\.\s+/, '');
             const parts = cleanLine.split(/(\*\*.*?\*\*)/g);
             return (
                <div key={i} className="flex gap-2.5 ml-1 mb-1.5 items-start">
                    <span className="text-emerald-500 dark:text-emerald-400 mt-1.5 shrink-0 text-[10px]">•</span>
                    <span className="leading-relaxed text-sm">
                        {parts.map((part, j) => {
                            if (part.startsWith('**') && part.endsWith('**')) {
                                const grade = part.slice(2, -2);
                                return <strong key={j} onClick={() => onGradeClick?.(grade)} className="font-bold text-slate-800 dark:text-white hover:text-primary-600 hover:underline cursor-pointer transition-colors">{grade}</strong>;
                            }
                            return <span key={j}>{part}</span>;
                        })}
                    </span>
                </div>
             );
        }

        const parts = line.split(/(\*\*.*?\*\*)/g);
        if (line.startsWith('##')) {
             return <h3 key={i} className="font-bold text-emerald-700 dark:text-emerald-400 mt-5 mb-2 text-base border-l-2 border-emerald-500 pl-3">{line.replace(/#/g, '')}</h3>
        }

        if (!trimmed) return <div key={i} className="h-4"></div>;

        return (
          <p key={i} className="mb-2 last:mb-0 leading-relaxed text-sm">
            {parts.map((part, j) => {
              if (part.startsWith('**') && part.endsWith('**')) {
                const grade = part.slice(2, -2);
                return <strong key={j} onClick={() => onGradeClick?.(grade)} className="font-bold text-slate-800 dark:text-white hover:text-primary-600 hover:underline cursor-pointer transition-colors">{grade}</strong>;
              }
              return <span key={j}>{part}</span>;
            })}
          </p>
        );
      })}

      {/* Dynamic Chart Triggers */}
      <div className="flex flex-wrap gap-2 mt-4 pt-4 border-t border-slate-100 dark:border-slate-800">
          {(text.includes('Ashby') || text.includes('散点') || text.includes('构效')) && (
              <ChartSuggestion type="Ashby" onClick={() => onNavigateToChart?.('ashby')} />
          )}
          {(text.includes('Radar') || text.includes('雷达') || text.includes('指纹')) && (
              <ChartSuggestion type="Radar" onClick={() => onNavigateToChart?.('radar')} />
          )}
          {(text.includes('GPC') || text.includes('分布')) && (
              <ChartSuggestion type="GPC" onClick={() => onNavigateToChart?.('gpc')} />
          )}
      </div>
    </div>
  );
};

export const AIAssistant: React.FC<AIAssistantProps> = ({ contextData, inlineView = false, onNavigateToChart, onGradeClick }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [input, setInput] = useState('');
  const { t, language } = useLanguage();
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [useThinking, setUseThinking] = useState(true); // Default to on for lab context
  const [attachedImage, setAttachedImage] = useState<string | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (messages.length === 0) {
        setMessages([{ 
            id: 'welcome', 
            role: 'model', 
            text: t('welcomeMessage') 
        }]);
    }
  }, [t]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading, isOpen]);

  const handleSendMessage = async (customInput?: string) => {
    const textToSend = customInput || input;
    if ((!textToSend.trim() && !attachedImage) || isLoading) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend,
      image: attachedImage || undefined
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setAttachedImage(null);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const parts: any[] = [];
      let systemInstruction = "You are ResinAI. A senior materials scientist at PetroChina Research Institute. Your goal is to analyze data specifically and precisely. When you mention a grade name, wrap it in **double asterisks** like **HDPE 5000S**. Suggest using specific charts if appropriate (Ashby, Radar, GPC).";

      if (userMsg.image) {
         const base64Data = userMsg.image.split(',')[1];
         const mimeType = userMsg.image.split(';')[0].split(':')[1] || 'image/jpeg';
         parts.push({ inlineData: { mimeType, data: base64Data } });
         systemInstruction += "\nYou are now focused on image-based QC analysis. Look for defects like specks or gels.";
         parts.push({ text: userMsg.text || "Analyze this resin sample." });
      } else {
         parts.push({ text: userMsg.text });
         if (contextData.length > 0) {
            const contextStr = JSON.stringify(contextData.slice(0, 20).map(p => ({
                grade: p.gradeName,
                manufacturer: p.manufacturer,
                mfr: p.properties['熔体质量流动速率']?.value,
                density: p.properties['密度']?.value,
                flex: p.properties['弯曲模量']?.value,
                impact: p.properties['悬臂梁缺口冲击强度']?.value,
                app: p.properties['典型应用']?.value
            })));
            parts.push({ text: `\n[Experimental Context - Selected Records]: ${contextStr}` });
         }
      }

      // Upgrade to gemini-3-pro-preview for complex material science tasks
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [{ role: 'user', parts: parts }],
        config: {
            systemInstruction: systemInstruction,
            thinkingConfig: useThinking ? { thinkingBudget: 2048 } : undefined,
        }
      });

      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        text: response.text || "Analysis result empty."
      }]);

    } catch (error) {
      console.error("AI Error:", error);
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        text: "## 连接异常\nResinAI 暂时无法访问中心计算节点。请检查网络状态或系统授权。"
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const renderInput = () => (
    <div className="flex items-end gap-2 bg-slate-100 dark:bg-slate-800/50 p-2 rounded-[2rem] border border-slate-200 dark:border-slate-700 focus-within:ring-4 focus-within:ring-primary-500/10 focus-within:border-primary-500 transition-all shadow-inner">
        <input type="file" ref={fileInputRef} accept="image/*" className="hidden" onChange={(e) => {
            const f = e.target.files?.[0];
            if(f){ const r = new FileReader(); r.onloadend = () => setAttachedImage(r.result as string); r.readAsDataURL(f); }
        }} />
        <button 
            onClick={() => fileInputRef.current?.click()} 
            className={`p-3 rounded-2xl transition-all shrink-0 ${attachedImage ? 'text-emerald-600 bg-emerald-100 dark:bg-emerald-900/30' : 'text-slate-400 hover:text-primary-600 hover:bg-white dark:hover:bg-slate-800'}`}
        >
            <ImageIcon size={22} />
        </button>
        <textarea
            value={input} onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => { if(e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSendMessage(); }}}
            placeholder={t('aiPlaceholder')}
            className="w-full max-h-48 min-h-[44px] py-3 bg-transparent text-sm text-slate-800 dark:text-slate-200 outline-none resize-none leading-relaxed"
            rows={1}
        />
        <div className="flex items-center gap-2 self-center pr-1">
            <button 
                onClick={() => setUseThinking(!useThinking)}
                className={`p-3 rounded-2xl transition-all ${useThinking ? 'text-indigo-600 bg-indigo-100 dark:bg-indigo-900/30' : 'text-slate-400 hover:text-primary-600'}`}
                title="深度逻辑引擎"
            >
                <BrainCircuit size={22} />
            </button>
            <button 
                onClick={() => handleSendMessage()} 
                disabled={isLoading || (!input.trim() && !attachedImage)} 
                className="p-3 bg-slate-900 dark:bg-primary-600 hover:bg-primary-700 disabled:opacity-20 text-white rounded-2xl shadow-xl transition-all active:scale-95 flex items-center justify-center shrink-0"
            >
                {isLoading ? <Loader2 size={22} className="animate-spin" /> : <Send size={22} />}
            </button>
        </div>
    </div>
  );

  if (inlineView) {
      return (
          <div className="flex flex-col h-full w-full bg-slate-50/30 dark:bg-transparent">
              <div className="flex-1 overflow-y-auto p-6 space-y-10 custom-scrollbar" ref={chatContainerRef}>
                <div className="max-w-4xl mx-auto space-y-8">
                  {messages.map(m => (
                      <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}>
                         <div className={`flex gap-4 max-w-[90%] ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                            <div className={`w-10 h-10 rounded-2xl flex items-center justify-center shrink-0 shadow-sm ${m.role === 'user' ? 'bg-white dark:bg-slate-800 border' : 'bg-primary-600 text-white shadow-primary-500/20 shadow-lg'}`}>
                                {m.role === 'user' ? <User size={18} className="text-slate-400" /> : <Bot size={18} />}
                            </div>
                            <div className={`rounded-[2rem] px-6 py-4 shadow-glass ${m.role === 'user' ? 'bg-slate-900 text-white rounded-tr-sm' : 'bg-white dark:bg-slate-850 border border-slate-100 dark:border-slate-800 rounded-tl-sm text-slate-700 dark:text-slate-200'}`}>
                                {m.image && <img src={m.image} className="max-w-full h-auto max-h-96 rounded-2xl mb-4 shadow-2xl border border-white/50" />}
                                <FormattedText text={m.text} onNavigateToChart={onNavigateToChart} onGradeClick={onGradeClick} />
                            </div>
                         </div>
                      </div>
                  ))}
                  {isLoading && (
                      <div className="flex justify-start">
                          <div className="flex gap-4">
                            <div className="w-10 h-10 bg-primary-100 dark:bg-primary-900/30 rounded-2xl flex items-center justify-center animate-pulse"><Sparkles size={18} className="text-primary-600" /></div>
