  };

  const handleExport = async () => {
    if (isExporting) return;
    setIsExporting(true);
    try {
        const blob = await api.exportReport(displayedProducts, 'csv');
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `resin_report_${new Date().toISOString().slice(0,10)}.csv`;
        document.body.appendChild(a);
        a.click();
        window.URL.revokeObjectURL(url);
        addToast('success', 'Report exported successfully');
    } catch (err: any) {
        addToast('error', `Export Failed: ${err.message}`);
    } finally {
        setIsExporting(false);
    }
  };

  const handleDeleteProducts = async (ids: string[]) => {
    try {
        await api.delete(ids);
        setAllProducts(prev => prev.filter(p => !ids.includes(p.id)));
        setDisplayedProducts(prev => prev.filter(p => !ids.includes(p.id)));
        setSelectedProductIds(new Set());
        addToast('success', `${ids.length} products deleted`);
    } catch (err: any) {
        addToast('error', `Delete Failed: ${err.message}`);
    }
  };

  const handleToggleAllColumns = (visible: boolean) => {
