        const updater = (prev: Product[]) => prev.map(p => {
            if (!ids.includes(p.id)) return p;
            const { _propertyUpdates, ...directUpdates } = updates as any;
            let newProperties = { ...p.properties };
            if (_propertyUpdates) Object.entries(_propertyUpdates).forEach(([key, val]) => { newProperties[key] = val as PropertyValue; });
            return { ...p, ...directUpdates, properties: newProperties, updatedAt: new Date().toISOString().split('T')[0] };
        });
        setAllProducts(updater);
        setDisplayedProducts(updater);
