                <div className="w-72 shrink-0 flex flex-col animate-in fade-in slide-in-from-left-4 duration-500">
                    <div className="flex-1 bg-white/60 dark:bg-slate-900/60 backdrop-blur-2xl border border-white/40 dark:border-slate-800 rounded-[2.5rem] shadow-sm overflow-hidden flex flex-col transition-all hover:shadow-lg">
                        <TreeSidebar categories={CATEGORY_TREE} selectedCategoryId={selectedCategoryId} onSelectCategory={setSelectedCategoryId} totalCount={allProducts.length} counts={{}} />
