            <div className="flex-1 flex flex-col min-w-0 bg-white/40 dark:bg-slate-900/40 backdrop-blur-3xl border border-white/40 dark:border-slate-800 rounded-[3rem] shadow-glass overflow-hidden relative transition-all duration-500">
