import React, { useState, useEffect, useRef } from 'react';
import { X, Save, User, Mail, Lock, Camera, CheckCircle2, Loader2, ShieldCheck, Trash2, RotateCcw } from 'lucide-react';
import { User as UserType } from '../types';
import { useLanguage } from '../contexts/LanguageContext';

interface ProfileModalProps {
  isOpen: boolean;
  onClose: () => void;
  user: UserType | null;
  onSave: (updatedUser: any) => void;
}

export const ProfileModal: React.FC<ProfileModalProps> = ({ isOpen, onClose, user, onSave }) => {
  const { t } = useLanguage();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [avatar, setAvatar] = useState('');
  const [isSaving, setIsSaving] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);

  useEffect(() => {
    if (user && isOpen) {
      setName(user.name);
      setEmail(user.email);
      setAvatar(user.avatar || '');
      setPassword(''); 
      setShowSuccess(false);
    }
  }, [user, isOpen]);

  if (!isOpen || !user) return null;

  const handleLocalUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        alert("File too large. Please use an image under 2MB.");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setAvatar(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const resetToDefault = () => {
    setAvatar(`https://api.dicebear.com/7.x/avataaars/svg?seed=${name}`);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);

    setTimeout(() => {
      const updatedData: any = {
        name,
        email,
        avatar
      };
      if (password) updatedData.password = password;

      onSave(updatedData);
      setIsSaving(false);
      setShowSuccess(true);

      setTimeout(() => {
        onClose();
      }, 1500);
    }, 1000);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-300">
      <div className="w-full max-w-lg bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300">
        <div className="px-6 py-5 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-slate-50/50 dark:bg-slate-950/50">
          <div className="flex items-center gap-3">
             <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 rounded-xl">
                <User size={20} />
             </div>
             <h3 className="text-lg font-bold text-slate-900 dark:text-white">{t('editProfile')}</h3>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
            <X size={20} />
          </button>
        </div>

        {showSuccess ? (
            <div className="p-12 flex flex-col items-center justify-center text-center animate-in fade-in zoom-in-95">
                <div className="w-20 h-20 bg-emerald-100 dark:bg-emerald-900/40 text-emerald-600 dark:text-emerald-400 rounded-full flex items-center justify-center mb-6 shadow-lg shadow-emerald-500/20">
                    <CheckCircle2 size={40} />
                </div>
                <h4 className="text-xl font-bold text-slate-900 dark:text-white mb-2">{t('updateSuccess')}</h4>
                {/* Fixed: Use 'securityNote' instead of missing 'securityProtocols' */}
                <p className="text-sm text-slate-500 dark:text-slate-400">{t('securityNote')}</p>
            </div>
        ) : (
            <form onSubmit={handleSubmit} className="p-8 space-y-6">
                <div className="flex flex-col items-center gap-6 mb-2">
                    <div className="relative group">
                        <div 
                          className="w-28 h-28 rounded-[2rem] overflow-hidden border-4 border-white dark:border-slate-800 shadow-2xl group-hover:scale-105 transition-all duration-300 cursor-pointer"
                          onClick={() => fileInputRef.current?.click()}
                        >
                            <img src={avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${name}`} alt="Preview" className="w-full h-full object-cover" />
                        </div>
                        <div className="absolute -bottom-2 flex gap-1 left-1/2 -translate-x-1/2">
                            <button 
                              type="button" onClick={() => fileInputRef.current?.click()}
                              className="p-2 bg-emerald-600 text-white rounded-xl shadow-lg hover:bg-emerald-500 active:scale-90 transition-all border-2 border-white dark:border-slate-900"
                              title={t('changeAvatar')}
                            >
                              <Camera size={16} />
                            </button>
                            <button 
                              type="button" onClick={resetToDefault}
                              className="p-2 bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 rounded-xl shadow-lg hover:bg-slate-200 active:scale-90 transition-all border-2 border-white dark:border-slate-900"
                              {/* Fixed: Use 'resetDefault' which is added to i18n */}
                              title={t('resetDefault')}
                            >
                              <RotateCcw size={16} />
                            </button>
                        </div>
                        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleLocalUpload} />
                    </div>
                    <div className="w-full space-y-1">
                      <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">{t('avatarUrl')}</label>
                      <input 
                          type="text" value={avatar.startsWith('data:') ? 'Local Image Attached (Base64)' : avatar}
                          onChange={(e) => setAvatar(e.target.value)}
                          className={`w-full px-4 py-2.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-xs font-mono outline-none focus:border-emerald-500 transition-all dark:text-slate-200 ${avatar.startsWith('data:') ? 'italic text-emerald-600 dark:text-emerald-400' : ''}`}
                          placeholder="Or paste an image URL..."
                      />
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                    <div className="space-y-1.5">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">{t('username')}</label>
                        <div className="relative group">
                            <User size={16} className="absolute left-3.5 top-3 text-slate-400 group-focus-within:text-emerald-500 transition-colors" />
                            <input 
                                type="text" required value={name} onChange={(e) => setName(e.target.value)}
                                className="w-full pl-11 pr-4 py-2.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm outline-none focus:border-emerald-500 transition-all dark:text-slate-200"
                            />
                        </div>
                    </div>
                    <div className="space-y-1.5">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">{t('email')}</label>
                        <div className="relative group">
                            <Mail size={16} className="absolute left-3.5 top-3 text-slate-400 group-focus-within:text-emerald-500 transition-colors" />
                            <input 
                                type="email" required value={email} onChange={(e) => setEmail(e.target.value)}
                                className="w-full pl-11 pr-4 py-2.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm outline-none focus:border-emerald-500 transition-all dark:text-slate-200"
                            />
                        </div>
                    </div>
                </div>

                <div className="space-y-1.5 pt-2 border-t border-slate-100 dark:border-slate-800">
                    {/* Fixed: Use 'keepEmpty' which is added to i18n */}
                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">{t('password')} ({t('keepEmpty')})</label>
                    <div className="relative group">
                        <Lock size={16} className="absolute left-3.5 top-3 text-slate-400 group-focus-within:text-emerald-500 transition-colors" />
                        <input 
                            type="password" value={password} onChange={(e) => setPassword(e.target.value)}
                            placeholder={t('keepEmpty')}
                            className="w-full pl-11 pr-4 py-2.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm outline-none focus:border-emerald-500 transition-all dark:text-slate-200"
                        />
                    </div>
                </div>

                <div className="flex items-center justify-between px-4 py-3 bg-slate-100 dark:bg-slate-800/50 rounded-2xl border border-slate-200 dark:border-slate-700">
                    <div className="flex items-center gap-2">
                        <ShieldCheck size={16} className="text-emerald-500" />
                        {/* Fixed: Use 'changeRole' which is added to i18n */}
                        <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">{t('changeRole')}</span>
                    </div>
                    <span className="text-[10px] font-bold text-emerald-600 dark:text-emerald-400 uppercase tracking-widest bg-emerald-50 dark:bg-emerald-900/20 px-2.5 py-1 rounded-lg border border-emerald-200 dark:border-emerald-800/50">
                        {user.role}
                    </span>
                </div>

                <div className="flex gap-4 pt-4">
                    <button type="button" onClick={onClose} className="flex-1 py-3 text-sm font-bold text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-2xl transition-all">{t('cancel')}</button>
                    <button 
                        type="submit" disabled={isSaving}
                        className="flex-[2] py-3 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-bold text-sm shadow-xl shadow-emerald-500/20 active:scale-95 disabled:opacity-70 flex items-center justify-center gap-2"
                    >
                        {isSaving ? <Loader2 size={20} className="animate-spin" /> : <><Save size={20} />{t('save')}</>}
                    </button>
                </div>
            </form>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
