// Chart: MFR vs Density Scatter Plot Option Configuration
export const getMfrDensityChartOption = (seriesData: { name: string; data: any[] }[], theme: 'light' | 'dark'): echarts.EChartsOption => {
  const isDark = theme === 'dark';
  // Scientific Palette
  const colorPalette = ['#0284c7', '#06b6d4', '#14b8a6', '#6366f1', '#f59e0b', '#ec4899', '#8b5cf6'];
  const gridColor = isDark ? '#334155' : '#e0e0e0';
  const axisColor = isDark ? '#94a3b8' : '#333333';

  return {
    backgroundColor: 'transparent',
    color: colorPalette,
    title: {
      text: '熔体指数与密度关联图 (MFR vs Density)',
      subtext: 'Distribution Analysis of Processability and Crystallinity',
      left: 'center',
      textStyle: { color: isDark ? '#e2e8f0' : '#333333', fontSize: 16, fontFamily: 'Arial, sans-serif' }
    },
    grid: {
      left: '10%',
      right: '12%',
      bottom: '15%',
      top: '18%',
      containLabel: true,
      show: true,
      borderWidth: 0,
    },
    tooltip: {
      trigger: 'item',
      confine: true,
      backgroundColor: isDark ? 'rgba(15, 23, 42, 0.9)' : 'rgba(255, 255, 255, 0.95)',
      formatter: (params: any) => {
        const val = params.value;
        return `
          <div style="font-weight:bold; margin-bottom:4px;">${val[2]}</div>
          <span style="display:inline-block;width:10px;height:10px;border-radius:50%;background-color:${params.color};margin-right:5px;"></span>
          ${params.seriesName}<br/>
          MFR: <b>${val[0]}</b> g/10min<br/>
          Density: <b>${val[1]}</b> g/cm³
        `;
      }
    },
    legend: {
      top: 45,
      right: 10,
      orient: 'vertical',
      type: 'scroll',
      textStyle: { color: axisColor },
      itemWidth: 14,
      itemHeight: 14
    },
    dataZoom: [
        { type: 'slider', xAxisIndex: 0, bottom: 5, height: 20 },
        { type: 'inside', xAxisIndex: 0 },
        { type: 'inside', yAxisIndex: 0 }
    ],
    xAxis: {
      type: 'log',
      name: 'MFR (g/10min)',
      nameLocation: 'middle',
      nameGap: 35,
      logBase: 10,
      splitLine: { show: true, lineStyle: { color: gridColor, type: 'dashed' } },
      axisLabel: { color: axisColor },
      axisLine: { lineStyle: { color: '#888' } }
    },
    yAxis: {
      type: 'value',
      name: 'Density (g/cm³)',
      nameLocation: 'middle',
      nameGap: 50,
      min: (v: any) => Number((v.min - 0.005).toFixed(3)),
      max: (v: any) => Number((v.max + 0.005).toFixed(3)),
      splitLine: { show: true, lineStyle: { color: gridColor, type: 'dashed' } },
      axisLabel: { color: axisColor, formatter: (v: number) => v.toFixed(3) },
      axisLine: { lineStyle: { color: '#888' } }
    },
    series: seriesData.map(s => ({
      name: s.name,
      type: 'scatter' as const,
      symbolSize: 14,
      itemStyle: { 
        opacity: 0.7, 
        borderColor: '#fff', 
        borderWidth: 1.5,
        shadowBlur: 4, 
        shadowColor: 'rgba(0,0,0,0.2)' 
      },
      data: s.data
    }))
  };
};

