                    <div className="space-y-2">
                        <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Model Name</label>
                        <input 
                            type="text" 
                            value={apiConfig.model}
                            onChange={(e) => setApiConfig({...apiConfig, model: e.target.value})}
                            placeholder="e.g. deepseek-chat, gpt-4o"
                            className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm outline-none focus:border-primary-500 font-mono"
                        />
