      return (
          <div className="flex flex-col h-full w-full bg-slate-50/30 dark:bg-transparent relative">
              {showSettings && <SettingsPanel />}
              <div className="absolute top-4 right-4 z-20">
                  <button onClick={() => setShowSettings(true)} className="p-2 bg-white/80 dark:bg-slate-800/80 backdrop-blur-sm rounded-xl border border-slate-200 dark:border-slate-700 text-slate-500 hover:text-primary-600 transition-colors shadow-sm">
                      <Settings2 size={18} />
                  </button>
              </div>

              <div className="flex-1 overflow-y-auto p-6 space-y-10 custom-scrollbar" ref={chatContainerRef}>
                <div className="max-w-4xl mx-auto space-y-8">
                  {messages.map(m => (
                      <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}>
                         <div className={`flex gap-4 max-w-[90%] ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                            <div className={`w-10 h-10 rounded-2xl flex items-center justify-center shrink-0 shadow-sm ${m.role === 'user' ? 'bg-white dark:bg-slate-800 border' : 'bg-primary-600 text-white shadow-primary-500/20 shadow-lg'}`}>
                                {m.role === 'user' ? <User size={18} className="text-slate-400" /> : <Bot size={18} />}
