import React, { useState, useEffect, useRef } from 'react';
import { X, FileSpreadsheet, UploadCloud, CheckCircle, AlertCircle, Database, Filter, Clipboard, FileText, FileJson, Image as ImageIcon, Trash2, File as FileIcon, FileDown, ShieldCheck } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import { Product } from '../types';

interface ImportModalProps {
  isOpen: boolean;
  onClose: () => void;
  onImport?: (products: Product[]) => void;
}

export const ImportModal: React.FC<ImportModalProps> = ({ isOpen, onClose, onImport }) => {
  const [step, setStep] = useState<1 | 2 | 3 | 4>(1);
  const [isDragging, setIsDragging] = useState(false);
  const [stagedFiles, setStagedFiles] = useState<File[]>([]);
  const [parsedProducts, setParsedProducts] = useState<Product[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { t } = useLanguage();

  // Reset state when modal opens/closes
  useEffect(() => {
    if (!isOpen) {
        setTimeout(() => {
            setStep(1);
            setStagedFiles([]);
            setParsedProducts([]);
        }, 300);
    }
  }, [isOpen]);

  // Basic CSV Parser
  const parseCSV = async (file: File): Promise<Product[]> => {
      const text = await file.text();
      const lines = text.split('\n');
      const products: Product[] = [];

      // Simple parsing assuming header is row 0
      // Headers: Grade, Manufacturer, Density, MFR...
      const headers = lines[0].split(',').map(h => h.trim().toLowerCase());

      for(let i=1; i<lines.length; i++) {
          if(!lines[i].trim()) continue;
          const cols = lines[i].split(',').map(c => c.trim());
          if(cols.length < 2) continue;

          // Map known columns
          const gradeIdx = headers.findIndex(h => h.includes('grade') || h.includes('牌号'));
          const manIdx = headers.findIndex(h => h.includes('manufacturer') || h.includes('厂家'));

          if(gradeIdx === -1) continue;

          const newProduct: Product = {
              id: `imported-${Date.now()}-${i}`,
              gradeName: cols[gradeIdx] || 'Unknown Grade',
              manufacturer: manIdx > -1 ? cols[manIdx] : 'Imported',
              manufacturerId: 'm-import',
              categoryIds: ['root_plastic'], // Default to root
              updatedAt: new Date().toISOString().split('T')[0],
              properties: {}
          };

          // Try to map properties dynamically
          headers.forEach((h, idx) => {
              if (idx !== gradeIdx && idx !== manIdx && cols[idx]) {
                  // Basic mapping logic
                  let key = h;
                  if (h.includes('density') || h.includes('密度')) key = '密度';
                  else if (h.includes('mfr') || h.includes('熔体')) key = '熔体质量流动速率';
                  else if (h.includes('tensile') || h.includes('拉伸')) key = '拉伸屈服应力';
                  else if (h.includes('modulus') || h.includes('模量')) key = '弯曲模量';
                  else if (h.includes('impact') || h.includes('冲击')) key = '悬臂梁缺口冲击强度';

                  const val = parseFloat(cols[idx]);
                  newProduct.properties[key] = {
                      value: isNaN(val) ? cols[idx] : val,
                      unit: '' // Simplified for import
                  };
              }
          });
          products.push(newProduct);
      }
      return products;
  };

  const processFiles = async () => {
      setStep(2);
      const allNewProducts: Product[] = [];

      for (const file of stagedFiles) {
          try {
              if (file.name.endsWith('.csv') || file.type.includes('csv')) {
                  const items = await parseCSV(file);
                  allNewProducts.push(...items);
              } else {
                  // Mock generation for non-CSV files for demo
                  allNewProducts.push({
                      id: `mock-${Date.now()}`,
                      gradeName: `Imported-${file.name.substring(0,5)}`,
                      manufacturer: 'Imported Data',
                      manufacturerId: 'm-import',
                      categoryIds: ['root_plastic'],
                      updatedAt: new Date().toISOString().split('T')[0],
                      properties: {
                          '密度': { value: 0.95 + Math.random() * 0.05, unit: 'g/cm³' },
                          '熔体质量流动速率': { value: Math.random() * 5, unit: 'g/10min' }
                      }
                  });
              }
          } catch (e) {
              console.error("Parse error", e);
          }
      }

      // Simulate processing delay for UX
      setTimeout(() => {
          setParsedProducts(allNewProducts);
          setStep(3);
      }, 1500);
  };

  // ... (Keep existing drag/drop logic: useEffect handlePaste, addFiles, removeFiles etc.)
  // Re-implementing them briefly for context as I am replacing the whole file content
  useEffect(() => {
    if (!isOpen) return;
    const handlePaste = (e: ClipboardEvent) => {
        e.preventDefault();
        const items = e.clipboardData?.items;
        if (!items) return;
        const newFiles: File[] = [];
        for (let i = 0; i < items.length; i++) {
            if (items[i].kind === 'file') {
                const file = items[i].getAsFile();
                if (file) newFiles.push(file);
            }
        }
        if (newFiles.length > 0) addFiles(newFiles);
    };
    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, [isOpen]);

  const addFiles = (files: FileList | File[]) => {
      const newFiles = Array.from(files);
      setStagedFiles(prev => [...prev, ...newFiles]);
  };
  const removeFile = (index: number) => {
      setStagedFiles(prev => prev.filter((_, i) => i !== index));
  };
  const formatFileSize = (bytes: number) => {
      if (bytes === 0) return '0 B';
      const k = 1024;
      const sizes = ['B', 'KB', 'MB', 'GB'];
      const i = Math.floor(Math.log(bytes) / Math.log(k));
      return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
  };
  const getFileIcon = (file: File) => {
      if (file.type.includes('image')) return <ImageIcon size={18} className="text-purple-500" />;
      if (file.type.includes('json')) return <FileJson size={18} className="text-amber-500" />;
      if (file.name.includes('csv')) return <FileSpreadsheet size={18} className="text-emerald-500" />;
      return <FileText size={18} className="text-blue-500" />;
  };
  const handleDownloadTemplate = () => {
      const csvContent = "Grade Name, Manufacturer, Density, MFR, Tensile Strength\nHDPE-Demo, Sinopec, 0.95, 0.8, 24";
      const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.setAttribute("href", url);
      link.setAttribute("download", "resindb_template.csv");
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
      <div className="w-full max-w-xl bg-white dark:bg-slate-900 rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200 border border-slate-200 dark:border-slate-800 flex flex-col max-h-[90vh]">

        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-950/50">
          <div className="flex items-center gap-2">
            <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-xl">
                <Database className="text-emerald-600 dark:text-emerald-400" size={20} />
            </div>
            <div>
                <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100 leading-none">{t('importTitle')}</h3>
                <p className="text-[10px] text-slate-500 font-medium mt-0.5 uppercase tracking-wide">{t('dataIngestion')}</p>
            </div>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors p-1 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800"><X size={20} /></button>
        </div>

        {/* Content Body */}
        <div className="p-6 overflow-y-auto custom-scrollbar flex-1">
          {step === 1 && (
            <div className="space-y-6">
                {/* Drag & Drop Zone */}
                <div 
                    className={`
                        relative group border-2 border-dashed rounded-3xl p-8 flex flex-col items-center justify-center text-center transition-all duration-300 cursor-pointer overflow-hidden
                        ${isDragging 
                            ? 'border-emerald-500 bg-emerald-50/50 dark:bg-emerald-900/20 scale-[1.02]' 
                            : 'border-slate-200 dark:border-slate-700 hover:border-emerald-400 hover:bg-slate-50 dark:hover:bg-slate-800/50 bg-slate-50/30 dark:bg-slate-950/30'
                        }
                    `}
                    onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
                    onDragLeave={() => setIsDragging(false)}
                    onDrop={(e) => { e.preventDefault(); setIsDragging(false); addFiles(e.dataTransfer.files); }}
                    onClick={() => fileInputRef.current?.click()}
                >
                    <input 
                        type="file" 
                        ref={fileInputRef} 
                        className="hidden" 
                        multiple 
                        accept=".csv,.xlsx,.json,.txt,image/*" 
                        onChange={(e) => { if(e.target.files) addFiles(e.target.files); }} 
                    />

                    <div className="w-16 h-16 bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 rounded-2xl flex items-center justify-center mb-4 shadow-inner group-hover:scale-110 transition-transform duration-300">
                        <UploadCloud size={32} />
                    </div>

                    <div className="space-y-1 relative z-10">
                        <h4 className="text-slate-900 dark:text-slate-100 font-bold text-sm">
                            {t('dragDrop')} <span className="text-emerald-600 dark:text-emerald-400">{t('browseFiles')}</span>
                        </h4>
                        <div className="flex items-center justify-center gap-2 text-xs text-slate-400 font-medium">
                            <span className="flex items-center gap-1"><Clipboard size={10} /> Ctrl+V to Paste</span>
                            <span>•</span>
                            <span>.CSV, .XLSX</span>
                        </div>
                    </div>
                    <div className="absolute right-[-20px] bottom-[-20px] text-slate-100 dark:text-slate-800 opacity-50 pointer-events-none transition-transform group-hover:rotate-12">
                        <FileIcon size={120} />
                    </div>
                </div>

                <div className="flex items-start gap-3 p-3 bg-blue-50 dark:bg-blue-900/10 border border-blue-100 dark:border-blue-900/30 rounded-2xl">
                    <div className="p-2 bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-xl shrink-0">
                        <FileDown size={18} />
                    </div>
