                                        <p className="text-[10px] text-slate-400 font-mono uppercase">{formatFileSize(file.size)}</p>
                                    </div>
                                    <button onClick={(e) => { e.stopPropagation(); removeFile(idx); }} className="p-1.5 text-slate-400 hover:text-rose-500 rounded-lg">
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                <div className="pt-2">
                    <button 
                        onClick={processFiles} 
                        disabled={stagedFiles.length === 0}
                        className={`w-full py-4 rounded-2xl font-bold text-sm shadow-xl transition-all flex items-center justify-center gap-2 ${stagedFiles.length > 0 ? 'bg-slate-900 dark:bg-emerald-600 text-white hover:scale-[1.01]' : 'bg-slate-100 dark:bg-slate-800 text-slate-400 cursor-not-allowed'}`}
                    >
                        {stagedFiles.length > 0 ? <><Database size={16} /> Parse {stagedFiles.length} Files</> : t('dragDropDesc')}
                    </button>
                </div>
            </div>
          )}

          {step === 2 && (
            <div className="flex flex-col items-center justify-center py-12">
                <div className="relative w-20 h-20 border-4 border-emerald-100 dark:border-emerald-900/30 border-t-emerald-600 rounded-full animate-spin mb-8"></div>
                <h4 className="text-slate-900 dark:text-slate-100 font-black text-lg animate-pulse">{t('processing')}</h4>
                <p className="text-xs text-slate-500 mt-2">{t('parsingFiles')}</p>
            </div>
          )}

          {step === 3 && (
            <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
                <div className="flex items-center justify-between">
                    <h4 className="font-bold text-slate-800 dark:text-slate-200 flex items-center gap-2"><Filter size={18} className="text-emerald-500" /> Parsed Data Preview</h4>
                    <span className="text-[10px] font-bold bg-emerald-100 text-emerald-600 px-2 py-0.5 rounded-full">{parsedProducts.length} Items</span>
                </div>
                <div className="max-h-60 overflow-y-auto custom-scrollbar border rounded-xl border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900">
                    {parsedProducts.slice(0, 10).map((p, i) => (
                        <div key={i} className="flex justify-between items-center p-3 border-b border-slate-100 dark:border-slate-800 last:border-0">
                            <div>
                                <div className="font-bold text-xs">{p.gradeName}</div>
                                <div className="text-[10px] text-slate-500">{p.manufacturer}</div>
                            </div>
                            <div className="text-[10px] bg-slate-200 dark:bg-slate-800 px-2 py-1 rounded">{Object.keys(p.properties).length} props</div>
                        </div>
                    ))}
                    {parsedProducts.length > 10 && <div className="p-2 text-center text-xs text-slate-400">...and {parsedProducts.length - 10} more</div>}
                </div>
                <div className="pt-2">
                    <button onClick={() => setStep(4)} className="w-full py-3.5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-bold text-sm shadow-lg flex items-center justify-center gap-2">
                        <CheckCircle size={16} /> {t('confirmMerge')}
                    </button>
                </div>
            </div>
          )}

          {step === 4 && (
            <div className="flex flex-col items-center justify-center py-6 text-center animate-in zoom-in-95 duration-500">
                <div className="w-24 h-24 bg-emerald-100 dark:bg-emerald-900/40 rounded-full flex items-center justify-center mb-6 shadow-xl">
                    <CheckCircle className="text-emerald-600 w-12 h-12" />
                </div>
                <h4 className="text-slate-900 dark:text-white font-black text-2xl mb-2">{t('success')}</h4>
                <p className="text-slate-500 text-sm mb-8"><span className="text-emerald-600 dark:text-emerald-400 font-bold">{parsedProducts.length} {t('recordsProcessed')}</span></p>
                <div className="flex gap-3 w-full">
                    <button onClick={() => { if(onImport) onImport(parsedProducts); onClose(); }} className="flex-1 px-4 py-3 bg-slate-900 dark:bg-emerald-600 text-white font-bold rounded-2xl shadow-xl active:scale-95 transition-all">{t('finish')}</button>
                </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect, ReactNode, useCallback } from 'react';
