const getDynamicColumns = (products: Product[]): ColumnConfig[] => {
  const propertyKeys = new Set<string>();
  products.forEach(p => { Object.keys(p.properties).forEach(k => propertyKeys.add(k)); });
  const defaultVisible = ['密度', '熔体质量流动速率', '拉伸屈服应力', '弯曲模量', '典型应用'];
  const dynamicCols: ColumnConfig[] = Array.from(propertyKeys).map(key => ({
    key, label: key, visible: defaultVisible.includes(key), isSystem: false
  })).sort((a, b) => {
      const aIsLikelyImportant = defaultVisible.includes(a.key);
      const bIsLikelyImportant = defaultVisible.includes(b.key);
      if (aIsLikelyImportant && !bIsLikelyImportant) return -1;
      if (!aIsLikelyImportant && bIsLikelyImportant) return 1;
      return a.label.localeCompare(b.label);
  });
  return [
    { key: 'gradeName', label: '牌号', visible: true, isSystem: true },
    { key: 'manufacturer', label: '生产厂家', visible: true, isSystem: true },
    ...dynamicCols
  ];
};

type AppView = 'dashboard' | 'analytics' | 'ai';

const AppContent: React.FC = () => {
  const { t, tProp, language } = useLanguage();
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('resindb-session');
    return saved ? JSON.parse(saved) : null;
  });

  const [toasts, setToasts] = useState<Toast[]>([]);
  const addToast = useCallback((type: Toast['type'], message: string) => {
      const id = Date.now().toString();
      setToasts(prev => [...prev, { id, type, message }]);
      setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3000);
  }, []);

  const [allProducts, setAllProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [selectedCategoryIds, setSelectedCategoryIds] = useState<Set<string>>(new Set());

  const [searchQuery, setSearchQuery] = useState('');
  const [columns, setColumns] = useState<ColumnConfig[]>([]);
  const [isImportOpen, setIsImportOpen] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [viewingProduct, setViewingProduct] = useState<Product | null>(null);
  const [activeView, setActiveView] = useState<AppView>('dashboard');
  const [isExporting, setIsExporting] = useState(false);
  const [isComparisonOpen, setIsComparisonOpen] = useState(false);

  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [showFilters, setShowFilters] = useState(false);
  const [numericFilters, setNumericFilters] = useState<Record<string, { min: string; max: string }>>({});

  useEffect(() => { setColumns(getDynamicColumns(allProducts)); }, [allProducts]);

  const categoryCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    allProducts.forEach(product => {
        const cats = Array.isArray(product.categoryIds) ? product.categoryIds : [];
        cats.forEach(catId => {
            counts[catId] = (counts[catId] || 0) + 1;
        });
    });
    return counts;
  }, [allProducts]);

  // Helper to find category name map
  const categoryNameMap = useMemo(() => {
      const map = new Map<string, string>();
      const traverse = (cats: Category[]) => {
          cats.forEach(c => {
              map.set(c.id, language === 'en' && c.nameEn ? c.nameEn : c.name);
              if (c.children) traverse(c.children);
          });
      };
      traverse(CATEGORY_TREE);
      return map;
  }, [language]);

  const resolvePropKey = useCallback((label: string): string | null => {
      const cleanLabel = label.toLowerCase();
      const directMatch = columns.find(c => c.key.toLowerCase() === cleanLabel || tProp(c.label).toLowerCase() === cleanLabel);
      if (directMatch) return directMatch.key;
      const reverseKey = Object.keys(propertyMap).find(k => k.toLowerCase() === cleanLabel || propertyMap[k].toLowerCase() === cleanLabel);
      if (reverseKey) return reverseKey;
      return null;
  }, [columns, tProp]);

  const filteredData = useMemo(() => {
    const syntaxRegex = /([\u4e00-\u9fa5\w]+):([<>]=?|[-.0-9a-zA-Z]+)/g;
    const syntaxFilters: { key: string, operator: string, value: string | number, max?: number }[] = [];
    let processedQuery = searchQuery;
    let match;
    while ((match = syntaxRegex.exec(searchQuery)) !== null) {
        const [full, label, condition] = match;
        const key = resolvePropKey(label);
        if (key) {
            processedQuery = processedQuery.replace(full, '');
            if (condition.includes('-') && !condition.startsWith('-')) {
                const parts = condition.split('-');
                syntaxFilters.push({ key, operator: 'range', value: parseFloat(parts[0]), max: parseFloat(parts[1]) });
            } else if (condition.match(/^[<>]=?/)) {
                const op = condition.match(/^[<>]=?/)?.[0] || '';
                const val = parseFloat(condition.replace(op, ''));
                syntaxFilters.push({ key, operator: op, value: val });
            } else {
                const numVal = parseFloat(condition);
                syntaxFilters.push({ key, operator: '=', value: isNaN(numVal) ? condition : numVal });
            }
        }
    }
    const textKeywords = processedQuery.toLowerCase().split(' ').filter(k => k.trim());
    return allProducts.filter(product => {
      // Logic Update: Multi-select filtering with robust handling for empty/null categoryIds
      if (selectedCategoryIds.size > 0) {
          const pCats = Array.isArray(product.categoryIds) ? product.categoryIds : [];
          const hasMatch = pCats.some(id => selectedCategoryIds.has(id));
          if (!hasMatch) return false;
      }

      const matchesText = textKeywords.every(query => product.gradeName.toLowerCase().includes(query) || product.manufacturer.toLowerCase().includes(query) || Object.keys(product.properties).some(k => k.toLowerCase().includes(query)));
      if (!matchesText) return false;
      const matchesSyntax = syntaxFilters.every(f => {
          const propVal = product.properties[f.key]?.value;
          const val = typeof propVal === 'number' ? propVal : parseFloat(String(propVal));
          if (isNaN(val) || typeof f.value === 'string') return String(propVal).toLowerCase().includes(String(f.value).toLowerCase());
          switch(f.operator) {
              case '>': return val > (f.value as number);
              case '<': return val < (f.value as number);
              case '>=': return val >= (f.value as number);
              case '<=': return val <= (f.value as number);
              case 'range': return val >= (f.value as number) && val <= (f.max || Infinity);
              case '=': return val === (f.value as number);
              default: return true;
          }
      });
      if (!matchesSyntax) return false;
      return Object.entries(numericFilters).every(([key, range]) => {
          const propVal = product.properties[key]?.value;
          const num = typeof propVal === 'number' ? propVal : parseFloat(String(propVal));
          if (isNaN(num)) return true;
          const min = range.min === '' ? -Infinity : parseFloat(range.min);
          const max = range.max === '' ? Infinity : parseFloat(range.max);
          return num >= min && num <= max;
      });
    });
  }, [allProducts, selectedCategoryIds, searchQuery, numericFilters, resolvePropKey]);

  const handleLogin = (user: User) => { setCurrentUser(user); localStorage.setItem('resindb-session', JSON.stringify(user)); };
  const handleLogout = () => { setCurrentUser(null); localStorage.removeItem('resindb-session'); };
  const handleToggleColumn = (key: string) => { setColumns(cols => cols.map(c => c.key === key ? { ...c, visible: !c.visible } : c)); };
  const handleToggleAllColumns = (visible: boolean) => { setColumns(cols => cols.map(c => c.isSystem ? c : { ...c, visible })); };

  const handleExport = async () => { setIsExporting(true); await new Promise(r => setTimeout(r, 800)); addToast('success', '分析报告已生成'); setIsExporting(false); };
  const handleDelete = (ids: string[]) => { setAllProducts(prev => prev.filter(p => !ids.includes(p.id))); setSelectedIds(new Set()); addToast('success', `已同步删除 ${ids.length} 条记录`); };

  const handleImportData = (newProducts: Product[]) => { 
      setAllProducts(prev => [...newProducts, ...prev]); 
      setIsImportOpen(false); 
      addToast('success', `${newProducts.length} 条数据入库成功`); 
  };

  const handleUpdateUserProfile = (updatedData: any) => {
    if (!currentUser) return;
    const newUser = { ...currentUser, ...updatedData };
    setCurrentUser(newUser);
    localStorage.setItem('resindb-session', JSON.stringify(newUser));
    addToast('success', t('updateSuccess'));
  };

  const handleAIGradeClick = (gradeName: string) => {
      const p = allProducts.find(prod => prod.gradeName.toLowerCase() === gradeName.toLowerCase());
      if (p) setViewingProduct(p);
      else addToast('info', `库中未找到牌号: ${gradeName}`);
  };

  const toggleCategory = (id: string) => {
      setSelectedCategoryIds(prev => {
          const next = new Set(prev);
          if (next.has(id)) {
              next.delete(id);
          } else {
              next.add(id);
          }
          return next;
      });
  };

  const selectSingleCategory = (id: string) => {
      setSelectedCategoryIds(new Set([id]));
  };

  const productsToCompare = useMemo(() => {
      return allProducts.filter(p => selectedIds.has(p.id));
  }, [allProducts, selectedIds]);

  const activeFilters = useMemo<FilterItem[]>(() => {
      const items: FilterItem[] = [];
      if (searchQuery.trim()) {
          items.push({
              id: 'search',
              label: `Search: "${searchQuery}"`,
              type: 'search',
              onRemove: () => setSearchQuery('')
          });
      }
      selectedCategoryIds.forEach(id => {
          items.push({
              id: `cat-${id}`,
              label: categoryNameMap.get(id) || id,
              type: 'category',
              onRemove: () => toggleCategory(id)
          });
      });
      return items;
  }, [searchQuery, selectedCategoryIds, categoryNameMap]);

  if (!currentUser) return <AuthScreen onLogin={handleLogin} />;

  return (
    <div className="flex h-screen bg-slate-50 dark:bg-slate-950 font-sans text-slate-900 dark:text-slate-100 overflow-hidden transition-colors duration-300">
      <ToastContainer toasts={toasts} removeToast={(id) => setToasts(prev => prev.filter(t => t.id !== id))} />

      <nav className="w-16 md:w-20 bg-slate-900 dark:bg-slate-950 flex flex-col items-center py-6 gap-6 z-[70] shrink-0 border-r border-white/5 shadow-2xl">
         <div className="w-12 h-12 bg-primary-600 rounded-2xl flex items-center justify-center shadow-lg shadow-primary-900/40 mb-2 overflow-hidden relative group cursor-pointer" onClick={() => setActiveView('dashboard')}>
            <Microscope size={24} className="text-white group-hover:rotate-12 transition-transform" />
            <div className="absolute inset-0 bg-white/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
         </div>
         <div className="flex-1 flex flex-col gap-6">
            {[
                { id: 'dashboard', icon: LayoutDashboard, label: '数据仓库' },
                { id: 'analytics', icon: PieChart, label: '科研可视化' },
                { id: 'ai', icon: Bot, label: 'AI 实验室' }
            ].map((btn) => (
                <button key={btn.id} onClick={() => setActiveView(btn.id as AppView)} className={`w-12 h-12 rounded-2xl transition-all duration-300 relative group flex items-center justify-center ${activeView === btn.id ? 'bg-primary-600 text-white shadow-lg shadow-primary-500/20 scale-105' : 'text-slate-500 hover:text-primary-400 hover:bg-slate-800'}`} title={btn.label}>
                    <btn.icon size={22} />
                    {activeView === btn.id && <div className="absolute -left-3 top-1/2 -translate-y-1/2 w-1.5 h-8 bg-primary-400 rounded-r-full"></div>}
                </button>
            ))}
         </div>
         <div className="flex flex-col gap-4 mb-2">
            <button onClick={() => setIsAdminOpen(true)} className="w-12 h-12 flex items-center justify-center text-slate-500 hover:text-amber-400 hover:bg-slate-800 rounded-2xl transition-all"><ShieldCheck size={22} /></button>
         </div>
      </nav>

      <div className="flex-1 flex flex-col min-w-0 h-full relative">
        <div className="shrink-0 z-[60] relative">
            <TopBar 
                user={currentUser} onLogout={handleLogout} onOpenProfile={() => setIsProfileOpen(true)} onOpenAdmin={() => setIsAdminOpen(true)} 
                searchQuery={searchQuery} onSearchChange={setSearchQuery} columns={columns} onToggleColumn={handleToggleColumn} onToggleAllColumns={handleToggleAllColumns} 
                onOpenImport={() => setIsImportOpen(true)} onExport={handleExport} isExporting={isExporting} viewMode={activeView === 'analytics' ? 'chart' : 'grid'} 
                onViewModeChange={(m) => setActiveView(m === 'chart' ? 'analytics' : 'dashboard')} showAdvancedFilters={showFilters} onToggleFilters={() => setShowFilters(!showFilters)} activeFilterCount={Object.keys(numericFilters).length}
            />
        </div>

        <div className="flex-1 flex overflow-hidden">
            {(activeView === 'dashboard' || activeView === 'analytics') && (
                <div className="w-72 shrink-0 border-r border-slate-200 dark:border-slate-800 bg-white/50 dark:bg-slate-900/50 backdrop-blur-sm flex flex-col">
                    <TreeSidebar 
                        categories={CATEGORY_TREE} 
                        selectedCategoryIds={selectedCategoryIds} 
                        onToggleCategory={toggleCategory} 
                        onClearCategories={() => setSelectedCategoryIds(new Set())}
                        totalCount={allProducts.length} 
                        counts={categoryCounts} 
                    />
                </div>
            )}

            <div className="flex-1 flex flex-col p-6 min-h-0 relative">
                <div className="flex-1 w-full min-h-0 relative animate-in fade-in duration-500">
                    {activeView === 'dashboard' && (
                        <div className="absolute inset-0 bg-white/40 dark:bg-slate-950/20 border border-white/20 dark:border-slate-800 rounded-[2.5rem] shadow-inner overflow-hidden">
                            <DataGrid 
                                data={filteredData} 
                                columns={columns} 
                                isLoading={false} 
                                onDelete={handleDelete} 
                                onUpdate={(p) => { setAllProducts(prev => prev.map(old => old.id === p.id ? p : old)); addToast('success', '牌号物性已更新'); }} 
                                onBatchUpdate={(ids, u) => { setAllProducts(prev => prev.map(p => ids.includes(p.id) ? {...p, ...u} : p)); addToast('success', '批量更新完成'); }} 
                                onCategorySelect={selectSingleCategory} 
                                selectedIds={selectedIds} 
                                onSelectionChange={setSelectedIds} 
                                onClearFilters={() => { setSelectedCategoryIds(new Set()); setSearchQuery(''); }}
                                activeFilters={activeFilters}
                            />
                        </div>
                    )}
                    {activeView === 'analytics' && (
                        <div className="absolute inset-0"><DataVisualizer data={filteredData} selectedProducts={allProducts.filter(p => selectedIds.has(p.id))} /></div>
                    )}
                    {activeView === 'ai' && (
                        <div className="absolute inset-0 flex flex-col bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 overflow-hidden shadow-2xl">
                             <div className="p-6 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-950/50 flex items-center justify-between">
                                <div className="flex items-center gap-4">
                                    <div className="p-3 bg-primary-600 rounded-2xl text-white shadow-lg shadow-primary-500/20"><Bot size={24} /></div>
                                    <div><h2 className="text-xl font-black text-slate-800 dark:text-white tracking-tight">ResinAI Lab</h2><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1.5"><Sparkles size={10} className="text-primary-500" /> Deep Scientific Engine Active</p></div>
                                </div>
                             </div>
                             <div className="flex-1 relative bg-slate-50/30 dark:bg-transparent overflow-hidden"><AIAssistant contextData={filteredData} inlineView={true} onGradeClick={handleAIGradeClick} onNavigateToChart={() => setActiveView('analytics')} /></div>
                        </div>
                    )}
                </div>
            </div>
        </div>

        {selectedIds.size > 0 && (
            <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[80] animate-in slide-in-from-bottom-10 duration-500 pointer-events-none">
                <div className="pointer-events-auto bg-slate-900/90 dark:bg-white/90 backdrop-blur-2xl px-6 py-4 rounded-[2.5rem] border border-white/10 dark:border-slate-200 shadow-2xl flex items-center gap-6">
                    <div className="flex items-center gap-3 pr-6 border-r border-white/10 dark:border-slate-200">
                        <div className="w-10 h-10 bg-primary-600 rounded-full flex items-center justify-center text-white font-black text-sm shadow-glow">{selectedIds.size}</div>
                        <div><p className="text-xs font-black text-white dark:text-slate-900 uppercase tracking-widest">{t('selected')}</p><p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-tighter">项记录已入选</p></div>
                    </div>
                    <div className="flex items-center gap-4">
                        <button onClick={() => setIsComparisonOpen(true)} className="flex flex-col items-center gap-1 group">
                            <div className="p-3 bg-white/5 dark:bg-slate-100 rounded-2xl text-white dark:text-slate-700 hover:bg-emerald-500 hover:text-white transition-all group-hover:scale-110 active:scale-95"><GitCompare size={20} /></div>
                            <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-tighter">对比分析</span>
                        </button>

                        <button onClick={handleExport} className="flex flex-col items-center gap-1 group">
                            <div className="p-3 bg-white/5 dark:bg-slate-100 rounded-2xl text-white dark:text-slate-700 hover:bg-primary-600 hover:text-white transition-all group-hover:scale-110 active:scale-95"><Download size={20} /></div>
                            <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-tighter">生成报告</span>
                        </button>
                        <button onClick={() => handleDelete(Array.from(selectedIds))} className="flex flex-col items-center gap-1 group">
                            <div className="p-3 bg-white/5 dark:bg-rose-100 rounded-2xl text-white dark:text-rose-700 hover:bg-rose-600 hover:text-white transition-all group-hover:scale-110 active:scale-95"><Trash2 size={20} /></div>
                            <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-tighter">{t('delete')}</span>
                        </button>
                    </div>
                </div>
            </div>
        )}
      </div>

      <ImportModal isOpen={isImportOpen} onClose={() => setIsImportOpen(false)} onImport={handleImportData} />
      <ProfileModal isOpen={isProfileOpen} onClose={() => setIsProfileOpen(false)} user={currentUser} onSave={handleUpdateUserProfile} />
      <AdminModal isOpen={isAdminOpen} onClose={() => setIsAdminOpen(false)} />
      {activeView !== 'ai' && <AIAssistant contextData={filteredData} />}
      <ProductDetailDrawer product={viewingProduct} onClose={() => setViewingProduct(null)} onCategoryClick={selectSingleCategory} />
      {isComparisonOpen && <ComparisonView products={productsToCompare} onClose={() => setIsComparisonOpen(false)} onRemoveProduct={(id) => { const next = new Set(selectedIds); next.delete(id); setSelectedIds(next); if(next.size === 0) setIsComparisonOpen(false); }} />}
    </div>
  );
};

const App: React.FC = () => (<LanguageProvider><ThemeProvider><AppContent /></ThemeProvider></LanguageProvider>);
export default App;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import * as echarts from 'echarts';
import { Loader2, AlertCircle, BarChart3, Database, ChevronDown, ChevronRight, Bug, RefreshCw } from 'lucide-react';
import { useTheme } from '../contexts/ThemeContext';
import { getRadarChartOption } from './charts/RadarBenchmark';
import { getAshbyChartOption } from './charts/AshbyScatter';
import { getGpcChartOption } from './charts/GpcDistribution';
import { getRheologyChartOption } from './charts/RheologyCurve';
import { getTernaryChartOption } from './charts/TernaryBlend';
import { getMfrDensityChartOption } from './charts/MfrDensityScatter';

export type ChartType = 'radar' | 'ashby' | 'gpc' | 'rheology' | 'ternary' | 'mfr_density';

interface ScientificChartProps {
  type: ChartType;
  data: any;
  loading?: boolean;
  className?: string;
  height?: string | number;
  onChartReady?: (instance: echarts.ECharts) => void;
}

export const ScientificChart: React.FC<ScientificChartProps> = ({ 
  type, 
  data, 
  loading = false, 
  className = "", 
  height = "100%",
  onChartReady 
}) => {
  const chartRef = useRef<HTMLDivElement>(null);
  const chartInstance = useRef<echarts.ECharts | null>(null);
  const resizeObserver = useRef<ResizeObserver | null>(null);
  const { theme } = useTheme();

  const [error, setError] = useState<string | null>(null);
  const [isChartEmpty, setIsChartEmpty] = useState(false);
  const [showDebug, setShowDebug] = useState(false);

  const disposeChart = useCallback(() => {
    if (chartInstance.current) {
      if (!chartInstance.current.isDisposed()) {
        chartInstance.current.dispose();
      }
      chartInstance.current = null;
    }
  }, []);

  const validateData = useCallback(() => {
    if (!data) return false;

    // Rheology expects { products: [], temps: [] }
    if (type === 'rheology') {
        return data.products && Array.isArray(data.products) && data.products.length > 0;
    }

    if (Array.isArray(data)) {
        if (data.length === 0) return false;

        // For scatter plots (Ashby, MFR-Density), check if any series has data
        if (type === 'ashby' || type === 'mfr_density') {
            return data.some(s => s.data && Array.isArray(s.data) && s.data.length > 0);
        }

        // For Radar, ensure there are values and they are not all empty/NaN
        if (type === 'radar') {
             return data.some(d => d.value && Array.isArray(d.value) && d.value.some((v: any) => v !== undefined && v !== null && !isNaN(v)));
        }
    }

    return true;
  }, [data, type]);

  const getOption = useCallback(() => {
    try {
        let option: any = {};
        switch (type) {
            case 'radar': option = getRadarChartOption(data, theme); break;
            case 'ashby': option = getAshbyChartOption(data, theme); break;
            case 'mfr_density': option = getMfrDensityChartOption(data, theme); break;
            case 'gpc': option = getGpcChartOption(data, theme); break;
            case 'rheology': option = getRheologyChartOption(data.products, theme, data.temps); break;
            case 'ternary': option = getTernaryChartOption(data, theme); break;
            default: throw new Error(`Unknown chart type: ${type}`);
        }

        if (option.grid) { option.grid.containLabel = true; }
        if (!option.tooltip) option.tooltip = {};
        option.tooltip.confine = true;
        option.tooltip.enterable = true;
        // CRITICAL: Higher Z-Index for Tooltip to stay above UI overlays
        option.tooltip.extraCssText = 'z-index: 99999 !important; box-shadow: 0 10px 30px rgba(0,0,0,0.2); border-radius: 12px; pointer-events: none;';

        ['xAxis', 'yAxis'].forEach(axis => {
            if (option[axis] && option[axis].type === 'log') {
               option[axis].logBase = 10;
               if (!option[axis].min) option[axis].min = (v: any) => v.min > 0 ? v.min * 0.9 : 0.01; 
            }
        });
        return option;
    } catch (err: any) {
        throw new Error(err.message || "Failed to generate visualization");
    }
  }, [type, data, theme]);

  useEffect(() => {
    if (!chartRef.current) return;

    // Clear error on new data
    setError(null);

    if (!validateData()) {
        setIsChartEmpty(true);
        if (chartInstance.current) {
            chartInstance.current.clear();
        }
        return;
    }

    setIsChartEmpty(false);

    if (!chartInstance.current) {
        chartInstance.current = echarts.init(chartRef.current, undefined, { renderer: 'canvas' });
        if (onChartReady) onChartReady(chartInstance.current);
    }

    try {
        const option = getOption();
        chartInstance.current.setOption(option, { notMerge: true });
    } catch (err: any) {
        setError(err.message);
        // Do not dispose immediately to keep the container size, just clear
        chartInstance.current.clear();
    }

    if (!resizeObserver.current) {
        resizeObserver.current = new ResizeObserver((entries) => {
            if (!chartInstance.current || chartInstance.current.isDisposed()) return;
            for (const entry of entries) {
                if (entry.contentRect.width > 0 && entry.contentRect.height > 0) chartInstance.current.resize();
            }
        });
        resizeObserver.current.observe(chartRef.current);
    }
  }, [data, theme, type, validateData, getOption, disposeChart, onChartReady]);

  useEffect(() => {
      return () => {
          if (resizeObserver.current) { resizeObserver.current.disconnect(); resizeObserver.current = null; }
          disposeChart();
      };
  }, [disposeChart]);

  // Helper to make error messages friendlier
  const getFriendlyErrorMessage = (rawError: string) => {
      if (rawError.includes('series')) return "The selected data structure doesn't match this chart type.";
      if (rawError.includes('undefined')) return "Some required properties are missing from the data.";
      if (rawError.includes('log')) return "Cannot plot zero or negative values on a logarithmic scale.";
      return "We encountered an unexpected issue rendering this visualization.";
  };

  if (error) {
      return (
          <div className={`flex flex-col items-center justify-center bg-slate-50/80 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-800 rounded-3xl ${className} relative overflow-hidden`} style={{ height, minHeight: '300px' }}>
              <div className="absolute inset-0 bg-[radial-gradient(#e11d48_1px,transparent_1px)] [background-size:16px_16px] opacity-[0.03]"></div>

              <div className="z-10 flex flex-col items-center max-w-sm text-center p-6">
                  <div className="p-3 bg-rose-100 dark:bg-rose-900/30 rounded-2xl mb-4 shadow-lg shadow-rose-500/10 animate-bounce">
                      <AlertCircle className="text-rose-500" size={28} />
                  </div>
                  <h3 className="text-sm font-black text-slate-800 dark:text-slate-200 uppercase tracking-wide mb-2">
                      Visualization Unavailable
                  </h3>
                  <p className="text-xs text-slate-500 dark:text-slate-400 leading-relaxed mb-6">
                      {getFriendlyErrorMessage(error)} <br/>
                      <span className="opacity-70">Try selecting different products or checking your filters.</span>
                  </p>

                  <div className="w-full">
                      <button 
                        onClick={() => setShowDebug(!showDebug)}
                        className="flex items-center justify-center gap-2 w-full py-2 px-4 rounded-xl bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-[10px] font-bold text-slate-500 hover:text-slate-700 dark:hover:text-slate-300 transition-all hover:shadow-sm"
                      >
                          <Bug size={12} />
                          {showDebug ? 'Hide' : 'Show'} Technical Details
                          {showDebug ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                      </button>

                      {showDebug && (
                          <div className="mt-3 p-3 bg-slate-900 text-slate-300 rounded-xl text-[10px] font-mono text-left break-all shadow-inner border border-slate-700 animate-in slide-in-from-top-2">
                              <p className="mb-1 text-rose-400 font-bold">Error Trace:</p>
                              {error}
                          </div>
                      )}
                  </div>
              </div>
          </div>
      );
  }

  return (
    <div className={`relative w-full ${className}`} style={{ height, minHeight: '300px' }}>
        <div ref={chartRef} className={`w-full h-full transition-opacity duration-500 ${loading || isChartEmpty ? 'opacity-0' : 'opacity-100'}`} />

        {loading && (
            <div className="absolute inset-0 z-10 flex flex-col items-center justify-center bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm rounded-2xl transition-all duration-300">
                <Loader2 className="w-8 h-8 text-emerald-500 animate-spin mb-3" />
                <span className="text-xs font-bold text-slate-500 dark:text-slate-400 animate-pulse tracking-widest">PROCESSING DATA...</span>
            </div>
        )}

        {!loading && isChartEmpty && (
            <div className="absolute inset-0 z-10 flex flex-col items-center justify-center bg-slate-50/50 dark:bg-slate-900/50 rounded-2xl border border-dashed border-slate-200 dark:border-slate-800 backdrop-blur-[2px]">
                <div className="p-4 bg-white dark:bg-slate-800 rounded-full shadow-lg mb-4 ring-4 ring-slate-100 dark:ring-slate-800">
                    <Database className="text-slate-300 dark:text-slate-500" size={32} />
                </div>
                <h3 className="text-sm font-black text-slate-600 dark:text-slate-300 uppercase tracking-wide mb-1">
                    No Visualization Data
                </h3>
                <p className="text-[11px] text-slate-400 max-w-[240px] text-center leading-relaxed">
                    The current selection contains insufficient data points for 
                    <span className="font-bold text-emerald-500 mx-1">
                        {type === 'mfr_density' ? 'MFR-Density' : type.charAt(0).toUpperCase() + type.slice(1)}
                    </span>
                    analysis. Try selecting more products with complete property sets.
                </p>
            </div>
        )}
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";
import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Send, Image as ImageIcon, Sparkles, X, Loader2, BrainCircuit, Bot, User, ScanEye, Trash2, Maximize2, Minimize2, ShieldCheck, Settings2, Save, TrendingUp, Search, AlertTriangle, WifiOff, Key } from 'lucide-react';
import { Product } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import { useTheme } from '../contexts/ThemeContext';

interface AIAssistantProps {
  contextData: Product[];
  inlineView?: boolean;
  onNavigateToChart?: (chartType: string) => void;
  onGradeClick?: (gradeName: string) => void;
}

interface Message {
  id: string;
  role: 'user' | 'model' | 'system'; // Added 'system' for errors/notices
  text: string;
  image?: string;
  errorType?: 'network' | 'auth' | 'generic'; // For specific error styling
}

// Configuration Interface for API Settings
interface ApiConfig {
  provider: 'gemini' | 'openai_compatible';
  baseUrl: string;
  apiKey: string;
  model: string;
}

const ChartSuggestion: React.FC<{ type: string, onClick: () => void }> = ({ type, onClick }) => {
    return (
        <button 
            onClick={onClick}
            className="flex items-center gap-2 px-3 py-1.5 bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 rounded-lg border border-primary-200 dark:border-primary-800 hover:bg-primary-100 transition-all text-[10px] font-bold uppercase tracking-wider group"
        >
            <TrendingUp size={12} className="group-hover:translate-y-[-1px] transition-transform" />
            查看{type}分析
        </button>
    );
};

const FormattedText: React.FC<{ 
    text: string; 
    onNavigateToChart?: (type: string) => void;
    onGradeClick?: (name: string) => void;
    className?: string 
}> = ({ text, onNavigateToChart, onGradeClick, className }) => {
  if (!text) return null;

  return (
    <div className={className}>
      {text.split('\n').map((line, i) => {
        const trimmed = line.trim();
        if (trimmed.startsWith('- ') || trimmed.startsWith('* ') || trimmed.match(/^\d+\./)) {
             const cleanLine = trimmed.replace(/^[-*]\s+|\d+\.\s+/, '');
             const parts = cleanLine.split(/(\*\*.*?\*\*)/g);
             return (
                <div key={i} className="flex gap-2.5 ml-1 mb-1.5 items-start">
                    <span className="text-emerald-500 dark:text-emerald-400 mt-1.5 shrink-0 text-[10px]">•</span>
                    <span className="leading-relaxed text-sm">
                        {parts.map((part, j) => {
                            if (part.startsWith('**') && part.endsWith('**')) {
                                const grade = part.slice(2, -2);
                                return <strong key={j} onClick={() => onGradeClick?.(grade)} className="font-bold text-slate-800 dark:text-white hover:text-primary-600 hover:underline cursor-pointer transition-colors">{grade}</strong>;
                            }
                            return <span key={j}>{part}</span>;
                        })}
                    </span>
                </div>
             );
        }

        const parts = line.split(/(\*\*.*?\*\*)/g);
        if (line.startsWith('##')) {
             return <h3 key={i} className="font-bold text-emerald-700 dark:text-emerald-400 mt-5 mb-2 text-base border-l-2 border-emerald-500 pl-3">{line.replace(/#/g, '')}</h3>
        }

        if (!trimmed) return <div key={i} className="h-4"></div>;

        return (
          <p key={i} className="mb-2 last:mb-0 leading-relaxed text-sm">
            {parts.map((part, j) => {
              if (part.startsWith('**') && part.endsWith('**')) {
                const grade = part.slice(2, -2);
                return <strong key={j} onClick={() => onGradeClick?.(grade)} className="font-bold text-slate-800 dark:text-white hover:text-primary-600 hover:underline cursor-pointer transition-colors">{grade}</strong>;
              }
              return <span key={j}>{part}</span>;
            })}
          </p>
        );
      })}

      <div className="flex flex-wrap gap-2 mt-4 pt-4 border-t border-slate-100 dark:border-slate-800">
          {(text.includes('Ashby') || text.includes('散点') || text.includes('构效')) && (
              <ChartSuggestion type="Ashby" onClick={() => onNavigateToChart?.('ashby')} />
          )}
          {(text.includes('Radar') || text.includes('雷达') || text.includes('指纹')) && (
              <ChartSuggestion type="Radar" onClick={() => onNavigateToChart?.('radar')} />
          )}
          {(text.includes('GPC') || text.includes('分布')) && (
              <ChartSuggestion type="GPC" onClick={() => onNavigateToChart?.('gpc')} />
          )}
      </div>
    </div>
  );
};

export const AIAssistant: React.FC<AIAssistantProps> = ({ contextData, inlineView = false, onNavigateToChart, onGradeClick }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [input, setInput] = useState('');
  const { t } = useLanguage();
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [useThinking, setUseThinking] = useState(true); 
  const [attachedImage, setAttachedImage] = useState<string | null>(null);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  // API Configuration State
  const [apiConfig, setApiConfig] = useState<ApiConfig>(() => {
      const saved = localStorage.getItem('resindb-api-config');
      return saved ? JSON.parse(saved) : {
          provider: 'gemini',
          baseUrl: 'https://api.openai.com/v1', // Placeholder for custom
          apiKey: '',
          model: 'gemini-3-pro-preview'
      };
  });

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (messages.length === 0) {
        setMessages([{ 
            id: 'welcome', 
            role: 'model', 
            text: t('welcomeMessage') 
        }]);
    }
  }, [t]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading, isOpen]);

  const saveConfig = (newConfig: ApiConfig) => {
      setApiConfig(newConfig);
      localStorage.setItem('resindb-api-config', JSON.stringify(newConfig));
      setShowSettings(false);
  };

  const filteredMessages = useMemo(() => {
    if (!searchQuery.trim()) return messages;
    return messages.filter(m => m.text.toLowerCase().includes(searchQuery.toLowerCase()));
  }, [messages, searchQuery]);

  const handleSendMessage = async (customInput?: string) => {
    const textToSend = customInput || input;
    if ((!textToSend.trim() && !attachedImage) || isLoading) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend,
      image: attachedImage || undefined
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setAttachedImage(null);
    setIsLoading(true);
    if(searchQuery) {
        setSearchQuery('');
        setIsSearchOpen(false);
    }

    // Prepare Context string
    let contextStr = "";
    if (contextData.length > 0) {
        contextStr = JSON.stringify(contextData.slice(0, 20).map(p => ({
            grade: p.gradeName,
            manufacturer: p.manufacturer,
            mfr: p.properties['熔体质量流动速率']?.value,
            density: p.properties['密度']?.value,
            flex: p.properties['弯曲模量']?.value,
            impact: p.properties['悬臂梁缺口冲击强度']?.value,
            app: p.properties['典型应用']?.value
        })));
    }

    const systemPromptText = "You are ResinAI. A senior materials scientist at PetroChina Research Institute. Analyze data specifically. Wrap grade names in **double asterisks** like **HDPE 5000S**. Suggest using specific charts if appropriate (Ashby, Radar, GPC)." + 
        (userMsg.image ? "\nFocus on image-based QC analysis." : "") + 
        (contextStr ? `\n[Experimental Context]: ${contextStr}` : "");

    try {
      let responseText = "";

      if (apiConfig.provider === 'gemini') {
          // --- Google Gemini Logic ---
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const parts: any[] = [];

          if (userMsg.image) {
             const base64Data = userMsg.image.split(',')[1];
             const mimeType = userMsg.image.split(';')[0].split(':')[1] || 'image/jpeg';
             parts.push({ inlineData: { mimeType, data: base64Data } });
          }
          parts.push({ text: userMsg.text });
          if (contextStr) parts.push({ text: `\nData: ${contextStr}` });

          const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: [{ role: 'user', parts: parts }],
            config: {
                systemInstruction: systemPromptText,
                thinkingConfig: useThinking ? { thinkingBudget: 2048 } : undefined,
            }
          });
          responseText = response.text || "Analysis result empty.";

      } else {
          // --- OpenAI Compatible Logic ---
          if (!apiConfig.apiKey) throw new Error("API Key Missing");

          const openaiMessages: any[] = [
              { role: "system", content: systemPromptText }
          ];

          let contentPayload: any = userMsg.text;

          if (userMsg.image) {
              contentPayload = [
                  { type: "text", text: userMsg.text },
                  { type: "image_url", image_url: { url: userMsg.image } }
              ];
          }

          openaiMessages.push({ role: "user", content: contentPayload });

          const response = await fetch(`${apiConfig.baseUrl}/chat/completions`, {
              method: 'POST',
              headers: {
                  'Content-Type': 'application/json',
                  'Authorization': `Bearer ${apiConfig.apiKey}`
              },
              body: JSON.stringify({
                  model: apiConfig.model || 'deepseek-chat', 
                  messages: openaiMessages,
                  temperature: 0.7,
                  max_tokens: 2048
              })
          });

          if (!response.ok) {
              const err = await response.text();
              throw new Error(`API ${response.status}: ${err}`);
          }

          const data = await response.json();
          responseText = data.choices?.[0]?.message?.content || "No response content.";
      }

      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        text: responseText
      }]);

    } catch (error: any) {
      console.error("AI Error:", error);

      let friendlyMsg = "I'm having trouble processing that request.";
      let errorType: Message['errorType'] = 'generic';

      if (error.message.includes('API Key') || error.message.includes('401') || error.message.includes('403')) {
          friendlyMsg = "It looks like my access credentials (API Key) are missing or invalid. Please check the settings.";
          errorType = 'auth';
      } else if (error.message.includes('fetch') || error.message.includes('Network') || error.message.includes('503')) {
          friendlyMsg = "I can't reach the data center right now. Please check your internet connection.";
          errorType = 'network';
      }

      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'system',
        text: friendlyMsg,
        errorType: errorType
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const renderInput = () => (
    <div className="flex items-end gap-2 bg-slate-100 dark:bg-slate-800/50 p-2 rounded-[2rem] border border-slate-200 dark:border-slate-700 focus-within:ring-4 focus-within:ring-primary-500/10 focus-within:border-primary-500 transition-all shadow-inner">
        <input type="file" ref={fileInputRef} accept="image/*" className="hidden" onChange={(e) => {
            const f = e.target.files?.[0];
            if(f){ const r = new FileReader(); r.onloadend = () => setAttachedImage(r.result as string); r.readAsDataURL(f); }
        }} />
        <button 
            onClick={() => fileInputRef.current?.click()} 
            className={`p-3 rounded-2xl transition-all shrink-0 ${attachedImage ? 'text-emerald-600 bg-emerald-100 dark:bg-emerald-900/30' : 'text-slate-400 hover:text-primary-600 hover:bg-white dark:hover:bg-slate-800'}`}
        >
            <ImageIcon size={22} />
        </button>
        <textarea
            value={input} onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => { if(e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSendMessage(); }}}
            placeholder={t('aiPlaceholder')}
            className="w-full max-h-48 min-h-[44px] py-3 bg-transparent text-sm text-slate-800 dark:text-slate-200 outline-none resize-none leading-relaxed"
            rows={1}
        />
        <div className="flex items-center gap-2 self-center pr-1">
            <button 
                onClick={() => setUseThinking(!useThinking)}
                className={`p-3 rounded-2xl transition-all ${useThinking ? 'text-indigo-600 bg-indigo-100 dark:bg-indigo-900/30' : 'text-slate-400 hover:text-primary-600'}`}
                title="深度逻辑引擎 (Thinking)"
            >
                <BrainCircuit size={22} />
            </button>
            <button 
                onClick={() => handleSendMessage()} 
                disabled={isLoading || (!input.trim() && !attachedImage)} 
                className="p-3 bg-slate-900 dark:bg-primary-600 hover:bg-primary-700 disabled:opacity-20 text-white rounded-2xl shadow-xl transition-all active:scale-95 flex items-center justify-center shrink-0"
            >
                {isLoading ? <Loader2 size={22} className="animate-spin" /> : <Send size={22} />}
            </button>
        </div>
    </div>
  );

  // ... (SearchBar and SettingsPanel components remain mostly same, can reuse existing logic)
  const SearchBar = () => (
    <div className="px-4 py-2 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-slate-100 dark:border-slate-800 animate-in slide-in-from-top-2 z-10 sticky top-0">
        <div className="relative">
            <Search className="absolute left-3 top-2.5 text-slate-400" size={14} />
            <input 
                autoFocus type="text" value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Search history..."
                className="w-full pl-9 pr-8 py-2 bg-slate-100 dark:bg-slate-800 border-none rounded-xl text-xs font-medium outline-none focus:ring-2 focus:ring-primary-500/20 text-slate-700 dark:text-slate-200"
            />
            {searchQuery && (
                <button onClick={() => setSearchQuery('')} className="absolute right-2.5 top-2.5 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
                    <X size={14} />
                </button>
            )}
        </div>
        {searchQuery && (
            <div className="mt-1 px-1 text-[10px] text-slate-400">Found {filteredMessages.length} results</div>
        )}
    </div>
  );

  const SettingsPanel = () => (
      <div className="absolute inset-0 bg-white/95 dark:bg-slate-900/95 backdrop-blur-xl z-[60] p-6 flex flex-col animate-in fade-in zoom-in-95 duration-200">
          <div className="flex items-center justify-between mb-6">
              <h3 className="text-lg font-black text-slate-800 dark:text-white flex items-center gap-2">
                  <Settings2 size={20} className="text-primary-500" />
                  AI 模型配置
              </h3>
              <button onClick={() => setShowSettings(false)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl"><X size={20} /></button>
          </div>
          <div className="space-y-5 flex-1 overflow-y-auto custom-scrollbar p-1">
              <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">API 提供商</label>
                  <div className="grid grid-cols-2 gap-3">
                      <button onClick={() => setApiConfig(prev => ({...prev, provider: 'gemini'}))} className={`p-4 rounded-2xl border-2 text-left transition-all ${apiConfig.provider === 'gemini' ? 'border-primary-500 bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300' : 'border-slate-200 dark:border-slate-800 hover:border-primary-200'}`}>
                          <div className="font-bold text-sm mb-1">Google Gemini</div>
                          <div className="text-[10px] opacity-70">Google GenAI SDK (Internal)</div>
                      </button>
                      <button onClick={() => setApiConfig(prev => ({...prev, provider: 'openai_compatible'}))} className={`p-4 rounded-2xl border-2 text-left transition-all ${apiConfig.provider === 'openai_compatible' ? 'border-primary-500 bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300' : 'border-slate-200 dark:border-slate-800 hover:border-primary-200'}`}>
                          <div className="font-bold text-sm mb-1">OpenAI 兼容 / 国产</div>
                          <div className="text-[10px] opacity-70">DeepSeek, Moonshot, GLM...</div>
                      </button>
                  </div>
              </div>
              {apiConfig.provider === 'openai_compatible' && (
                  <>
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Base URL</label>
                        <input type="text" value={apiConfig.baseUrl} onChange={(e) => setApiConfig({...apiConfig, baseUrl: e.target.value})} placeholder="https://api.deepseek.com" className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm outline-none focus:border-primary-500 font-mono"/>
                    </div>
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">API Key</label>
                        <input type="password" value={apiConfig.apiKey} onChange={(e) => setApiConfig({...apiConfig, apiKey: e.target.value})} placeholder="sk-..." className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm outline-none focus:border-primary-500 font-mono"/>
                    </div>
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Model Name</label>
                        <input type="text" value={apiConfig.model} onChange={(e) => setApiConfig({...apiConfig, model: e.target.value})} placeholder="e.g. deepseek-chat" className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm outline-none focus:border-primary-500 font-mono"/>
                    </div>
                  </>
              )}
          </div>
          <button onClick={() => saveConfig(apiConfig)} className="w-full py-3 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-xl font-bold flex items-center justify-center gap-2 mt-4 hover:opacity-90 transition-opacity"><Save size={16} /> 保存配置</button>
      </div>
  );

  if (inlineView) {
      return (
          <div className="flex flex-col h-full w-full bg-slate-50/30 dark:bg-transparent relative">
              {showSettings && <SettingsPanel />}
              <div className="absolute top-4 right-4 z-20 flex gap-2">
                  <button onClick={() => setIsSearchOpen(!isSearchOpen)} className={`p-2 backdrop-blur-sm rounded-xl border border-slate-200 dark:border-slate-700 transition-colors shadow-sm ${isSearchOpen ? 'bg-primary-50 border-primary-200 text-primary-600' : 'bg-white/80 dark:bg-slate-800/80 text-slate-500 hover:text-primary-600'}`}>
                      <Search size={18} />
                  </button>
                  <button onClick={() => setShowSettings(true)} className="p-2 bg-white/80 dark:bg-slate-800/80 backdrop-blur-sm rounded-xl border border-slate-200 dark:border-slate-700 text-slate-500 hover:text-primary-600 transition-colors shadow-sm">
                      <Settings2 size={18} />
                  </button>
              </div>

              {isSearchOpen && <SearchBar />}

              <div className="flex-1 overflow-y-auto p-6 space-y-10 custom-scrollbar" ref={chatContainerRef}>
                <div className="max-w-4xl mx-auto space-y-8">
                  {filteredMessages.map(m => (
                      <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}>
                         <div className={`flex gap-4 max-w-[90%] ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                            {/* Avatar */}
                            <div className={`w-10 h-10 rounded-2xl flex items-center justify-center shrink-0 shadow-sm ${
                                m.role === 'user' ? 'bg-white dark:bg-slate-800 border' : 
                                m.role === 'system' ? 'bg-rose-100 dark:bg-rose-900/30 text-rose-600 border border-rose-200 dark:border-rose-800' :
                                'bg-primary-600 text-white shadow-primary-500/20 shadow-lg'
                            }`}>
                                {m.role === 'user' ? <User size={18} className="text-slate-400" /> : 
                                 m.role === 'system' ? <AlertTriangle size={18} /> : 
                                 <Bot size={18} />}
                            </div>

                            {/* Message Bubble */}
                            <div className={`rounded-[2rem] px-6 py-4 shadow-glass ${
                                m.role === 'user' ? 'bg-slate-900 text-white rounded-tr-sm' : 
                                m.role === 'system' ? 'bg-rose-50 dark:bg-rose-950/20 border border-rose-100 dark:border-rose-900/30 text-rose-700 dark:text-rose-300 rounded-tl-sm' :
                                'bg-white dark:bg-slate-850 border border-slate-100 dark:border-slate-800 rounded-tl-sm text-slate-700 dark:text-slate-200'
                            }`}>
                                {m.image && <img src={m.image} className="max-w-full h-auto max-h-96 rounded-2xl mb-4 shadow-2xl border border-white/50" />}

                                {m.role === 'system' && (
                                    <div className="flex items-center gap-2 mb-2 pb-2 border-b border-rose-200 dark:border-rose-800/30">
                                        {m.errorType === 'network' ? <WifiOff size={14} /> : m.errorType === 'auth' ? <Key size={14} /> : <AlertTriangle size={14} />}
                                        <span className="text-xs font-bold uppercase tracking-wider">System Alert</span>
                                    </div>
                                )}

                                <FormattedText text={m.text} onNavigateToChart={onNavigateToChart} onGradeClick={onGradeClick} />

                                {m.errorType === 'auth' && (
                                    <button onClick={() => setShowSettings(true)} className="mt-3 text-xs font-bold text-rose-600 underline hover:text-rose-700">Open Settings</button>
                                )}
                            </div>
                         </div>
                      </div>
                  ))}
                  {isLoading && (
                      <div className="flex justify-start">
                          <div className="flex gap-4">
                            <div className="w-10 h-10 bg-primary-100 dark:bg-primary-900/30 rounded-2xl flex items-center justify-center animate-pulse"><Sparkles size={18} className="text-primary-600" /></div>
                            <div className="flex items-center gap-3 bg-white dark:bg-slate-850 border px-6 py-4 rounded-[2rem] shadow-sm">
                                <div className="flex gap-1">
                                    <span className="w-1.5 h-1.5 bg-primary-500 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                                    <span className="w-1.5 h-1.5 bg-primary-500 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                                    <span className="w-1.5 h-1.5 bg-primary-500 rounded-full animate-bounce"></span>
                                </div>
                                <span className="text-xs font-black text-primary-600 uppercase tracking-widest">
                                    {apiConfig.provider === 'gemini' ? 'Gemini Thinking...' : `${apiConfig.model} Generating...`}
                                </span>
                            </div>
                          </div>
                      </div>
                  )}
                </div>
                <div ref={messagesEndRef} className="h-4" />
              </div>
              <div className="p-8 bg-white/50 dark:bg-slate-900/50 backdrop-blur-xl border-t border-slate-100 dark:border-slate-800 shadow-float">
                  <div className="max-w-4xl mx-auto">
                    <div className="flex gap-2 mb-4 overflow-x-auto no-scrollbar pb-1">
                        {['对标当前过滤结果', '预测加工流动性', '检索高冲击牌号'].map(q => (
                            <button key={q} onClick={() => handleSendMessage(q)} className="whitespace-nowrap px-4 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-[10px] font-bold text-slate-500 hover:text-primary-600 hover:border-primary-300 transition-all shadow-sm">#{q}</button>
                        ))}
                    </div>
                    {renderInput()}
                  </div>
              </div>
          </div>
      );
  }

  // ... (Small Popup View - mostly reused logic but updated Message handling)
  return (
    <>
      <button
        onClick={() => setIsOpen(true)}
        className={`fixed bottom-8 right-8 z-40 w-16 h-16 bg-primary-600 rounded-full shadow-2xl flex items-center justify-center text-white hover:scale-110 active:scale-95 transition-all ${isOpen ? 'scale-0' : 'scale-100'}`}
      >
        <Sparkles size={28} />
      </button>

      <div 
        className={`fixed bottom-8 right-8 z-50 bg-white dark:bg-slate-900 rounded-[2.5rem] shadow-2xl ring-1 ring-slate-200 dark:ring-slate-800 flex flex-col overflow-hidden transition-all duration-500 origin-bottom-right ${isOpen ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 translate-y-10 scale-95 pointer-events-none'} ${isExpanded ? 'w-[700px] h-[85vh]' : 'w-[440px] h-[600px]'}`}
      >
        {showSettings && <SettingsPanel />}

        <div className="flex items-center justify-between px-6 py-4 border-b bg-slate-50/80 dark:bg-slate-950/80 backdrop-blur-md">
            <div className="flex items-center gap-3">
                <div className="p-1.5 bg-primary-100 dark:bg-primary-900/30 text-primary-600 rounded-lg shadow-sm"><Bot size={18} /></div>
                <div>
                    <span className="font-black text-sm tracking-tight text-slate-800 dark:text-white uppercase block">ResinAI</span>
                    <span className="text-[9px] text-slate-400 font-bold uppercase tracking-wider block">
                        {apiConfig.provider === 'gemini' ? 'Gemini Pro' : apiConfig.model}
                    </span>
                </div>
            </div>
            <div className="flex gap-1">
                <button onClick={() => setIsSearchOpen(!isSearchOpen)} className={`p-2 rounded-xl transition-colors ${isSearchOpen ? 'bg-primary-50 text-primary-600' : 'text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'}`}>
                    <Search size={18} />
                </button>
                <button onClick={() => setShowSettings(!showSettings)} className="p-2 text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl transition-colors"><Settings2 size={18} /></button>
                <button onClick={() => setIsExpanded(!isExpanded)} className="p-2 text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl transition-colors">{isExpanded ? <Minimize2 size={18} /> : <Maximize2 size={18} />}</button>
                <button onClick={() => setIsOpen(false)} className="p-2 text-slate-400 hover:text-rose-500 rounded-xl transition-colors"><X size={20} /></button>
            </div>
        </div>

        {isSearchOpen && <SearchBar />}

        <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar bg-slate-50/30 dark:bg-transparent" ref={chatContainerRef}>
            {filteredMessages.map(m => (
                <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in`}>
                    <div className={`max-w-[85%] p-4 rounded-2xl text-xs shadow-sm ${
                        m.role === 'user' ? 'bg-slate-900 text-white rounded-tr-none' : 
                        m.role === 'system' ? 'bg-rose-50 dark:bg-rose-950/30 text-rose-700 dark:text-rose-200 border border-rose-100 dark:border-rose-900/50' :
                        'bg-white dark:bg-slate-800 border dark:border-slate-700 rounded-tl-none text-slate-700 dark:text-slate-200'
                    }`}>
                        {m.image && <img src={m.image} className="max-w-full h-auto max-h-48 rounded-xl mb-3 shadow-md" />}
                        {m.role === 'system' && <div className="font-bold mb-1 flex items-center gap-1"><AlertTriangle size={12}/> System Alert</div>}
                        <FormattedText text={m.text} onNavigateToChart={onNavigateToChart} onGradeClick={onGradeClick} />
                    </div>
                </div>
            ))}
            {isLoading && <div className="flex justify-start animate-pulse"><div className="w-10 h-8 bg-primary-100 dark:bg-primary-900/30 rounded-xl flex items-center justify-center"><Sparkles size={16} className="text-primary-600" /></div></div>}
        </div>

        <div className="p-4 border-t bg-white dark:bg-slate-900">
            {attachedImage && (
                <div className="flex items-center justify-between p-2 mb-2 bg-slate-50 dark:bg-slate-800 border rounded-xl">
                    <img src={attachedImage} className="w-8 h-8 rounded object-cover" />
                    <button onClick={() => setAttachedImage(null)} className="text-slate-400 hover:text-rose-500"><X size={14} /></button>
                </div>
            )}
            {renderInput()}
        </div>
      </div>
    </>
  );
};

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Product, ColumnConfig, SortConfig, PropertyValue } from '../types';
import { Factory, Edit, Trash2, CheckSquare, Square, ArrowUp, ArrowDown, ChevronLeft, ChevronRight, Eye, Radar, Loader2, AlertCircle, SearchX, RotateCcw, Filter, X, Search, Tag, Trophy } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import { EditProductModal } from './EditProductModal';
import { DeleteConfirmationModal } from './DeleteConfirmationModal';
import { ProductDetailDrawer } from './ProductDetailDrawer';
import * as echarts from 'echarts';

export interface FilterItem {
  id: string;
  label: string;
  type: 'search' | 'category' | 'numeric';
  onRemove: () => void;
}

interface DataGridProps {
  data: Product[];
  columns: ColumnConfig[];
  isLoading: boolean;
  onDelete: (ids: string[]) => void;
  onUpdate: (product: Product) => void;
  onBatchUpdate: (ids: string[], updates: Partial<Product>) => void;
  onCategorySelect: (id: string) => void;
  selectedIds: Set<string>;
  onSelectionChange: (ids: Set<string>) => void;
  onClearFilters?: () => void;
  activeFilters?: FilterItem[];
}

const GridSkeleton: React.FC<{ rows: number; cols: number }> = ({ rows, cols }) => (
  <div className="w-full animate-pulse space-y-4 p-4">
    <div className="flex gap-4 mb-8">
      {Array.from({ length: cols }).map((_, i) => (
        <div key={i} className="h-4 bg-slate-100 dark:bg-slate-800 rounded-full flex-1" />
      ))}
    </div>
    {Array.from({ length: rows }).map((_, i) => (
      <div key={i} className="flex gap-4 items-center">
        <div className="w-6 h-6 bg-slate-100 dark:bg-slate-800 rounded-md" />
        {Array.from({ length: cols }).map((_, j) => (
          <div key={j} className={`h-8 bg-slate-50 dark:bg-slate-800/50 rounded-xl flex-1 ${j === 0 ? 'flex-[2]' : ''}`} />
        ))}
      </div>
    ))}
  </div>
);

const QuickRadarPopup: React.FC<{ product: Product; anchorRef: React.RefObject<HTMLDivElement> }> = ({ product, anchorRef }) => {
    const chartRef = useRef<HTMLDivElement>(null);
    const { tProp } = useLanguage();

    useEffect(() => {
        if (!chartRef.current) return;
        const myChart = echarts.init(chartRef.current);
        const props = ['密度', '熔体质量流动速率', '拉伸屈服应力', '弯曲模量', '悬臂梁缺口冲击强度'];
        const values = props.map(p => {
            const v = product.properties?.[p]?.value;
            return typeof v === 'number' ? v : parseFloat(String(v)) || 0;
        });

        myChart.setOption({
            radar: {
                indicator: props.map(p => ({ name: tProp(p).slice(0,6), max: 100 })), 
                shape: 'circle', splitNumber: 3, axisName: { fontSize: 8, color: '#94a3b8' }
            },
            series: [{ type: 'radar', data: [{ value: values, areaStyle: { color: 'rgba(99, 102, 241, 0.3)' }, lineStyle: { color: '#6366f1' } }], symbol: 'none' }]
        });
        return () => myChart.dispose();
    }, [product, tProp]);

    const rect = anchorRef.current?.getBoundingClientRect();
    if (!rect) return null;

    return (
        <div className="fixed z-[100] w-48 h-48 bg-white dark:bg-slate-900 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-800 p-2 animate-in fade-in zoom-in-95 pointer-events-none" 
             style={{ left: rect.left + 40, top: rect.top - 60 }}>
            <div ref={chartRef} className="w-full h-full" />
        </div>
    );
};

const renderCellContent = (val: any, unit?: string, isLongText = false, isBest = false): React.ReactNode => {
    if (val === null || val === undefined || val === '') {
        return <span className="text-slate-300 dark:text-slate-700 font-mono">-</span>;
    }

    if (typeof val === 'number') {
        if (isNaN(val)) return <span className="text-slate-300 dark:text-slate-700 font-mono">-</span>;
        return (
            <div className={`flex items-baseline gap-1 ${isBest ? 'bg-emerald-100/50 dark:bg-emerald-900/30 px-2 py-0.5 rounded-md -ml-2 border border-emerald-200/50 dark:border-emerald-800/50' : ''}`}>
                <span className={`font-mono font-bold tracking-tight ${isBest ? 'text-emerald-700 dark:text-emerald-400' : 'text-primary-600 dark:text-primary-400'}`}>{val}</span>
                {unit && <span className={`text-[9px] font-black uppercase tracking-tighter ${isBest ? 'text-emerald-500/70' : 'text-slate-400'}`}>{unit}</span>}
                {isBest && <Trophy size={10} className="text-emerald-500 ml-1" />}
            </div>
        );
    }

    const displayStr = typeof val === 'object' ? JSON.stringify(val) : String(val);
    return (
      <span 
        className={`text-slate-700 dark:text-slate-300 font-medium ${isLongText ? 'line-clamp-1 max-w-[240px]' : 'truncate max-w-[180px]'}`} 
        title={displayStr}
      >
        {displayStr}
      </span>
    );
};

// Helper to determine if lower value is better
const isLowBest = (key: string) => {
    const k = key.toLowerCase();
    return k.includes('density') || k.includes('密度') || 
           k.includes('mfr') || k.includes('flow') || k.includes('流动') ||
           k.includes('shrinkage') || k.includes('收缩') ||
           k.includes('haze') || k.includes('雾度') ||
           k.includes('absorption') || k.includes('吸水');
};

export const DataGrid: React.FC<DataGridProps> = ({ data = [], columns = [], isLoading, onDelete, onUpdate, onBatchUpdate, onCategorySelect, selectedIds = new Set(), onSelectionChange, onClearFilters, activeFilters = [] }) => {
  const { t, tProp } = useLanguage();
  const visibleColumns = useMemo(() => (columns || []).filter((c) => c.visible), [columns]);
  const [sortConfig, setSortConfig] = useState<SortConfig | null>(null);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [deletingIds, setDeletingIds] = useState<string[]>([]);
  const [viewingProduct, setViewingProduct] = useState<Product | null>(null);
  const [hoveredProduct, setHoveredProduct] = useState<Product | null>(null);
  const radarAnchorRef = useRef<HTMLDivElement>(null);

  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 15;

  const sortedData = useMemo(() => {
    if (!data) return [];
    if (!sortConfig) return data;
    return [...data].sort((a, b) => {
      const aProp = a.properties?.[sortConfig.key];
      const bProp = b.properties?.[sortConfig.key];
      let aV = aProp?.value ?? (a as any)[sortConfig.key] ?? '';
      let bV = bProp?.value ?? (b as any)[sortConfig.key] ?? '';

      // Handle nulls always at bottom
      if (aV === '' || aV === null || aV === undefined) return 1;
      if (bV === '' || bV === null || bV === undefined) return -1;

      const aN = parseFloat(String(aV)), bN = parseFloat(String(bV));
      if (!isNaN(aN) && !isNaN(bN)) return sortConfig.direction === 'asc' ? aN - bN : bN - aN;
      return sortConfig.direction === 'asc' ? String(aV).localeCompare(String(bV)) : String(bV).localeCompare(String(aV));
    });
  }, [data, sortConfig]);

  const paginatedData = useMemo(() => {
    const start = (currentPage - 1) * pageSize;
    return sortedData.slice(start, start + pageSize);
  }, [sortedData, currentPage]);

  const totalPages = Math.ceil(sortedData.length / pageSize);

  useEffect(() => {
    if (currentPage > totalPages && totalPages > 0) { setCurrentPage(totalPages); }
  }, [totalPages, currentPage]);

  // Determine extremes for highlighting within the current view
  const columnExtremes = useMemo(() => {
    const extremes: Record<string, number> = {};
    const visibleCols = columns.filter(c => !c.isSystem && c.visible);

    visibleCols.forEach(col => {
        const key = col.key;
        const lowBest = isLowBest(key);
        let bestVal = lowBest ? Infinity : -Infinity;
        let found = false;

        paginatedData.forEach(p => {
            const val = p.properties?.[key]?.value;
            const num = parseFloat(String(val));
            if (!isNaN(num)) {
                found = true;
                if (lowBest) {
                    if (num < bestVal) bestVal = num;
                } else {
                    if (num > bestVal) bestVal = num;
                }
            }
        });
        if (found && bestVal !== Infinity && bestVal !== -Infinity) {
            extremes[key] = bestVal;
        }
    });
    return extremes;
  }, [paginatedData, columns]);

  const toggleSelection = (id: string) => {
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id); else next.add(id);
    onSelectionChange(next);
  };

  const toggleAllSelection = () => {
    if (selectedIds.size === paginatedData.length && paginatedData.length > 0) { onSelectionChange(new Set()); }
    else { onSelectionChange(new Set(paginatedData.map(p => p.id))); }
  };

  if (isLoading) return <GridSkeleton rows={10} cols={visibleColumns.length || 5} />;

  if (!isLoading && data.length === 0) {
      return (
          <div className="h-full flex flex-col items-center justify-center p-12 text-center bg-slate-50/50 dark:bg-slate-900/30 rounded-[3rem] border border-dashed border-slate-200 dark:border-slate-800">
              <div className="w-20 h-20 bg-white dark:bg-slate-800 rounded-full flex items-center justify-center shadow-glass mb-6">
                  <SearchX size={32} className="text-slate-300 dark:text-slate-600" />
              </div>
              <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100 mb-2">未找到匹配结果</h3>
              <p className="text-sm text-slate-500 max-w-xs mx-auto tracking-tight mb-6">尝试调整您的过滤条件或搜索关键词以获取更多结果。</p>
              {onClearFilters && (
                  <button onClick={onClearFilters} className="flex items-center gap-2 px-5 py-2.5 bg-primary-600 hover:bg-primary-500 text-white rounded-xl shadow-lg shadow-primary-500/20 font-bold text-xs transition-all active:scale-95">
                      <RotateCcw size={14} /> 重置所有筛选
                  </button>
              )}
          </div>
      );
  }

  return (
    <div className="h-full flex flex-col relative overflow-hidden group/grid">
      {/* Active Filters Bar */}
      {activeFilters.length > 0 && (
          <div className="px-6 py-3 bg-white/50 dark:bg-slate-950/50 border-b border-slate-100 dark:border-slate-800 flex items-center gap-3 shrink-0 overflow-x-auto custom-scrollbar-horizontal backdrop-blur-sm animate-in slide-in-from-top-1">
              <div className="flex items-center gap-1.5 text-[10px] font-black text-slate-400 uppercase tracking-widest shrink-0">
                  <Filter size={12} /> {activeFilters.length} Active Filters
              </div>
              <div className="h-4 w-px bg-slate-200 dark:bg-slate-800 shrink-0 mx-1"></div>

              {activeFilters.map(f => (
                  <div key={f.id} className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-bold border shadow-sm transition-all animate-in zoom-in duration-200 ${
                      f.type === 'search' 
                      ? 'bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-300 border-blue-100 dark:border-blue-800' 
                      : 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300 border-primary-100 dark:border-primary-800'
                  }`}>
                      {f.type === 'search' ? <Search size={10} /> : <Tag size={10} />}
                      <span>{f.label}</span>
                      <button onClick={f.onRemove} className="p-0.5 rounded-full hover:bg-white/50 dark:hover:bg-black/20 transition-colors ml-1">
                          <X size={12} />
                      </button>
                  </div>
              ))}

              {onClearFilters && activeFilters.length > 1 && (
                  <button 
                    onClick={onClearFilters} 
                    className="ml-auto text-[10px] font-bold text-slate-400 hover:text-rose-500 hover:underline transition-colors whitespace-nowrap px-2"
                  >
                      Clear All
                  </button>
              )}
          </div>
      )}

      <div className="flex-1 overflow-auto custom-scrollbar">
        <table className="w-full text-sm text-left border-separate border-spacing-0">
          <thead className="sticky top-0 z-30 bg-white/90 dark:bg-slate-950/90 backdrop-blur-xl shadow-sm">
            <tr>
              <th className="px-4 py-4 w-12 border-b border-slate-100 dark:border-slate-800">
                <button onClick={toggleAllSelection} className="text-slate-400 hover:text-primary-500 transition-colors">
                    {selectedIds.size > 0 && selectedIds.size === paginatedData.length ? <CheckSquare size={18} className="text-primary-500" /> : <Square size={18} />}
                </button>
              </th>
              {visibleColumns.map((col) => (
                <th key={col.key} className="px-4 py-4 font-black text-[10px] text-slate-400 uppercase tracking-[0.15em] border-b border-slate-100 dark:border-slate-800 cursor-pointer hover:text-primary-600 transition-colors group/head" onClick={() => setSortConfig({ key: col.key, direction: sortConfig?.key === col.key && sortConfig.direction === 'asc' ? 'desc' : 'asc' })}>
                  <div className="flex items-center gap-1.5">{tProp(col.label)}<span className={`transition-all duration-300 ${sortConfig?.key === col.key ? 'opacity-100 scale-100' : 'opacity-0 scale-75 group-hover/head:opacity-40'}`}>{sortConfig?.key === col.key && sortConfig.direction === 'desc' ? <ArrowDown size={12} /> : <ArrowUp size={12} />}</span></div>
                </th>
              ))}
              <th className="px-4 py-4 border-b border-slate-100 dark:border-slate-800 text-right w-24 font-black text-[10px] text-slate-400 uppercase tracking-widest">操作</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50 dark:divide-slate-900">
            {paginatedData.map((p) => (
                <tr key={p.id} className={`group transition-all duration-200 cursor-pointer ${selectedIds.has(p.id) ? 'bg-primary-50/40 dark:bg-primary-950/20' : 'hover:bg-slate-50/50 dark:hover:bg-slate-900/40'}`} onClick={() => toggleSelection(p.id)}>
                    <td className="px-4 py-3.5" onClick={e => e.stopPropagation()}><button onClick={() => toggleSelection(p.id)} className={`transition-colors ${selectedIds.has(p.id) ? "text-primary-500" : "text-slate-300 group-hover:text-slate-400"}`}>{selectedIds.has(p.id) ? <CheckSquare size={16} /> : <Square size={16} />}</button></td>
                    {visibleColumns.map((col) => {
                        // Check if this cell contains the best value for this column
                        let isBest = false;
                        if (!col.isSystem) {
                            const val = p.properties?.[col.key]?.value;
                            const numVal = parseFloat(String(val));
                            if (!isNaN(numVal) && columnExtremes[col.key] !== undefined && columnExtremes[col.key] === numVal) {
                                isBest = true;
                            }
                        }

                        return (
                            <td key={col.key} className="px-4 py-3.5 whitespace-nowrap">
                                {col.key === 'gradeName' ? (
                                    <div className="flex items-center gap-2">
                                        <span className="font-bold text-slate-800 dark:text-white group-hover:text-primary-600 dark:group-hover:text-primary-400 transition-colors">{p.gradeName}</span>
                                        <div onMouseEnter={(e) => { e.stopPropagation(); setHoveredProduct(p); }} onMouseLeave={() => setHoveredProduct(null)} className="cursor-help text-indigo-500 opacity-0 group-hover:opacity-100 transition-all scale-75 group-hover:scale-100"><Radar size={14} /></div>
                                    </div>
                                ) : col.key === 'manufacturer' ? (
                                    <div className="flex items-center gap-1.5"><Factory size={12} className="text-slate-300 dark:text-slate-600" /><span className="text-slate-500 dark:text-slate-400 font-medium text-xs truncate max-w-[120px]">{p.manufacturer}</span></div>
                                ) : (
                                    renderCellContent(p.properties?.[col.key]?.value, p.properties?.[col.key]?.unit, col.key.includes('应用'), isBest)
                                )}
                            </td>
                        );
                    })}
                    <td className="px-4 py-3.5 text-right" onClick={e => e.stopPropagation()}><div className="flex items-center justify-end gap-1 opacity-0 group-hover:opacity-100 transition-all translate-x-2 group-hover:translate-x-0"><button onClick={() => setViewingProduct(p)} className="p-1.5 text-slate-400 hover:text-primary-500 hover:bg-primary-50 dark:hover:bg-primary-900/30 rounded-lg transition-all" title={t('details')}><Eye size={14} /></button><button onClick={() => setEditingProduct(p)} className="p-1.5 text-slate-400 hover:text-amber-500 hover:bg-amber-50 dark:hover:bg-amber-900/30 rounded-lg transition-all" title={t('editProduct')}><Edit size={14} /></button></div></td>
                </tr>
            ))}
          </tbody>
        </table>
      </div>
      {hoveredProduct && <QuickRadarPopup product={hoveredProduct} anchorRef={radarAnchorRef} />}
      <div ref={radarAnchorRef} className="hidden" />
      <div className="flex items-center justify-between px-6 py-4 bg-white/80 dark:bg-slate-950/80 border-t border-slate-100 dark:border-slate-800 backdrop-blur-xl z-20">
         <div className="flex items-center gap-4"><span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{t('showing')} <span className="text-slate-700 dark:text-slate-200">{paginatedData.length}</span> / <span className="text-slate-700 dark:text-slate-200">{sortedData.length}</span></span>{selectedIds.size > 0 && <div className="h-4 w-px bg-slate-200 dark:bg-slate-800" />}{selectedIds.size > 0 && <span className="text-[10px] font-black text-primary-500 uppercase tracking-widest animate-in fade-in slide-in-from-left-2">{selectedIds.size} {t('selected')}</span>}</div>
         <div className="flex items-center gap-4"><div className="flex items-center gap-1"><button onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} className="p-2 border border-slate-200 dark:border-slate-800 rounded-xl disabled:opacity-20 hover:bg-slate-50 dark:hover:bg-slate-900 text-slate-500 transition-all active:scale-95"><ChevronLeft size={16} /></button><div className="px-4 flex items-center gap-2"><span className="text-xs font-black tabular-nums text-slate-700 dark:text-slate-200">{currentPage}</span><span className="text-[10px] font-bold text-slate-300 dark:text-slate-700">/</span><span className="text-xs font-bold text-slate-400 tabular-nums">{totalPages || 1}</span></div><button onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages || totalPages === 0} className="p-2 border border-slate-200 dark:border-slate-800 rounded-xl disabled:opacity-20 hover:bg-slate-50 dark:hover:bg-slate-900 text-slate-500 transition-all active:scale-95"><ChevronRight size={16} /></button></div></div>
      </div>
      <EditProductModal isOpen={!!editingProduct} onClose={() => setEditingProduct(null)} product={editingProduct} onSave={async p => { onUpdate(p); setEditingProduct(null); return true; }} />
      <DeleteConfirmationModal isOpen={deletingIds.length > 0} onClose={() => setDeletingIds([])} onConfirm={() => { onDelete(deletingIds); setDeletingIds([]); }} productNames={deletingIds.map(id => data.find(p => p.id === id)?.gradeName || 'Unknown')} />
      <ProductDetailDrawer product={viewingProduct} onClose={() => setViewingProduct(null)} onCategoryClick={onCategorySelect} />
    </div>
  );
};
